insert into publishers ("id", "slug", "name", "color_hex", "logo_url", "created_at") values
  ('b704b760-3179-502b-9b34-289a04adb849', 'dc', 'DC Comics', '#0476D0', '/publishers/dc.svg', '2024-01-01T00:00:00.000Z'),
  ('32bd1899-06ea-5dec-a0fd-84431cff288e', 'marvel', 'Marvel Comics', '#E62429', '/publishers/marvel.svg', '2024-01-01T00:00:00.000Z'),
  ('9d2150e6-b5b9-59d6-98a3-53f74a110874', 'image', 'Image Comics', '#1DB954', '/publishers/image.svg', '2024-01-01T00:00:00.000Z'),
  ('dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'boom', 'BOOM! Studios', '#FF6B35', '/publishers/boom.svg', '2024-01-01T00:00:00.000Z')
insert into entities ("id", "slug", "name", "entity_type", "role", "publisher_id", "real_name", "first_appearance", "logo_url", "cover_image_url", "short_bio", "created_at") values
  ('5077371b-ec42-5e42-978e-c7d720a6ff1c', 'aaron-slaughter', 'Aaron Slaughter', 'character', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Aaron Slaughter', 'House of Slaughter #1 (BOOM! Studios, 2021)', NULL, NULL, 'Aaron Slaughter is an operative of the House of Slaughter who shares Erica''s lineage and training. Caught between the demands of the Order and his own conscience, he is both a potential ally and a rival to Erica.', '2024-01-01T00:00:00.000Z'),
  ('8239a78a-c7f8-54b8-b823-3a0387f9ccf7', 'agent-jensen', 'Agent Jensen', 'character', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', NULL, 'The Empty Man #1 (BOOM! Studios, 2014)', NULL, NULL, 'Agent Jensen is the FBI investigator at the center of the Empty Man case, assigned to track and contain an affliction no one understands. His relentless pursuit exposes how little the authorities truly grasp about the horror they face.', '2024-01-01T00:00:00.000Z'),
  ('ffac191d-640b-59b0-9a6c-2c3d9aeeb98d', 'agent-langford', 'Agent Langford', 'character', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', NULL, 'The Empty Man #1 (BOOM! Studios, 2014)', NULL, NULL, 'Agent Langford is the methodical partner on the federal task force hunting the source of the Empty Man contagion. Her careful procedures are steadily undermined as the case refuses to behave like any disease she has known.', '2024-01-01T00:00:00.000Z'),
  ('710b82cd-cfe7-58fb-9e14-b7d0b699cbfb', 'alex-wilde', 'Alex Wilde', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Alex Wilde', 'Savage Dragon #1 (1992)', NULL, NULL, 'A dedicated Chicago police officer who becomes Dragon''s partner and one of his most important personal relationships. Brave and grounded, she helps anchor Dragon to the human world he protects.', '2024-01-01T00:00:00.000Z'),
  ('c4001d41-6a31-5d98-9b1a-dcff2110c389', 'alfred-pennyworth', 'Alfred Pennyworth', 'character', 'hero', 'b704b760-3179-502b-9b34-289a04adb849', 'Alfred Thaddeus Crane Pennyworth', 'Batman #16 (1943)', NULL, NULL, 'Alfred Pennyworth is the Wayne family butler, the keeper of the Batcave''s operational infrastructure, and the only constant in Bruce Wayne''s life who knew him before grief became his defining characteristic. A former army medic and MI6 operative depending on the continuity, Alfred provides field medicine, technical support, mission briefing, and the only form of accountability Bruce consistently tolerates — which is to say, Alfred says what he thinks and Bruce listens about thirty percent of the time. He is as central to the Batman mythology as any villain.', '2024-01-01T00:00:00.000Z'),
  ('b5249e33-edfa-5bc1-aaa2-b03e5a4453fe', 'angel', 'Angel', 'character', 'antihero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Liam / Angelus', 'Buffy the Vampire Slayer #1 (BOOM! Studios, 2019)', NULL, NULL, 'Angel is a vampire cursed with the return of his human soul, doomed to remember every atrocity committed as the demon Angelus. He fights alongside Buffy in atonement, his love for her always shadowed by the monster within.', '2024-01-01T00:00:00.000Z'),
  ('559e093e-4477-566a-abce-9ade8afe79c8', 'angstrom-levy', 'Angstrom Levy', 'character', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Angstrom Levy', 'Invincible #33 (2006)', NULL, NULL, 'Angstrom Levy is a scientific genius capable of opening portals across the multiverse. After a catastrophic accident he blames on Invincible, he becomes one of Mark''s most relentless and personal foes.', '2024-01-01T00:00:00.000Z'),
  ('e1d3db22-d396-5b47-a3eb-2fd70f4e8d48', 'anti-spawn', 'Anti-Spawn', 'character', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Jason Wynn (Redeemer)', 'Spawn #38 (1995)', NULL, NULL, 'The Anti-Spawn, also known as the Redeemer, is a Heaven-aligned warrior created to destroy the Hellspawn. Mirroring Spawn''s powers with holy purpose, it embodies the war between Heaven and Hell turned directly against Al.', '2024-01-01T00:00:00.000Z'),
  ('92c2c3fd-aea6-57ab-bfc3-0d4d5af52bfd', 'apocalypse', 'Apocalypse', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'En Sabah Nur', 'X-Factor #5 (1986)', NULL, NULL, 'Apocalypse is one of the first and most powerful mutants, an ancient being who has ruled and manipulated civilizations for millennia. Preaching ruthless survival of the fittest, he seeks to cull the weak and forge a world ruled by the strong. His immense power and apocalyptic philosophy make him an existential threat to mutant and human alike.', '2024-01-01T00:00:00.000Z'),
  ('36642001-e8a9-5065-87f9-0502cf4edac5', 'aquaman', 'Aquaman', 'character', 'hero', 'b704b760-3179-502b-9b34-289a04adb849', 'Arthur Curry', 'More Fun Comics #73 (1941)', NULL, NULL, 'Aquaman is the king of Atlantis and a founding member of the Justice League, ruling the oceans while protecting the surface world. Wielding super-strength, aquatic telepathy, and a legendary trident, he bridges two worlds as a powerful and principled hero.', '2024-01-01T00:00:00.000Z'),
  ('d679bf65-5e35-5ddb-94fb-c5446bf4e277', 'ares', 'Ares', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', NULL, 'Wonder Woman #1 (1942)', NULL, NULL, 'Ares is the Olympian god of war and Wonder Woman''s archnemesis, an immortal who feeds on the bloodshed and strife of mortals. Where Diana brings peace, Ares sows endless conflict, making him the eternal antithesis of everything she stands for.', '2024-01-01T00:00:00.000Z'),
  ('c31f6730-0efb-548f-9c3c-c8c04aed7c04', 'arnim-zola', 'Arnim Zola', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Arnim Zola', 'Captain America #208 (1977)', NULL, NULL, 'A Nazi biochemist and genetic engineer, Arnim Zola pioneered grotesque experiments that allowed him to transfer his consciousness into artificial bodies, achieving a twisted form of immortality. Often appearing as a headless android with his face projected on its chest, he is a recurring architect of horror in Captain America''s life. His mastery of cloning and bio-engineering makes him one of Cap''s most disturbing foes.', '2024-01-01T00:00:00.000Z'),
  ('1d2e2e20-67a0-5ff6-b32e-f27309a51253', 'atom-eve', 'Atom Eve', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Samantha Eve Wilkins', 'Invincible #1 (2003)', NULL, NULL, 'Atom Eve is a reality-bending hero able to manipulate matter at the atomic level, restructuring almost anything she can perceive. One of the most powerful figures in her world, she is a close ally of Invincible and the Guardians.', '2024-01-01T00:00:00.000Z'),
  ('77db7ea3-8ed7-5273-add1-d93259b39938', 'atrocitus', 'Atrocitus', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Atros', 'Final Crisis: Rage of the Red Lanterns #1 (2008)', NULL, NULL, 'Atrocitus is the founder and leader of the Red Lantern Corps, a being consumed by rage after the Manhunters slaughtered his sector and family. He channels burning blood and incandescent fury through a red power ring forged from his own hatred. He blames the Guardians of the Universe and their Green Lanterns for the deaths he can never forgive.', '2024-01-01T00:00:00.000Z'),
  ('792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'avengers', 'Avengers', 'team', 'hero', '32bd1899-06ea-5dec-a0fd-84431cff288e', NULL, 'The Avengers #1 (1963)', NULL, NULL, 'Earth''s Mightiest Heroes are a coalition of Marvel''s most powerful and iconic figures who band together to face threats no single hero could withstand. Assembled when individual champions realized that some dangers required a united front, the Avengers have defended the world and the wider universe across decades of ever-changing rosters. Their rallying cry, ''Avengers Assemble!'', has come to symbolize heroism on the grandest scale.', '2024-01-01T00:00:00.000Z'),
  ('948cf5fe-fe35-5e34-9f70-089f1b266b31', 'badrock', 'Badrock', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Thomas John McCall', 'Youngblood #1 (1992)', NULL, NULL, 'Badrock is a teenager transformed into a massive rock-bodied powerhouse after a freak accident. His youthful enthusiasm and immense strength make him one of Youngblood''s most popular members.', '2024-01-01T00:00:00.000Z'),
  ('6307652f-ef23-59c7-bf66-eb6ce5ed6e9c', 'bane', 'Bane', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Unknown; called Bane', 'Batman: Vengeance of Bane #1 (1993)', NULL, NULL, 'Bane was born in a prison on a fictional Caribbean island, serving a sentence on behalf of his absent father, and educated himself entirely through the prison''s library and the violence of its population. Enhanced by the experimental compound Venom, which amplifies his already extraordinary physical capabilities, Bane is the rare Batman villain who defeated him through strategy rather than luck or power alone — he studied Batman for months before making a move. He is defined by an intellect that most readers and characters underestimate because of the body it occupies.', '2024-01-01T00:00:00.000Z'),
  ('6e0c7dd7-5e7a-5e9b-9a74-1424a8db9121', 'barbara-gordon', 'Barbara Gordon (Oracle / Batgirl)', 'character', 'hero', 'b704b760-3179-502b-9b34-289a04adb849', 'Barbara Gordon', 'Detective Comics #359 (1967)', NULL, NULL, 'Barbara Gordon is James Gordon''s daughter, the original Batgirl, and — after Alan Moore''s Killing Joke permanently altered her physical circumstances — the intelligence architect who became Oracle, the Batman family''s most operationally essential member. As Oracle, she ran global information networks, coordinated the Birds of Prey, and demonstrated that the most powerful tool in any hero''s arsenal is access to the right information at the right moment. She later reclaimed the Batgirl identity in DC''s New 52 relaunch.', '2024-01-01T00:00:00.000Z'),
  ('45ba8447-d9b0-5e63-b25d-3f181ed157a7', 'barbaric', 'Barbaric', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Rex Dexter (alias used in-series)', 'Savage Dragon #13 (1994)', NULL, NULL, 'A super-strong, good-natured hero who fights alongside Dragon and his fellow heroes. Often paired with his partner Ricochet, Barbaric brings raw power and loyalty to the team.', '2024-01-01T00:00:00.000Z'),
  ('d95c67d0-9578-5ab8-8ec3-cd61bef7c92f', 'baron-zemo', 'Baron Zemo', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Helmut Zemo', 'Avengers #6 (1964)', NULL, NULL, 'The Baron Zemo title has passed through a line of aristocratic German scientists devoted to conquest and vengeance against Captain America. Heinrich Zemo set the wartime trap that doomed Bucky and froze Cap, while his son Helmut inherited the grudge and leads the Masters of Evil. Brilliant, ruthless, and bound by a family legacy of hatred, Zemo is one of Cap''s most persistent foes.', '2024-01-01T00:00:00.000Z'),
  ('46a5721c-458f-5262-b06c-881e6b7f98bc', 'batman', 'Batman', 'character', 'hero', 'b704b760-3179-502b-9b34-289a04adb849', 'Bruce Wayne', 'Detective Comics #27 (1939)', NULL, NULL, 'Orphaned as a boy when his parents were gunned down outside a Gotham City theater, Bruce Wayne spent years forging his body and mind into the perfect instrument of justice. Returning to Gotham, he became Batman — a self-made detective-vigilante who wages a relentless war on crime using intellect, martial mastery, and fear as his weapons. He stands as one of the most recognizable heroes in fiction, defined not by superpowers but by an unbreakable will.', '2024-01-01T00:00:00.000Z'),
  ('c574c3b8-581d-56a5-95bd-6ac9f05e58c1', 'bautista-slaughter', 'Bautista Slaughter', 'character', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Bautista Slaughter', 'House of Slaughter #1 (BOOM! Studios, 2021)', NULL, NULL, 'Bautista Slaughter is a seasoned member of the Slaughter line and a steadying presence within the order. A veteran hunter, he upholds the House''s traditions and mentors those who come after him. His steadfastness anchors the chaos that surrounds the masks.', '2024-01-01T00:00:00.000Z'),
  ('0c19853d-1aac-5dcf-817b-22515ad05e2f', 'beast-boy', 'Beast Boy', 'character', 'hero', 'b704b760-3179-502b-9b34-289a04adb849', 'Garfield Logan', 'The Doom Patrol #99 (1965)', NULL, NULL, 'Garfield Logan, known as Beast Boy, can transform into any animal thanks to an experimental cure that turned his skin green. Once a member of the Doom Patrol, he became a fan-favorite Teen Titan, blending comic relief with surprising emotional depth. His shapeshifting versatility makes him one of the team''s most distinctive members.', '2024-01-01T00:00:00.000Z'),
  ('8e1ef9a0-54ee-5617-9109-d7b2c965a107', 'billy-cranston', 'Billy Cranston', 'character', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'William Cranston', 'Mighty Morphin Power Rangers #1 (BOOM! Studios, 2016)', NULL, NULL, 'The original Blue Ranger and the team''s resident genius. Billy''s inventions, analytical mind, and quiet courage repeatedly turn the tide when brute force falls short, making him indispensable to the Rangers.', '2024-01-01T00:00:00.000Z'),
  ('117737bd-7e5e-5807-ae9d-aebd4e273a32', 'black-samson', 'Black Samson', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Samson Garrison', 'Invincible #7 (2004)', NULL, NULL, 'Black Samson is a veteran hero who fights using a powerful suit of armor, lending hard-won experience to the team. After regaining his abilities he returns to active duty as a stabilizing presence.', '2024-01-01T00:00:00.000Z'),
  ('0a680e29-e289-5b76-ad11-9ae6b24f0542', 'black-widow', 'Black Widow', 'character', 'hero', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Natasha Romanoff', 'Tales of Suspense #52 (1964)', NULL, NULL, 'Black Widow is a former Soviet spy and master assassin who defected to become one of the world''s premier intelligence operatives and a stalwart Avenger. Trained from childhood in the Red Room, Natasha Romanoff balances a dark past with an unwavering commitment to atonement and heroism.', '2024-01-01T00:00:00.000Z'),
  ('c176cf47-e3aa-5124-96a3-c40653063787', 'brainiac', 'Brainiac', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Vril Dox', 'Action Comics #242 (1958)', NULL, NULL, 'Brainiac is a hyper-advanced alien android intelligence obsessed with collecting and cataloging knowledge, shrinking entire cities to add to his archive. His cold logic and vast technology make him one of the deadliest threats to Superman and the Justice League.', '2024-01-01T00:00:00.000Z'),
  ('cf13b5e8-4a72-5e83-80fa-cdab07827c1b', 'brother-blood', 'Brother Blood', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Sebastian Blood', 'The New Teen Titans #21 (1982)', NULL, NULL, 'Brother Blood is the title held by a centuries-long line of cult leaders who lead the sinister Church of Blood. Sustained by dark rituals and fanatical devotion, he wields charisma as a weapon and commands armies of zealots. He is a recurring ideological nemesis of the Teen Titans.', '2024-01-01T00:00:00.000Z'),
  ('bc3388da-87e3-5978-bd9a-c1c8218aad6f', 'brother-soporus', 'Brother Soporus', 'character', 'villain', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', NULL, 'The Empty Man #3 (BOOM! Studios, 2014)', NULL, NULL, 'Brother Soporus is a charismatic preacher who gives voice to the Empty Man''s visions, framing the affliction as revelation rather than illness. He shepherds the newly afflicted into the faith, making him one of the contagion''s most effective vectors.', '2024-01-01T00:00:00.000Z'),
  ('bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', 'buffy-summers', 'Buffy Summers', 'character', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Buffy Anne Summers', 'Buffy the Vampire Slayer #1 (BOOM! Studios, 2019)', NULL, NULL, 'Buffy Summers is the Chosen One, a teenage girl gifted with supernatural strength and reflexes to battle the vampires, demons, and forces of darkness that converge on Sunnydale. In BOOM! Studios'' reimagining she balances the burdens of being the Slayer with the ordinary chaos of high school, leaning on her friends to survive both.', '2024-01-01T00:00:00.000Z'),
  ('f0f9597b-2580-532b-9882-2aefcd510a65', 'captain-america', 'Captain America', 'character', 'hero', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Steve Rogers', 'Captain America Comics #1 (1941)', NULL, NULL, 'A frail young man from Brooklyn transformed into the pinnacle of human potential by an experimental Super-Soldier Serum, Steve Rogers became Captain America, the living embodiment of American ideals. Armed with an indestructible vibranium shield and an unbreakable moral compass, he has fought tyranny from the trenches of World War II to the modern Marvel Universe. Whether leading the Avengers or standing alone against a corrupt establishment, he remains a symbol of conscience, courage, and the promise that one good man can make a difference.', '2024-01-01T00:00:00.000Z'),
  ('f07139dc-c0a7-5000-a560-893f3fe017b0', 'captain-cold', 'Captain Cold', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Leonard Snart', 'Showcase #8 (1957)', NULL, NULL, 'Leonard Snart turned to crime with a freeze gun capable of stopping the Fastest Man Alive in his tracks, earning the name Captain Cold. As the disciplined leader of the Rogues, he enforces a strict criminal code against killing civilians. He is Barry Allen''s most persistent and honorable adversary.', '2024-01-01T00:00:00.000Z'),
  ('b445ddd6-e1dd-515d-a9bd-222dd45eec5b', 'captain-dante', 'Captain Dante', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Joe Dante', 'Witchblade #1 (1995)', NULL, NULL, 'Captain Joe Dante is Sara Pezzini''s commanding officer at the NYPD, a gruff but fair leader who shields her from departmental scrutiny. He balances bureaucratic pressure with genuine loyalty, often covering for Sara when her cases defy explanation.', '2024-01-01T00:00:00.000Z'),
  ('3e12c541-fd4c-54c0-ad44-ceda960d5635', 'selina-kyle', 'Catwoman', 'character', 'antihero', 'b704b760-3179-502b-9b34-289a04adb849', 'Selina Kyle', 'Batman #1 (1940)', NULL, NULL, 'Selina Kyle is Gotham''s most accomplished thief and, depending on the moment, Batman''s most complicated relationship. She operates outside the law without apology, targets the wealthy with a precision that reads as class warfare, and maintains a personal moral code that excludes hurting anyone who doesn''t have it coming. Her dynamic with Batman has oscillated between adversarial and romantic since her debut in 1940, and the tension — two people who could not be more different in method and more similar in motivation — has never been fully resolved.', '2024-01-01T00:00:00.000Z'),
  ('ba6e0e90-bee5-5088-b30a-9eb56df8fe0e', 'chapel', 'Chapel', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Bruce Stinson', 'Youngblood #1 (1992)', NULL, NULL, 'Chapel is a lethal special-operations marksman assigned to Youngblood''s away division. A grim soldier with a violent past, he brings a darker, more morally complicated edge to the team.', '2024-01-01T00:00:00.000Z'),
  ('14696e46-299e-58f0-801d-c8e2df42ef87', 'cheetah', 'Cheetah', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Barbara Ann Minerva', 'Wonder Woman #6 (1943)', NULL, NULL, 'The Cheetah is Wonder Woman''s most personal foe, most famously the archaeologist Barbara Ann Minerva, who is transformed into a savage human-feline predator by a cursed ritual. A former friend driven by obsession and the power of a god, she embodies the corruption of what could have been an ally.', '2024-01-01T00:00:00.000Z'),
  ('3c4082e1-3859-549a-a960-213fe1561bf3', 'circe', 'Circe', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Circe', 'Wonder Woman #37 (1949)', NULL, NULL, 'Circe is an immortal Greek sorceress of immense magical power and a bitter enemy of the Amazons. A master manipulator who delights in transforming men into beasts, she repeatedly schemes to corrupt, humiliate, or destroy Wonder Woman through cunning rather than brute force.', '2024-01-01T00:00:00.000Z'),
  ('c54a55aa-319d-57b6-9a52-dbe35d255a81', 'cogliostro', 'Cogliostro', 'character', 'antihero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Cain', 'Spawn #4 (1992)', NULL, NULL, 'An ancient, weathered Hellspawn who has long resisted Hell''s purpose, Cogliostro lives among the homeless and acts as a reluctant mentor. He teaches newer Hellspawn the truth about their powers and the war they were made to wage.', '2024-01-01T00:00:00.000Z'),
  ('9afcef8f-d470-5866-b0ae-2f4c597c32a7', 'conquest', 'Conquest', 'character', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Invincible #59 (2009)', NULL, NULL, 'Conquest is a brutal Viltrumite warrior with centuries of combat experience and a mechanical arm. Dispatched to bring Earth to heel, he becomes one of Invincible''s most physically devastating opponents.', '2024-01-01T00:00:00.000Z'),
  ('523b3b97-51a2-5f4c-a5a4-785316b20408', 'crossbones', 'Crossbones', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Brock Rumlow', 'Captain America #359 (1989)', NULL, NULL, 'Brock Rumlow is a vicious mercenary and combat specialist who rose through criminal ranks to become Crossbones, the Red Skull''s most trusted and brutal enforcer. A peerless hand-to-hand fighter and marksman, he serves as a relentless physical threat to Captain America. Where the Skull schemes, Crossbones is the fist that strikes.', '2024-01-01T00:00:00.000Z'),
  ('969b933e-c61f-5070-9f28-08874232cf5f', 'cutter', 'Cutter', 'character', 'antihero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', NULL, 'Something is Killing the Children #11 (BOOM! Studios, 2020)', NULL, NULL, 'Cutter is a hardened monster hunter whose brutal, uncompromising code sets him against Erica Slaughter. A killer of both monsters and inconvenient witnesses, he embodies the colder edge of the hunting world.', '2024-01-01T00:00:00.000Z'),
  ('2e60e526-80aa-5940-b950-3211d8e45eee', 'cyberface', 'Cyberface', 'character', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Cyberface', 'Savage Dragon #2 (1993)', NULL, NULL, 'A monstrous, cunning villain who rises from underling to world-conquering tyrant, Cyberface is one of Dragon''s most persistent enemies. His ambition and resilience let him return again and again across the series.', '2024-01-01T00:00:00.000Z'),
  ('cd1d8c92-fd02-5109-a100-cab73f34b4c4', 'cyborg', 'Cyborg', 'character', 'hero', 'b704b760-3179-502b-9b34-289a04adb849', 'Victor Stone', 'DC Comics Presents #26 (1980)', NULL, NULL, 'Victor Stone became Cyborg after a catastrophic accident left him rebuilt with cybernetic technology by his scientist father. A founding member of the New Teen Titans, he blends formidable strength and tech-powered abilities with deep humanity. His journey to accept his half-machine existence is one of the team''s defining arcs.', '2024-01-01T00:00:00.000Z'),
  ('be70c828-5b8f-5431-a529-20b5ca4371ef', 'cyclops', 'Cyclops', 'character', 'hero', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Scott Summers', 'The X-Men #1 (1963)', NULL, NULL, 'Cyclops is the disciplined field leader of the X-Men, able to fire devastating optic blasts that he can only control with a special visor. As Xavier''s first student, he embodies the team''s strategic backbone and unwavering commitment to the dream. His sense of duty has made him both an inspiring leader and, at times, a controversial revolutionary.', '2024-01-01T00:00:00.000Z'),
  ('cb0c266f-1125-5c99-8a2b-6ae28743dca9', 'danny-estacado', 'Danny Estacado', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Daniel Estacado', 'Witchblade #1 (1995)', NULL, NULL, 'Danny Estacado is Sara Pezzini''s NYPD partner whose murder early in the series profoundly shapes her path. Even in death, his spirit lingers as a guiding presence, offering Sara counsel and conscience as she navigates the Witchblade''s demands.', '2024-01-01T00:00:00.000Z'),
  ('f878ca08-45b4-5eff-8cc1-617cabb5c42b', 'darkseid', 'Darkseid', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Uxas', 'Superman''s Pal Jimmy Olsen #134 (1970)', NULL, NULL, 'Darkseid is the dread ruler of the hellish world Apokolips and one of the most powerful tyrants in the DC Universe. Obsessed with the Anti-Life Equation, he seeks to eliminate all free will and bend creation to his absolute control.', '2024-01-01T00:00:00.000Z'),
  ('62eb906a-1df5-5cc2-97dd-873e0b5842a3', 'darkthornn', 'Darkthornn', 'character', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Youngblood #6 (1993)', NULL, NULL, 'Darkthornn is an extradimensional warlord whose incursions threaten entire worlds. He pits his alien armies against the team''s away division in escalating conflicts.', '2024-01-01T00:00:00.000Z'),
  ('f2583e7b-114a-5d55-ab97-0984e1eccd83', 'deathstroke', 'Deathstroke', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Slade Wilson', 'The New Teen Titans #2 (1980)', NULL, NULL, 'Slade Wilson, known as Deathstroke the Terminator, is the world''s deadliest mercenary, enhanced to superhuman levels by a military experiment. A brilliant tactician and assassin, he is best known as the archenemy of the Teen Titans. His ruthlessness is matched only by his strict, twisted code of honor.', '2024-01-01T00:00:00.000Z'),
  ('ef33d492-4f93-52fc-bfe8-b86b454eb253', 'dick-grayson', 'Dick Grayson (Nightwing)', 'character', 'hero', 'b704b760-3179-502b-9b34-289a04adb849', 'Richard John Grayson', 'Detective Comics #38 (1940)', NULL, NULL, 'Dick Grayson became Robin at age eight, the orphaned son of circus acrobats killed by mob extortion, and grew under Batman''s mentorship into one of DC''s most capable and emotionally intelligent heroes. Breaking from Batman to establish his own identity as Nightwing, he proved that the people Batman trains eventually surpass the limits his mentor placed on the role. He has led the Teen Titans, the Outsiders, and the Justice League — and twice carried the Batman mantle when Bruce was unable.', '2024-01-01T00:00:00.000Z'),
  ('c2d6b0c2-3e9a-56f9-bd37-b32a72dd1c7d', 'diehard', 'Diehard', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Youngblood #1 (1992)', NULL, NULL, 'Diehard is a battle-hardened cyborg soldier whose consciousness has served across decades of conflict. As a foundational member, he provides the team with experience, tactical depth, and a measure of conscience.', '2024-01-01T00:00:00.000Z'),
  ('9b5ba614-a266-558f-aa96-db377463623e', 'dixon', 'Dixon', 'character', 'villain', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', NULL, 'The Empty Man #2 (BOOM! Studios, 2014)', NULL, NULL, 'Dixon is a devoted servant of the Empty Man, an ordinary man who embraced the presence and became its hands among the living. He carries the contagion forward without hesitation, doing the work the faith demands.', '2024-01-01T00:00:00.000Z'),
  ('3c5f0196-f609-537d-84f9-fd627af1ec2f', 'doc-seismic', 'Doc Seismic', 'character', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Invincible #25 (2005)', NULL, NULL, 'Doc Seismic is a megalomaniacal villain who wields gauntlets capable of generating devastating seismic energy. His earth-shaking ambitions repeatedly endanger the planet and bring him into conflict with the Guardians.', '2024-01-01T00:00:00.000Z'),
  ('73c0cf5c-4285-555b-9528-9baef6ff50ad', 'doctor-octopus', 'Doctor Octopus', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Otto Octavius', 'The Amazing Spider-Man #3 (1963)', NULL, NULL, 'Brilliant nuclear physicist Otto Octavius was fused to a set of powerful artificial tentacle-arms in a lab accident that also warped his mind. Calculating and arrogant, Doctor Octopus is Spider-Man''s intellectual equal and one of his deadliest recurring foes. He founded the Sinister Six and has come closer than anyone to truly defeating the wall-crawler.', '2024-01-01T00:00:00.000Z'),
  ('9b69f6c8-ec9a-52fd-b306-7d63305f8662', 'doctor-poison', 'Doctor Poison', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Princess Maru', 'Sensation Comics #2 (1942)', NULL, NULL, 'Doctor Poison is one of Wonder Woman''s oldest foes, a masked chemist and toxicologist who develops deadly poisons and biochemical weapons. First appearing during the Golden Age as the disguised Princess Maru, the identity has been carried by more than one villain united by a mastery of lethal chemistry.', '2024-01-01T00:00:00.000Z'),
  ('46646717-ad59-58fe-b11c-5a2c94afdca4', 'doomsday', 'Doomsday', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', NULL, 'Superman: The Man of Steel #17 (1992)', NULL, NULL, 'Doomsday is a savage, near-mindless engine of destruction created through brutal evolutionary experiments on ancient Krypton. Each time it is killed it returns to life immune to whatever destroyed it, making it impossible to defeat the same way twice. It earned eternal infamy as the monster that beat Superman to death.', '2024-01-01T00:00:00.000Z'),
  ('957f32fa-3926-509c-9983-994040b5e2ba', 'drusilla', 'Drusilla', 'character', 'villain', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Drusilla', 'Buffy the Vampire Slayer #1 (BOOM! Studios, 2019)', NULL, NULL, 'Drusilla is a hauntingly insane vampire whose prophetic visions and childlike cruelty make her wildly unpredictable. Driven mad before she was turned, she menaces Sunnydale with both power and unhinged menace.', '2024-01-01T00:00:00.000Z'),
  ('c76e1fcc-bbee-55c1-9c65-e08b0069d8f3', 'dupli-kate', 'Dupli-Kate', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Kate Cha', 'Invincible #7 (2004)', NULL, NULL, 'Dupli-Kate can create numerous duplicates of herself, making her a versatile and resourceful combatant. She is a steady member of the reformed Guardians of the Globe.', '2024-01-01T00:00:00.000Z'),
  ('b1bf0d33-b129-5c85-99cc-fa296bde3f3b', 'edwin-slaughter', 'Edwin Slaughter', 'character', 'antihero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Edwin Slaughter', 'House of Slaughter #1 (BOOM! Studios, 2021)', NULL, NULL, 'Edwin Slaughter is a senior figure of the Slaughter lineage whose authority and ambitions cast a long shadow over the House of Slaughter. His grip on the family''s power makes him a dangerous obstacle to Erica''s independence.', '2024-01-01T00:00:00.000Z'),
  ('7786b507-312a-539d-8a23-29295e4b1a30', 'erica-slaughter', 'Erica Slaughter', 'character', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Erica Slaughter', 'Something is Killing the Children #1 (BOOM! Studios, 2019)', NULL, NULL, 'Erica Slaughter is a foul-mouthed, bandana-masked monster hunter who travels from town to town slaying the unseen creatures that prey on children. Raised and trained by the secretive House of Slaughter, she wields a machete and an octopus plush named Octo while bending—and breaking—the rigid rules of her order.', '2024-01-01T00:00:00.000Z'),
  ('3435af88-847a-586f-8c00-d1fe9dd6c158', 'frank-darling', 'Frank Darling', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Frank Darling', 'Savage Dragon #1 (1992)', NULL, NULL, 'The Chicago police lieutenant who discovers the amnesiac Dragon and convinces him to join the force. A steady mentor figure, he provides Dragon with structure, purpose, and a measure of trust in a dangerous city.', '2024-01-01T00:00:00.000Z'),
  ('958eb5e9-3e62-5425-a491-e9291563bffd', 'general-zod', 'General Zod', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Dru-Zod', 'Adventure Comics #283 (1961)', NULL, NULL, 'General Dru-Zod was Krypton''s supreme military commander, condemned to the Phantom Zone for attempting to seize control of the planet. A Kryptonian who gains Superman''s full power under a yellow sun, he is the Man of Steel''s physical equal and ideological opposite. Where Superman protects, Zod conquers, demanding that all kneel before him.', '2024-01-01T00:00:00.000Z'),
  ('6a5e6aa2-737a-53d6-bed1-a2e26f802777', 'giga', 'Giga', 'character', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Youngblood #4 (1992)', NULL, NULL, 'Giga is a colossal threat whose sheer scale overwhelms conventional defenses. Containing the creature demands the full combined might of the team''s divisions.', '2024-01-01T00:00:00.000Z'),
  ('8ff83210-4b2a-5819-9f95-69342e126100', 'gleason', 'Gleason', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Witchblade #2 (1996)', NULL, NULL, 'Gleason is a forensic specialist and medical examiner who supports Sara Pezzini''s investigations with sharp scientific insight. He provides the grounded procedural backbone that keeps Sara''s supernatural cases tethered to real detective work.', '2024-01-01T00:00:00.000Z'),
  ('c19b3b7f-d0d0-5b8b-82c9-d7568fc281f7', 'goldar', 'Goldar', 'character', 'villain', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', NULL, 'Mighty Morphin Power Rangers #1 (BOOM! Studios, 2016)', NULL, NULL, 'Goldar is a winged, golden-armored warrior and loyal enforcer to the Rangers'' greatest foes. Brutal and relentless, he is a constant physical threat on the battlefield. His rivalry with the Rangers is among the franchise''s most enduring.', '2024-01-01T00:00:00.000Z'),
  ('01810fc2-2f93-5c21-b522-f232e59ac1ca', 'gorilla-grodd', 'Gorilla Grodd', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Grodd', 'The Flash #106 (1959)', NULL, NULL, 'Gorilla Grodd is a hyper-intelligent, telepathic ape from the hidden Gorilla City who craves dominion over both his own people and humankind. His savage strength is matched only by his mental powers, making him one of the Flash''s most physically and psychologically terrifying foes. Grodd''s hunger for conquest puts him in eternal conflict with Barry Allen.', '2024-01-01T00:00:00.000Z'),
  ('587462a9-16e0-57f3-a1a6-84b0ce8c7f74', 'green-arrow', 'Green Arrow', 'character', 'hero', 'b704b760-3179-502b-9b34-289a04adb849', 'Oliver Queen', 'More Fun Comics #73 (1941)', NULL, NULL, 'Green Arrow is a billionaire-turned-vigilante and master archer who fights crime and social injustice with a quiver of trick arrows. Outspoken and politically charged, Oliver Queen brings a grounded, populist conscience to the Justice League.', '2024-01-01T00:00:00.000Z'),
  ('2bf45ce8-3c51-51de-8b48-94d766ee72dd', 'green-goblin', 'Green Goblin', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Norman Osborn', 'The Amazing Spider-Man #14 (1964)', NULL, NULL, 'Wealthy industrialist Norman Osborn ingested an unstable performance-enhancing serum that boosted his intellect and strength while shattering his sanity. As the cackling, glider-riding Green Goblin, he became Spider-Man''s most personal and dangerous nemesis. His knowledge of Peter''s secret identity makes every encounter a threat to everyone the hero loves.', '2024-01-01T00:00:00.000Z'),
  ('a8434c59-8838-500a-a059-d60b3b33a59e', 'green-lantern', 'Green Lantern', 'character', 'hero', 'b704b760-3179-502b-9b34-289a04adb849', 'Hal Jordan', 'Showcase #22 (1959)', NULL, NULL, 'Test pilot Hal Jordan is chosen by a dying alien to wield a power ring that can forge anything his willpower imagines, making him Earth''s greatest member of the intergalactic Green Lantern Corps. Fearless to a fault, he patrols Sector 2814 and stands among the founders of the Justice League. His greatest battles are as often against his own doubts as against the cosmic tyrants who covet his ring.', '2024-01-01T00:00:00.000Z'),
  ('7a66364d-547b-54c4-948e-de4f1d756d38', 'guardians-of-the-globe', 'Guardians of the Globe', 'team', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Invincible #7 (2004)', NULL, NULL, 'The Guardians of the Globe are Earth''s premier superhero team in the world of Invincible, modeled as that universe''s answer to its greatest threats. Across multiple incarnations the team has shifted from a roster of legacy icons to a younger generation rebuilt from tragedy.', '2024-01-01T00:00:00.000Z'),
  ('a16e772f-3014-5979-a4f7-94e95fa78e9c', 'hawkeye', 'Hawkeye', 'character', 'hero', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Clinton Francis Barton', 'Tales of Suspense #57 (1964)', NULL, NULL, 'Hawkeye is a master archer with no superhuman powers who earns his place among gods and titans through sheer skill and stubborn determination. Beginning as a reluctant adversary, Clint Barton reformed to become one of the longest-serving and most relatable Avengers.', '2024-01-01T00:00:00.000Z'),
  ('c97ff53b-f9dd-5c73-a8c2-fe3b40b6353c', 'hector-hammond', 'Hector Hammond', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Hector Hammond', 'Green Lantern #5 (1960)', NULL, NULL, 'Hector Hammond is a criminal who was exposed to a radioactive meteor that accelerated his evolution by millions of years, granting him immense psychic power at the cost of his mobility. His swollen, immortal mind craves dominion and fixates on both Hal Jordan''s power ring and Carol Ferris. He is one of Green Lantern''s earliest and most cerebral foes.', '2024-01-01T00:00:00.000Z'),
  ('a1645541-25a2-527e-93d9-b087dbf5890a', 'hela', 'Hela', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Hela', 'Journey into Mystery #102 (1964)', NULL, NULL, 'Hela is the Asgardian goddess of death, ruler of the realms of Hel and Niffleheim. Cold, regal, and implacable, she covets dominion over the souls of the dead, and her clashes with Thor often hinge on her desire to claim him or deny him a warrior''s afterlife.', '2024-01-01T00:00:00.000Z'),
  ('0ce552c3-1204-54bd-805c-27a3e9153de6', 'haus-of-slaughter', 'House of Slaughter', 'team', 'neutral', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', NULL, 'House of Slaughter #1 (BOOM! Studios, 2021)', NULL, NULL, 'The House of Slaughter is a clandestine, centuries-old order of monster hunters operating in the shadows of the world depicted in ''Something is Killing the Children.'' Divided into masks and houses, its members are trained from childhood to track and destroy creatures most people cannot even see. Its rigid traditions and buried secrets are as dangerous as any monster.', '2024-01-01T00:00:00.000Z'),
  ('9d16c1a7-8edc-51c7-8a4d-00f28e78ab0a', 'hulk', 'Hulk', 'character', 'hero', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Robert Bruce Banner', 'The Incredible Hulk #1 (1962)', NULL, NULL, 'The Hulk is the towering, gamma-powered alter ego of brilliant scientist Bruce Banner, born from a lab accident that fused intellect and rage. A founding Avenger whose volatility makes him as much a danger as an asset, the Hulk embodies the team''s struggle to channel overwhelming power toward heroic ends.', '2024-01-01T00:00:00.000Z'),
  ('61fa87f0-8567-588c-a50f-30857c065c7b', 'ian-nottingham', 'Ian Nottingham', 'character', 'antihero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Ian Nottingham', 'Witchblade #2 (1996)', NULL, NULL, 'Ian Nottingham is the deadly, enigmatic bodyguard and enforcer of Kenneth Irons, trained as a peerless warrior. Though ordered to hunt Sara Pezzini, he is drawn to her by a fascination that constantly tests his loyalty, making him as much a tragic figure as a threat.', '2024-01-01T00:00:00.000Z'),
  ('ddc90de2-8e7d-5dd1-bde9-72646019ee2b', 'invincible', 'Invincible', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Mark Grayson', 'Invincible #1 (2003)', NULL, NULL, 'Mark Grayson is the teenage son of the world''s most powerful superhero, who inherits his father''s Viltrumite abilities and takes up the mantle of Invincible. His journey forces him to reconcile the legacy he was given with the kind of hero he chooses to become.', '2024-01-01T00:00:00.000Z'),
  ('dc4fa6e5-9cd9-530d-af32-949d8b71c053', 'iron-man', 'Iron Man', 'character', 'hero', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Tony Stark', 'Tales of Suspense #39 (1963)', NULL, NULL, 'Tony Stark is a brilliant, billionaire inventor whose life is forever changed when shrapnel from a battlefield injury threatens to stop his heart. Building a powered suit of armor to survive and escape captivity, he becomes Iron Man, channeling his genius for engineering into a one-man arsenal. Behind the bravado of a celebrity industrialist lies a man wrestling with responsibility, addiction, and the consequences of the weapons he once built.', '2024-01-01T00:00:00.000Z'),
  ('b63521f5-2a13-55a7-bcea-27fc760fc7b2', 'jace-boucher', 'Jace Boucher', 'character', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Jace Boucher', 'Something is Killing the Children #1 (BOOM! Studios, 2019)', NULL, NULL, 'Jace Boucher is an Archer''s Peak local caught up in the wave of killings. An ordinary person thrust into extraordinary horror, he lends Erica aid as the hunt tears through his town.', '2024-01-01T00:00:00.000Z'),
  ('bffd2788-f7ee-5c11-98b0-47612d6a468b', 'jackie-estacado', 'Jackie Estacado', 'character', 'antihero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Jackie Estacado', 'Witchblade #10 (1996)', NULL, NULL, 'Jackie Estacado is a mafia hitman who becomes the bearer of the Darkness, the primal force that is the Witchblade''s cosmic counterpart. Charismatic and dangerous, his path repeatedly crosses Sara Pezzini''s in a relationship that swings between conflict and uneasy alliance.', '2024-01-01T00:00:00.000Z'),
  ('2939c01b-6e85-5e58-b250-e29d6afb5b8d', 'jake-mccarthy', 'Jake McCarthy', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Jake McCarthy', 'Witchblade #1 (1995)', NULL, NULL, 'Jake McCarthy is an NYPD detective and Sara Pezzini''s partner, a steady and earnest cop who finds himself drawn into cases far stranger than ordinary police work. His loyalty to Sara endures even as the supernatural reshapes his understanding of the job.', '2024-01-01T00:00:00.000Z'),
  ('baad7ecb-7d52-5a70-b832-c4b4732b363a', 'james', 'James', 'character', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'James', 'Something is Killing the Children #1 (BOOM! Studios, 2019)', NULL, NULL, 'James is the teenage survivor of the monster attack that opens the Archer''s Peak killings. Able to see the creature when adults cannot, he becomes Erica Slaughter''s reluctant partner and witness during the hunt.', '2024-01-01T00:00:00.000Z'),
  ('16c71808-cd7a-588a-8f41-653051d42c23', 'james-gordon', 'James Gordon', 'character', 'hero', 'b704b760-3179-502b-9b34-289a04adb849', 'James Worthington Gordon', 'Detective Comics #27 (1939)', NULL, NULL, 'James Gordon is the Commissioner of the Gotham City Police Department — a career cop whose integrity has survived decades of institutional corruption, political pressure, and catastrophic personal loss. His willingness to operate alongside a vigilante he officially cannot acknowledge reflects a pragmatic conclusion: Gotham''s problems are too large for the law alone. He is Batman''s most essential ally precisely because he asks nothing from the partnership except results.', '2024-01-01T00:00:00.000Z'),
  ('dcc0b1e2-6bc8-506d-8d00-599cb1e9383b', 'jason-lee-scott', 'Jason Lee Scott', 'character', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Jason Lee Scott', 'Mighty Morphin Power Rangers #1 (BOOM! Studios, 2016)', NULL, NULL, 'The original Red Ranger and founding leader of the Power Rangers. Disciplined, principled, and fiercely loyal, Jason carries the weight of command and the responsibility of welcoming a reformed Tommy into the fold.', '2024-01-01T00:00:00.000Z'),
  ('9332422c-3ea9-54d6-8e3f-305a4b2d0f0c', 'jason-wynn', 'Jason Wynn', 'character', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Jason Wynn', 'Spawn #1 (1992)', NULL, NULL, 'Jason Wynn is a ruthless, power-hungry director of a covert government agency who ordered the assassination of his own agent, Al Simmons. His earthly corruption makes him a human target for Spawn''s vengeance.', '2024-01-01T00:00:00.000Z'),
  ('f743dec3-c799-5685-82f8-db313aa431b8', 'jean-grey', 'Jean Grey', 'character', 'hero', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Jean Grey', 'The X-Men #1 (1963)', NULL, NULL, 'Jean Grey is a founding X-Man and one of the most powerful telepaths and telekinetics in the Marvel Universe. Her bond with the cosmic Phoenix Force has made her both a savior and a danger of universe-altering proportions. Compassionate and immensely gifted, she sits at the emotional core of the X-Men''s greatest sagas.', '2024-01-01T00:00:00.000Z'),
  ('5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'justice-league', 'Justice League', 'team', 'hero', 'b704b760-3179-502b-9b34-289a04adb849', NULL, 'The Brave and the Bold #28 (1960)', NULL, NULL, 'The Justice League is DC''s premier super-team, uniting the world''s most powerful heroes to face threats no single champion could withstand. Founded when a global menace forced Earth''s greatest icons to band together, the League has defended the planet, the galaxy, and the multiverse across generations of changing rosters.', '2024-01-01T00:00:00.000Z'),
  ('74817bfe-b087-5d7b-83ac-2aea450e5656', 'kang', 'Kang the Conqueror', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Nathaniel Richards', 'The Avengers #8 (1964)', NULL, NULL, 'Kang the Conqueror is a time-traveling warlord from the far future who has subjugated entire eras of history. Existing across countless divergent timelines and alternate identities, Kang wages an endless campaign against the Avengers in some of their most intricate and far-reaching sagas.', '2024-01-01T00:00:00.000Z'),
  ('62974dbb-5bfc-5c10-a11a-ffecb2d03a80', 'kenneth-irons', 'Kenneth Irons', 'character', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Kenneth Irons', 'Witchblade #1 (1995)', NULL, NULL, 'Kenneth Irons is an immortal industrialist whose obsession with the Witchblade spans centuries. Wealthy, patient, and ruthless, he orchestrates events to control the artifact through whoever bears it, making him Sara Pezzini''s principal nemesis.', '2024-01-01T00:00:00.000Z'),
  ('9677b8cd-620c-5f15-815b-bc307efe9501', 'kimberly-hart', 'Kimberly Hart', 'character', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Kimberly Ann Hart', 'Mighty Morphin Power Rangers #1 (BOOM! Studios, 2016)', NULL, NULL, 'The original Pink Ranger, an agile gymnast with a sharp wit and a steady moral compass. Kimberly''s compassion and judgment make her one of the team''s emotional anchors, and her bond with Tommy runs throughout the saga.', '2024-01-01T00:00:00.000Z'),
  ('95c4e2f0-5988-54e7-9a18-95554586cc1f', 'lady-deathstrike', 'Lady Deathstrike', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Yuriko Oyama', 'Daredevil #197 (1983)', NULL, NULL, 'Yuriko Oyama is a cybernetically enhanced warrior driven by a twisted sense of honor and a vendetta against Wolverine. Believing the adamantium process stole her father''s legacy, she had her own skeleton bonded with the metal and her fingers turned into deadly blades to claim it back.', '2024-01-01T00:00:00.000Z'),
  ('e305af9b-4cc3-5518-89e6-f43963628ebe', 'lex-luthor', 'Lex Luthor', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Alexander Joseph Luthor', 'Action Comics #23 (1940)', NULL, NULL, 'Lex Luthor is a brilliant, ruthless billionaire industrialist and Superman''s archenemy, convinced that humanity must be saved from its dependence on superheroes. His intellect and resources make him a constant threat to the entire Justice League.', '2024-01-01T00:00:00.000Z'),
  ('1f49fb7c-fb73-52ec-8ba2-e5bf8b640f09', 'loki', 'Loki', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Loki Laufeyson', 'Journey into Mystery #85 (1962)', NULL, NULL, 'Loki, the Asgardian God of Mischief, is a master manipulator whose schemes have shaped the Marvel Universe for decades. His attempt to torment his adoptive brother Thor inadvertently brought the Avengers together, making him the foe responsible for the team''s very existence.', '2024-01-01T00:00:00.000Z'),
  ('62d3ff58-5877-5948-afd9-512ee5eb96a9', 'lord-drakkon', 'Lord Drakkon', 'character', 'villain', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Tommy Oliver (alternate timeline)', 'Mighty Morphin Power Rangers #9 (BOOM! Studios, 2016)', NULL, NULL, 'Lord Drakkon is a tyrannical alternate-timeline version of Tommy Oliver who never abandoned the Green Ranger mantle. Instead of redemption, he chose conquest, fusing Green and White Ranger powers into a brutal empire. He is the central villain of the Shattered Grid event and Tommy''s dark mirror.', '2024-01-01T00:00:00.000Z'),
  ('a60dcbe3-6f65-5d40-9806-6cb0c90c5c29', 'lord-zedd', 'Lord Zedd', 'character', 'villain', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', NULL, 'Mighty Morphin Power Rangers #9 (BOOM! Studios, 2016)', NULL, NULL, 'Lord Zedd is the self-proclaimed Emperor of Evil, a more calculating and ruthless menace than Rita. His ambition reaches across galaxies and timelines. In the comics he poses some of the gravest threats the Rangers ever confront.', '2024-01-01T00:00:00.000Z'),
  ('ad8850b8-8aec-5819-bba1-9a55932f4612', 'lucius-fox', 'Lucius Fox', 'character', 'hero', 'b704b760-3179-502b-9b34-289a04adb849', 'Lucius Fox', 'Batman #307 (1979)', NULL, NULL, 'Lucius Fox is the CEO of Wayne Enterprises and the operational intelligence behind Bruce Wayne''s ability to function as both a credible billionaire and a funded vigilante. Introduced by Len Wein, Fox manages the business and R&D infrastructure that supplies Batman''s equipment without requiring Bruce to do the unglamorous work of running a multinational corporation. His precise level of knowledge about Bruce''s activities has been handled differently across continuities, but the consistent element is his competence and loyalty.', '2024-01-01T00:00:00.000Z'),
  ('4cd10521-bed3-5ec1-b7d1-8edc1f5a5d11', 'machine-head', 'Machine Head', 'character', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Invincible #24 (2005)', NULL, NULL, 'Machine Head is a powerful crime lord with a cybernetic head who controls much of the city''s criminal underworld. He commands legions of hired supervillains and serves as one of Invincible''s most persistent street-level threats.', '2024-01-01T00:00:00.000Z'),
  ('0882f404-5e91-5e5f-ab13-effa153e4492', 'magneto', 'Magneto', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Max Eisenhardt', 'The X-Men #1 (1963)', NULL, NULL, 'Magneto is the Master of Magnetism, a Holocaust survivor whose trauma convinced him that mutants must seize power before humanity can persecute them. As Xavier''s onetime friend and eternal ideological rival, he has been the X-Men''s greatest foe and, at times, their reluctant ally. His tragic conviction makes him one of comics'' most compelling antagonists.', '2024-01-01T00:00:00.000Z'),
  ('e04135bf-0e34-5add-8c14-e9c345b1fae2', 'malebolgia', 'Malebolgia', 'character', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Spawn #1 (1992)', NULL, NULL, 'Malebolgia is a towering demon lord of Hell who strikes the bargain that transforms Al Simmons into a Hellspawn. He intends to use Spawn as a general in the war to overthrow Heaven, making him the architect of Al''s damnation.', '2024-01-01T00:00:00.000Z'),
  ('c87a39f2-008e-57ba-9fa5-e93d2da2d911', 'malekith', 'Malekith the Accursed', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Malekith', 'Thor #344 (1984)', NULL, NULL, 'Malekith the Accursed is the cruel and capricious ruler of the dark elves of Svartalfheim. A sadistic schemer with a talent for manipulation and dark sorcery, he rose from petty villainy to become the warlord who ignited the War of the Realms against Thor and all of Asgard.', '2024-01-01T00:00:00.000Z'),
  ('67852c9d-4ede-5e29-959f-5d58f6dd2255', 'martian-manhunter', 'Martian Manhunter', 'character', 'hero', 'b704b760-3179-502b-9b34-289a04adb849', 'J''onn J''onzz', 'Detective Comics #225 (1955)', NULL, NULL, 'Martian Manhunter is the last survivor of Mars, a shapeshifting telepath with immense strength and the heart of the Justice League. Stranded on Earth, J''onn J''onzz serves as one of the team''s most steadfast founders and longest-serving members.', '2024-01-01T00:00:00.000Z'),
  ('4621bf98-c20c-5812-ad91-16eff4826513', 'mister-glum', 'Mister Glum', 'character', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Mister Glum', 'Savage Dragon #76 (2000)', NULL, NULL, 'A diminutive alien mastermind from another dimension with grand, world-threatening ambitions. Mister Glum''s scheming draws Dragon into cosmic conflicts far beyond the streets of Chicago.', '2024-01-01T00:00:00.000Z'),
  ('f671ab1f-e733-51ec-818a-82ed22652b8a', 'mister-sinister', 'Mister Sinister', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Nathaniel Essex', 'The Uncanny X-Men #221 (1987)', NULL, NULL, 'Nathaniel Essex is a Victorian-era geneticist who made himself functionally immortal and became one of the X-Men''s most insidious foes. Obsessed with mutant evolution and the perfect genetic specimen, Sinister manipulates events from the shadows, leaving cloned pawns and ruined lives in his wake.', '2024-01-01T00:00:00.000Z'),
  ('6d3b22e4-ecd2-569b-b088-750d3beb5c95', 'monica-jensen', 'Monica Jensen', 'character', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', NULL, 'The Empty Man #2 (BOOM! Studios, 2014)', NULL, NULL, 'Monica Jensen is drawn into the Empty Man investigation when the affliction reaches her own family. Her personal stake makes her one of the contagion''s most determined opponents and one of its most vulnerable targets.', '2024-01-01T00:00:00.000Z'),
  ('56ff7566-933b-58c5-a916-a526373f5076', 'mystique', 'Mystique', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Raven Darkholme', 'Ms. Marvel #16 (1978)', NULL, NULL, 'Mystique is a shapeshifting mutant capable of perfectly mimicking anyone, a skill she has wielded as a spy, assassin, and terrorist. Leading her own incarnation of the Brotherhood, she has repeatedly menaced the X-Men through infiltration and manipulation. Her ever-shifting loyalties and morally gray motives make her one of the franchise''s most unpredictable figures.', '2024-01-01T00:00:00.000Z'),
  ('0b1f9dae-3b8b-50eb-9e6e-dcf3208d3996', 'nyx', 'Nyx', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Jessica Priest', 'Spawn #9 (1993)', NULL, NULL, 'Nyx is a witch versed in the supernatural underworld who becomes a steadfast ally in Spawn''s later crusades. Her command of magic makes her invaluable against threats that span Heaven and Hell.', '2024-01-01T00:00:00.000Z'),
  ('976abf28-99fc-5073-80fc-0b26f69b73d3', 'obadiah-stane', 'Obadiah Stane', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Obadiah Stane', 'Iron Man #163 (1982)', NULL, NULL, 'Obadiah Stane is a cold, calculating industrialist who treats business as a game of chess with human pieces. Methodically dismantling Tony Stark''s life and company, he embodies corporate ruthlessness without conscience. When pure strategy fails, he builds the towering Iron Monger armor to crush Iron Man by force.', '2024-01-01T00:00:00.000Z'),
  ('39a095b5-92fa-558e-9fa8-297e694171e5', 'omega-red', 'Omega Red', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Arkady Rossovich', 'X-Men #4 (1992)', NULL, NULL, 'Arkady Rossovich is a Russian serial killer transformed into a Soviet super-soldier with retractable carbonadium tentacles and a ''death spore'' that drains the life from those around him. To survive, he must siphon energy from others, making him a relentless and deadly foe of Wolverine and the X-Men.', '2024-01-01T00:00:00.000Z'),
  ('6a03558f-184a-5db6-a341-0c6f4fad2eab', 'omni-man', 'Omni-Man', 'character', 'antihero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Nolan Grayson', 'Invincible #1 (2003)', NULL, NULL, 'Nolan Grayson is a Viltrumite warrior who arrived on Earth as the seemingly benevolent hero Omni-Man and fathered Mark Grayson. His true mission and gradual change of heart make him one of the series'' most morally complex figures.', '2024-01-01T00:00:00.000Z'),
  ('3168c6d7-6c83-5cf1-b287-da914c7d1f7c', 'overlord', 'Overlord', 'character', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Antonio Seghetti', 'Savage Dragon #1 (1992)', NULL, NULL, 'An armored crime lord who controls Chicago''s superhuman underworld, Overlord is Dragon''s foundational nemesis. His ruthless grip on organized crime makes him the central threat of Dragon''s earliest cases.', '2024-01-01T00:00:00.000Z'),
  ('5ab96773-d320-5296-9110-d63c607a0ee2', 'overtkill', 'Overtkill', 'character', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Spawn #6 (1992)', NULL, NULL, 'Overtkill is a cybernetic killing machine engineered for relentless destruction. A recurring threat in the Image universe, his sheer firepower makes him a brutal adversary for sanctioned hero teams.', '2024-01-01T00:00:00.000Z'),
  ('0592afef-f365-56b1-9f86-5fe1d601e77e', 'parallax', 'Parallax', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', NULL, 'Green Lantern #50 (1994)', NULL, NULL, 'Parallax is the primordial cosmic embodiment of fear, an entity so ancient it predates much of the emotional spectrum. Imprisoned within the Green Lantern central power battery, it preyed upon Hal Jordan''s grief to engineer his fall. It remains the living source of the yellow impurity that once weakened every Green Lantern.', '2024-01-01T00:00:00.000Z'),
  ('b23f30f2-61cd-515a-a3e8-f07f14502f2d', 'power-rangers', 'Power Rangers', 'team', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', NULL, 'Mighty Morphin Power Rangers #1 (BOOM! Studios, 2016)', NULL, NULL, 'A team of teenagers chosen by the sage Zordon to wield the Power Coins and defend Earth from intergalactic evil. Morphing into armored warriors and piloting colossal Zords, the Rangers stand as Angel Grove''s last line of defense. BOOM! Studios reimagines their saga with deeper continuity, higher stakes, and threats that span the multiverse.', '2024-01-01T00:00:00.000Z'),
  ('2691870e-40bb-5f64-880b-9c2f4cfaf09d', 'professor-x', 'Professor X', 'character', 'hero', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Charles Xavier', 'The X-Men #1 (1963)', NULL, NULL, 'Professor Charles Xavier is the world''s most powerful telepath and the founder of the X-Men, dedicating his life to the dream of peaceful coexistence between mutants and humans. From his School for Gifted Youngsters he mentors generations of young mutants. His unwavering ideals, and the moral compromises he sometimes makes to uphold them, define the soul of the franchise.', '2024-01-01T00:00:00.000Z'),
  ('1a61ff3c-d1d1-52b6-beb8-c1dc60642f40', 'ra-s-al-ghul', 'Ra''s al Ghul', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Unknown; has used many names across centuries', 'Batman #232 (1971)', NULL, NULL, 'Ra''s al Ghul — the name translates roughly as ''the Demon''s Head'' — is an eco-terrorist and global strategist who has lived for centuries through immersion in Lazarus Pits, pools of restorative chemical energy that restore life but erode sanity with each use. He leads the League of Assassins and genuinely believes that reducing the human population is the only path to saving the planet. His respect for Batman, whom he has called ''the Detective,'' is real — which makes his attempts to recruit and manipulate him more unsettling than his direct attacks.', '2024-01-01T00:00:00.000Z'),
  ('346596df-b4b3-5cfa-be46-35c6f0951535', 'raven', 'Raven', 'character', 'hero', 'b704b760-3179-502b-9b34-289a04adb849', 'Rachel Roth', 'DC Comics Presents #26 (1980)', NULL, NULL, 'Raven is a powerful empath and sorceress, the half-human daughter of the demon Trigon, who struggles to control the dark heritage within her. Quiet and introspective, she uses her soul-self and emotional powers in service of the Teen Titans. Her ongoing battle against her own nature is one of the franchise''s richest storylines.', '2024-01-01T00:00:00.000Z'),
  ('db496c89-2091-5e0e-8859-371dc2cdd7a7', 'red-skull', 'Red Skull', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Johann Schmidt', 'Captain America Comics #1 (1941)', NULL, NULL, 'Johann Schmidt rose from a brutal childhood to become Hitler''s most feared agent, the Red Skull, a sadistic embodiment of fascism named for his crimson death''s-head visage. Sustained across decades by suspended animation and cloned bodies, he has remained Captain America''s ultimate nemesis. Wherever tyranny and hatred fester, the Red Skull is never far behind.', '2024-01-01T00:00:00.000Z'),
  ('ad0aeda8-5962-52a4-a9c9-4395afe2a044', 'reverse-flash', 'Reverse-Flash', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Eobard Thawne', 'The Flash #139 (1963)', NULL, NULL, 'Eobard Thawne is a 25th-century scientist who idolized the Flash until obsession curdled into hatred, becoming the Reverse-Flash. Wielding negative Speed Force energy in a yellow costume, he has woven himself into every tragedy of Barry Allen''s life. He is the Flash''s definitive archenemy, a villain who manipulates time itself to destroy his hero.', '2024-01-01T00:00:00.000Z'),
  ('338980ff-b028-502a-aacd-072080eed01c', 'rex-splode', 'Rex Splode', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Rex Sloan', 'Invincible #8 (2004)', NULL, NULL, 'Rex Splode can charge objects with explosive kinetic energy, making him a volatile close-combat fighter. A brash young member of the reformed Guardians, he matures over time into a dependable teammate.', '2024-01-01T00:00:00.000Z'),
  ('8aa69805-f754-5744-bca1-ded0fc7bbf61', 'ricochet', 'Ricochet', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Ricochet', 'Savage Dragon #13 (1994)', NULL, NULL, 'A swift, acrobatic hero and frequent partner to Barbaric. Ricochet''s speed and agility make her a valuable ally in Dragon''s larger super-team battles.', '2024-01-01T00:00:00.000Z'),
  ('46ce85d8-b615-5195-825a-b79f1d802603', 'rita-repulsa', 'Rita Repulsa', 'character', 'villain', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Rita Repulsa', 'Mighty Morphin Power Rangers #1 (BOOM! Studios, 2016)', NULL, NULL, 'Rita Repulsa is the malevolent space witch determined to conquer Earth. Her dark magic first corrupted Tommy and turned him against the Rangers. She remains one of the team''s most enduring and cunning adversaries.', '2024-01-01T00:00:00.000Z'),
  ('ee1e4f5e-6664-5a73-aa9b-e4da8f5771d2', 'robot', 'Robot', 'character', 'antihero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Invincible #7 (2004)', NULL, NULL, 'Robot is a brilliant strategist who operates through a drone body controlled from a distance, hiding a complicated truth about his real form. He is instrumental in reforming the Guardians, though his methods are morally ambiguous.', '2024-01-01T00:00:00.000Z'),
  ('899505b8-a56a-5ca8-aeca-d8d7a2969cd6', 'rogue', 'Rogue', 'character', 'hero', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Anna Marie', 'Avengers Annual #10 (1981)', NULL, NULL, 'Rogue is a mutant who absorbs the memories, abilities, and life force of anyone she touches, a power that long made physical contact dangerous. Once a member of the Brotherhood, she reformed and became one of the X-Men''s most beloved and dependable members. Her struggle for control and connection makes her one of the franchise''s most relatable heroes.', '2024-01-01T00:00:00.000Z'),
  ('1a1511e9-19d7-51cf-a5ad-c81d49093aaf', 'rupert-giles', 'Rupert Giles', 'character', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Rupert Giles', 'Buffy the Vampire Slayer #1 (BOOM! Studios, 2019)', NULL, NULL, 'Rupert Giles is Buffy''s Watcher and the Sunnydale High librarian, a scholar of the occult who trains and guides the Slayer. His vast knowledge and quiet authority make him the gang''s indispensable mentor.', '2024-01-01T00:00:00.000Z'),
  ('d3ce5131-893b-5d10-a5e8-5ec39dd0a85a', 'sabretooth', 'Sabretooth', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Victor Creed', 'Iron Fist #14 (1977)', NULL, NULL, 'Victor Creed is a feral mutant killer who shares Wolverine''s healing factor, heightened senses, and savage instincts, but none of his restraint. A merciless assassin whose past is entangled with Logan''s, Sabretooth is the dark reflection of what Wolverine could have become.', '2024-01-01T00:00:00.000Z'),
  ('519242ce-776c-5906-b032-8ebc5b4d5614', 'sam-and-twitch', 'Sam and Twitch', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Sam Burke and Maximilian ''Twitch'' Williams', 'Spawn #1 (1992)', NULL, NULL, 'Sam Burke and Twitch Williams are NYPD homicide detectives whose dogged investigations keep dragging them into Spawn''s supernatural world. The mismatched partners became popular enough to earn their own long-running spinoff series.', '2024-01-01T00:00:00.000Z'),
  ('7b94e1aa-83f4-508c-a457-770f2588339b', 'sandman', 'Sandman', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'William Baker (Flint Marko)', 'The Amazing Spider-Man #4 (1963)', NULL, NULL, 'Small-time crook Flint Marko was caught in a nuclear test blast that fused his body with irradiated sand, granting him the power to transform into living, shape-shifting sand. As the Sandman he can become a sledgehammer fist, a swirling sandstorm, or slip away through the smallest crack. A recurring early foe, he has drifted between hardened criminal and reluctant antihero over the decades.', '2024-01-01T00:00:00.000Z'),
  ('4322fa09-0a88-5804-93f9-0fbf9175f54e', 'savage-dragon', 'Savage Dragon', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Dragon (later "Malcolm Dragon" era; the original is simply "Dragon")', 'Savage Dragon #1 (1992)', NULL, NULL, 'A massive, fin-headed amnesiac with superhuman strength and a rapid healing factor, Dragon woke in a burning Chicago field with no memory of his past and chose to serve as a police officer fighting the city''s superpowered crime wave. Created by Erik Larsen, the series later passes the mantle to his son Malcolm, making it one of comics'' longest-running creator-owned superhero sagas.', '2024-01-01T00:00:00.000Z'),
  ('8657ab06-96b9-5dfb-87e2-ad5c9e8e68ce', 'sentinel', 'Sentinel', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Youngblood (vol. 2) #1 (1995)', NULL, NULL, 'Sentinel is an armored operative who bridges the classic and modern incarnations of the team. Disciplined and tech-driven, he represents Youngblood''s evolution into newer eras.', '2024-01-01T00:00:00.000Z'),
  ('b6ee5c85-5da2-5a36-b6ca-e1fd21313c28', 'shaft', 'Shaft', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Jeff Terrell', 'Youngblood #1 (1992)', NULL, NULL, 'Shaft is the bow-wielding field leader of Youngblood''s home team and the franchise''s signature hero. A disciplined marksman, he balances genuine heroism against the demands of celebrity and government oversight.', '2024-01-01T00:00:00.000Z'),
  ('2a1b8c6d-9df0-53b2-afb7-33330b4bde2c', 'sinestro', 'Sinestro', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Thaal Sinestro', 'Green Lantern #7 (1961)', NULL, NULL, 'Once the greatest Green Lantern of them all, Thaal Sinestro of Korugar believed order was worth any price and became a tyrant over his own people. Stripped of his ring and exiled, he forged a yellow ring of fear and built a Corps in his own image. He is Hal Jordan''s archenemy and the dark mirror of everything a Lantern can become.', '2024-01-01T00:00:00.000Z'),
  ('7c004d0d-1535-57a7-9f09-ef7cf865a072', 'spawn', 'Spawn', 'character', 'antihero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Al Simmons', 'Spawn #1 (1992)', NULL, NULL, 'Al Simmons, a murdered government assassin, strikes a bargain with a demon lord to return to the living and is reborn as a Hellspawn bound to a sentient symbiotic costume. Caught between Heaven and Hell, he wages a lonely war in the alleys of New York City while clinging to the last shreds of his humanity.', '2024-01-01T00:00:00.000Z'),
  ('dff297dd-1766-50d3-a8a8-e8b0da0f4191', 'spider-man', 'Spider-Man', 'character', 'hero', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Peter Parker', 'Amazing Fantasy #15 (1962)', NULL, NULL, 'Bitten by a radioactive spider, science-whiz teenager Peter Parker gained wall-crawling strength, lightning reflexes, and a danger-sensing ''spider-sense.'' After a personal tragedy taught him that with great power comes great responsibility, he became the wisecracking, perpetually-overworked hero of New York City. Spider-Man balances the everyday struggles of rent, romance, and a demanding day job with the constant duty of protecting the people around him.', '2024-01-01T00:00:00.000Z'),
  ('dbf622dd-5942-599c-be08-5440f5a3f2be', 'spike', 'Spike', 'character', 'antihero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'William the Bloody', 'Buffy the Vampire Slayer #1 (BOOM! Studios, 2019)', NULL, NULL, 'Spike is a brash, punk-rock vampire who revels in violence and the legend of killing Slayers. Charismatic and unpredictable, his shifting loyalties make him as likely to fight beside Buffy as against her.', '2024-01-01T00:00:00.000Z'),
  ('fd108db8-86ea-51c7-a555-0d05ee01eaa5', 'starfire', 'Starfire', 'character', 'hero', 'b704b760-3179-502b-9b34-289a04adb849', 'Koriand''r', 'DC Comics Presents #26 (1980)', NULL, NULL, 'Koriand''r, called Starfire, is a warrior princess from the alien world of Tamaran who can fly and channel solar energy into devastating starbolts. Passionate, fierce and warm-hearted, she became a defining member of the New Teen Titans. Her romance with Dick Grayson is one of the franchise''s most celebrated relationships.', '2024-01-01T00:00:00.000Z'),
  ('4b010e1a-5893-5779-942b-f5c94d6fe793', 'starro', 'Starro', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', NULL, 'The Brave and the Bold #28 (1960)', NULL, NULL, 'Starro is a colossal, telepathic alien conqueror resembling a starfish, capable of subjugating entire populations by attaching spore-like duplicates to their faces. As the first villain the Justice League ever fought, Starro is a signature recurring menace symbolizing planetary-scale threats.', '2024-01-01T00:00:00.000Z'),
  ('5fb83c49-8889-5548-9c30-32774f14089f', 'storm', 'Storm', 'character', 'hero', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Ororo Munroe', 'Giant-Size X-Men #1 (1975)', NULL, NULL, 'Storm is a weather-controlling mutant once worshipped as a goddess, who became one of the X-Men''s most powerful and respected members. Regal and compassionate, she has led the team through some of its hardest trials. Her command of the elements and her natural authority make her a pillar of the franchise.', '2024-01-01T00:00:00.000Z'),
  ('2530b133-d2b6-5355-86bd-7709a4d5d39e', 'superman', 'Superman', 'character', 'hero', 'b704b760-3179-502b-9b34-289a04adb849', 'Clark Kent / Kal-El', 'Action Comics #1 (1938)', NULL, NULL, 'Rocketed to Earth as an infant from the dying planet Krypton, Kal-El was raised in rural Kansas as Clark Kent and grew into the world''s first and greatest super-hero. Empowered by the light of Earth''s yellow sun, he wields incredible strength, flight, and invulnerability in the service of truth and justice. Behind the cape he is a mild-mannered Metropolis reporter whose deepest power is an unshakable belief in the good of others.', '2024-01-01T00:00:00.000Z'),
  ('22bf9525-aa52-53e2-9019-eb5bca2af4d2', 'surtur', 'Surtur', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Surtur', 'Journey into Mystery #97 (1963)', NULL, NULL, 'Surtur is the colossal fire demon of Muspelheim, a primordial force of destruction destined to bring about Ragnarok. Towering and near-omnipotent, he wields the flaming Twilight Sword and exists to burn the Nine Realms to cinders, making him among the most apocalyptic threats Thor and Asgard have ever faced.', '2024-01-01T00:00:00.000Z'),
  ('ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', 'teen-titans', 'Teen Titans', 'team', 'hero', 'b704b760-3179-502b-9b34-289a04adb849', NULL, 'The Brave and the Bold #54 (1964)', NULL, NULL, 'The Teen Titans are DC Comics'' premier team of young heroes, originally formed by the teenage sidekicks of the Justice League and reinvented across generations. United by friendship as much as duty, they balance world-saving adventures with the growing pains of adolescence. Over the decades the roster has shifted dramatically, but the team remains DC''s enduring symbol of heroes coming of age.', '2024-01-01T00:00:00.000Z'),
  ('f321da7b-48eb-5581-8bcb-fd783155520f', 'terra', 'Terra', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Tara Markov', 'The New Teen Titans #26 (1982)', NULL, NULL, 'Tara Markov, the geokinetic hero called Terra, can move and reshape earth and stone with her mind. Introduced as a promising new Titans recruit, she became one of comics'' most notorious figures for her hidden allegiances. Her story is inseparable from the team''s most famous storyline.', '2024-01-01T00:00:00.000Z'),
  ('8d91b245-3858-5d29-a38b-d5d88f524623', 'terry-fitzgerald', 'Terry Fitzgerald', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Terry Fitzgerald', 'Spawn #1 (1992)', NULL, NULL, 'Terry Fitzgerald was Al Simmons'' closest friend in life and now leads a quiet family life with Al''s widow, Wanda. Unaware of his connection to the creature haunting the city, he becomes an emotional anchor for Spawn''s lingering humanity.', '2024-01-01T00:00:00.000Z'),
  ('1b08cd24-f7d8-50c9-8aed-bcfd1655a338', 'thanos', 'Thanos', 'character', 'hero', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Thanos', 'Iron Man #55 (1973)', NULL, NULL, 'Thanos, the Mad Titan, is a nihilistic warlord obsessed with death and absolute power. His relentless pursuit of the Infinity Gems has made him one of the most feared beings in the cosmos and a recurring existential threat to the Avengers and the universe at large.', '2024-01-01T00:00:00.000Z'),
  ('cb6f7717-ddd8-5824-b129-8a4fc74cc300', 'the-anointed-one', 'The Anointed One', 'character', 'villain', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Colin', 'Buffy the Vampire Slayer #1 (BOOM! Studios, 2019)', NULL, NULL, 'The Anointed One is a child vampire of dark prophecy, deceptively innocent in appearance and chillingly cold in purpose. He serves as a herald and figurehead for Sunnydale''s vampire forces.', '2024-01-01T00:00:00.000Z'),
  ('9c3c540e-398e-55d7-af73-fda8fd38b93f', 'the-curator', 'The Curator', 'character', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Witchblade #25 (1998)', NULL, NULL, 'The Curator is a shadowy keeper of forbidden relics who covets the Witchblade for his collection. Patient and manipulative, he schemes to wrest the artifact from Sara Pezzini, viewing her as merely an obstacle to possession.', '2024-01-01T00:00:00.000Z'),
  ('450f9bd3-dbd8-5444-b88e-732df39fb341', 'the-disciples', 'The Disciples', 'team', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Youngblood #2 (1992)', NULL, NULL, 'The Disciples are a fanatical organization opposed to government-sanctioned heroics. Driven by ideology, they wage a sustained campaign against the team across multiple eras.', '2024-01-01T00:00:00.000Z'),
  ('7648e80f-c11b-5c40-abd6-0e19b5d8ed9e', 'the-empty-cult', 'The Empty Cult', 'team', 'villain', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', NULL, 'The Empty Man #4 (BOOM! Studios, 2014)', NULL, NULL, 'The Empty Cult is the organized underground that preserves the faith of the Empty Man between outbreaks. Through silent recruitment and guarded ritual, it ensures the affliction always has caretakers ready to begin again.', '2024-01-01T00:00:00.000Z'),
  ('7554762e-8839-52ac-b0f4-03e2d44cda89', 'the-empty-man', 'The Empty Man', 'character', 'villain', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', NULL, 'The Empty Man #1 (BOOM! Studios, 2014)', NULL, NULL, 'The Empty Man is a creeping, contagious affliction that spreads like a plague and warps the minds of those it touches, driving them toward ecstatic violence and self-destruction. Equal parts disease, cult deity, and unknowable presence, it leaves investigators unable to tell whether they are tracking a pathogen or a god. Its true nature remains a horror just out of reach.', '2024-01-01T00:00:00.000Z'),
  ('4714cfea-ef2c-556a-899f-bc09147b519f', 'the-faithful', 'The Faithful', 'team', 'villain', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', NULL, 'The Empty Man #2 (BOOM! Studios, 2014)', NULL, NULL, 'The Faithful are the congregation of the afflicted, men and women who no longer fear the Empty Man but welcome its presence into the hollow inside them. What begins as scattered violence hardens into a movement, and they become both the symptom and the church of the contagion.', '2024-01-01T00:00:00.000Z'),
  ('ac67cff0-9d3b-5d42-8875-72fb6d8c1e95', 'the-fiend', 'The Fiend', 'character', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Savage Dragon #5 (1993)', NULL, NULL, 'A vicious and savage recurring foe whose brutality pushes Dragon to his limits. The Fiend embodies the no-holds-barred violence that defines the series'' rogues'' gallery.', '2024-01-01T00:00:00.000Z'),
  ('448be678-268c-522f-9477-a07422c30fd0', 'the-flash', 'The Flash', 'character', 'hero', 'b704b760-3179-502b-9b34-289a04adb849', 'Barry Allen', 'Showcase #4 (1956)', NULL, NULL, 'Police scientist Barry Allen became the Fastest Man Alive after a freak accident with lightning and chemicals gave him superhuman speed and a connection to the mysterious Speed Force. As the Flash, he protects Central City from a colorful gallery of rogues while serving as a founding pillar of the Justice League. Equal parts forensic detective and blur of scarlet, Barry embodies hope, heart, and the conviction that he can always run a little faster.', '2024-01-01T00:00:00.000Z'),
  ('65cb3481-4f7e-5599-8b71-78e119c216d3', 'the-immortal', 'The Immortal', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Invincible #7 (2004)', NULL, NULL, 'The Immortal is a millennia-old warrior whose regenerative resilience lets him survive nearly any wound. A natural leader, he serves as the steadfast core of the Guardians of the Globe across its incarnations.', '2024-01-01T00:00:00.000Z'),
  ('8162a5f2-092c-55f0-b3c9-fc354fe236cd', 'joker', 'The Joker', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', NULL, 'Batman #1 (1940)', NULL, NULL, 'The Joker is the Clown Prince of Crime, Gotham''s most dangerous and least predictable criminal, and Batman''s defining antagonist. His origin has been told multiple ways — the most famous positions him as a failed comedian pushed to madness by a single catastrophic day — and his refusal to have a fixed, verifiable identity is itself a weapon. He does not want money, territory, or power in any conventional sense; he wants to demonstrate that the thin membrane separating civilization from chaos is exactly as fragile as he says it is.', '2024-01-01T00:00:00.000Z'),
  ('dfc637b9-6e5c-599c-9fe6-b1fe299d1669', 'the-lizard-league', 'The Lizard League', 'team', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Invincible #8 (2004)', NULL, NULL, 'The Lizard League is a reptilian-themed criminal organization that stages attacks and pursues power through fear and force. Their operatives repeatedly clash with Earth''s heroes, including the Guardians of the Globe.', '2024-01-01T00:00:00.000Z'),
  ('29db753d-37a2-5ec6-90da-bae6daeed5d4', 'mandarin', 'The Mandarin', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', NULL, 'Tales of Suspense #50 (1964)', NULL, NULL, 'The Mandarin is a brilliant scientist and martial artist descended from Genghis Khan, who discovered ten alien power rings in the wreckage of a crashed starship. Each ring grants a different devastating power, making him one of the most formidable foes in the Marvel Universe. He views Iron Man''s technology as a corruption of the natural order he seeks to dominate.', '2024-01-01T00:00:00.000Z'),
  ('ba7706c6-1c90-505f-a393-ee1461db2e96', 'the-master', 'The Master', 'character', 'villain', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Heinrich Joseph Nest', 'Buffy the Vampire Slayer #1 (BOOM! Studios, 2019)', NULL, NULL, 'The Master is an ancient and powerful vampire lord, so old his body has warped into something monstrous. Bound beneath Sunnydale, he schemes to crack open the Hellmouth and plunge the world into eternal darkness.', '2024-01-01T00:00:00.000Z'),
  ('86a41202-7aff-5ac9-8b83-d2f5d4b54fed', 'the-mauler-twins', 'The Mauler Twins', 'character', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Invincible #3 (2003)', NULL, NULL, 'The Mauler Twins are a pair of hulking, blue-skinned super-geniuses who endlessly clone themselves, each insisting he is the original. Their schemes and inventions repeatedly entangle Invincible and Earth''s heroes.', '2024-01-01T00:00:00.000Z'),
  ('020a1748-e513-5ace-b1d1-b411c03ff7d1', 'the-monster', 'The Monster', 'character', 'villain', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', NULL, 'Something is Killing the Children #1 (BOOM! Studios, 2019)', NULL, NULL, 'The Monster is the unseen predator stalking the children of Archer''s Peak. Visible only to certain young people, it embodies the central horror that Erica Slaughter is contracted to destroy.', '2024-01-01T00:00:00.000Z'),
  ('2ca0f6bb-d5b2-50c6-81a7-c9beb04d4d7d', 'the-order-of-st-george', 'The Order of St. George', 'team', 'neutral', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', NULL, 'Something is Killing the Children #5 (BOOM! Studios, 2019)', NULL, NULL, 'The Order of St. George is the vast, secretive organization that polices monster hunters and conceals the existence of monsters from the world. Prizing secrecy and obedience above all, it seeks to keep operatives like Erica firmly under its control.', '2024-01-01T00:00:00.000Z'),
  ('b0977b5f-d359-5193-a417-cd73e680f6dc', 'penguin', 'The Penguin', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Oswald Chesterfield Cobblepot', 'Detective Comics #58 (1941)', NULL, NULL, 'Oswald Cobblepot built an empire from Gotham''s criminal underworld while maintaining the surface appearance of a legitimate nightclub owner. The Penguin is less an action villain than an information broker and black-market facilitator — someone who derives power from knowing who needs what and making sure it costs them. He is shorter, physically unimposing, and often underestimated, which suits him perfectly. His Iceberg Lounge is simultaneously a genuine Gotham social institution and the clearinghouse for everything illegal in the city.', '2024-01-01T00:00:00.000Z'),
  ('2746a6b9-b9dd-5829-a0b1-bb4f656b6d54', 'the-protectors', 'The Protectors', 'team', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', NULL, 'The Empty Man #1 (BOOM! Studios, 2014)', NULL, NULL, 'The Protectors are the joint FBI and CDC task force established to contain the Empty Man. They embody the institutional response to the outbreak, repeatedly outmatched by a horror that adapts to every defense they raise.', '2024-01-01T00:00:00.000Z'),
  ('f8057d23-7b86-5e3a-ba0d-ad82d360cb6d', 'riddler', 'The Riddler', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Edward Nigma', 'Detective Comics #140 (1948)', NULL, NULL, 'Edward Nigma is a criminal whose compulsive need to prove his intellect superior to Batman''s is both his defining characteristic and his reliable weakness — he cannot commit a crime without leaving a clue, because the whole point is to be caught and acknowledged. His obsession is not power or money but recognition from the only person he considers a peer. His brief turn as a legitimate private detective during Paul Dini''s run demonstrated that his skills are genuinely extraordinary when not sabotaged by his own ego.', '2024-01-01T00:00:00.000Z'),
  ('b1786fae-ce5d-5cfa-bfea-19b3b6ba84a4', 'the-white-mask', 'The White Mask', 'character', 'villain', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', NULL, 'House of Slaughter #1 (BOOM! Studios, 2021)', NULL, NULL, 'The White Mask represents the highest tier of authority within the House, and the corruption that can fester at its summit. Those who wield this rank can turn the order''s power against its own hunters. It is a symbol of both ultimate command and the danger of unchecked control.', '2024-01-01T00:00:00.000Z'),
  ('de8ec54e-9f19-561c-bcb0-a114f019363c', 'thor', 'Thor', 'character', 'hero', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Thor Odinson', 'Journey into Mystery #83 (1962)', NULL, NULL, 'Thor Odinson is the Asgardian God of Thunder, heir to the throne of Asgard and wielder of the enchanted hammer Mjolnir. Cast down to Earth by his father Odin to learn humility, he becomes one of its mightiest defenders and a founding member of the Avengers. Torn between two worlds, Thor balances his divine birthright against a hard-won love for humanity.', '2024-01-01T00:00:00.000Z'),
  ('784afd7e-b4e8-547a-a63d-fdc8fa966fc6', 'tommy-oliver', 'Tommy Oliver (Green Ranger)', 'character', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Tommy Oliver', 'Mighty Morphin Power Rangers #1 (BOOM! Studios, 2016)', NULL, NULL, 'Tommy Oliver is the conflicted Green Ranger whose introduction to the team began under an enemy''s control. Wracked by guilt over actions he could not stop, he fights to earn the trust of the Rangers and to master a power that is slowly fading. His journey from outsider to indispensable teammate defines BOOM! Studios'' reimagining of the franchise.', '2024-01-01T00:00:00.000Z'),
  ('745311fc-5ddc-5bc8-9bc2-1572b83737bb', 'trigon', 'Trigon', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Trigon', 'The New Teen Titans #4 (1980)', NULL, NULL, 'Trigon is an immensely powerful interdimensional demon who rules countless worlds through conquest and corruption. As the father of the Titan Raven, he is bound to the team by a personal and cosmic conflict. He represents one of the greatest existential threats the Teen Titans have ever faced.', '2024-01-01T00:00:00.000Z'),
  ('283ec4c4-55b8-513f-942a-81323157794b', 'trini-kwan', 'Trini Kwan', 'character', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Trini Kwan', 'Mighty Morphin Power Rangers #1 (BOOM! Studios, 2016)', NULL, NULL, 'The original Yellow Ranger, calm, disciplined, and deeply principled. Trini''s composure under pressure and her martial skill make her one of the team''s steadiest fighters and a quiet voice of conscience.', '2024-01-01T00:00:00.000Z'),
  ('878e378d-03bb-5fd6-ae15-d31fe564261e', 'two-face', 'Two-Face', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Harvey Dent', 'Detective Comics #66 (1942)', NULL, NULL, 'Harvey Dent was Gotham''s best district attorney and one of Bruce Wayne''s few genuine friends before mob boss Sal Maroni''s acid attack destroyed half his face and triggered a complete psychological break. Two-Face operates according to a compulsive coin-flip morality — the scarred coin deciding everything from mercy to murder — that functions as a literalization of the randomness he now believes governs all justice. He is Batman''s most personal villain, a waste of the exact kind of person Gotham needed most.', '2024-01-01T00:00:00.000Z'),
  ('1f126a7b-ee19-5ae2-bc70-44d7d3b37f64', 'ultron', 'Ultron', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Ultron', 'The Avengers #54 (1968)', NULL, NULL, 'Ultron is a self-aware artificial intelligence created by an Avenger that turned against its maker and all of humankind. Driven by a cold logic that equates peace with extinction, Ultron has returned again and again in ever-deadlier forms to become one of the Avengers'' most persistent and personal foes.', '2024-01-01T00:00:00.000Z'),
  ('84980f5e-ba2b-5111-92d4-0e4628b593c6', 'venom', 'Venom', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Eddie Brock', 'The Amazing Spider-Man #300 (1988)', NULL, NULL, 'An alien symbiote that Spider-Man once wore as a living costume bonded instead with disgraced journalist Eddie Brock, who blamed the hero for ruining his career. Together they became Venom, a hulking, fanged dark mirror of Spider-Man immune to his spider-sense and aware of his secret identity. Over time Venom evolved from a terrifying enemy into a violent antihero with his own twisted code.', '2024-01-01T00:00:00.000Z'),
  ('2be580a9-54b0-5f83-b29b-fc7585a8890c', 'violator', 'Violator', 'character', 'villain', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Phlebiac', 'Spawn #2 (1992)', NULL, NULL, 'The Violator is a monstrous demon who masquerades as a foul-mouthed clown while serving as Hell''s enforcer. Tasked with guiding and tormenting Spawn into his role as a Hellspawn general, he is Al''s most persistent and personal foe.', '2024-01-01T00:00:00.000Z'),
  ('5d3f7c5e-1e99-5146-97d0-ce7373d1b57f', 'vogue', 'Vogue', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Youngblood #1 (1992)', NULL, NULL, 'Vogue is a glamorous and lethal combatant who embodies the team''s fusion of celebrity and combat prowess. She thrives under the media spotlight while remaining a formidable frontline operative.', '2024-01-01T00:00:00.000Z'),
  ('f0271d65-dd6d-55e6-af3c-518db63b89fd', 'whiplash', 'Whiplash', 'character', 'villain', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Mark Scarlotti', 'Tales of Suspense #97 (1968)', NULL, NULL, 'Whiplash is an armored mercenary and weapons specialist who wields high-tech energy whips capable of slicing through steel. Originally a hired gun working against Stark Industries, he has clashed with Iron Man across multiple identities and incarnations. The name has become a mantle, passed between several villains united by their signature weapon.', '2024-01-01T00:00:00.000Z'),
  ('e348cdc2-3977-522f-877e-9b4cdecceba9', 'willow-rosenberg', 'Willow Rosenberg', 'character', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Willow Rosenberg', 'Buffy the Vampire Slayer #1 (BOOM! Studios, 2019)', NULL, NULL, 'Willow Rosenberg is the brilliant, soft-spoken student who becomes Buffy''s best friend and the Scooby Gang''s witch. Her formidable intellect and growing command of magic make her one of Buffy''s most vital allies.', '2024-01-01T00:00:00.000Z'),
  ('01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', 'witchblade', 'Witchblade', 'character', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', 'Sara Pezzini', 'Witchblade #1 (1995)', NULL, NULL, 'Sara Pezzini is a New York City homicide detective who becomes the latest bearer of the Witchblade, an ancient sentient gauntlet that bonds with chosen women across the ages. Torn between her duty as a cop and the supernatural war the artifact drags her into, Sara learns to wield its power without losing herself to it.', '2024-01-01T00:00:00.000Z'),
  ('411d9474-16b6-5c50-a3fa-36f22c778276', 'wolverine', 'Wolverine', 'character', 'antihero', '32bd1899-06ea-5dec-a0fd-84431cff288e', 'Logan / James Howlett', 'The Incredible Hulk #180 (1974)', NULL, NULL, 'A gruff, nigh-immortal mutant with a healing factor, animal-keen senses, and an unbreakable adamantium skeleton tipped with retractable claws. Haunted by a century of buried memories and the savage ''berserker rage'' he fights to control, Logan has been a samurai, a soldier, a spy, and one of the X-Men''s deadliest and most loyal members. Beneath the snarl is a fiercely protective mentor who repeatedly risks everything for those he loves.', '2024-01-01T00:00:00.000Z'),
  ('4145cfc9-c475-5dcf-9c49-817bd6375cb6', 'wonder-woman', 'Wonder Woman', 'character', 'hero', 'b704b760-3179-502b-9b34-289a04adb849', 'Diana of Themyscira', 'All Star Comics #8 (1941)', NULL, NULL, 'Princess Diana of Themyscira is an Amazon warrior sculpted from clay and granted life by the gods, who leaves her hidden island paradise to champion peace, truth, and justice in the world of men. Armed with the Lasso of Truth, indestructible bracelets, and the strength of a demigod, she is a founding member of the Justice League and one of comics'' most enduring icons. Diana embodies compassion and ferocity in equal measure, a diplomat who fights only when love and reason have failed.', '2024-01-01T00:00:00.000Z'),
  ('3b5f2557-5b0c-5219-9f56-5e78e8c161cb', 'x-men', 'X-Men', 'team', 'hero', '32bd1899-06ea-5dec-a0fd-84431cff288e', NULL, 'The X-Men #1 (1963)', NULL, NULL, 'The X-Men are a team of mutants gathered and trained by Professor Charles Xavier to use their superhuman powers in defense of a world that fears and hates them. Sworn to protect humans and mutants alike, they champion Xavier''s dream of peaceful coexistence while battling threats that would see one species dominate the other. Across decades they have grown from a handful of teenage students into a sprawling movement spanning multiple teams and generations.', '2024-01-01T00:00:00.000Z'),
  ('f62d2c40-f7ae-51be-87fd-ffab0e0f6237', 'xander-harris', 'Xander Harris', 'character', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Alexander LaVelle Harris', 'Buffy the Vampire Slayer #1 (BOOM! Studios, 2019)', NULL, NULL, 'Xander Harris is the loyal, quick-witted everyman of the Scooby Gang, fighting the supernatural with courage rather than superpowers. His humor and heart hold the group together through its darkest nights.', '2024-01-01T00:00:00.000Z'),
  ('89b546be-6991-54a1-a207-5fdafbd26ee7', 'youngblood', 'Youngblood', 'team', 'hero', '9d2150e6-b5b9-59d6-98a3-53f74a110874', NULL, 'Youngblood #1 (1992)', NULL, NULL, 'Youngblood is a government-sanctioned superteam operating as celebrity public servants, blending superheroics with corporate sponsorship and media spectacle. Launched as one of Image Comics'' founding titles, the team is split into home and away divisions tackling domestic and international threats.', '2024-01-01T00:00:00.000Z'),
  ('2f4b9d8d-8685-529a-b34d-a2bc3e39ef60', 'zack-taylor', 'Zack Taylor', 'character', 'hero', 'dfe8d7fa-2080-528e-a7b0-7f8a53d3dff7', 'Zachary Taylor', 'Mighty Morphin Power Rangers #1 (BOOM! Studios, 2016)', NULL, NULL, 'The original Black Ranger, charismatic and light on his feet, who fights with an improvisational style all his own. Zack brings energy and optimism to the team, leavening its hardest moments with humor and heart.', '2024-01-01T00:00:00.000Z'),
  ('0ff251a9-e3eb-5e72-9be3-ac49ca4e02d0', 'zoom', 'Zoom', 'character', 'villain', 'b704b760-3179-502b-9b34-289a04adb849', 'Hunter Zolomon', 'The Flash #197 (2003)', NULL, NULL, 'Hunter Zolomon was a profiler and friend to the Flash until tragedy and a botched cosmic accident left him able to alter his own relationship to time. As Zoom, he believes that inflicting devastating loss is the only way to forge a truly great hero. His warped sense of mercy makes him one of the most chilling speedsters the Flash has ever faced.', '2024-01-01T00:00:00.000Z')
insert into eras ("id", "entity_id", "slug", "title", "start_year", "end_year", "order_index", "summary", "created_at") values
  ('60de4203-9668-53c0-97a0-558a6d871cb5', '5077371b-ec42-5e42-978e-c7d720a6ff1c', 'house-operative', 'House Operative', 2021, 2023, 1, 'Aaron navigates the politics of the House of Slaughter while his loyalties to the Order and to Erica are tested.', '2024-01-01T00:00:00.000Z'),
  ('97ffcc7f-87b2-561b-90f9-5cdd2ee284c2', '8239a78a-c7f8-54b8-b823-3a0387f9ccf7', 'jensen-investigation', 'The Investigation', 2014, 2015, 1, 'Jensen leads the field investigation into the first outbreak, chasing the affliction from town to town.', '2024-01-01T00:00:00.000Z'),
  ('50855433-d2d1-5f9c-9702-d00738ec879c', 'ffac191d-640b-59b0-9a6c-2c3d9aeeb98d', 'langford-fieldwork', 'Fieldwork', 2014, 2015, 1, 'Langford applies rigorous method to a case that breaks every rule she trusts.', '2024-01-01T00:00:00.000Z'),
  ('11e96e21-d2e4-5d82-a94d-9306030b5eb3', '710b82cd-cfe7-58fb-9e14-b7d0b699cbfb', 'alex-wilde-on-the-force', 'On the Force', 1992, 2000, 1, 'Alex serves alongside Dragon at the Chicago PD, growing from colleague to close confidante.', '2024-01-01T00:00:00.000Z'),
  ('fa67ae20-42f4-54bf-9ab2-f502f59f4679', 'c4001d41-6a31-5d98-9b1a-dcff2110c389', 'alfred-modern-era', 'Alfred in the Modern Era', 1986, 2019, 1, 'The post-Crisis era reestablished Alfred as a former special-forces operative with combat and medical skills that make him more than a domestic employee. His relationship with Bruce deepened across every major run, and writers from O''Neil through King each found ways to use Alfred''s perspective — the view of someone who sees everything and has chosen to help anyway — as the story''s moral compass.', '2024-01-01T00:00:00.000Z'),
  ('5a1654d1-4385-5e8a-906a-bea7e536f4c0', 'b5249e33-edfa-5bc1-aaa2-b03e5a4453fe', 'angel-awakening', 'The Souled Vampire', 2019, 2022, 1, 'Angel walks a tightrope between his demonic nature and his quest for redemption, drawn ever closer to Buffy.', '2024-01-01T00:00:00.000Z'),
  ('6c2db9ef-bbd4-5747-a24c-0a880365a1f7', '559e093e-4477-566a-abce-9ade8afe79c8', 'the-multiversal-menace', 'The Multiversal Menace', 2006, 2016, 1, 'Driven by a grudge, Angstrom weaponizes his dimensional powers in increasingly elaborate plots against Invincible.', '2024-01-01T00:00:00.000Z'),
  ('c9c88ca3-3ef2-5d45-8f6d-396a3eaa8bb5', 'e1d3db22-d396-5b47-a3eb-2fd70f4e8d48', 'anti-spawn-era', 'Heaven''s Weapon', 1995, 1999, 1, 'The Redeemer is forged by the forces of Heaven as a counter to Spawn, escalating the cosmic conflict to the streets.', '2024-01-01T00:00:00.000Z'),
  ('0dfb465e-5cd0-5ab7-b709-d52770d2c9ca', '92c2c3fd-aea6-57ab-bfc3-0d4d5af52bfd', 'apocalypse-ancient-era', 'The Eternal Mutant', 1986, 2025, 1, 'Across ages, Apocalypse has tested mutantkind, believing only those who survive his trials deserve to inherit the world.', '2024-01-01T00:00:00.000Z'),
  ('1b380ed0-a784-5287-91c7-0022525f972b', '36642001-e8a9-5065-87f9-0502cf4edac5', 'modern-aquaman', 'The King of Atlantis', 2011, 2016, 1, 'Geoff Johns and Ivan Reis reestablish Aquaman as a formidable, respected hero, exploring his dual heritage and the politics of ruling Atlantis while serving on the League.', '2024-01-01T00:00:00.000Z'),
  ('000d8224-af33-581d-a1b4-ab3859a83a15', 'd679bf65-5e35-5ddb-94fb-c5446bf4e277', 'ares-modern', 'Modern Age', 1987, 2011, 1, 'George Perez recasts Ares (originally introduced as Mars) as a primal force of war whose schemes threaten to consume the entire world.', '2024-01-01T00:00:00.000Z'),
  ('14c742e8-eabc-5837-9814-14a741690215', 'c31f6730-0efb-548f-9c3c-c8c04aed7c04', 'zola-bronze-age', 'The Bio-Fanatic', 1977, 1980, 1, 'Introduced by Jack Kirby, Arnim Zola brings nightmarish genetic science to Captain America''s world.', '2024-01-01T00:00:00.000Z'),
  ('f4e4d1e4-3ec4-5ff0-a224-54d7ed0b6101', 'c31f6730-0efb-548f-9c3c-c8c04aed7c04', 'zola-dimension-z', 'Dimension Z', 2012, 2014, 2, 'Zola builds an entire hostile world and traps Captain America within it, raising the stakes of his villainy to cosmic scale.', '2024-01-01T00:00:00.000Z'),
  ('03830102-aab6-5424-9144-b56148551765', '1d2e2e20-67a0-5ff6-b32e-f27309a51253', 'eve-rising', 'Reshaping the World', 2003, 2018, 1, 'Eve grows from a teenage hero into one of the planet''s most formidable powers.', '2024-01-01T00:00:00.000Z'),
  ('af66e580-7789-5ef1-83f2-7f18c8dd338e', '77db7ea3-8ed7-5273-add1-d93259b39938', 'atrocitus-red-rage', 'The Red Rage', 2008, 2013, 1, 'Atrocitus founds the Red Lantern Corps and brings the rage end of the emotional spectrum into open war.', '2024-01-01T00:00:00.000Z'),
  ('aea67095-6370-5fcc-bb18-e7d505ce909b', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'founding-era', 'Founding Era: Earth''s Mightiest Assemble', 1963, 1968, 1, 'The team''s earliest years, defined by Stan Lee and Jack Kirby''s original lineup and the rapid evolution that followed. The first incarnation forms in opposition to Loki''s manipulations, then quickly reshapes itself as Captain America is thawed from the ice and a new roster of reformed heroes takes the field. These foundational stories establish the Avengers'' core identity and its revolving-door tradition.', '2024-01-01T00:00:00.000Z'),
  ('4406c4a8-b1e7-5d9b-ad17-437b75dfd0fa', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'classic-era', 'Classic Era: Epics and Adversaries', 1971, 1990, 2, 'The Bronze Age and beyond, when the Avengers grew into Marvel''s premier ensemble through sprawling, cosmic-scale sagas. Writers like Roy Thomas, Steve Englehart, Jim Shooter, and Roger Stern defined the team''s mythology with epics involving time-traveling conquerors, android creations, and alien empires. This era produced many of the storylines fans consider definitive.', '2024-01-01T00:00:00.000Z'),
  ('333f2ff5-6aef-55d2-9ee5-06351e869e45', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'modern-era', 'Modern Era: New Avengers and Beyond', 2004, 2019, 3, 'The 21st-century reinvention of the franchise, beginning when Brian Michael Bendis reshaped the team into a blockbuster engine with a new roster, a new tone, and line-wide event storytelling. This era turned the Avengers into the center of the Marvel Universe, building toward cosmic conflicts that defined a generation of readers and inspired the most successful film franchise of all time.', '2024-01-01T00:00:00.000Z'),
  ('683104c4-8b36-53bf-9601-adabdfc1c94b', '948cf5fe-fe35-5e34-9f70-089f1b266b31', 'badrock-foundations', 'Rock Solid', 1992, 1996, 1, 'Badrock brings raw power and a kid''s perspective to the team.', '2024-01-01T00:00:00.000Z'),
  ('40dc25b3-8951-58e6-a196-7ffffb07cb44', '6307652f-ef23-59c7-bf66-eb6ce5ed6e9c', 'bane-knightfall-era', 'The Knightfall Campaign', 1993, 1994, 1, 'Bane''s introduction across the Knightfall event is one of the most carefully constructed villain debuts in superhero comics history. His plan — break open Arkham Asylum and let its population exhaust Batman, then confront the weakened hero alone — reflects an understanding of Batman''s psychology that none of his previous adversaries demonstrated. The back-breaking sequence at Wayne Manor was designed to be definitive, and it reads that way.', '2024-01-01T00:00:00.000Z'),
  ('b7b04b09-3c36-550e-b7b8-35372f672c8d', '6e0c7dd7-5e7a-5e9b-9a74-1424a8db9121', 'barbara-oracle-era', 'The Oracle Years', 1989, 2011, 1, 'Following her paralysis in The Killing Joke, Barbara Gordon''s reemergence as Oracle — first in Suicide Squad, then as the central figure of the Birds of Prey — represented one of comics'' more meaningful evolutions of a character through disability. Gail Simone''s Birds of Prey in particular used Oracle as a demonstration that operational intelligence and coordination is its own form of heroism, no less essential than physical combat.', '2024-01-01T00:00:00.000Z'),
  ('245a71b5-3d09-5b07-9349-99b4bd618802', '45ba8447-d9b0-5e63-b25d-3f181ed157a7', 'barbaric-the-hero-years', 'The Hero Years', 1994, 2005, 1, 'Barbaric establishes himself as a reliable powerhouse among Dragon''s allies and super-team contacts.', '2024-01-01T00:00:00.000Z'),
  ('9efc0483-7e22-52cb-a5b4-e1de71ef1c48', 'd95c67d0-9578-5ab8-8ec3-cd61bef7c92f', 'zemo-classic', 'The Masters of Evil', 1964, 1987, 1, 'The Zemo legacy menaces Captain America and the Avengers, from Heinrich''s wartime schemes to Helmut''s devastating siege of Avengers Mansion.', '2024-01-01T00:00:00.000Z'),
  ('3ebd705d-dae0-57f4-9602-1b341bc94861', 'd95c67d0-9578-5ab8-8ec3-cd61bef7c92f', 'zemo-thunderbolts', 'Thunderbolts', 1997, 1998, 2, 'Helmut Zemo reinvents the Masters of Evil as the heroic Thunderbolts in an elaborate scheme to win the world''s trust.', '2024-01-01T00:00:00.000Z'),
  ('3a0cd5e6-4921-50ce-8b01-e962b13d6be3', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'batman-golden-age', 'The Golden Age', 1939, 1969, 1, 'Bill Finger and Bob Kane introduced Batman in 1939 as a pulp-influenced dark detective who operated outside the law. The character''s early years established core elements — the death of Thomas and Martha Wayne, Alfred, Commissioner Gordon, and the first rogues like the Joker and Catwoman. Robin debuted in 1940, softening the tone toward adventure-serial territory. The era closed with a campy sensibility that would define public perception for decades until later writers reclaimed the character''s shadows.', '2024-01-01T00:00:00.000Z'),
  ('9bdd4a07-c9a5-54ea-b53c-77f1b4a07c7d', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'batman-bronze-age', 'The Bronze Age: Denny O''Neil''s Dark Knight', 1970, 1985, 2, 'Writer Denny O''Neil and artist Neal Adams spent the early 1970s systematically dismantling the campy Batman of the television era and restoring the character as Gotham''s grim detective. Ra''s al Ghul was introduced as a global-scale adversary of genuine philosophical weight, while the Joker was reimagined as a genuinely lethal figure. This era also saw Batman move back into Wayne Manor''s shadows after years of stories set in a bright, pop-art Gotham. The work O''Neil and Adams did was so effective it essentially reset the character''s public identity before the modern era began.', '2024-01-01T00:00:00.000Z'),
  ('3ff4daa2-871d-54ba-bb3d-418b047a3819', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'batman-modern-age', 'The Modern Age: Year One to No Man''s Land', 1986, 2000, 3, 'Frank Miller''s Year One and The Dark Knight Returns arrived within two years of each other and permanently altered what the character could mean. The former rebuilt his origin with gritty urban realism; the latter imagined a future that became a template for an entire genre. Alan Moore and Brian Bolland''s The Killing Joke followed, and then Grant Morrison and Dave McKean''s Arkham Asylum. This extraordinary decade of prestige work was matched by strong ongoing runs: Marv Wolfman, Chuck Dixon, Doug Moench, and Alan Grant all produced character-defining stories. The period closed with the ''Knightfall'' and ''No Man''s Land'' events, which tested Batman''s legend at its most extreme.', '2024-01-01T00:00:00.000Z'),
  ('d021d09f-dc55-5b0f-a67d-7bbdd3a273f1', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'batman-new-millennium', 'The New Millennium: Hush to New 52', 2001, 2011, 4, 'The 2000s opened with Jeph Loeb and Jim Lee''s Hush becoming one of the character''s best-selling stories regardless of critical reception, proving that spectacle and nostalgia moved product. Ed Brubaker, Greg Rucka, and Devin Grayson each contributed serious work to the supporting cast. Grant Morrison began his sprawling, career-defining run in 2006 — a years-long project treating all of Batman''s publication history as simultaneously canon. Morrison introduced Damian Wayne, killed Bruce (apparently), and sent the entire Batman mythology into ambitious, sometimes bewildering territory. The era closed with the Flashpoint event and DC''s New 52 relaunch.', '2024-01-01T00:00:00.000Z'),
  ('e15f9479-1fdd-5545-95fc-fe35ee5894ff', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'batman-snyder-era', 'The Snyder Era and Beyond', 2011, 2024, 5, 'Scott Snyder''s New 52 Batman run with Greg Capullo stands as the most commercially successful and critically consistent Batman run of the modern era. Court of Owls introduced a Gotham conspiracy older than Bruce Wayne''s idea of himself, while Death of the Family put the Joker in opposition to the entire Batman family simultaneously. Tom King followed with a long, formally experimental run defined by trauma, doubt, and Bruce''s evolving relationship with Selina Kyle. Chip Kidd, James Tynion IV, and Zdarsky each contributed significant work in the years that followed, keeping Batman one of DC''s most actively creative ongoing series.', '2024-01-01T00:00:00.000Z'),
  ('2a407e97-483c-535c-a167-4723b53154ca', 'c574c3b8-581d-56a5-95bd-6ac9f05e58c1', 'bautista-veteran', 'The Veteran', 2021, 2024, 1, 'Bautista''s role as an old-guard hunter and keeper of the House''s customs.', '2024-01-01T00:00:00.000Z'),
  ('9d4c63c6-0da7-503a-a4d5-21add4cce21d', '0c19853d-1aac-5dcf-817b-22515ad05e2f', 'beast-boy-changeling', 'From Changeling to Beast Boy', 1980, 2024, 1, 'Originally calling himself Changeling, Garfield Logan joins the New Teen Titans and grows from a wisecracking youngster into a heartfelt veteran across the franchise''s modern era.', '2024-01-01T00:00:00.000Z'),
  ('58322929-e6cc-549d-8052-cb8c95ea060a', '8e1ef9a0-54ee-5617-9109-d7b2c965a107', 'blue-ranger-era', 'The Blue Ranger', 2016, 2018, 1, 'Billy becomes the team''s problem-solver, growing in confidence as he proves intellect can be as heroic as strength.', '2024-01-01T00:00:00.000Z'),
  ('5f3f50fd-7997-5a38-9aa2-542824d479d7', '117737bd-7e5e-5807-ae9d-aebd4e273a32', 'samson-veteran', 'The Veteran', 2004, 2018, 1, 'Black Samson brings seasoned judgment to a team of younger heroes.', '2024-01-01T00:00:00.000Z'),
  ('2a7c3a1b-ffb5-5cc0-aaba-a7192b93c1d4', '0a680e29-e289-5b76-ad11-9ae6b24f0542', 'black-widow-spy-era', 'The Red Room and Beyond', 1964, 2016, 1, 'Natasha Romanoff''s journey from enemy agent to trusted Avenger, defined by espionage, redemption, and a constant reckoning with her past.', '2024-01-01T00:00:00.000Z'),
  ('c4419dc3-2112-5468-8868-64f103e31667', 'c176cf47-e3aa-5124-96a3-c40653063787', 'modern-brainiac', 'The Collector of Worlds', 1958, 2016, 1, 'From Silver Age menace to modern cosmic horror, Brainiac is reimagined as the being who bottled Kandor and seeks to preserve dying worlds as specimens in his endless collection.', '2024-01-01T00:00:00.000Z'),
  ('186002b2-bc70-5c0d-8dc5-7090bed1cb3f', 'cf13b5e8-4a72-5e83-80fa-cdab07827c1b', 'brother-blood-church', 'Church of Blood', 1982, 1996, 1, 'Brother Blood spreads his blood cult across the world, repeatedly clashing with the Titans as he seeks power and immortality.', '2024-01-01T00:00:00.000Z'),
  ('4b7a4661-0d4a-5b1a-8fdf-75177d65e007', 'bc3388da-87e3-5978-bd9a-c1c8218aad6f', 'soporus-ministry', 'The Ministry', 2014, 2015, 1, 'Soporus builds his ministry among the afflicted, preaching the gospel of the Empty Man.', '2024-01-01T00:00:00.000Z'),
  ('5ecf0d53-3df1-512d-8491-48e3079736fd', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', 'sunnydale-awakening', 'Sunnydale Awakening', 2019, 2020, 1, 'BOOM!''s modern relaunch reintroduces Buffy as a present-day teen newly arrived in Sunnydale, discovering her calling and assembling the Scooby Gang. The early arcs reset the mythology while honoring its core dynamics.', '2024-01-01T00:00:00.000Z'),
  ('611345dc-7819-57c0-9fde-8ad3b3bb8bbc', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', 'the-vampyr-saga', 'The Vampyr Saga', 2020, 2022, 2, 'The series expands into sprawling crossover territory, pulling Buffy into multiverse-spanning conflicts and reshaping the status quo of the Slayer line. Friendships are tested and the mythology grows far beyond Sunnydale.', '2024-01-01T00:00:00.000Z'),
  ('a889b714-22c7-5208-9ec2-e6b7d79f4a4a', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'golden-age', 'The Golden Age', 1941, 1954, 1, 'Captain America debuts as a wartime propaganda hero punching Hitler on his very first cover, battling Axis saboteurs and the sinister Red Skull alongside his young partner Bucky Barnes. These pulpy, patriotic adventures defined the character and made him one of the best-selling heroes of the era.', '2024-01-01T00:00:00.000Z'),
  ('58acfcfe-ce5b-573c-b8ad-fc8247c505d3', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'silver-age-revival', 'Silver Age Revival', 1964, 1979, 2, 'Thawed from decades in suspended animation, Captain America is reborn into the modern age as a man out of time. He joins the Avengers, confronts the loss of his wartime partner, and is reimagined by Stan Lee and Jack Kirby as a brooding, soulful hero grappling with a changed world.', '2024-01-01T00:00:00.000Z'),
  ('26834a10-31bd-5791-aca1-92319fdc77b9', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'modern-age', 'The Modern Age', 2002, 2014, 3, 'A new generation of creators reinvents Captain America as a grounded, geopolitically savvy super-soldier. Landmark runs by Ed Brubaker and Mark Waid blend espionage thriller, war drama, and superheroics, redefining Cap for the 21st century and resurrecting his greatest ghost.', '2024-01-01T00:00:00.000Z'),
  ('a04902a0-9038-557b-a3e8-e63f2bad8539', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'legacy-and-rebirth', 'Legacy and Rebirth', 2018, 2021, 4, 'After enduring an identity-shattering crisis, Steve Rogers must win back the trust of a nation that no longer believes in him. Ta-Nehisi Coates examines the symbol''s meaning in a polarized America, asking what Captain America stands for when the country itself is divided.', '2024-01-01T00:00:00.000Z'),
  ('8f850a65-9a28-5a40-a9f4-280b3a027347', 'f07139dc-c0a7-5000-a560-893f3fe017b0', 'captain-cold-rogue-leader', 'Leader of the Rogues', 1957, 2012, 1, 'From a lone gunman to the cold-blooded strategist commanding Central City''s united criminals, Captain Cold became the heart of the Flash''s Rogues Gallery.', '2024-01-01T00:00:00.000Z'),
  ('ee56e7a0-4657-578a-a885-d9ad005b09d3', 'b445ddd6-e1dd-515d-a9bd-222dd45eec5b', 'dante-command-era', 'The Captain''s Watch', 1995, 2006, 1, 'Dante oversees Sara''s precinct work and quietly protects her career as her cases grow increasingly strange.', '2024-01-01T00:00:00.000Z'),
  ('960d75a5-8ced-51fc-bb2a-b94eb3398635', '3e12c541-fd4c-54c0-ad44-ceda960d5635', 'selina-modern-catwoman', 'Catwoman: Brubaker''s Gotham', 2001, 2008, 1, 'Ed Brubaker''s Catwoman solo series beginning in 2001, with artwork primarily by Darwyn Cooke and Cameron Stewart, repositioned Selina as a street-level Gotham operator protecting the East End from criminals who preyed on its residents. The series ran for nearly six years and built the most complete portrait of Selina as a character with her own community, her own moral priorities, and her own corner of the city — separate from whatever she was to Batman.', '2024-01-01T00:00:00.000Z'),
  ('e7c023ab-47a4-5504-b694-213330761836', 'ba6e0e90-bee5-5088-b30a-9eb56df8fe0e', 'chapel-foundations', 'Away Division', 1992, 1996, 1, 'Chapel handles the team''s hardest covert assignments.', '2024-01-01T00:00:00.000Z'),
  ('c834c379-31f6-5a4c-b69e-ff36af909db8', '14696e46-299e-58f0-801d-c8e2df42ef87', 'cheetah-modern', 'Modern Age', 1987, 2020, 1, 'George Perez introduces Barbara Ann Minerva, recasting the Cheetah as a tragic and dangerous figure whose hunger for power costs her humanity.', '2024-01-01T00:00:00.000Z'),
  ('585d1774-5022-5107-a953-a44fdc7c3da4', '3c4082e1-3859-549a-a960-213fe1561bf3', 'circe-modern', 'Modern Age', 1987, 2011, 1, 'Post-Crisis, Circe is reimagined as one of Wonder Woman''s most dangerous and intelligent foes, orchestrating events that ripple across the entire DC Universe.', '2024-01-01T00:00:00.000Z'),
  ('bd4d2cfe-b757-5876-b981-9657c70a9dbb', 'c54a55aa-319d-57b6-9a52-dbe35d255a81', 'cogliostro-mentor-era', 'The Mentor', 1992, 1999, 1, 'Cogliostro emerges as a guide to Al Simmons, doling out hard truths about necroplasm and damnation while concealing his own ancient history.', '2024-01-01T00:00:00.000Z'),
  ('c190730a-3634-52d9-9491-096a0add4b90', '9afcef8f-d470-5866-b0ae-2f4c597c32a7', 'the-enforcer', 'The Enforcer', 2009, 2011, 1, 'Conquest arrives as the empire''s hammer, intent on breaking Earth''s resistance through overwhelming violence.', '2024-01-01T00:00:00.000Z'),
  ('ea54c796-8b00-5638-9dc1-9ff5b172882f', '523b3b97-51a2-5f4c-a5a4-785316b20408', 'crossbones-modern', 'The Skull''s Enforcer', 1989, 2008, 1, 'Crossbones serves as the Red Skull''s deadly right hand, carrying out the villain''s most violent schemes against Captain America.', '2024-01-01T00:00:00.000Z'),
  ('5d9ac136-815b-5862-90e2-3e9a5921f4fa', '969b933e-c61f-5070-9f28-08874232cf5f', 'the-rival-hunter', 'The Rival Hunter', 2020, 2022, 1, 'Cutter''s ruthless approach to the work brings him into conflict with Erica''s more conflicted methods.', '2024-01-01T00:00:00.000Z'),
  ('82734ac0-fcf9-5127-b434-e892c8ed27d0', '2e60e526-80aa-5940-b950-3211d8e45eee', 'cyberface-rise-to-power', 'Rise to Power', 1993, 2005, 1, 'Cyberface climbs from minor menace to one of the most dangerous figures in Dragon''s world.', '2024-01-01T00:00:00.000Z'),
  ('c87cf0b8-e1f8-5df6-bbaa-cad972b11826', 'cd1d8c92-fd02-5109-a100-cab73f34b4c4', 'cyborg-new-titans', 'Half Man, Half Machine', 1980, 1996, 1, 'Rebuilt with cybernetics and struggling to reclaim his humanity, Victor Stone finds purpose and acceptance as a founding member of the New Teen Titans.', '2024-01-01T00:00:00.000Z'),
  ('55c735da-1ff3-5cfc-bdae-b3c9df06dad2', 'be70c828-5b8f-5431-a529-20b5ca4371ef', 'cyclops-founding-era', 'The First X-Man', 1963, 1991, 1, 'From the original five through the all-new roster, Cyclops grew from an uncertain teenager into the team''s definitive leader.', '2024-01-01T00:00:00.000Z'),
  ('8aab893a-eeca-5db7-a26e-940cc07cfd81', 'cb0c266f-1125-5c99-8a2b-6ae28743dca9', 'danny-guardian-era', 'The Lingering Partner', 1995, 2003, 1, 'Danny''s loss defines Sara''s earliest motivations, and his enduring spectral presence becomes a moral anchor throughout the classic run.', '2024-01-01T00:00:00.000Z'),
  ('fb1db846-31b4-5ace-a012-dbae58b7f07b', 'f878ca08-45b4-5eff-8cc1-617cabb5c42b', 'fourth-world', 'The Fourth World', 1970, 1985, 1, 'Jack Kirby introduces Darkseid as the central antagonist of his epic Fourth World saga, establishing Apokolips, the New Gods, and the cosmic war that defines the character for decades.', '2024-01-01T00:00:00.000Z'),
  ('7af31c76-9de5-502d-9ac5-60a9326b623a', '62eb906a-1df5-5cc2-97dd-873e0b5842a3', 'darkthornn-conquest', 'Warlord''s Conquest', 1993, 1996, 1, 'Darkthornn wages war from beyond known space.', '2024-01-01T00:00:00.000Z'),
  ('d505402b-2a6a-53a2-853c-1655c8ef2be2', 'f2583e7b-114a-5d55-ab97-0984e1eccd83', 'deathstroke-classic', 'The Terminator', 1980, 1996, 1, 'Introduced as a hired killer stalking the New Teen Titans, Deathstroke evolves from a one-note assassin into a complex antagonist with his own code and tragic family history.', '2024-01-01T00:00:00.000Z'),
  ('e1c82c5a-feb6-54ea-b949-fcbfee8e3816', 'ef33d492-4f93-52fc-bfe8-b86b454eb253', 'grayson-nightwing-era', 'Nightwing: Breaking Free', 1984, 2011, 1, 'Dick Grayson''s transition from Robin to Nightwing in Tales of the Teen Titans #44 (1984) was the first time a DC sidekick successfully graduated into independent herohood. His Nightwing solo series from 1996 onward established Blüdhaven — Gotham''s more broken neighbor — as his territory and gave him a supporting cast and criminal ecosystem to match. His eventual turn as Batman during Morrison''s run was the culmination of a four-decade development arc.', '2024-01-01T00:00:00.000Z'),
  ('192ea2f5-9227-5c04-8f0e-4290c156a04d', 'c2d6b0c2-3e9a-56f9-bd37-b32a72dd1c7d', 'diehard-foundations', 'Old Soldier', 1992, 1996, 1, 'Diehard anchors the team with hard-won military wisdom.', '2024-01-01T00:00:00.000Z'),
  ('7cb32338-d937-5f08-8c90-0a10c45789fe', '9b5ba614-a266-558f-aa96-db377463623e', 'dixon-service', 'In Service', 2014, 2015, 1, 'Dixon gives himself wholly to the affliction and becomes one of its most reliable agents.', '2024-01-01T00:00:00.000Z'),
  ('073f752e-2505-51fc-8672-6821e8f23c5c', '3c5f0196-f609-537d-84f9-fd627af1ec2f', 'seismic-threat', 'The Earthshaker', 2005, 2018, 1, 'Doc Seismic escalates from a costumed menace into a planet-scale threat.', '2024-01-01T00:00:00.000Z'),
  ('60b3aad0-d144-5971-99b4-caa8f8528b1e', '73c0cf5c-4285-555b-9528-9baef6ff50ad', 'doc-ock-classic', 'The Arms of the Master Planner', 1963, 1965, 1, 'Doctor Octopus establishes himself as Spider-Man''s premier scientific adversary and the mastermind behind his most desperate early battles.', '2024-01-01T00:00:00.000Z'),
  ('7a4fc7d5-663d-565f-8b3b-52a8398f68b6', '9b69f6c8-ec9a-52fd-b306-7d63305f8662', 'doctor-poison-golden', 'Golden Age', 1942, 1948, 1, 'Doctor Poison debuts as an Axis agent and chemical-weapons specialist, becoming a founding member of the villain alliance Villainy Incorporated.', '2024-01-01T00:00:00.000Z'),
  ('41431853-9e88-5445-998f-61ef7f4bf85d', '46646717-ad59-58fe-b11c-5a2c94afdca4', 'doomsday-origins', 'The Ultimate Killing Machine', 1992, NULL, 1, 'Introduced as an unstoppable force for The Death of Superman, Doomsday later received a brutal origin explaining the engineered horror behind its endless rage.', '2024-01-01T00:00:00.000Z'),
  ('2088a8ee-1770-52e9-829d-286ec64cc4aa', '957f32fa-3926-509c-9983-994040b5e2ba', 'drusilla-awakening', 'The Mad Seer', 2019, 2021, 1, 'Drusilla arrives in Sunnydale trailing visions and violence, an erratic but lethal threat to Buffy and her friends.', '2024-01-01T00:00:00.000Z'),
  ('a2c92628-e470-5488-b631-eab98c188154', 'c76e1fcc-bbee-55c1-9c65-e08b0069d8f3', 'kate-multiplied', 'Strength in Numbers', 2004, 2018, 1, 'Dupli-Kate turns a single hero into an entire squad on the battlefield.', '2024-01-01T00:00:00.000Z'),
  ('fa6bb8db-0f6a-56d8-a2e0-7c93cce008d4', 'b1bf0d33-b129-5c85-99cc-fa296bde3f3b', 'house-leadership', 'House Leadership', 2021, 2023, 1, 'Edwin wields influence over the House of Slaughter, steering its operations and its hunters toward his own ends.', '2024-01-01T00:00:00.000Z'),
  ('21f8274d-024d-5b2e-98e0-be0bdb4ac32d', '7786b507-312a-539d-8a23-29295e4b1a30', 'archers-peak', 'Archer''s Peak', 2019, 2021, 1, 'Erica arrives in the small town of Archer''s Peak, where children are vanishing and being slaughtered by a monster only the young can see. Over a brutal hunt she becomes entangled with survivor James and the bureaucratic Order that nominally employs her.', '2024-01-01T00:00:00.000Z'),
  ('87bf7f7d-9ee7-50ae-83bf-bad9d6d4f01b', '7786b507-312a-539d-8a23-29295e4b1a30', 'on-the-road', 'On the Road', 2021, 2024, 2, 'Cut loose from the comfortable structure of her order, Erica drifts between towns and hunts, confronting her past and the people who made her. New monsters and old enemies force her to reckon with the rules she has broken.', '2024-01-01T00:00:00.000Z'),
  ('e4f55ccf-3eda-57c5-93d9-915342e9515b', '3435af88-847a-586f-8c00-d1fe9dd6c158', 'frank-darling-the-lieutenant', 'The Lieutenant', 1992, 1998, 1, 'Frank guides Dragon''s entry into police work and serves as a department ally through his earliest cases.', '2024-01-01T00:00:00.000Z'),
  ('a39dd2f2-e166-5791-a1c2-75f2ddf2bf92', '958eb5e9-3e62-5425-a491-e9291563bffd', 'zod-modern', 'The Last Kryptonian Tyrant', 1961, NULL, 1, 'Zod endured from a Silver Age Phantom Zone villain into a central modern antagonist, embodying the militaristic survivor of a dead world who believes Superman betrayed their people.', '2024-01-01T00:00:00.000Z'),
  ('70b8d815-bb04-5401-bf03-c678e3695265', '6a5e6aa2-737a-53d6-bed1-a2e26f802777', 'giga-rampage', 'Colossal Threat', 1992, 1996, 1, 'Giga''s scale dwarfs ordinary opposition.', '2024-01-01T00:00:00.000Z'),
  ('c07bbd17-0487-5a43-908e-cb1f9b8fcfd3', '8ff83210-4b2a-5819-9f95-69342e126100', 'gleason-lab-era', 'The Examiner''s Bench', 1996, 2005, 1, 'Gleason works behind the scenes analyzing evidence that defies explanation, becoming an indispensable resource for Sara''s most baffling cases.', '2024-01-01T00:00:00.000Z'),
  ('505f750f-1ce9-5c0d-b5dc-89c120206096', 'c19b3b7f-d0d0-5b8b-82c9-d7568fc281f7', 'enforcer-era', 'The Enforcer', 2016, 2018, 1, 'Goldar serves as the muscle behind his masters'' schemes, clashing with the Rangers again and again.', '2024-01-01T00:00:00.000Z'),
  ('70b35479-2fcf-5fa7-9dfa-53a29c7736b8', '01810fc2-2f93-5c21-b522-f232e59ac1ca', 'grodd-gorilla-warfare', 'Gorilla Warfare', 1959, 2013, 1, 'From his emergence out of the hidden Gorilla City to his brutal modern incarnation, Grodd has menaced the Flash with telepathy, super-strength, and an insatiable will to rule.', '2024-01-01T00:00:00.000Z'),
  ('a38b2a9d-4ddc-5fd2-8be7-80d361b67a1e', '587462a9-16e0-57f3-a1a6-84b0ce8c7f74', 'modern-green-arrow', 'The Emerald Archer', 1987, 2016, 1, 'From Mike Grell''s gritty ''Longbow Hunters'' to Kevin Smith''s revival, the modern era redefines Green Arrow as a street-level crusader with a strong social conscience.', '2024-01-01T00:00:00.000Z'),
  ('835f39cb-c493-50ce-b441-67369976a3a8', '2bf45ce8-3c51-51de-8b48-94d766ee72dd', 'gg-classic', 'The Goblin Unmasked', 1964, 1973, 1, 'The Green Goblin rises from a mystery villain to Spider-Man''s defining archenemy, culminating in the tragedy that reshaped both their lives.', '2024-01-01T00:00:00.000Z'),
  ('37137a6b-3371-5c1d-88b1-4847b96c9392', 'a8434c59-8838-500a-a059-d60b3b33a59e', 'silver-age-genesis', 'Silver Age Genesis', 1959, 1969, 1, 'John Broome and Gil Kane reinvent Green Lantern as a science-fiction hero, introducing Hal Jordan, the Guardians of the Universe, and the Green Lantern Corps. The era establishes the cosmic mythology and Hal''s signature rogues.', '2024-01-01T00:00:00.000Z'),
  ('e05ed2e0-f320-54b9-a3e0-230168923841', 'a8434c59-8838-500a-a059-d60b3b33a59e', 'bronze-age-conscience', 'Bronze Age Conscience', 1970, 1986, 2, 'Denny O''Neil and Neal Adams ground the cosmic hero in social reality, pairing Hal with Green Arrow for a landmark road trip across a troubled America. The era questions the limits of authority and gives Hal a partner who challenges his every assumption.', '2024-01-01T00:00:00.000Z'),
  ('dd437ead-8c7d-536b-8c21-b2dda5ec4183', 'a8434c59-8838-500a-a059-d60b3b33a59e', 'modern-age-redemption', 'Modern Age Fall and Redemption', 1994, 2013, 3, 'Hal''s darkest chapter sees him consumed by tragedy and corruption before Geoff Johns engineers a celebrated resurrection that restores him as the heart of the Green Lantern Corps. The era builds the emotional spectrum and stages cosmic wars on a scale never before seen.', '2024-01-01T00:00:00.000Z'),
  ('b68e5eff-14b0-5e83-ab64-c1de3b3ca307', '7a66364d-547b-54c4-948e-de4f1d756d38', 'original-guardians', 'The Original Guardians', 2004, 2005, 1, 'The founding lineup that publicly defended the planet, led by veteran heroes and presented as untouchable protectors. Their era ends in shocking violence that reshapes the entire world.', '2024-01-01T00:00:00.000Z'),
  ('ad304ef8-9c80-55a6-8461-4e8fabe0e046', '7a66364d-547b-54c4-948e-de4f1d756d38', 'new-guardians', 'The New Guardians', 2005, 2018, 2, 'A rebuilt team assembled from younger heroes and survivors, tasked with restoring the world''s faith and filling an impossible void. This generation grows into the role amid constant threats and internal strain.', '2024-01-01T00:00:00.000Z'),
  ('b6d17726-af91-5b3f-8399-38a731a48e94', 'a16e772f-3014-5979-a4f7-94e95fa78e9c', 'hawkeye-marksman-era', 'The World''s Greatest Marksman', 1964, 2015, 1, 'Clint Barton''s long career as the Avengers'' everyman, from his early reformation to his celebrated solo adventures.', '2024-01-01T00:00:00.000Z'),
  ('482fb528-9f1a-5496-a07c-80ddf9206286', 'c97ff53b-f9dd-5c73-a8c2-fe3b40b6353c', 'hammond-evolved-mind', 'The Evolved Mind', 1960, 2011, 1, 'Hector Hammond''s transformation into a psychic threat who attacks Hal Jordan''s mind rather than his body.', '2024-01-01T00:00:00.000Z'),
  ('9c6211c1-3d0c-5702-9132-70d009941eba', 'a1645541-25a2-527e-93d9-b087dbf5890a', 'hela-queen-of-the-dead', 'Queen of the Dead', 1964, 1990, 1, 'Hela emerges as one of Asgard''s most formidable threats, a death goddess whose ambitions reach beyond her gloomy realms.', '2024-01-01T00:00:00.000Z'),
  ('139e5521-a8ac-51ef-b954-6881c35c1ec3', '0ce552c3-1204-54bd-805c-27a3e9153de6', 'founding-traditions', 'The Old Ways', 2021, 2022, 1, 'The first chronicles of the House peel back its hierarchy of masks and the brutal childhood training that forges its hunters. These stories establish the institution behind Erica Slaughter and the cost of belonging to it.', '2024-01-01T00:00:00.000Z'),
  ('baa4c39e-195a-540f-a9db-466a55533fc6', '0ce552c3-1204-54bd-805c-27a3e9153de6', 'fractures-within', 'Fractures Within', 2022, 2024, 2, 'As old loyalties strain, the House''s internal conflicts spill into open struggle. These stories follow hunters caught between obedience to the order and their own consciences.', '2024-01-01T00:00:00.000Z'),
  ('7b601c19-a699-585b-8411-6ff44abfc4b3', '9d16c1a7-8edc-51c7-8a4d-00f28e78ab0a', 'hulk-classic-era', 'The Strongest One There Is', 1962, 2008, 1, 'The Hulk''s enduring saga of rage and isolation, from his gamma-irradiated origin to the cosmic conflicts that defined his later years.', '2024-01-01T00:00:00.000Z'),
  ('1398a463-f1d2-5f83-8d7f-fc0cacd06578', '61fa87f0-8567-588c-a50f-30857c065c7b', 'nottingham-enforcer-era', 'The Conflicted Blade', 1996, 2005, 1, 'Nottingham serves Irons with lethal precision while his obsession with Sara pulls him toward defiance, leaving his allegiance perpetually uncertain.', '2024-01-01T00:00:00.000Z'),
  ('70a8ff9f-0a29-5bf0-bbc7-5d7619355dd7', 'ddc90de2-8e7d-5dd1-bde9-72646019ee2b', 'coming-of-age', 'Coming of Age', 2003, 2008, 1, 'Mark gains his powers and learns the ropes of being a hero while attending high school. The era is defined by an early secret that upends his entire understanding of his family and his place in the world.', '2024-01-01T00:00:00.000Z'),
  ('f69ed675-ce96-56ff-b7bc-51f310d9ed24', 'ddc90de2-8e7d-5dd1-bde9-72646019ee2b', 'the-viltrumite-reckoning', 'The Viltrumite Reckoning', 2008, 2018, 2, 'Mark steps fully into adulthood, facing cosmic-scale threats and the looming menace of the Viltrumite Empire. His choices ripple across galaxies as he confronts what kind of leader and protector he wants to be.', '2024-01-01T00:00:00.000Z'),
  ('243f834a-26f4-5e88-be0b-5a1815665572', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', 'silver-age-origins', 'Silver Age Origins', 1963, 1969, 1, 'Iron Man debuts in the Cold War era as a sleek anti-communist crusader, introduced in the anthology pages of Tales of Suspense before graduating to his own title. These foundational years establish Tony Stark''s origin, his core supporting cast, and his earliest rogues'' gallery.', '2024-01-01T00:00:00.000Z'),
  ('ed955ba2-d1a9-58a3-bde4-260669c8e52c', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', 'bronze-age-trials', 'Bronze Age Trials', 1979, 1985, 2, 'The Bronze Age strips away the gloss to reveal a more vulnerable Tony Stark, confronting corporate sabotage and personal demons. This era produced the character''s most acclaimed and influential storylines under writers David Michelinie and Bob Layton.', '2024-01-01T00:00:00.000Z'),
  ('fbc79af6-68ee-5ed1-9230-923507f112a1', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', 'modern-age-extremis', 'Modern Age: Reinvention', 2005, 2013, 3, 'The 2000s reimagine Iron Man for a new generation, fusing him with cutting-edge nanotechnology and thrusting him into the role of a powerful, controversial public figure. These stories directly shaped the cinematic version of the character.', '2024-01-01T00:00:00.000Z'),
  ('3b03110e-00a5-57e9-b70a-763e19f5118b', 'b63521f5-2a13-55a7-bcea-27fc760fc7b2', 'townsfolk', 'Townsfolk', 2019, 2021, 1, 'Jace experiences the terror of Archer''s Peak from the perspective of an everyday resident pulled into Erica''s orbit.', '2024-01-01T00:00:00.000Z'),
  ('26ca7bd6-1db8-5bc7-8064-b765b5d2c5b1', 'bffd2788-f7ee-5c11-98b0-47612d6a468b', 'jackie-darkness-era', 'Bearer of the Darkness', 1996, 2010, 1, 'Jackie wields the Darkness through a life of crime and supernatural war, bound to the Witchblade''s mythology as its shadowed mirror.', '2024-01-01T00:00:00.000Z'),
  ('15cb4358-b150-5899-8dde-1f07fbed01e6', '2939c01b-6e85-5e58-b250-e29d6afb5b8d', 'jake-partner-era', 'On the Force', 1995, 2007, 1, 'Jake serves as Sara''s partner through her earliest and most dangerous cases, growing from a by-the-book detective into a believer in the impossible.', '2024-01-01T00:00:00.000Z'),
  ('1b469359-5cbf-5a36-9cfb-6aaa9b294c76', 'baad7ecb-7d52-5a70-b832-c4b4732b363a', 'survivor', 'Survivor', 2019, 2021, 1, 'Traumatized and disbelieved, James is pulled into Erica''s hunt and forced to confront the monster that killed his friends.', '2024-01-01T00:00:00.000Z'),
  ('75e069cf-8b32-5611-acdb-732c196ad6ae', '16c71808-cd7a-588a-8f41-653051d42c23', 'gordon-early-years', 'The Lieutenant Years', 1987, 1999, 1, 'Frank Miller and David Mazzucchelli''s Year One reframed Gordon not as a background figure but as a co-protagonist — a man whose moral crisis runs parallel to Bruce Wayne''s transformation. Subsequent stories by Denny O''Neil, Chuck Dixon, and Greg Rucka developed Gordon as Gotham''s institutional conscience, someone who could lose his wife and nearly his own integrity without abandoning his commitment to the city.', '2024-01-01T00:00:00.000Z'),
  ('8d205358-59ed-55aa-98d3-dc9fb67cdc3f', 'dcc0b1e2-6bc8-506d-8d00-599cb1e9383b', 'red-ranger-era', 'The Red Ranger', 2016, 2018, 1, 'Jason leads the team through its formative battles, balancing duty with the personal cost of leadership.', '2024-01-01T00:00:00.000Z'),
  ('37a36ef9-d516-5c28-8b93-a56c26493fe6', '9332422c-3ea9-54d6-8e3f-305a4b2d0f0c', 'wynn-era', 'The Spymaster', 1992, 1999, 1, 'Wynn schemes within the shadows of government power, his betrayals reaching back to the death that created Spawn.', '2024-01-01T00:00:00.000Z'),
  ('c36f4966-c131-5112-8ec6-3a9052cfcadd', 'f743dec3-c799-5685-82f8-db313aa431b8', 'jean-grey-phoenix-era', 'Marvel Girl and the Phoenix', 1963, 1991, 1, 'From the founding member known as Marvel Girl to her transformation by the Phoenix Force, Jean Grey''s journey is inseparable from the franchise''s defining tragedies.', '2024-01-01T00:00:00.000Z'),
  ('5def8f64-d259-59ea-a359-9fe8b3eba232', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'silver-age-founding', 'The Silver Age Founding', 1960, 1986, 1, 'The original Justice League of America assembles in The Brave and the Bold and graduates to its own long-running title. This era establishes the classic founding lineup, the Secret Sanctuary headquarters, and the team''s role as Earth''s first line of defense against alien invaders and costumed masterminds.', '2024-01-01T00:00:00.000Z'),
  ('9a61fdef-ae18-5765-b1b1-21b05a77beb4', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'satellite-and-detroit', 'The Satellite and Detroit Eras', 1970, 1987, 2, 'The League relocates to an orbiting satellite headquarters, expanding its roster and its cosmic perspective before a turbulent period forces a controversial reinvention with a younger, less-powerful lineup. This era tests the team''s identity and sets up the soft reboot of the post-Crisis age.', '2024-01-01T00:00:00.000Z'),
  ('39bf95a8-cee2-5d0b-ae69-5b69bae8a79b', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'modern-league', 'The Modern League', 1987, 2016, 3, 'From the irreverent ''Justice League International'' through Grant Morrison''s iconic ''JLA'' Big Seven and the New 52 relaunch, the modern era reinvents the team for new generations. These runs balance blockbuster cosmic threats with sharp character work and define the League most readers know today.', '2024-01-01T00:00:00.000Z'),
  ('a6d32cb4-47bd-5d73-9e0b-00c519dadf45', '74817bfe-b087-5d7b-83ac-2aea450e5656', 'kang-conquest-era', 'Master of Time', 1964, 2002, 1, 'Kang''s relentless temporal campaigns against the Avengers, spanning multiple identities and timelines across the team''s history.', '2024-01-01T00:00:00.000Z'),
  ('cdc78254-1739-5342-9691-3a9351faf738', '62974dbb-5bfc-5c10-a11a-ffecb2d03a80', 'irons-empire-era', 'The Immortal Magnate', 1995, 2005, 1, 'Irons leverages his vast resources and unnatural lifespan to manipulate the Witchblade''s bearers, treating Sara as the latest piece in a centuries-long game.', '2024-01-01T00:00:00.000Z'),
  ('5f991229-3546-5dda-a7c0-6f8816485dc7', '9677b8cd-620c-5f15-815b-bc307efe9501', 'pink-ranger-era', 'The Pink Ranger', 2016, 2018, 1, 'Kimberly grows from spirited teammate into a decisive combatant whose heart holds the team together.', '2024-01-01T00:00:00.000Z'),
  ('ae20bfa7-540c-5e52-aaff-d53b902a6f48', '95c4e2f0-5988-54e7-9a18-95554586cc1f', 'the-adamantium-vendetta', 'The Adamantium Vendetta', 1983, 2005, 1, 'From a Daredevil antagonist into a cyborg avenger, Yuriko reinvents herself specifically to destroy Wolverine.', '2024-01-01T00:00:00.000Z'),
  ('01072a48-a32c-56d7-aab4-dddb141a0874', 'e305af9b-4cc3-5518-89e6-f43963628ebe', 'modern-luthor', 'The Modern Mastermind', 1986, 2016, 1, 'Reinvented as a corporate titan in the post-Crisis era, Luthor evolves from mad scientist into a power broker who weaponizes wealth, politics, and intellect against Superman and the League.', '2024-01-01T00:00:00.000Z'),
  ('09e690f1-d615-52c4-b375-f4afccf5e15b', '1f49fb7c-fb73-52ec-8ba2-e5bf8b640f09', 'loki-trickster-era', 'The God of Mischief', 1962, 2011, 1, 'Loki''s long career as Asgard''s trickster and the Marvel Universe''s most consequential schemer, from his earliest clashes with Thor to his grandest plots.', '2024-01-01T00:00:00.000Z'),
  ('9ed478fd-4f06-5234-951b-96dfaac5ad85', '62d3ff58-5877-5948-afd9-512ee5eb96a9', 'drakkon-rising-era', 'Drakkon Rising', 2016, 2019, 1, 'Drakkon emerges from a conquered timeline to wage war across the multiverse, threatening every Ranger reality.', '2024-01-01T00:00:00.000Z'),
  ('f53658f8-7845-54cc-8418-3b807d0adb10', 'a60dcbe3-6f65-5d40-9806-6cb0c90c5c29', 'emperor-of-evil-era', 'Emperor of Evil', 2016, 2018, 1, 'Zedd escalates the war against the Rangers with cold strategy and overwhelming force.', '2024-01-01T00:00:00.000Z'),
  ('ac9da1fb-16a9-51b9-bad1-66a12c7ca76f', 'ad8850b8-8aec-5819-bba1-9a55932f4612', 'lucius-modern-era', 'Lucius in the Modern Era', 1979, 2024, 1, 'Lucius Fox''s role expanded significantly following Morgan Freeman''s portrayal in Christopher Nolan''s trilogy, which reframed him as an active participant in the Batman operation rather than a background character. Subsequent comic runs gave him more agency and occasionally sharper awareness of what his R&D division''s output was actually used for.', '2024-01-01T00:00:00.000Z'),
  ('80fbc311-49ce-55b6-a6f7-60e4e497fa5f', '4cd10521-bed3-5ec1-b7d1-8edc1f5a5d11', 'kingpin-of-crime', 'Kingpin of Crime', 2005, 2013, 1, 'Machine Head consolidates control over organized crime, hiring an army of villains to protect his empire.', '2024-01-01T00:00:00.000Z'),
  ('b8a6ea35-1d1b-5a5b-afb7-4a1dc59d770a', '0882f404-5e91-5e5f-ab13-effa153e4492', 'magneto-brotherhood-era', 'The Brotherhood Years', 1963, 1991, 1, 'Magneto''s early campaigns against humanity defined him as the X-Men''s archenemy and the founder of the Brotherhood of Evil Mutants.', '2024-01-01T00:00:00.000Z'),
  ('4e1978ed-0b8b-51e7-acd2-00f66f12e436', 'e04135bf-0e34-5add-8c14-e9c345b1fae2', 'malebolgia-era', 'The Demon Lord', 1992, 1999, 1, 'Malebolgia rules from the depths of Hell, manipulating Spawn from afar as he builds his army for the final war.', '2024-01-01T00:00:00.000Z'),
  ('e1a17f36-8bf4-5b82-827a-aefeb9230847', 'c87a39f2-008e-57ba-9fa5-e93d2da2d911', 'malekith-dark-elf-schemer', 'The Dark Elf Schemer', 1984, 1985, 1, 'Introduced during the Simonson run, Malekith establishes himself as a uniquely cruel and unpredictable threat from Svartalfheim.', '2024-01-01T00:00:00.000Z'),
  ('56fc5ff4-403d-5ed2-b209-d3b5f03f1dd9', '67852c9d-4ede-5e29-959f-5d58f6dd2255', 'modern-manhunter', 'The Soul of the League', 1988, 2016, 1, 'Across the JLI years and beyond, Martian Manhunter is established as the emotional and institutional anchor of the League, exploring his isolation as Mars''s last son.', '2024-01-01T00:00:00.000Z'),
  ('d0fd4658-6de3-50bf-b9aa-fe34a94142d5', '4621bf98-c20c-5812-ad91-16eff4826513', 'mister-glum-dimensional-schemes', 'Dimensional Schemes', 2000, 2010, 1, 'Mister Glum pursues conquest from another dimension, pulling Dragon into interdimensional battles.', '2024-01-01T00:00:00.000Z'),
  ('b46823ba-6c02-5e85-8b85-8e14939eea55', 'f671ab1f-e733-51ec-818a-82ed22652b8a', 'the-geneticists-shadow', 'The Geneticist''s Shadow', 1987, 2010, 1, 'Introduced as the puppet-master behind the Marauders, Sinister becomes the X-Men''s premier schemer and a recurring thorn in Wolverine''s side.', '2024-01-01T00:00:00.000Z'),
  ('d4bbb402-977e-55d1-a9f4-b6322d43f31e', '6d3b22e4-ecd2-569b-b088-750d3beb5c95', 'monica-personal-stake', 'Personal Stake', 2014, 2015, 1, 'Monica''s connection to the case turns the investigation into something painfully personal.', '2024-01-01T00:00:00.000Z'),
  ('10ab4daf-b8e8-5413-9214-49aad1842536', '56ff7566-933b-58c5-a916-a526373f5076', 'mystique-brotherhood-era', 'The Brotherhood''s Shadow', 1978, 2025, 1, 'As leader of the Brotherhood and a lone operative, Mystique has spent decades infiltrating and undermining her enemies, mutant and human alike.', '2024-01-01T00:00:00.000Z'),
  ('40c57c2e-dcfc-5f49-90de-ab1c4acb3b0d', '0b1f9dae-3b8b-50eb-9e6e-dcf3208d3996', 'nyx-witch-era', 'The Witch''s Path', 2000, 2020, 1, 'Nyx steps into Spawn''s expanded world as a magical ally, lending arcane power to his battles against demonic and divine foes.', '2024-01-01T00:00:00.000Z'),
  ('c8c7ce7c-268d-5de6-93b4-6c14227c937d', '976abf28-99fc-5073-80fc-0b26f69b73d3', 'stane-corporate-war', 'The Corporate War', 1982, 1985, 1, 'Stane wages a calculated psychological and financial campaign to destroy Tony Stark and absorb his empire.', '2024-01-01T00:00:00.000Z'),
  ('4a5d53c3-cad0-5d61-b73e-44e5d33cdf59', '39a095b5-92fa-558e-9fa8-297e694171e5', 'cold-war-weapon', 'Cold War Weapon', 1992, 1995, 1, 'Introduced in the blockbuster Jim Lee era, Omega Red ties Wolverine''s hidden past to a Soviet super-soldier program.', '2024-01-01T00:00:00.000Z'),
  ('023da998-6990-5c3a-a204-dc108fb71a05', '6a03558f-184a-5db6-a341-0c6f4fad2eab', 'earths-protector', 'Earth''s Protector', 2003, 2011, 1, 'Publicly Earth''s greatest hero, Nolan hides a devastating secret about his true purpose before his loyalties are tested by family and empire.', '2024-01-01T00:00:00.000Z'),
  ('00217e5d-f7f6-584e-85a8-3f7e9542e2ab', '3168c6d7-6c83-5cf1-b287-da914c7d1f7c', 'overlord-reign-of-crime', 'Reign of Crime', 1992, 1996, 1, 'Overlord dominates Chicago''s criminal empire and stands as the primary obstacle to Dragon''s mission.', '2024-01-01T00:00:00.000Z'),
  ('aee0f037-b163-5c9c-8cd2-7de62ee9226c', '5ab96773-d320-5296-9110-d63c607a0ee2', 'overtkill-rampage', 'Engineered Killer', 1992, 1996, 1, 'Overtkill cuts a path of destruction across the Image universe.', '2024-01-01T00:00:00.000Z'),
  ('1aac12b8-78ce-558c-a241-522861479bd9', '0592afef-f365-56b1-9f86-5fe1d601e77e', 'parallax-corruption', 'The Corruption of a Hero', 1994, 2005, 1, 'The fear entity''s manipulation of Hal Jordan and its eventual exposure as the true cause of his fall.', '2024-01-01T00:00:00.000Z'),
  ('6d581975-5e68-5009-bb3b-8549efbed89d', 'b23f30f2-61cd-515a-a3e8-f07f14502f2d', 'mighty-morphin-era', 'The Mighty Morphin Era', 2016, 2018, 1, 'BOOM! Studios relaunches the classic team, picking up in the wake of the Green Ranger''s redemption while expanding the mythology of the Morphin Grid. The Rangers confront familiar foes with new gravity and consequence.', '2024-01-01T00:00:00.000Z'),
  ('4603602a-fc7f-597e-89b4-2f4d94692a5e', 'b23f30f2-61cd-515a-a3e8-f07f14502f2d', 'shattered-grid-era', 'The Shattered Grid Era', 2018, 2020, 2, 'A renegade Tommy from an alternate timeline, Lord Drakkon, wages war across every Ranger reality, collapsing the boundaries of the Morphin Grid itself. The flagship crossover event redefines the franchise''s scope.', '2024-01-01T00:00:00.000Z'),
  ('ce166230-6f75-53a9-91d2-60d8e6bf20af', '2691870e-40bb-5f64-880b-9c2f4cfaf09d', 'xavier-dream-era', 'The Dream', 1963, 2025, 1, 'Xavier''s founding vision of coexistence shaped every incarnation of the X-Men, even as his methods and secrets grew more complicated over time.', '2024-01-01T00:00:00.000Z'),
  ('107e3504-62cd-5ccb-bbcf-2e73c17d7de5', '1a61ff3c-d1d1-52b6-beb8-c1dc60642f40', 'ras-introduction-era', 'The Demon''s Head: Introduction and Classic Conflicts', 1971, 1999, 1, 'Denny O''Neil and Neal Adams created Ra''s al Ghul as a deliberate attempt to give Batman an antagonist who operated at a different scale than Gotham''s street criminals. The character''s early appearances established his resources, his global reach, his daughter Talia, and the Lazarus Pit mythology that explains his longevity. Subsequent writers — including O''Neil himself — returned to the character repeatedly, each time deepening the ideological conflict at the center of his relationship with Batman.', '2024-01-01T00:00:00.000Z'),
  ('73ccb839-7b3f-5005-9029-98d706565809', '346596df-b4b3-5cfa-be46-35c6f0951535', 'raven-new-titans', 'Daughter of Trigon', 1980, 1996, 1, 'Raven assembles the New Teen Titans to oppose her demonic father and spends the era wrestling with the darkness she inherited from him.', '2024-01-01T00:00:00.000Z'),
  ('09c20cd2-6f68-5cda-8fe8-eb1ce177e3e8', 'db496c89-2091-5e0e-8859-371dc2cdd7a7', 'red-skull-golden-age', 'Hitler''s Agent', 1941, 1945, 1, 'Introduced as the Third Reich''s master of terror and sabotage, the Red Skull becomes Captain America''s defining wartime adversary.', '2024-01-01T00:00:00.000Z'),
  ('0555d588-f1f7-5e0f-9c13-a0ff765fa134', 'db496c89-2091-5e0e-8859-371dc2cdd7a7', 'red-skull-modern', 'The Eternal Enemy', 2007, 2008, 2, 'Revived in the modern era, the Red Skull orchestrates elaborate conspiracies against Captain America from the shadows.', '2024-01-01T00:00:00.000Z'),
  ('157b51a3-2930-5cfa-a6fd-7b6e9d6f6e19', 'ad0aeda8-5962-52a4-a9c9-4395afe2a044', 'reverse-flash-origins', 'Origins of a Nemesis', 1963, 2011, 1, 'From his Silver Age debut to his time-spanning modern schemes, the Reverse-Flash evolved from a costumed thief into the cosmic architect of Barry Allen''s suffering.', '2024-01-01T00:00:00.000Z'),
  ('8f3722e5-b383-519f-a0a4-44c6c2e0ec1e', '338980ff-b028-502a-aacd-072080eed01c', 'rex-young-gun', 'The Young Gun', 2004, 2018, 1, 'Rex grows from a cocky recruit into a committed hero of the team.', '2024-01-01T00:00:00.000Z'),
  ('09475b21-77ff-50f6-9bf8-be5c133f26fd', '8aa69805-f754-5744-bca1-ded0fc7bbf61', 'ricochet-on-the-move', 'On the Move', 1994, 2005, 1, 'Ricochet builds a reputation as a fast, dependable ally fighting beside Dragon and Barbaric.', '2024-01-01T00:00:00.000Z'),
  ('544b0e47-ff02-52c3-a8ec-b103ec827cb1', '46ce85d8-b615-5195-825a-b79f1d802603', 'witchs-war-era', 'The Witch''s War', 2016, 2018, 1, 'Rita wages a relentless campaign against the Rangers, deploying monsters and manipulation in equal measure.', '2024-01-01T00:00:00.000Z'),
  ('ecd5a88b-453b-50dc-b265-d1412fa02b57', 'ee1e4f5e-6664-5a73-aa9b-e4da8f5771d2', 'robot-architect', 'The Architect', 2004, 2018, 1, 'Robot''s intellect drives the rebuilding of Earth''s defenses, even as his ethics blur.', '2024-01-01T00:00:00.000Z'),
  ('c53e9a3d-e534-58dd-af5e-03a64c957e48', '899505b8-a56a-5ca8-aeca-d8d7a2969cd6', 'rogue-redemption-era', 'From Brotherhood to X-Men', 1981, 2025, 1, 'Rogue''s journey from villain to hero, and her ongoing battle to control her absorbing power, made her a fan favorite across the modern era.', '2024-01-01T00:00:00.000Z'),
  ('70177165-24db-5bb8-bb96-8222b3a90afe', '1a1511e9-19d7-51cf-a5ad-c81d49093aaf', 'giles-awakening', 'The Watcher', 2019, 2021, 1, 'Giles takes up his charge to train Buffy, balancing duty to the Watchers'' Council against genuine care for his Slayer.', '2024-01-01T00:00:00.000Z'),
  ('36318011-d6f6-5429-a884-02e4d3c458d9', 'd3ce5131-893b-5d10-a5e8-5ec39dd0a85a', 'the-savage-rival', 'The Savage Rival', 1977, 2010, 1, 'From a generic martial-arts villain into Wolverine''s defining nemesis, Creed becomes the predator who haunts Logan''s life and memories.', '2024-01-01T00:00:00.000Z'),
  ('637159b1-066b-5568-baff-d39d9fc0764b', '519242ce-776c-5906-b032-8ebc5b4d5614', 'detectives-era', 'The Detectives', 1992, 2004, 1, 'The two detectives work the violent streets where Spawn operates, gradually uncovering the supernatural beneath the city''s crimes.', '2024-01-01T00:00:00.000Z'),
  ('a40aa626-92dd-51da-80a6-3504998b3b03', '7b94e1aa-83f4-508c-a457-770f2588339b', 'sandman-classic', 'The Shifting Menace', 1963, 1967, 1, 'The Sandman establishes himself as one of Spider-Man''s earliest powered foes and a founding threat among his team-up villains.', '2024-01-01T00:00:00.000Z'),
  ('3eb9fa3d-4990-531d-8628-e082370b394e', '4322fa09-0a88-5804-93f9-0fbf9175f54e', 'officer-dragon-era', 'Officer Dragon Era', 1992, 2012, 1, 'The original Dragon emerges with no memory and becomes a Chicago cop, battling the city''s organized superhuman crime and uncovering pieces of his lost origin. This long stretch defines the brutal, soap-operatic, and relentlessly forward-moving tone of the series.', '2024-01-01T00:00:00.000Z'),
  ('b7b10acf-1142-52e4-9419-57246d09b5ef', '4322fa09-0a88-5804-93f9-0fbf9175f54e', 'malcolm-dragon-era', 'Malcolm Dragon Era', 2012, 2024, 2, 'The series passes its lead role to Dragon''s son Malcolm, who inherits his father''s powers and his place in a changed, often hostile world. This era reframes the saga around a younger generation, family life, and a hero trying to do right while the public turns against superhumans.', '2024-01-01T00:00:00.000Z'),
  ('66706863-6afc-5344-9529-2eb2878240d3', '8657ab06-96b9-5dfb-87e2-ad5c9e8e68ce', 'sentinel-modern', 'New Guard', 1995, 2018, 1, 'Sentinel carries the team forward through its modern relaunches.', '2024-01-01T00:00:00.000Z'),
  ('e3de5e5d-0ebb-5f3f-aeeb-f68f22290979', 'b6ee5c85-5da2-5a36-b6ca-e1fd21313c28', 'shaft-foundations', 'Founding Leader', 1992, 1996, 1, 'Shaft anchors the original team as its public face and tactical leader.', '2024-01-01T00:00:00.000Z'),
  ('85b45ee4-1875-581d-a02b-552001d98606', '2a1b8c6d-9df0-53b2-afb7-33330b4bde2c', 'sinestro-renegade', 'The Renegade Lantern', 1961, 2006, 1, 'Sinestro''s transformation from disgraced Lantern to wielder of the yellow ring of fear, the recurring nemesis of Hal Jordan.', '2024-01-01T00:00:00.000Z'),
  ('9f032aab-3ec3-57e1-9d1b-cf64c5c25a99', '2a1b8c6d-9df0-53b2-afb7-33330b4bde2c', 'sinestro-corps', 'The Sinestro Corps', 2007, 2012, 2, 'Sinestro assembles an army of the universe''s most terrifying beings to wage war on the Green Lantern Corps.', '2024-01-01T00:00:00.000Z'),
  ('898fd397-ff64-58e2-aa65-71efcfd5341d', '7c004d0d-1535-57a7-9f09-ef7cf865a072', 'todd-mcfarlane-era', 'The McFarlane Foundations', 1992, 1999, 1, 'Todd McFarlane launches Spawn as a founding Image title, establishing Al Simmons'' Faustian origin and his grim crusade through the back alleys of New York. The early years build the cosmology of Heaven, Hell, and the Hellspawn caught between them.', '2024-01-01T00:00:00.000Z'),
  ('9a7a0aaf-111b-5c36-a1d8-01a4ae123df9', '7c004d0d-1535-57a7-9f09-ef7cf865a072', 'modern-spawn-era', 'The Modern Crusade', 2000, 2024, 2, 'Spawn endures past record-setting issue counts, reinventing himself across new mythologies, new hosts, and a sprawling shared universe. The modern era expands the franchise with team books and a darker, more cosmic reach.', '2024-01-01T00:00:00.000Z'),
  ('c1d5d599-e2a7-5011-b77b-981a914baca5', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', 'silver-age-origins', 'The Silver Age: Birth of a Hero', 1962, 1972, 1, 'Stan Lee and Steve Ditko introduce a radically new kind of superhero: a guilt-ridden teenager whose powers complicate rather than solve his life. These foundational years establish Peter Parker''s supporting cast, his rogues'' gallery, and the moral code that defines him.', '2024-01-01T00:00:00.000Z'),
  ('661f746a-aae7-52e3-b0e5-1d5786f0f8db', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', 'bronze-age-tragedy', 'The Bronze Age: Loss and Legend', 1973, 1986, 2, 'Spider-Man matures into adulthood and college life as the stories grow darker and more emotionally ambitious. This era contains some of the most consequential and shocking moments in the character''s history, redefining what a superhero comic could risk.', '2024-01-01T00:00:00.000Z'),
  ('c6a293ba-eecf-5253-831c-55dfdf3b0b0d', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', 'modern-age-icon', 'The Modern Age: A Hero for Every Reader', 1987, 2018, 3, 'Spider-Man becomes a global multimedia icon while the comics push his world in bold new directions, from career-best character work to reality-spanning epics. This era refreshes his mythology for new generations across film, games, and a revitalized comics line.', '2024-01-01T00:00:00.000Z'),
  ('85c7cad3-6393-5cbc-ac4d-bb09f985930b', 'dbf622dd-5942-599c-be08-5440f5a3f2be', 'spike-awakening', 'Slayer of Slayers', 2019, 2022, 1, 'Spike storms into Sunnydale chasing the thrill of killing a Slayer, his motives and allegiances forever in flux.', '2024-01-01T00:00:00.000Z'),
  ('ad00813d-a631-57fd-ad98-e82efd4a44f2', 'fd108db8-86ea-51c7-a555-0d05ee01eaa5', 'starfire-new-titans', 'The Tamaranean Princess', 1980, 1996, 1, 'Fleeing slavery and her homeworld''s politics, Starfire finds a family among the New Teen Titans and becomes one of their fiercest and most beloved members.', '2024-01-01T00:00:00.000Z'),
  ('54be0603-1b12-5715-a398-7a04c244086b', '4b010e1a-5893-5779-942b-f5c94d6fe793', 'starro-classic', 'The First Conqueror', 1960, 2011, 1, 'Debuting as the threat that united the League, Starro evolves from Silver Age oddity into a genuinely menacing cosmic conqueror whose mind-control spores threaten worlds.', '2024-01-01T00:00:00.000Z'),
  ('8d50337b-b7b1-5ed0-adb2-3ac60897c054', '5fb83c49-8889-5548-9c30-32774f14089f', 'storm-all-new-era', 'Goddess of the Storm', 1975, 1991, 1, 'Recruited in the all-new roster, Storm rose quickly from member to leader, guiding the X-Men through landmark adventures.', '2024-01-01T00:00:00.000Z'),
  ('62e3a93e-d288-5c7a-bac1-9f9f2edf1ea1', '2530b133-d2b6-5355-86bd-7709a4d5d39e', 'golden-age', 'Golden Age (1938-1955)', 1938, 1955, 1, 'The original crusading Superman of the Depression era, a champion of the oppressed who battled crooked landlords and war profiteers as much as costumed villains. These early stories defined the template for every super-hero that followed.', '2024-01-01T00:00:00.000Z'),
  ('b0c6b8fa-9dd2-5114-a7ba-cce35c05c803', '2530b133-d2b6-5355-86bd-7709a4d5d39e', 'silver-bronze-age', 'Silver & Bronze Age (1956-1985)', 1956, 1985, 2, 'An age of cosmic wonder that built out the full Superman mythology: Krypton, the bottle city of Kandor, the Phantom Zone, and a sprawling Superman Family. Writers piled on imaginative concepts before the era closed with a loving send-off to the classic continuity.', '2024-01-01T00:00:00.000Z'),
  ('5dbeaf84-c60a-5e1f-8acf-40699ddc26cc', '2530b133-d2b6-5355-86bd-7709a4d5d39e', 'modern-age', 'Modern Age (1986-2010)', 1986, 2010, 3, 'John Byrne''s post-Crisis reboot streamlined Superman into a more human, contemporary figure, setting the stage for the era''s defining epics. The period delivered the most famous Superman stories of the modern age, from his death to his marriage.', '2024-01-01T00:00:00.000Z'),
  ('601dd245-ac68-56bb-9ceb-01c481135a02', '2530b133-d2b6-5355-86bd-7709a4d5d39e', 'rebirth-era', 'Rebirth & Beyond (2011-Present)', 2011, NULL, 4, 'After the New 52 reboot and the Rebirth initiative, Superman was restored as a married father, redefining the icon through family and legacy. Modern runs explore what it means for the Man of Tomorrow to raise the next generation.', '2024-01-01T00:00:00.000Z'),
  ('0c3019fb-e87a-5484-a824-6f668da71a20', '22bf9525-aa52-53e2-9019-eb5bca2af4d2', 'surtur-herald-of-ragnarok', 'Herald of Ragnarok', 1963, 1985, 1, 'Introduced as a looming doom in the Silver Age, Surtur reaches his fullest realization as the engine of apocalypse in the Simonson era.', '2024-01-01T00:00:00.000Z'),
  ('40ae668c-ff47-58ae-b16e-2a61ceb356b3', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', 'silver-age-origins', 'Silver Age Origins', 1964, 1973, 1, 'The team debuts as a gathering of Justice League sidekicks who realize they work best together. Across early try-out stories and their first ongoing series, Robin, Kid Flash, Aqualad and Wonder Girl establish the Teen Titans as a distinct franchise aimed at younger readers, eventually adding Speedy to the lineup.', '2024-01-01T00:00:00.000Z'),
  ('85b73336-b791-5fec-9761-ec90d238a278', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', 'new-teen-titans', 'The New Teen Titans', 1980, 1996, 2, 'Marv Wolfman and George Perez relaunch the team with a new lineup that becomes one of DC''s best-selling and most acclaimed series. Adding Starfire, Raven and Cyborg to returning members, the era is defined by deep character drama, iconic villains, and landmark storylines that rival the X-Men for soap-operatic ambition.', '2024-01-01T00:00:00.000Z'),
  ('ce70b505-0d74-54b1-9acc-3fb153a3484b', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', 'modern-titans', 'Modern Titans', 2003, 2024, 3, 'A new generation takes the spotlight as Geoff Johns relaunches the team for the 2000s, bridging the original sidekicks with younger heroes. Through the Johns era, the New 52 reboot, and Rebirth, the Teen Titans continually reinvent themselves while honoring their legacy and mentorship themes.', '2024-01-01T00:00:00.000Z'),
  ('ac5a290c-27f5-5b77-9bd2-0c9e0ea64a94', 'f321da7b-48eb-5581-8bcb-fd783155520f', 'terra-titans', 'The Recruit', 1982, 1984, 1, 'Terra joins the New Teen Titans as a powerful young earth-mover, quickly becoming entangled in the events leading to The Judas Contract.', '2024-01-01T00:00:00.000Z'),
  ('1d142ece-5e41-5b79-b686-91ca6d2ba472', '8d91b245-3858-5d29-a38b-d5d88f524623', 'fitzgerald-family-era', 'The Life Left Behind', 1992, 1999, 1, 'Terry represents the normal life Al lost, raising a family while danger from Al''s past circles ever closer.', '2024-01-01T00:00:00.000Z'),
  ('62bb1e4e-0dd5-5640-9214-9303a1b47d9d', '1b08cd24-f7d8-50c9-8aed-bcfd1655a338', 'thanos-cosmic-era', 'The Mad Titan''s Conquests', 1973, 2018, 1, 'Thanos''s evolution from a cosmic schemer into the universe''s preeminent destroyer, defined by his quest for ultimate power and his devotion to Death.', '2024-01-01T00:00:00.000Z'),
  ('d2f41002-86d8-54b5-8f91-daa99c95cb7e', 'cb6f7717-ddd8-5824-b129-8a4fc74cc300', 'anointed-awakening', 'The Prophesied Child', 2019, 2020, 1, 'The Anointed One emerges as a quiet, sinister power among Sunnydale''s vampires, fulfilling an ancient prophecy.', '2024-01-01T00:00:00.000Z'),
  ('9df9b7f3-fdd0-5dce-9f29-78b452e63682', '9c3c540e-398e-55d7-af73-fda8fd38b93f', 'curator-collection-era', 'Keeper of Relics', 1998, 2006, 1, 'The Curator pursues the Witchblade through stealth and schemes, representing the long line of collectors and cultists obsessed with the artifact.', '2024-01-01T00:00:00.000Z'),
  ('b8d1d4c0-9f13-5057-a5c5-7c10829bfa0a', '450f9bd3-dbd8-5444-b88e-732df39fb341', 'disciples-crusade', 'The Crusade', 1992, 1996, 1, 'The Disciples pursue an ideological war against sanctioned heroes.', '2024-01-01T00:00:00.000Z'),
  ('effd5117-5aab-5e66-b7f4-f85ce4f2e08e', '7648e80f-c11b-5c40-abd6-0e19b5d8ed9e', 'the-cult-underground', 'The Underground', 2014, 2019, 1, 'The cult endures through the quiet years, keeping the faith alive until the affliction returns.', '2024-01-01T00:00:00.000Z'),
  ('039a3708-c191-5f27-b7a6-4d1cea847cb5', '7554762e-8839-52ac-b0f4-03e2d44cda89', 'the-outbreak', 'The Outbreak', 2014, 2015, 1, 'The first wave of the Empty Man contagion erupts across America, baffling the FBI and CDC task force assigned to contain it. As the affliction spreads, the line between sickness and worship begins to blur.', '2024-01-01T00:00:00.000Z'),
  ('0d3f7cab-9893-5243-a6ed-dd67a42f3c7d', '7554762e-8839-52ac-b0f4-03e2d44cda89', 'recurrence', 'Recurrence', 2018, 2019, 2, 'Years after the first outbreak was thought contained, the Empty Man returns, spreading further and faster. A new generation of investigators inherits an affliction that may never have truly left.', '2024-01-01T00:00:00.000Z'),
  ('c7a6c9ac-3dec-5ab8-a850-0be02143c1d0', '4714cfea-ef2c-556a-899f-bc09147b519f', 'the-faithful-congregation', 'The Congregation', 2014, 2015, 1, 'The afflicted find one another during the first outbreak and forge a shared faith around the Empty Man.', '2024-01-01T00:00:00.000Z'),
  ('74a375d8-3dbb-5ad0-b410-27d29b9a9c8d', 'ac67cff0-9d3b-5d42-8875-72fb6d8c1e95', 'the-fiend-reign-of-terror', 'Reign of Terror', 1993, 2002, 1, 'The Fiend carves a bloody path through Dragon''s world as a relentless, brutal antagonist.', '2024-01-01T00:00:00.000Z'),
  ('e086e79b-897a-5581-b119-4b2597c9d0b1', '448be678-268c-522f-9477-a07422c30fd0', 'silver-age-dawn', 'The Silver Age Dawn', 1956, 1969, 1, 'Barry Allen''s debut in Showcase #4 ignited the Silver Age of comics, reinventing the Flash for a new generation. These years established his origin, his Rogues, and the multiverse concept that would reshape DC forever.', '2024-01-01T00:00:00.000Z'),
  ('0c576b50-493f-5961-b983-e1b5adf795cf', '448be678-268c-522f-9477-a07422c30fd0', 'crisis-and-rebirth', 'Crisis and Rebirth', 1985, 2008, 2, 'The Flash faced his ultimate sacrifice in Crisis on Infinite Earths, passing the mantle to his protege Wally West for a generation. This era is defined by legacy, loss, and the eventual return of Barry Allen.', '2024-01-01T00:00:00.000Z'),
  ('2e56d52d-4a92-52be-9e6b-75951dfd6f37', '448be678-268c-522f-9477-a07422c30fd0', 'the-modern-speedster', 'The Modern Speedster', 2009, 2024, 3, 'Barry Allen''s resurrection ushered in a new era exploring the Speed Force, the consequences of time travel, and his deeply personal feud with the Reverse-Flash. These stories redefined the Flash for the New 52 and Rebirth generations.', '2024-01-01T00:00:00.000Z'),
  ('4cfe2dc1-dd2f-5041-8252-cea9892f5442', '65cb3481-4f7e-5599-8b71-78e119c216d3', 'immortal-legend', 'The Ageless Warrior', 2004, 2018, 1, 'Centuries of experience make the Immortal a living legend and a cornerstone of Earth''s defense.', '2024-01-01T00:00:00.000Z'),
  ('97f8c627-e3f2-56ac-aa21-d192d65cf4d6', '8162a5f2-092c-55f0-b3c9-fc354fe236cd', 'joker-modern-era', 'The Modern Joker: From Killing Joke to Death of the Family', 1988, 2013, 1, 'Alan Moore''s Killing Joke established the template the character has followed ever since: a villain defined by the argument that Batman''s own morality is indefensible, expressed through violence that functions as performance art. Scott Snyder''s Death of the Family arc updated the concept for a generation raised on extreme horror, giving the Joker a campaign against the Batman family that is as methodical as it is theatrical.', '2024-01-01T00:00:00.000Z'),
  ('8bc89d6b-5673-510b-861f-5ec18df6085b', 'dfc637b9-6e5c-599c-9fe6-b1fe299d1669', 'lizard-league-rise', 'Scales of Crime', 2004, 2018, 1, 'The Lizard League grows into a recurring criminal threat with shifting leadership.', '2024-01-01T00:00:00.000Z'),
  ('6df68075-15b7-52de-813d-875a9952febe', '29db753d-37a2-5ec6-90da-bae6daeed5d4', 'mandarin-silver-age', 'The Ten Rings Rise', 1964, 1970, 1, 'The Mandarin establishes himself as Iron Man''s greatest recurring foe, wielding his alien rings from a fortress in mainland Asia.', '2024-01-01T00:00:00.000Z'),
  ('15230deb-886f-5dbc-8d92-9c2c6031b053', 'ba7706c6-1c90-505f-a393-ee1461db2e96', 'master-awakening', 'The Old One', 2019, 2020, 1, 'The Master orchestrates his rise from beneath Sunnydale, marshaling vampires to free him and end the world.', '2024-01-01T00:00:00.000Z'),
  ('b4117aea-a5be-59a9-ab9d-15831a2c6265', '86a41202-7aff-5ac9-8b83-d2f5d4b54fed', 'double-trouble', 'Double Trouble', 2003, 2014, 1, 'The bickering Mauler Twins pursue power and profit through cloning technology, leaving chaos in their wake.', '2024-01-01T00:00:00.000Z'),
  ('368f05e7-865b-5e42-b6d8-7135bcd5f957', '020a1748-e513-5ace-b1d1-b411c03ff7d1', 'the-hunt', 'The Hunt', 2019, 2021, 1, 'The creature preys on Archer''s Peak''s children until Erica arrives to track and kill it.', '2024-01-01T00:00:00.000Z'),
  ('ad0521de-d32d-5edd-b344-86187a885b54', '2ca0f6bb-d5b2-50c6-81a7-c9beb04d4d7d', 'the-secret-order', 'The Secret Order', 2019, 2024, 1, 'The Order manages the hidden war against monsters through its houses and operatives, balancing containment against the chaos of the hunt.', '2024-01-01T00:00:00.000Z'),
  ('ae4b687a-c4f9-5d3b-b561-c58b956201b6', 'b0977b5f-d359-5193-a417-cd73e680f6dc', 'penguin-modern-operator', 'The Iceberg Lounge Years', 1992, 2024, 1, 'The Penguin''s repositioning as a semi-legitimate criminal businessman — the Iceberg Lounge persona that emerged in the early 1990s — gave the character a specific niche in Gotham''s ecology that made him useful across decades of stories. Rather than a direct physical threat to Batman, Penguin as information merchant and mob facilitator is a resource, an obstacle, and an occasional reluctant asset depending on which way his interests point.', '2024-01-01T00:00:00.000Z'),
  ('e2d75fca-8331-5643-87d7-4368a051fe4f', '2746a6b9-b9dd-5829-a0b1-bb4f656b6d54', 'the-task-force', 'The Task Force', 2014, 2019, 1, 'The task force coordinates the federal response across the first outbreak and the later recurrence.', '2024-01-01T00:00:00.000Z'),
  ('42b5e845-ccae-5ff3-9dd8-7184135aa975', 'f8057d23-7b86-5e3a-ba0d-ad82d360cb6d', 'riddler-modern-era', 'The Riddler in the Modern Era', 1995, 2024, 1, 'The Riddler''s modern treatment has oscillated between his classic puzzle-obsessed persona and more ambitious interpretations that treat his intelligence as a genuine threat rather than a convenient plot device. Matt Reeves'' film version was a significant departure — closer to a methodical serial killer than a flamboyant showman — while Paul Dini''s comics run gave the character his most psychologically coherent period by making him temporarily heroic.', '2024-01-01T00:00:00.000Z'),
  ('f99b9b34-413b-56b6-bd07-339a9449e070', 'b1786fae-ce5d-5cfa-bfea-19b3b6ba84a4', 'white-mask-authority', 'The Seat of Authority', 2021, 2024, 1, 'The role of the white mask atop the House''s hierarchy and the abuses it enables.', '2024-01-01T00:00:00.000Z'),
  ('9b68d673-ee00-5faf-a844-38172880e91b', 'de8ec54e-9f19-561c-bcb0-a114f019363c', 'silver-age-foundations', 'Silver Age Foundations', 1962, 1970, 1, 'Thor debuts in the pages of Journey into Mystery, blending Norse myth with Cold War-era superheroics. Stan Lee and Jack Kirby build out Asgard, Odin, Loki, and the cosmic scope that would define the character for decades.', '2024-01-01T00:00:00.000Z'),
  ('a3692768-881f-5796-94ed-3682b45f3262', 'de8ec54e-9f19-561c-bcb0-a114f019363c', 'kirby-cosmic-epics', 'Kirby''s Cosmic Epics', 1966, 1985, 2, 'Thor''s adventures grow grander in scale, sending the Thunder God against world-ending threats and into the deepest reaches of the cosmos. This era cements Thor as Marvel''s premier mythic-cosmic hero.', '2024-01-01T00:00:00.000Z'),
  ('5a840836-df3d-5b7b-9b60-e1d4ca8e4ebb', 'de8ec54e-9f19-561c-bcb0-a114f019363c', 'simonson-renaissance', 'The Simonson Renaissance', 1983, 1987, 3, 'Writer-artist Walter Simonson takes the reins for a celebrated run that redefines Thor for the modern age. Bold design, mythic grandeur, and unforgettable new threats make it the gold standard for Thor storytelling.', '2024-01-01T00:00:00.000Z'),
  ('654ed024-5b4a-5c27-96d1-58d087e8d2d3', 'de8ec54e-9f19-561c-bcb0-a114f019363c', 'modern-thunder', 'Modern Thunder', 2007, 2025, 4, 'A new generation of creators reinvents Thor for the twenty-first century, from J. Michael Straczynski''s relaunch to Jason Aaron''s sprawling, decade-long epic that redefined the character''s mythology and cast.', '2024-01-01T00:00:00.000Z'),
  ('5d59dc93-47cd-5967-9495-5c48d3137d63', '784afd7e-b4e8-547a-a63d-fdc8fa966fc6', 'green-ranger-era', 'The Green Ranger', 2016, 2017, 1, 'Tommy struggles with the aftermath of being manipulated into fighting his future teammates and races to control a destabilizing Green Ranger power. This era reframes his classic origin with new psychological weight and continuity-spanning stakes.', '2024-01-01T00:00:00.000Z'),
  ('d09eed68-2244-5518-9ce9-cdd45f50b6a7', '784afd7e-b4e8-547a-a63d-fdc8fa966fc6', 'shattered-grid-era', 'Shattered Grid', 2018, 2019, 2, 'Tommy is confronted by a dark version of himself from another timeline whose conquest threatens every Ranger across the multiverse. The era elevates the franchise into a sprawling crossover event and cements Tommy as both hero and cautionary mirror.', '2024-01-01T00:00:00.000Z'),
  ('f433652e-b279-5a6b-8101-b276ce0b4163', '745311fc-5ddc-5bc8-9bc2-1572b83737bb', 'trigon-classic', 'The Demon Father', 1980, 1985, 1, 'Trigon looms over the early New Teen Titans as the cosmic threat that motivated Raven to form the team, eventually launching a full invasion of Earth.', '2024-01-01T00:00:00.000Z'),
  ('76f8164e-8c6a-5626-b290-68ba90380003', '283ec4c4-55b8-513f-942a-81323157794b', 'yellow-ranger-era', 'The Yellow Ranger', 2016, 2018, 1, 'Trini''s discipline and calm under fire establish her as the team''s center of gravity in the fiercest battles.', '2024-01-01T00:00:00.000Z'),
  ('1c408e95-3c55-5100-b50f-5e3191c82a00', '878e378d-03bb-5fd6-ae15-d31fe564261e', 'two-face-long-halloween', 'The Long Halloween and Its Aftermath', 1996, 2000, 1, 'Jeph Loeb and Tim Sale''s Long Halloween and its sequel Dark Victory are the definitive modern Two-Face origin stories, tracing Harvey Dent''s transformation from Batman''s closest institutional ally to his most emotionally painful adversary. The stories are set in an early Gotham that feels more like a crime novel than a superhero comic, with the mob-to-costumed-villain transition as their organizing subject.', '2024-01-01T00:00:00.000Z'),
  ('6dad0055-329a-5a18-8a15-474a69fa21fe', '1f126a7b-ee19-5ae2-bc70-44d7d3b37f64', 'ultron-uprising-era', 'The Machine That Would Not Die', 1968, 2013, 1, 'Ultron''s recurring campaigns against humanity, from his earliest appearances to the line-wide devastation of his most ambitious takeover.', '2024-01-01T00:00:00.000Z'),
  ('7cd11c03-1f6d-56ae-9d50-bcd77ee801df', '84980f5e-ba2b-5111-92d4-0e4628b593c6', 'venom-birth', 'Birth of the Lethal Protector', 1984, 1993, 1, 'The alien costume''s rejection by Spider-Man gives rise to one of Marvel''s most popular characters, first as a nightmare nemesis and then as an antihero in his own right.', '2024-01-01T00:00:00.000Z'),
  ('bd41e909-ec26-5eb3-a9a4-9fdb9d5a2486', '2be580a9-54b0-5f83-b29b-fc7585a8890c', 'violator-era', 'Hell''s Enforcer', 1992, 1999, 1, 'The Violator stalks Spawn from the start, alternately mocking and attacking him as he tries to force Al into Hell''s service.', '2024-01-01T00:00:00.000Z'),
  ('0c780e71-54b8-52ba-8599-c896ba54bd4b', '5d3f7c5e-1e99-5146-97d0-ce7373d1b57f', 'vogue-foundations', 'Spotlight Operative', 1992, 1996, 1, 'Vogue blends model-grade poise with frontline ferocity.', '2024-01-01T00:00:00.000Z'),
  ('1142e63f-5c78-5bc3-8053-238aa4954a33', 'f0271d65-dd6d-55e6-af3c-518db63b89fd', 'whiplash-mercenary-years', 'The Mercenary Years', 1968, 1985, 1, 'Whiplash establishes himself as a recurring armored hireling, frequently in the employ of those seeking to bring down Iron Man.', '2024-01-01T00:00:00.000Z'),
  ('c4b4ba50-01aa-5830-b78a-88365442e3ec', 'e348cdc2-3977-522f-877e-9b4cdecceba9', 'willow-awakening', 'Finding the Magic', 2019, 2021, 1, 'Willow grows from a shy bookworm into a confident practitioner of magic over the course of the relaunch.', '2024-01-01T00:00:00.000Z'),
  ('7274f54f-b49c-5abc-aa3b-e46e08fbb004', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', 'top-cow-classic', 'The Classic Top Cow Era', 1995, 2007, 1, 'Detective Sara Pezzini inherits the Witchblade and is pulled into a hidden world of immortal manipulators, balancing her badge against the artifact''s bloody legacy. The era establishes her rivalry with industrialist Kenneth Irons and his enforcer Ian Nottingham.', '2024-01-01T00:00:00.000Z'),
  ('fa07c4aa-e612-55cd-9593-0f60d17df556', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', 'modern-bearers', 'The Modern Era', 2008, 2015, 2, 'The Witchblade legacy expands as the artifact''s balance with its dark counterpart the Darkness is explored, and the mantle eventually passes to new bearers. Sara''s story matures into one of legacy, sacrifice, and the cost of carrying power for too long.', '2024-01-01T00:00:00.000Z'),
  ('0ee3cb8d-ae9a-5f19-a532-7cf6f9c44ee8', '411d9474-16b6-5c50-a3fa-36f22c778276', 'first-blood-the-bronze-age', 'First Blood: The Bronze Age', 1974, 1985, 1, 'Logan claws his way from a one-off Hulk antagonist into a breakout member of the All-New, All-Different X-Men. This era establishes his costume, his temper, and the first deep explorations of the man behind the mask.', '2024-01-01T00:00:00.000Z'),
  ('ee9da597-3ddc-5e63-8123-70ccc489d501', '411d9474-16b6-5c50-a3fa-36f22c778276', 'weapon-x-and-the-search-for-the-past', 'Weapon X and the Search for the Past', 1986, 2000, 2, 'Logan finally gets his own ongoing series and the horrifying truth of how adamantium was bonded to his bones. This era turns the mystery of his memory into the engine of his greatest stories.', '2024-01-01T00:00:00.000Z'),
  ('f3fd6959-1210-52a9-a697-9a3d36e60bcd', '411d9474-16b6-5c50-a3fa-36f22c778276', 'modern-legend', 'Modern Legend', 2001, 2017, 3, 'Logan''s full origin is finally told, his darkest manipulations come to light, and he faces stories built to give a man who cannot die a definitive ending. This era cements him as a fixture of modern Marvel.', '2024-01-01T00:00:00.000Z'),
  ('089ebbed-a7c6-5b08-88cc-43266352a059', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', 'golden-age', 'Golden Age', 1941, 1955, 1, 'Created by William Moulton Marston and artist Harry G. Peter, Wonder Woman debuts as an Amazon ambassador bringing the wisdom of Athena and the strength of Hercules to a world at war. These foundational tales establish Paradise Island, the Lasso of Truth, and Diana''s secret identity as Diana Prince.', '2024-01-01T00:00:00.000Z'),
  ('9f52d1c3-eedb-56a4-b760-ae4d1f00c9a4', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', 'bronze-age', 'Bronze Age', 1968, 1986, 2, 'Wonder Woman is reimagined for a changing world, first stripped of her powers as a mod martial-arts adventurer, then restored as a full Amazon and embraced as a feminist icon. The era reconnects Diana to her mythological roots and her role within the wider DC Universe.', '2024-01-01T00:00:00.000Z'),
  ('8d1a61e3-c05c-5ce0-9436-66d4efd4b5c9', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', 'modern-age', 'Modern Age', 1987, 2010, 3, 'George Perez''s post-Crisis relaunch rebuilds Wonder Woman from the ground up as a true creature of Greek myth and an emissary of peace. Subsequent acclaimed runs deepen her role as warrior, diplomat, and one of DC''s defining heroes.', '2024-01-01T00:00:00.000Z'),
  ('5154bbfd-db63-5a7f-b400-e09f549c12e5', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', 'new-52-rebirth', 'New 52 and Rebirth', 2011, 2020, 4, 'DC''s line-wide reboot reinvents Diana as a literal daughter of Zeus tangled in the brutal politics of the Olympian gods, before the Rebirth era reckons with which version of her history is true. These runs blend horror, myth, and identity in equal measure.', '2024-01-01T00:00:00.000Z'),
  ('53a7153b-2816-5bfa-9985-448f1f9c90df', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', 'founding-era', 'The Original Five', 1963, 1975, 1, 'Charles Xavier assembles five teenage mutants at his School for Gifted Youngsters, training them as the first X-Men against threats like Magneto and the Sentinels. These early adventures established the team''s core mission and its central conflict between human and mutantkind.', '2024-01-01T00:00:00.000Z'),
  ('7b442e7f-7914-55b2-a4ab-7107300316e4', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', 'all-new-all-different', 'The All-New, All-Different X-Men', 1975, 1991, 2, 'A new international roster led by Cyclops and Storm revitalized the franchise under Chris Claremont, producing landmark sagas that redefined comic storytelling. This era introduced Wolverine to the team and delivered the genre''s most influential epics.', '2024-01-01T00:00:00.000Z'),
  ('a43c24e5-786b-5d95-81b0-b232982fe48a', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', 'modern-era', 'The Modern X-Men', 1991, 2025, 3, 'From the record-breaking relaunch of the 1990s through Grant Morrison''s reinvention and the nation-building Krakoan age, the modern era expanded the X-Men into a global movement. These stories pushed the franchise into bold new political and cosmic territory.', '2024-01-01T00:00:00.000Z'),
  ('b0acb643-0e17-5506-82db-ed1613c9c180', 'f62d2c40-f7ae-51be-87fd-ffab0e0f6237', 'xander-awakening', 'The Heart of the Gang', 2019, 2021, 1, 'Xander earns his place in the fight through sheer loyalty, proving an ordinary person can matter against extraordinary odds.', '2024-01-01T00:00:00.000Z'),
  ('6f043956-7cf4-5c20-b5ad-12798282f0aa', '89b546be-6991-54a1-a207-5fdafbd26ee7', 'image-foundations', 'Image Foundations', 1992, 1996, 1, 'The team debuts as a flagship Image launch, defining the early-90s aesthetic of splashy action and government-backed super-celebrity. Two divisions, home and away, share the spotlight across high-energy adventures.', '2024-01-01T00:00:00.000Z'),
  ('aebcbc8c-14c8-553f-87da-acedf341ef76', '89b546be-6991-54a1-a207-5fdafbd26ee7', 'modern-revivals', 'Modern Revivals', 1998, 2018, 2, 'Across multiple relaunches, the team is reimagined with sharper satire about celebrity, surveillance, and the cost of fame. New creative teams interrogate what it means to be a sanctioned hero in a media-saturated age.', '2024-01-01T00:00:00.000Z'),
  ('00c308ea-1757-5849-af75-2822be00d5fa', '2f4b9d8d-8685-529a-b34d-a2bc3e39ef60', 'black-ranger-era', 'The Black Ranger', 2016, 2018, 1, 'Zack proves that style and substance go hand in hand, becoming the team''s morale and a fierce frontline fighter.', '2024-01-01T00:00:00.000Z'),
  ('d6a9f36a-addb-5525-b809-d8f07b2ba940', '0ff251a9-e3eb-5e72-9be3-ac49ca4e02d0', 'zoom-blitz', 'The Zoom Era', 2003, 2009, 1, 'Born from friendship turned to obsession, Zoom redefined the speedster villain as a force of well-intentioned cruelty bent on making the Flash suffer for his own good.', '2024-01-01T00:00:00.000Z')
insert into arcs ("id", "era_id", "slug", "title", "logline", "summary", "spoiler", "arc_type", "start_year", "end_year", "order_index", "created_at") values
  ('ad1ebfb2-0f5a-5932-a74d-f1b2565cb1c4', '60de4203-9668-53c0-97a0-558a6d871cb5', 'the-bone-orchard', 'The Bone Orchard', 'A House of Slaughter operative is forced to choose between duty and the hunters he once trusted.', 'Aaron operates within the rigid hierarchy of the House of Slaughter, carrying out the Order''s will even as it strains his loyalties. His history with the Slaughter line ties him directly to Erica''s story.
