  ('7094dc63-5ca8-5ef2-bd66-2d08c52f380d', 'b66d0522-cf9a-5374-b62d-5e56a79431eb', 'Wonder Woman: Eyes of the Gorgon', 'trade', 'Wonder Woman (1987) #206-213', 1, 1, NULL, '9781401295189', NULL, '2024-01-01T00:00:00.000Z'),
  ('9ecaf913-239c-5aaf-b0ba-c0cd2002965e', '3a2189ac-d666-5085-8987-a48ee7fc3f22', 'Wonder Woman Vol. 1: Blood', 'trade', 'Wonder Woman (2011) #1-6', 1, 1, NULL, '9781401235628', NULL, '2024-01-01T00:00:00.000Z'),
  ('09e097b5-c42d-57b3-b132-0dfaee89fa0a', '3a2189ac-d666-5085-8987-a48ee7fc3f22', 'Wonder Woman by Brian Azzarello and Cliff Chiang Omnibus', 'omnibus', 'Wonder Woman (2011) #0-35', 2, 2, NULL, '9781401294076', NULL, '2024-01-01T00:00:00.000Z'),
  ('95c173ae-d3e6-513b-94b6-af1d518a2d11', '1e7f1d7d-d2d9-5dfc-a674-62b164ca578c', 'Wonder Woman Vol. 1: The Lies', 'trade', 'Wonder Woman (2016) #1, 3, 5, 7, 9, 11', 1, 1, 'Rebirth alternated The Lies (odd issues) and Year One (even issues) week to week; collected editions separate the two threads.', '9781401267865', NULL, '2024-01-01T00:00:00.000Z'),
  ('60c60f62-6630-5040-add6-3d62f1956d0b', '1e7f1d7d-d2d9-5dfc-a674-62b164ca578c', 'Wonder Woman Vol. 2: Year One', 'trade', 'Wonder Woman (2016) #2, 4, 6, 8, 10, 12', 2, 2, 'Year One is the even-numbered issues; read after or alongside The Lies.', '9781401268787', NULL, '2024-01-01T00:00:00.000Z'),
  ('af396820-08f7-51d6-baa3-5b3eed16df83', '344a1dec-6541-53a4-87f8-816ab2bac326', 'X-Men: Season One', 'hardcover', 'Original Graphic Novel', 1, 1, NULL, NULL, NULL, '2024-01-01T00:00:00.000Z'),
  ('0b1fc242-2b62-512d-9d0d-e433472e3df7', '344a1dec-6541-53a4-87f8-816ab2bac326', 'Marvel Masterworks: The X-Men Vol. 1', 'hardcover', 'The X-Men #1-10', 2, 2, NULL, '9780785191902', NULL, '2024-01-01T00:00:00.000Z'),
  ('ce26519f-73e2-54c4-a54d-cdb45e91b3cb', '4def3c54-6290-5c36-9edb-eee4505d1bed', 'Marvel Masterworks: The X-Men Vol. 2', 'hardcover', 'The X-Men #11-21', 1, 1, NULL, '9780785193418', NULL, '2024-01-01T00:00:00.000Z'),
  ('52251197-e6e7-5ac2-88c9-40f1c34ca3ed', '56151a61-03a6-5319-b40c-a5f5ff677e6b', 'X-Men: The Dark Phoenix Saga', 'trade', 'Uncanny X-Men #129-138', 1, 1, NULL, '9780785164210', NULL, '2024-01-01T00:00:00.000Z'),
  ('56555e14-6cee-5639-b8a1-b5e0a154ecd5', '272b5ace-7eda-5abb-a911-e026541199d7', 'X-Men: Days of Future Past', 'trade', 'Uncanny X-Men #138-143', 1, 1, NULL, '9780785164036', NULL, '2024-01-01T00:00:00.000Z'),
  ('6a1745d9-0207-51d9-86b6-ac825955f021', 'c443e1bf-0bc3-5b1a-82f8-cf4e5fc177c3', 'X-Men: God Loves, Man Kills', 'trade', 'Marvel Graphic Novel #5', 1, 1, NULL, '9780785156017', NULL, '2024-01-01T00:00:00.000Z'),
  ('0e944453-0213-54cb-997f-fcf87d363fb8', '7ac5eff3-e9fb-5459-b6e7-6a8811dc204d', 'X-Men: Fatal Attractions', 'trade', 'X-Factor #92, X-Force #25, Uncanny X-Men #304, X-Men #25, Wolverine #75, Excalibur #71', 1, 1, NULL, '9780785156628', NULL, '2024-01-01T00:00:00.000Z'),
  ('29ef6cad-b574-55e4-9e50-80bc7007bfc1', '348fa5db-1e6a-5133-bff8-05fb2d55bec7', 'New X-Men by Grant Morrison Omnibus', 'omnibus', 'New X-Men #114-154', 1, 1, NULL, '9780785158837', NULL, '2024-01-01T00:00:00.000Z'),
  ('8bb02631-2c2a-5455-a418-1018bba6bfdd', 'd02eabd8-8c07-59d7-88dd-73608ed2989c', 'House of X / Powers of X', 'hardcover', 'House of X #1-6, Powers of X #1-6', 1, 1, NULL, '9781302915711', NULL, '2024-01-01T00:00:00.000Z'),
  ('01f6e1f2-6a8a-52cf-ac7e-b1460b59da7a', '57516ddd-0fb9-5bf5-b273-f17f7448cded', 'Buffy the Vampire Slayer Vol. 1: High School Is Hell', 'trade', '#1-4', 1, 1, NULL, NULL, NULL, '2024-01-01T00:00:00.000Z'),
  ('24d1f72c-99fc-5718-af25-ddd5f425ae38', '9d04df0e-afd2-59b2-894d-7c174b40f87c', 'Youngblood #1-5', 'single_issues', '#1-5', 1, 1, NULL, NULL, NULL, '2024-01-01T00:00:00.000Z'),
  ('62e55e72-bb34-5f89-838a-d870f97ab35b', '0d37922c-cc05-5024-a188-f951719a141f', 'Youngblood #6-8', 'single_issues', '#6-8', 1, 1, NULL, NULL, NULL, '2024-01-01T00:00:00.000Z'),
  ('ddd2cc30-3597-5731-b1a3-7ec2eb01226e', '4bf7da1e-cc26-5d4c-9e3a-a74ccc82ee6e', 'Youngblood: Judgment Day Tie-Ins', 'trade', NULL, 1, 1, NULL, NULL, NULL, '2024-01-01T00:00:00.000Z'),
  ('c5398a36-3039-5d63-b511-fa042e7fa141', '43e3a1ac-d3f9-5dfc-b246-11da0c9f6949', 'Youngblood: Reborn', 'trade', '#1-6', 1, 1, NULL, NULL, NULL, '2024-01-01T00:00:00.000Z'),
  ('2b56c285-84c8-5d10-85ca-34b103c31b5d', 'aef667a3-4d4e-5873-807e-6d806682e66b', 'Mighty Morphin Power Rangers Vol. 2', 'trade', '#5-8', 1, 1, NULL, NULL, NULL, '2024-01-01T00:00:00.000Z'),
  ('4f69539c-cce1-5345-8376-ac0af4edebf0', '83e63e73-465a-5256-99a5-d58c4790d919', 'The Flash by Geoff Johns Book Five', 'trade', 'The Flash #192-200', 1, 1, NULL, '9781401294519', NULL, '2024-01-01T00:00:00.000Z')
insert into start_here ("id", "entity_id", "arc_id", "order_index", "label", "reason") values
  ('859790b2-dbf2-55f7-ae9f-77bc16503327', '5077371b-ec42-5e42-978e-c7d720a6ff1c', 'ad1ebfb2-0f5a-5932-a74d-f1b2565cb1c4', 1, 'Absolute Beginner', 'This arc introduces Aaron and the inner workings of the House of Slaughter.'),
  ('4bc0c427-9323-525a-a9c6-bc4a836cfd31', '8239a78a-c7f8-54b8-b823-3a0387f9ccf7', '34281266-a9f3-58f3-8d84-59523b03be1a', 1, 'Absolute Beginner', 'Follow the lead investigator from the very first case file.'),
  ('d3d742fd-60b1-5ba2-a378-2e5503b29821', 'ffac191d-640b-59b0-9a6c-2c3d9aeeb98d', '682b0d0f-5a7f-5579-bb38-3e8bd16a80e3', 1, 'Absolute Beginner', 'Watch a methodical investigator confront a case that breaks the rules.'),
  ('705d8be8-7725-50ba-bb37-e588e73b03ec', 'b5249e33-edfa-5bc1-aaa2-b03e5a4453fe', '7e9d873a-1e4c-5ed5-81e2-d5736bd93e88', 1, 'Modern Era', 'The Hellmouth crossover showcases Angel''s uneasy alliance with Buffy at full scale.'),
  ('751f5a8a-1542-5d7c-b6cd-4dc7ef1bf0d7', 'e1d3db22-d396-5b47-a3eb-2fd70f4e8d48', '9c7da77e-ea7f-509c-8e99-fb59f199e14e', 1, 'Classic Fan', 'This arc introduces the Redeemer as Heaven''s weapon against Spawn.'),
  ('aa155f79-5351-51f6-837a-d43c33173f62', '92c2c3fd-aea6-57ab-bfc3-0d4d5af52bfd', '060cdb7b-2e3a-5bd8-932b-b4f66037caef', 1, 'See his world made real', 'Age of Apocalypse shows exactly what a world ruled by En Sabah Nur looks like.'),
  ('39ab18c7-58e6-54c5-8faf-04c65db2626b', '36642001-e8a9-5065-87f9-0502cf4edac5', 'd4071e73-6925-5667-a6d4-9864a64ab093', 1, 'Dive into the modern Aquaman', '''The Trench'' is the best modern starting point, reestablishing Aquaman as a powerful, respected hero.'),
  ('e3150ca6-b928-5e8d-9e4f-07a01a81f2e6', 'd679bf65-5e35-5ddb-94fb-c5446bf4e277', 'b2768984-eab2-5049-9f4a-796f21f1e886', 1, 'Best Introduction', 'Ares''s defining modern appearance is the central threat of George Perez''s Gods and Mortals, where his philosophy of war is set against Diana''s mission of peace.'),
  ('3cfd7de9-ce06-5123-8e75-91c516fe25ff', 'c31f6730-0efb-548f-9c3c-c8c04aed7c04', 'be7c8379-46cc-599e-a098-9de80d79a14c', 1, 'Start Here', 'Castaway in Dimension Z is Zola''s most ambitious scheme and a bold modern showcase for the character.'),
  ('e829ae78-329e-5235-899b-8e5b11c6b8d0', '1d2e2e20-67a0-5ff6-b32e-f27309a51253', '22c5cfde-0d38-5819-8dba-d81e7d36d362', 1, 'Absolute Beginner', 'See Eve discover the scale of her power from the very start.'),
  ('b9fe17c2-8c68-5e19-812c-69f67174dc3d', '77db7ea3-8ed7-5273-add1-d93259b39938', '91559069-37dd-5ec8-9d21-6f9bd88f8a12', 1, 'Best Introduction', 'Rage of the Red Lanterns introduces Atrocitus, his tragic origin, and the rage-powered Corps he commands.'),
  ('80548138-f727-527e-8239-7d6d29f0896f', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'bbf9d715-3c0f-5f09-b0ce-98b840cae269', 1, 'Start with the origin', 'The team''s founding issue is the definitive starting point, establishing the lineup, the name, and the revolving-door dynamic that defines them.'),
  ('512c36e3-3e0b-51ba-b5bb-6e85583b816a', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', '03b8190d-f1a5-522f-9d94-a9de6255ad1a', 2, 'The modern jumping-on point', 'If you prefer a contemporary tone close to the films, ''Breakout'' relaunches the team with an accessible mystery and a star-studded roster.'),
  ('8fbd77f5-8206-5ffa-8375-a9b549394408', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', '9a1ec13a-d339-5725-9571-f6fe715a9153', 3, 'Experience a classic epic', 'The Kree-Skrull War shows the Avengers at their most ambitious, a cosmic benchmark that proves the team can carry universe-spanning stakes.'),
  ('cbe8e740-9d26-57ec-8ca1-952904c6ca97', '948cf5fe-fe35-5e34-9f70-089f1b266b31', '0bd1679e-d087-57a9-8721-b55a93e7313b', 1, 'Absolute Beginner', 'See the team''s powerhouse find his footing.'),
  ('1f18f1a1-4193-59de-bb19-49f4bcde02c7', '6307652f-ef23-59c7-bf66-eb6ce5ed6e9c', '4be84c6f-0211-5ab3-bc7d-20bf38313f37', 1, 'Best Introduction', 'Batman: Vengeance of Bane #1 followed immediately by Knightfall Vol. 1 is the complete Bane introduction — the one-shot establishes the character, the event delivers his plan.'),
  ('a1b5cbe4-776c-5117-b3f7-5e904a3d034c', '6e0c7dd7-5e7a-5e9b-9a74-1424a8db9121', '64e73110-1b56-5efe-906f-7958deedce26', 1, 'Best Introduction', 'Birds of Prey: Of Like Minds is where Oracle is most fully herself — a leader, strategist, and character defined by what she can do rather than what was done to her.'),
  ('24f8822e-f81f-561b-898d-7c2112c68ab8', 'd95c67d0-9578-5ab8-8ec3-cd61bef7c92f', '5182edc0-70f1-56a9-b442-06515371e3bc', 1, 'Start Here', 'Under Siege showcases Helmut Zemo at his most dangerous in a definitive Avengers epic.'),
  ('bb003cc6-2c6f-5815-b013-985faacfd377', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'dfe567e0-2799-59a5-9952-ff567bdf2366', 1, 'Absolute Beginner', 'Batman: Year One is the definitive origin retelling — lean, novelistic, and completely self-contained. Frank Miller and David Mazzucchelli''s 1987 story works for anyone who has never read a Batman comic and rewards longtime fans equally.'),
  ('db7cc12a-f8df-56d6-8939-c9d9a9eaab60', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'd0535082-b961-54a7-ac6e-28534146cf02', 2, 'Modern Era', 'The Court of Owls introduces a genuinely new mythology around a character who has had everything done to him. Scott Snyder and Greg Capullo''s New 52 run is the best sustained modern Batman work and this is where it starts.'),
  ('0201281e-7c70-57a6-b8e2-8558a35a439d', '46a5721c-458f-5262-b06c-881e6b7f98bc', '1b11ea26-5a42-585d-9ea8-339d0cd4a233', 3, 'Classic Fan', 'Knightfall remains the most audacious ''break the hero'' story in superhero history — it follows through on its premise completely, and the consequences reshape the Batman mythology for a decade. Required reading for anyone who thinks they know how far the character can be pushed.'),
  ('f6eab728-3b08-55d8-b84e-879655b6788e', '8e1ef9a0-54ee-5617-9109-d7b2c965a107', 'a1c1be97-62d2-5626-a00d-a57732a4cb35', 1, 'Absolute Beginner', 'Mind Over Might highlights Billy''s intellect as the team''s secret weapon.'),
  ('49a6568f-b0d5-5159-a129-9cbca80218a8', '0a680e29-e289-5b76-ad11-9ae6b24f0542', '5e02cabc-f8e5-58c1-9279-9e13fc0c634b', 1, 'A grounded spy thriller', '''The Name of the Rose'' showcases Natasha as a solo lead in an espionage story true to her roots.'),
  ('b230055e-3681-5f57-9ec0-8ac61f2fca30', 'bc3388da-87e3-5978-bd9a-c1c8218aad6f', '9d9267b5-91a9-596d-8eec-1d046c5efd31', 1, 'Absolute Beginner', 'Meet the preacher who turns the affliction into a religion.'),
  ('dbb3a45f-df5c-574a-a907-e13afd267918', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', 'de6f02aa-1d89-5a51-8b75-9d4523a1f41f', 1, 'Absolute Beginner', 'The origin arc reintroduces Buffy, the Hellmouth, and the Scooby Gang with no prior knowledge required.'),
  ('d891db7a-f179-5c12-b2fe-12120979b25a', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', '57ed0377-4f4b-5a28-b850-eb0fd36513a2', 2, 'Classic Fan', 'An ancient-vampire threat captures the original show''s monster-of-the-week-to-apocalypse rhythm fans love.'),
  ('b2aafe28-c59d-5c37-8306-352ec18f8897', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', '87b6fa94-6940-5888-a0d4-2ae4f7a3ff42', 3, 'Modern Era', 'The Hellmouth crossover shows the relaunch at its most ambitious, weaving the whole BOOM! Buffyverse together.'),
  ('0d146c4f-f2ad-5f00-b820-bc391bdbf20f', 'f0f9597b-2580-532b-9882-2aefcd510a65', '49ee1495-beac-5e52-9195-cb85d902db52', 1, 'Absolute Beginner', 'Start at the very beginning with Cap''s origin story, a clean entry point that needs no prior knowledge and establishes everything the character stands for.'),
  ('ed9ca159-4cc9-5250-a7cc-fa606854241c', 'f0f9597b-2580-532b-9882-2aefcd510a65', '2ed04474-2a58-5964-a4e9-00d76344e51c', 2, 'Classic Fan', 'The Secret Empire is the Bronze Age peak that defines Cap''s relationship with his country and shows the depth beneath the star-spangled costume.'),
  ('dd8ba777-24c3-59ec-ab20-f648af16615b', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'eca8b16c-99cb-5558-bba9-d2c82874697b', 3, 'Modern Era', 'Ed Brubaker''s The Winter Soldier is the definitive modern Captain America story and the basis for the acclaimed film, blending espionage, emotion, and action.'),
  ('737c5769-17d7-56fa-9c01-4d39cb5e3ca3', '3e12c541-fd4c-54c0-ad44-ceda960d5635', 'f36da3a3-ea0c-5f76-bdd2-c654f463fcdf', 1, 'Best Introduction', 'Selina''s Big Score is a clean, beautifully drawn standalone heist story that establishes exactly who Selina Kyle is when she''s the protagonist of her own story rather than a supporting figure in Batman''s.'),
  ('367fe63d-d278-5687-9fee-28b2f8492399', '14696e46-299e-58f0-801d-c8e2df42ef87', '157846be-fc83-5a2f-8011-8c2e3e229ebf', 1, 'Best Introduction', 'Greg Rucka''s Year One portrays Barbara Ann Minerva as a friend before her tragic transformation, giving the Cheetah''s villainy real emotional weight.'),
  ('7d568b72-ff53-54c8-b97e-c499f390298c', 'c54a55aa-319d-57b6-9a52-dbe35d255a81', 'cbf18df8-5c13-5c12-9689-8f595b84efe0', 1, 'Absolute Beginner', 'Cogliostro''s first guidance of Spawn is the clearest introduction to his role.'),
  ('b580db96-8452-580f-87db-84e32fb0deef', 'be70c828-5b8f-5431-a529-20b5ca4371ef', 'ba28d1da-18ae-56a0-8f2f-8bcca6905030', 1, 'Meet the first X-Man', 'These early issues show Cyclops becoming the leader who defines the team.'),
  ('9d817b69-ab77-5ef9-8f2f-d3dc688ac95a', 'f878ca08-45b4-5eff-8cc1-617cabb5c42b', '5c624f84-0540-58fc-8caa-51c313dd0e35', 1, 'Begin with Kirby''s epic', 'The Fourth World saga is the definitive introduction to Darkseid and his cosmic war.'),
  ('d1751626-0649-5ec5-a767-5fef96bc044e', 'ef33d492-4f93-52fc-bfe8-b86b454eb253', 'dcff3470-129e-565f-ad66-952219ebf010', 1, 'Best Introduction', 'Nightwing: Year One bridges the Robin and Nightwing identities cleanly and works as a standalone entry for readers unfamiliar with the character''s full history.'),
  ('b2fbdbd2-d8aa-50cf-b0ed-11a89a194865', '9b5ba614-a266-558f-aa96-db377463623e', 'b79920b3-bd3f-5cea-b85c-f52af0c4217b', 1, 'Absolute Beginner', 'See what total devotion to the affliction looks like.'),
  ('09f5530e-cc3b-52e9-8642-8e339e85e288', '73c0cf5c-4285-555b-9528-9baef6ff50ad', 'f85d2ff3-45b4-55c9-8e3d-7f1720b9dd79', 1, 'Classic Fan', 'Meet the villain who first made Spider-Man doubt himself and became his ultimate intellectual rival.'),
  ('ff3573c6-a8ba-53a1-b6b2-5cdf56f9b619', '46646717-ad59-58fe-b11c-5a2c94afdca4', 'a78c5367-9184-582e-8b56-460476835ad7', 1, 'Defining Story', 'The Death of Superman is the only story you need to understand Doomsday: the unstoppable monster''s sole purpose is to be the threat Superman cannot survive.'),
  ('22ac175d-9328-5069-b2d0-28a372f645fb', '7786b507-312a-539d-8a23-29295e4b1a30', '7696a454-d1e2-50f0-84d7-65da596ab8f5', 1, 'Absolute Beginner', 'The origin arc introduces Erica, the monsters, and the central premise with no prior knowledge required.'),
  ('28cc6a87-861c-51b2-bdf0-3b282caf0240', '7786b507-312a-539d-8a23-29295e4b1a30', '1e6d70e2-cdaf-550a-a6d1-3d8b221fd372', 2, 'Classic Fan', 'Watch the secret order descend on Archer''s Peak as the world''s mythology snaps into focus.'),
  ('28acc359-55ac-5cf6-8273-665b9e7989af', '7786b507-312a-539d-8a23-29295e4b1a30', '5e6db018-af74-5592-a48a-773d495d469b', 3, 'Modern Era', 'Follow Erica as a fugitive hunter confronting the family and institution that made her.'),
  ('4369d851-7405-5acd-9b44-7d3eccca60c6', '958eb5e9-3e62-5425-a491-e9291563bffd', '96c2b072-50fb-5d8b-8b34-ba3beba78f61', 1, 'Defining Story', 'New Krypton elevates Zod from a Phantom Zone escapee into the commanding leader of a Kryptonian nation, the fullest modern expression of his threat to Superman.'),
  ('ebb4eb28-ae4f-50c7-a65a-c3538b7ba35a', '587462a9-16e0-57f3-a1a6-84b0ce8c7f74', '7c819388-6183-58d8-aa22-a54b313fc016', 1, 'Start with the defining miniseries', '''The Longbow Hunters'' is the essential modern reinvention of Green Arrow.'),
  ('d8eb6ff2-afe0-5d5b-bb24-22ed8267f9d1', '2bf45ce8-3c51-51de-8b48-94d766ee72dd', '998e0f67-2589-571d-b0a9-5bcce8b72658', 1, 'Classic Fan', 'See the Green Goblin evolve from a costumed mystery into Spider-Man''s ultimate personal enemy.'),
  ('dd803951-6b5e-57b6-8b2a-5b34438fff7e', 'a8434c59-8838-500a-a059-d60b3b33a59e', '4bd790e4-7778-596c-9693-a24ff4f1ec76', 1, 'Absolute Beginner', 'Green Lantern: Rebirth is the cleanest modern entry point. It re-establishes who Hal Jordan is, explains his fall and return in one self-contained story, and requires no prior reading.'),
  ('317714e0-29d0-5b73-9040-ef485598f29e', 'a8434c59-8838-500a-a059-d60b3b33a59e', '6a7ddaa7-d3d9-5357-9f2c-1191120ef874', 2, 'Classic Fan', 'Hard-Traveling Heroes is the most acclaimed Silver/Bronze Age run, pairing Hal with Green Arrow for socially conscious adventures that defined the character''s depth.'),
  ('e8ae73de-150c-5197-bb4c-a76ce9e52b8e', 'a8434c59-8838-500a-a059-d60b3b33a59e', '66acb8b9-5f3f-5e92-ad9c-c8663edea4e9', 3, 'Modern Era', 'The Sinestro Corps War is the definitive modern epic, showcasing the full Corps mythology and Hal''s leadership against his archenemy on a cosmic scale.'),
  ('7d3485d0-1a37-5d79-9c04-d8fbec0726c5', '7a66364d-547b-54c4-948e-de4f1d756d38', '19a2b15b-477e-5464-9f03-97432e52b00f', 1, 'Absolute Beginner', 'Start where the team is introduced as the world''s trusted protectors, before everything changes.'),
  ('7e6c2922-1d2d-5688-8ab9-d8f669473c8f', '7a66364d-547b-54c4-948e-de4f1d756d38', '59ac8452-ac46-5f18-8baa-043b7aff6177', 2, 'Classic Fan', 'The pivotal fall that redefined the entire series and the team''s place in it.'),
  ('878f230f-bc06-59a0-997b-33ecfaf74a9a', '7a66364d-547b-54c4-948e-de4f1d756d38', '995b4bfd-5d7c-57dc-b2d4-a4907c774c79', 3, 'Modern Era', 'Follow the expanded successor team as a true global institution.'),
  ('7f03dd4e-bd93-5476-a175-3e4cb7160da9', 'a16e772f-3014-5979-a4f7-94e95fa78e9c', '283ef007-6e28-59b0-9a98-289584395d65', 1, 'The acclaimed solo run', '''My Life as a Weapon'' is a beloved, accessible introduction to Hawkeye as a grounded everyman hero.'),
  ('7d42413e-d1a1-5191-b381-d2f642bdc5d2', 'c97ff53b-f9dd-5c73-a8c2-fe3b40b6353c', '63549718-de21-561e-b571-062519e6c522', 1, 'Best Introduction', 'Showcase Presents collects Hammond''s origin and earliest clashes with Hal Jordan, the foundation of the character.'),
  ('d2c5c812-3c2d-52c0-8767-20c8bdd05794', 'a1645541-25a2-527e-93d9-b087dbf5890a', '13f3cdf5-8701-57a0-b343-4615ec231de7', 1, 'Classic Fan', 'The Curse of Hela captures the death goddess at her most malevolent during the celebrated Simonson era.'),
  ('95ed6f9c-99d9-547f-b673-62a5a2cdf0d2', '0ce552c3-1204-54bd-805c-27a3e9153de6', '420f8772-3694-5e2f-9e19-399bef5fc0fb', 1, 'Absolute Beginner', 'The origin arc introduces the House, its masks, and the bond between Aaron and Erica with no prior reading required.'),
  ('dbb5467e-b6c3-585b-9d20-f45b9482db11', '0ce552c3-1204-54bd-805c-27a3e9153de6', '83ffde42-e1ea-53a5-a403-950c37194265', 2, 'Classic Fan', 'Readers who know the order''s surface should dig into how the mask hierarchy actually governs every hunter.'),
  ('826ca264-4b8e-57ab-a656-ec72c7321b16', '0ce552c3-1204-54bd-805c-27a3e9153de6', 'cdf64ee1-8b06-5842-901e-3ca8ebc76a27', 3, 'Modern Era', 'The most recent saga exposes the founding bloodlines'' secrets and the war brewing inside the House.'),
  ('cf2e6e5e-0278-5b9e-8f4b-6f595d3b2c19', '9d16c1a7-8edc-51c7-8a4d-00f28e78ab0a', '847f71b9-c137-5dc6-8836-926252b4e20a', 1, 'A modern classic', '''Planet Hulk'' reinvents the character with an epic, accessible standalone saga.'),
  ('a38a4c95-c775-5be1-8593-1699c1dde785', '61fa87f0-8567-588c-a50f-30857c065c7b', '3e824301-2d40-50e7-9e35-acfd0b54a8f9', 1, 'Classic Fan', 'Nottingham''s conflicted bond with Sara is one of the most compelling threads of the classic run.'),
  ('cbd69160-2d56-50b3-907c-9b60112b57d1', 'ddc90de2-8e7d-5dd1-bde9-72646019ee2b', '4337f2e5-2e0d-5a7f-80e5-a74ebebf8049', 1, 'Absolute Beginner', 'Start at the very beginning to meet Mark, see how he gains his powers, and experience the series'' tonal twist firsthand.'),
  ('e41d42a8-fcf6-5e3e-8a08-52751c06e145', 'ddc90de2-8e7d-5dd1-bde9-72646019ee2b', '5bb56784-65b1-5204-8e6b-dabc8832009d', 2, 'Classic Fan', 'The series'' defining emotional gut-punch and the moment Invincible truly becomes essential reading.'),
  ('dce810fc-abc1-5b52-8ee9-f88bd642718e', 'ddc90de2-8e7d-5dd1-bde9-72646019ee2b', 'f0db4bac-eaa3-50c8-8034-d45b1df3416b', 3, 'Modern Era', 'Jump into the galaxy-spanning conflict that pays off years of buildup and shows Invincible at his most heroic.'),
  ('45c1c606-57de-5358-bab2-a606f2da0fe0', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', '1436a5e6-91e0-5b98-8b9e-09cbc700380f', 1, 'Absolute Beginner', 'Extremis is the cleanest modern jumping-on point, a self-contained arc that retells the origin and defines the version of Iron Man most readers know from film.'),
  ('ebe76006-9038-5048-994f-aa84d9234f87', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', 'd9d0498b-0360-5e16-9250-a0ee52c48aaf', 2, 'Classic Fan', 'Demon in a Bottle is the definitive character-defining story, a landmark of mature superhero storytelling that captures Tony Stark at his most human.'),
  ('17cee8f7-2511-527b-a479-f19282e66d0c', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', '6674c1e3-de2f-5e92-9ca5-19ea1e19a6b4', 3, 'Modern Era', 'The Five Nightmares launches the acclaimed Invincible Iron Man run, pitting Tony against a next-generation threat with high stakes and contemporary themes.'),
  ('c37da792-bfb7-5deb-b037-b052f91b37e1', 'bffd2788-f7ee-5c11-98b0-47612d6a468b', 'f87d75cc-7fb9-502f-b167-0831789d1401', 1, 'Classic Fan', 'Jackie''s debut introduces the Darkness and the dual-force mythology central to Sara''s wider story.'),
  ('2879a062-45ec-55b2-9112-8926a52b2096', '2939c01b-6e85-5e58-b250-e29d6afb5b8d', '610926df-8c39-595f-abc3-c98c4adc9068', 1, 'Absolute Beginner', 'Jake''s introduction coincides with the start of Sara''s journey, making it the natural place to meet him.'),
  ('48b513d9-587b-545e-b580-a75f734bfde1', 'baad7ecb-7d52-5a70-b832-c4b4732b363a', '013d902a-ccf2-5d0e-bab2-3f1e0cbf37cf', 1, 'Absolute Beginner', 'James''s introduction is the reader''s entry point into the horror of Archer''s Peak.'),
  ('edf8d0ea-9e34-574b-8d23-946974cb85bb', '16c71808-cd7a-588a-8f41-653051d42c23', 'fdff9bfc-fbc2-5a27-b5ef-90518e549553', 1, 'Best Introduction', 'Batman: Year One is as much Gordon''s story as Bruce''s — the best single place to understand what makes him essential to the mythology.'),
  ('e04400f0-5862-5274-a037-74c9639f4423', 'dcc0b1e2-6bc8-506d-8d00-599cb1e9383b', 'd57b0e6d-13a2-5724-b85d-bba42aaaa06e', 1, 'Absolute Beginner', 'Burden of Command introduces Jason''s leadership and the trust that binds the team.'),
  ('edcb39f1-ea0c-5221-bd5c-771d59440d18', '9332422c-3ea9-54d6-8e3f-305a4b2d0f0c', 'a7db8055-2583-5257-a5d4-08548080b8c2', 1, 'Absolute Beginner', 'This arc reveals Wynn''s betrayal at the root of Al Simmons'' death.'),
  ('8a302fef-8234-50ab-9ff6-4149eb3af697', 'f743dec3-c799-5685-82f8-db313aa431b8', 'acbbcc73-3fd8-5725-b942-c067364753df', 1, 'The heart of the X-Men', 'Jean''s bond with the Phoenix drives the franchise''s most iconic saga.'),
  ('fa7bb2f8-44a1-5f44-b2b0-4cb30d6896d1', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'a09159f7-03ef-5f75-b112-906dce676a89', 1, 'Start with the modern origin', 'The New 52''s ''Origin'' is the most accessible entry point, retelling how the team forms against a planetary invasion with the contemporary lineup most new readers recognize.'),
  ('ca0ac207-5abd-50ad-9b72-cdd117f3918b', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'c47093a0-8a8b-5085-997c-6dc9c35d10f2', 2, 'Then read the definitive Big Seven', 'Grant Morrison''s ''New World Order'' restores the iconic seven-member League to mythic scale and is widely considered the best modern run to read next.'),
  ('d78f5d3d-a2a0-5a1c-8b2f-3541ebf0b006', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', '8a36c5af-0f3f-51b1-b941-b5f9d25acff9', 3, 'Go back to where it all began', 'The original ''Starro the Conqueror'' is the team''s very first adventure, showing the founding premise in its purest Silver Age form.'),
  ('ca0b1a24-95b4-5ff9-9b7f-dd9582e65502', '74817bfe-b087-5d7b-83ac-2aea450e5656', 'c1bc9f84-8586-575d-bedf-a23d7a39c5cd', 1, 'The ultimate Kang epic', '''The Kang Dynasty'' shows the conqueror at the height of his power and is the definitive showcase of his threat.'),
  ('3a364090-20c7-5bd2-b1b6-4e1f00fbab25', '62974dbb-5bfc-5c10-a11a-ffecb2d03a80', '703ef059-c2a2-5cc8-b995-b59c4cccbd37', 1, 'Classic Fan', 'Irons'' machinations define the classic run, and this arc captures his obsession at full force.'),
  ('cc13dab5-601a-5266-a6c8-fbdd29549ae7', '9677b8cd-620c-5f15-815b-bc307efe9501', '3a7c6ce9-b572-532f-9b7a-dd7152493d7e', 1, 'Absolute Beginner', 'Heart of the Team showcases Kimberly''s compassion and its strategic value to the Rangers.'),
  ('62a53931-b88f-58b0-a746-02950e5f93e8', '1f49fb7c-fb73-52ec-8ba2-e5bf8b640f09', '7a026209-5355-5b4b-bf23-92917ed0a4cd', 1, 'See the schemer at work', '''Siege'' showcases Loki''s long-game manipulation paying off on a universe-altering scale.'),
  ('d2be85ce-1781-5683-9be6-9712eb6a77d9', '62d3ff58-5877-5948-afd9-512ee5eb96a9', '09a3a650-a0c5-5e2d-9d94-33ffb947d8b3', 1, 'Modern Era', 'Meet Tommy''s dark counterpart, the breakout villain of the modern comic line.'),
  ('def568c0-d7af-501b-b97b-e2d2465cc08d', '0882f404-5e91-5e5f-ab13-effa153e4492', '73133717-48fc-5619-bfe7-1690012e95eb', 1, 'Understand the man behind the helmet', 'Magneto Testament reveals the formative tragedy that shaped his entire worldview.'),
  ('5203e32c-b54e-5e22-a676-f10c4d564ee0', 'e04135bf-0e34-5add-8c14-e9c345b1fae2', 'a5c8528c-a71d-5f10-8a70-a96cd6685190', 1, 'Absolute Beginner', 'This arc reveals the bargain that created Spawn and the demon behind it.'),
  ('9ce8f74b-fd92-5149-9e70-870ff4e88b46', 'c87a39f2-008e-57ba-9fa5-e93d2da2d911', '725a9930-a10c-5616-a66d-34be04766c4f', 1, 'Classic Fan', 'The Casket of Ancient Winters introduces Malekith during the iconic Simonson run, the perfect place to meet the dark elf.'),
  ('95dfea9b-93cf-557e-8d27-c191439e90e2', '67852c9d-4ede-5e29-959f-5d58f6dd2255', 'ede6c458-6db9-544c-82b0-c372801e5e86', 1, 'Explore the last son of Mars', '''Son of Mars'' is the definitive solo deep-dive into Martian Manhunter''s character and history.'),
  ('5ead262f-0346-51c1-846f-2c57fb94ec94', '6d3b22e4-ecd2-569b-b088-750d3beb5c95', '72605591-ce23-5a51-8a82-1e784afe5679', 1, 'Absolute Beginner', 'Experience the case at its most personal stakes.'),
  ('eb43cfdb-6dcf-587e-ab45-537c248d5bf6', '0b1f9dae-3b8b-50eb-9e6e-dcf3208d3996', '0eb3077f-6159-52c7-94cb-e75446f3da33', 1, 'Modern Era', 'This arc introduces Nyx as Spawn''s magical ally in the modern run.'),
  ('66ba7ccc-8e2e-5101-b08c-89b3b121b6b1', '976abf28-99fc-5073-80fc-0b26f69b73d3', '9fb2bf09-eab0-5de8-bf1b-4ad7090c2ccd', 1, 'Classic Fan', 'Stane''s gambit is the definitive corporate-villain arc and the origin of the Iron Monger.'),
  ('fcacb1ce-a611-5b2f-9ab5-a8915ae929be', '6a03558f-184a-5db6-a341-0c6f4fad2eab', 'b738e3cf-3f9a-568a-be5b-49b0ec3d4648', 1, 'Absolute Beginner', 'Omni-Man''s arc is the emotional engine of the early series and the key to understanding Invincible.'),
  ('92364fce-fd41-5f59-b820-070481a21e72', '0592afef-f365-56b1-9f86-5fe1d601e77e', 'f422f653-3184-5f83-bfa0-01f83b7c8425', 1, 'Best Introduction', 'Green Lantern: Rebirth reveals Parallax''s true nature and its grip on Hal Jordan, the definitive context for the entity.'),
  ('a0da3b29-03d0-5c47-ba37-8b2b46f7d63e', 'b23f30f2-61cd-515a-a3e8-f07f14502f2d', '9a2c9f08-7519-5edb-a054-97b73a155c40', 1, 'Absolute Beginner', 'Starts the BOOM! continuity from the beginning, grounding you in the team dynamic and Tommy''s redemption before the stakes escalate.'),
  ('059fb60b-3164-5f1f-840a-ae9389ab6171', 'b23f30f2-61cd-515a-a3e8-f07f14502f2d', '2cc76d1e-7b57-5bee-85f1-9e727db0a31d', 2, 'Classic Fan', 'Black Dragon Rising delivers the nostalgic monster-of-the-arc thrills with modern depth, perfect for longtime fans.'),
  ('0be0bd51-9e92-5ceb-9672-c80fc2eeffdc', 'b23f30f2-61cd-515a-a3e8-f07f14502f2d', 'fe36141d-24ed-582f-a3ca-895c71f5bfcb', 3, 'Modern Era', 'Shattered Grid is the ambitious multiversal event that defines the modern comics and showcases the franchise''s full scope.'),
  ('43b29bb5-2ceb-5507-9a12-b76b5db138f9', '2691870e-40bb-5f64-880b-9c2f4cfaf09d', '84690b28-3df7-576e-b7ee-c21e94fdb136', 1, 'Where the dream begins', 'Xavier''s founding of the school sets the entire mythology in motion.'),
  ('73340cd2-4087-536d-9c18-0d771ab4067c', '1a61ff3c-d1d1-52b6-beb8-c1dc60642f40', '9d5958f7-76f2-5920-8e58-2193f2d3a549', 1, 'Best Introduction', 'Batman: Tales of the Demon collects the O''Neil/Adams stories that introduced Ra''s and remain the clearest distillation of the character''s concept and appeal.'),
  ('d00b494e-b5fd-5c0a-9014-527b1b5aa3dd', 'db496c89-2091-5e0e-8859-371dc2cdd7a7', 'c8d56f5a-7d65-590a-a0a6-41fb3f34e293', 1, 'Start Here', 'See the Red Skull at the height of his powers as the architect of the conspiracy in Brubaker''s acclaimed modern run.'),
  ('c86b73e4-f537-5583-962d-0ebea01ea3ec', 'ad0aeda8-5962-52a4-a9c9-4395afe2a044', 'b975e6bb-1c49-5d11-8c27-66bb9bf6b5f8', 1, 'Villain Spotlight', 'The Reverse-Flash''s debut establishes the twisted mirror-image dynamic that defines his rivalry with Barry Allen.'),
  ('239d6abd-e285-5f13-88fc-fed51f1ad6c8', 'ee1e4f5e-6664-5a73-aa9b-e4da8f5771d2', '334579fa-4020-5978-a6a2-fb9e759dac4a', 1, 'Absolute Beginner', 'Watch Robot engineer the reformed Guardians from the ground up.'),
  ('e7daa36c-ee15-577b-8168-d776359d061d', '899505b8-a56a-5ca8-aeca-d8d7a2969cd6', 'cdfed88c-6714-5d6d-b60e-383680117d60', 1, 'A villain''s redemption', 'Rogue''s defection from the Brotherhood is one of the franchise''s great character turns.'),
  ('613afe46-f350-5616-b8e4-42b468cbbf14', '1a1511e9-19d7-51cf-a5ad-c81d49093aaf', '50e18243-7ae9-5e31-a8c1-67cd3628cdd1', 1, 'Absolute Beginner', 'Giles''s introduction establishes the Watcher mythology and his mentorship of Buffy.'),
  ('f801316d-5a2d-509d-b6a1-418c8d4186a1', 'd3ce5131-893b-5d10-a5e8-5ec39dd0a85a', '84cbe1d7-f147-50ce-90e1-1fdaea285a2c', 1, 'Best Introduction', 'Mutant Massacre shows exactly how dangerous Sabretooth is and why his shadow falls so heavily over Wolverine.'),
  ('72efb888-b6be-57ac-a002-9543f672fa8e', '519242ce-776c-5906-b032-8ebc5b4d5614', 'f2663d99-fbfa-5c9f-bc7b-8f4b82d74de7', 1, 'Absolute Beginner', 'Udaku is the definitive showcase of the detective duo.'),
  ('fcda1f07-5f1a-56ad-9e9a-0d6d53e6d2d9', '7b94e1aa-83f4-508c-a457-770f2588339b', '6a7da75e-3e20-5d33-a77b-c838c96bd810', 1, 'Classic Fan', 'Meet one of Spider-Man''s earliest super-powered foes and a charter member of the Sinister Six.'),
  ('8cb382ab-858d-5a8e-95bc-403549725b5c', '4322fa09-0a88-5804-93f9-0fbf9175f54e', '359f2183-98f1-545f-8948-31532d9a0409', 1, 'Absolute Beginner', 'Start at the very beginning to meet the amnesiac Dragon and watch his origin unfold from issue one.'),
  ('73558d57-3391-5b2e-93a2-403f55d7f1dc', '4322fa09-0a88-5804-93f9-0fbf9175f54e', '41666cfc-5ca2-5278-9be6-5e608107d313', 2, 'Classic Fan', 'The Fallen captures peak original-Dragon action and the soap-opera intensity longtime readers love.'),
  ('be833df3-5b25-52da-895f-ea71d0772980', '4322fa09-0a88-5804-93f9-0fbf9175f54e', 'bcce1882-1096-587d-82bf-514ed6ea9929', 3, 'Modern Era', 'A New Dragon is the natural jumping-on point for the Malcolm-led modern run.'),
  ('100de21d-8859-5a40-84e1-bfaa458ad0e2', 'b6ee5c85-5da2-5a36-b6ca-e1fd21313c28', '78b13eb3-4b12-57bf-8efd-04358c17a6a1', 1, 'Absolute Beginner', 'Meet the team''s leader at the franchise''s origin.'),
  ('dd6fceef-3fc1-52a6-9de6-75afb386e646', '2a1b8c6d-9df0-53b2-afb7-33330b4bde2c', '039f076d-ef46-5760-b663-7894a85b42fc', 1, 'Best Introduction', 'The Sinestro Corps War is the definitive Sinestro story, showing the full threat of his fear-powered army against the Green Lantern Corps.'),
  ('29df8d6f-4b17-5dda-9ed1-766ce38a53b6', '7c004d0d-1535-57a7-9f09-ef7cf865a072', 'efad82c9-6e3a-560d-aedd-619498536991', 1, 'Absolute Beginner', 'The origin arc introduces Al Simmons, his deal with Hell, and the rules of his new existence with no prior knowledge required.'),
  ('670797d3-7548-553b-ba09-ac09a10b974c', '7c004d0d-1535-57a7-9f09-ef7cf865a072', 'f150b0bc-f593-5d97-91b2-37f3e4bdb5c2', 2, 'Classic Fan', 'The Violator''s arrival defines the classic McFarlane-era conflict and Spawn''s signature nemesis.'),
  ('bad406e7-ee0a-5326-85f9-49e8c7ec182a', '7c004d0d-1535-57a7-9f09-ef7cf865a072', 'b861af23-24d1-560c-a4d3-d1e255984e68', 3, 'Modern Era', 'The Scorched arc shows Spawn as the anchor of a modern connected universe of titles.'),
  ('5a6bddab-f150-5719-88e9-2177d6ccccb6', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', '66f6b6e8-4870-5702-97b3-4889cb5d0ff7', 1, 'Absolute Beginner', 'The complete, self-contained origin in a single issue. Read how Peter gains his powers and learns the lesson that makes him a hero, with no prior knowledge required.'),
  ('de36c789-6745-59fe-a96a-61947b81f468', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', 'e21001c5-5a12-51f3-b864-85515820cf0a', 2, 'Classic Fan', 'A standalone Bronze Age masterpiece that shows Spider-Man at his most tested. You can read it cold and understand exactly why it tops ''greatest stories'' lists.'),
  ('791b46e7-f028-58fa-8423-c51f8a1aa0d2', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', 'c25fdbac-aac2-5972-a3df-28ba45ab8871', 3, 'Modern Era', 'The multiverse epic that launched the modern Spider brand and inspired the animated films. A thrilling entry point into today''s Spider-Man mythology.'),
  ('ffe0a7c2-a776-5953-9493-d00303985ee9', '5fb83c49-8889-5548-9c30-32774f14089f', '0e7e9d9e-d5e7-5ff8-8e84-fc57d7fbf108', 1, 'Witness the goddess rise', 'Storm''s introduction and ascent in the all-new roster showcase why she is a fan favorite.'),
  ('125e0612-ba39-5e68-be81-ec3b34c98d47', '2530b133-d2b6-5355-86bd-7709a4d5d39e', 'c7d9e0f1-4fd4-5fe3-af3f-d1086341937d', 1, 'Absolute Beginner', 'John Byrne''s six-issue reboot is the cleanest modern jumping-on point, retelling Superman''s origin and introducing his entire world from scratch with no prior reading required.'),
  ('5770d2b4-1be9-5bdc-b7ef-7afb21a7ce1a', '2530b133-d2b6-5355-86bd-7709a4d5d39e', 'e875bb89-f6dc-52dd-b69e-daaab0b5d962', 2, 'Classic Fan', 'The Death of Superman is the most famous Superman story ever published and captures the high-stakes, blockbuster spirit of his classic adventures against an unstoppable foe.'),
  ('8eaf7eea-fce3-5665-9aed-8938b8a02df0', '2530b133-d2b6-5355-86bd-7709a4d5d39e', 'e66fd81f-b362-5974-885c-98b8490fe781', 3, 'Modern Era', 'All-Star Superman is a self-contained, continuity-free masterpiece that distills everything great about the character into twelve perfect issues, ideal for any modern reader.'),
  ('456a2aac-cf39-57a6-b508-ba823329cabb', '22bf9525-aa52-53e2-9019-eb5bca2af4d2', '810faed2-c4b7-5655-923d-aebe631db757', 1, 'Classic Fan', 'Doom of the Gods is the definitive Surtur story and the climax of the legendary Simonson run.'),
  ('7c091920-845c-5b99-b5cd-5199b9e36877', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', '82f80ca4-5a5e-5cb7-b5f5-9fa1e77d6064', 1, 'Start with the definitive Titans story', 'The Judas Contract is the single most acclaimed Teen Titans story and the perfect showcase of the team''s relationships, stakes and signature villain.'),
  ('e4ba356c-0f0d-515d-827b-8036a81262f8', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', 'b4c55576-0c97-51e8-bb71-15315ad0a355', 2, 'Meet the modern team', 'A Kid''s Game is the most accessible modern jumping-on point, reintroducing the franchise with clear mentorship themes for new readers.'),
  ('530b5bd8-6fd7-588d-b01e-feb5241530ab', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', '64f845ac-70f8-56d0-8c1d-7c5ee2da8567', 3, 'Understand Raven and Trigon', 'The Terror of Trigon delivers the team''s most personal cosmic conflict and the backstory that anchors the popular animated incarnations.'),
  ('c010e258-8299-5b21-9dea-faae2f35b1cb', '8d91b245-3858-5d29-a38b-d5d88f524623', 'f161854b-eac8-569f-95ec-4e197ab6b187', 1, 'Absolute Beginner', 'This arc establishes Terry''s bond with Al and the family at the heart of Spawn''s tragedy.'),
  ('214690df-6354-5f3e-9308-07d515ca319b', '1b08cd24-f7d8-50c9-8aed-bcfd1655a338', 'fbb43a47-3510-55ed-b84a-9db87162e957', 1, 'Begin with the quest', 'This miniseries is the definitive introduction to Thanos at his most calculating and dangerous.'),
  ('28374955-eb03-5c92-8482-92feccd10130', '7648e80f-c11b-5c40-abd6-0e19b5d8ed9e', '04c7bcc5-7bc5-57cf-85c1-dc51b0e9946b', 1, 'Modern Era', 'The recurrence reveals the cult that kept the faith alive in secret.'),
  ('1eb91b82-1200-5b29-a5d6-2908665ed95d', '7554762e-8839-52ac-b0f4-03e2d44cda89', '1d0eaad0-11e2-5f5f-bf87-afed56209f5b', 1, 'Absolute Beginner', 'The original six-issue outbreak introduces the affliction, the task force, and the dread that defines the whole series.'),
  ('d2e482a7-fd75-508c-b24c-68164e4e5e01', '7554762e-8839-52ac-b0f4-03e2d44cda89', '283c15e5-8576-523c-b2f8-7631fc1e5b4b', 2, 'Classic Fan', 'Watch the public health crisis curdle into a faith as the Empty Man''s followers organize.'),
  ('0f7a760a-997e-54b0-9e4f-a24c8a240ce8', '7554762e-8839-52ac-b0f4-03e2d44cda89', 'c0a2a383-3974-5510-ad2d-3dcd93dbcf09', 3, 'Modern Era', 'The 2018 revival reframes the horror on a generational scale for readers who want the contemporary take.'),
  ('0ba1c511-1737-544e-b5d4-647feb7c2427', '4714cfea-ef2c-556a-899f-bc09147b519f', '8d73da21-921c-52cf-941a-be770aab1121', 1, 'Absolute Beginner', 'See how a contagion becomes a congregation in the first outbreak.'),
  ('a6a9fdb0-3ebe-51a3-b12c-5c69d6ef18be', '448be678-268c-522f-9477-a07422c30fd0', '1f63da5d-a7a6-587b-b349-edd3a8c25038', 1, 'Absolute Beginner', 'Start at the very beginning with Barry''s lightning-bolt origin, the cleanest entry point into who the Flash is and how he got his powers.'),
  ('4a6a465c-7be3-537f-867c-9a1ef211a87d', '448be678-268c-522f-9477-a07422c30fd0', 'ec90011a-c4c6-5401-9f92-d9853c3e10f2', 2, 'Classic Fan', 'Flash of Two Worlds is the quintessential Silver Age Flash tale and the birth of the DC Multiverse, perfect for readers who love comics history.'),
  ('4bd70688-0997-5ae6-a4df-073dff22c6aa', '448be678-268c-522f-9477-a07422c30fd0', 'a3f3d324-759e-5422-b52b-e00e4636533f', 3, 'Modern Era', 'Flashpoint is the modern Flash''s defining story, an emotional time-travel epic that reshaped the entire DC Universe and inspired the film and TV adaptations.'),
  ('11e67f4b-303d-5c32-bdd9-6b92b2e587f4', '65cb3481-4f7e-5599-8b71-78e119c216d3', '6bb5f3f6-50c0-5eac-8636-978ba4de1567', 1, 'Absolute Beginner', 'Meet the team''s enduring anchor as he leads through crisis.'),
  ('6d955ebf-caaf-5f87-8e49-5da66f97e297', '8162a5f2-092c-55f0-b3c9-fc354fe236cd', '75dfea31-6679-5497-9fe8-771e5a8ca685', 1, 'Best Introduction', 'The Killing Joke is the most complete single-issue portrait of what the Joker is and why he matters — essential reading before any other Joker story.'),
  ('95531cd6-0869-5e62-9be4-fef90ff4f91e', '29db753d-37a2-5ec6-90da-bae6daeed5d4', '2e89d5d0-3f75-5280-96ea-768d7ecff005', 1, 'Classic Fan', 'His debut arc establishes the definitive Iron Man archnemesis and the lore of the ten rings.'),
  ('043e1128-484e-5bf9-b810-9f221aed5a9c', '2746a6b9-b9dd-5829-a0b1-bb4f656b6d54', 'e53b2f4e-70c4-5d8f-8b81-0a028fc09bb6', 1, 'Absolute Beginner', 'See the institutional response take shape from the first outbreak.'),
  ('46a33b90-647f-5097-9356-f2fc1e1d2478', 'f8057d23-7b86-5e3a-ba0d-ad82d360cb6d', '20a82c71-d3b9-575c-b464-b4c90fe7fc9d', 1, 'Best Introduction', 'Paul Dini''s Detective Comics run — including the Riddler''s private detective period — is the best single entry point for readers who want to understand what makes the character interesting beyond puzzle gimmicks.'),
  ('66cd9888-111a-54fe-80ee-202f866e7408', 'de8ec54e-9f19-561c-bcb0-a114f019363c', '4f9d5e26-b8ee-50f9-a813-ce9a0b8a6f8d', 1, 'Absolute Beginner', 'The God Butcher is a self-contained, gorgeously drawn modern epic that needs no prior reading and showcases everything that makes Thor compelling.'),
  ('982346f9-4212-57ea-872b-8b61ff501e69', 'de8ec54e-9f19-561c-bcb0-a114f019363c', '14201fa5-4dae-5a2a-95b7-6821ee8dc328', 2, 'Classic Fan', 'The Ballad of Beta Ray Bill kicks off Walter Simonson''s legendary run, the most beloved Thor era and a perfect entry into the character''s mythic Silver and Bronze Age roots.'),
  ('6a126b45-2a0e-51e6-a6f9-75272343aefd', 'de8ec54e-9f19-561c-bcb0-a114f019363c', 'c6550eb3-216d-55b0-a5a5-a7d9d65ed1a2', 3, 'Modern Era', 'War of the Realms is the explosive payoff to the modern Thor saga, ideal for readers who want the current status quo and a universe-spanning event.'),
  ('691ab4a9-9e4c-558b-877a-9f900c602ea1', '784afd7e-b4e8-547a-a63d-fdc8fa966fc6', '32f6d45c-1b52-5498-b13e-5b25da924c76', 1, 'Absolute Beginner', 'Start with Tommy''s reimagined origin to understand his guilt, his fading power, and why the team is wary of him.'),
  ('006a4e65-a67e-5f44-a1c2-d6b508e2269c', '784afd7e-b4e8-547a-a63d-fdc8fa966fc6', '5113dcc9-3e17-5762-be19-939340200224', 2, 'Classic Fan', 'If you know the TV show, jump to the arc where Tommy must protect a power that is slowly killing him.'),
  ('566228b1-0382-58f0-af0f-3b1b4eb152a3', '784afd7e-b4e8-547a-a63d-fdc8fa966fc6', 'f466b187-513f-5c48-8a73-df08961e47c2', 3, 'Modern Era', 'The definitive modern Power Rangers event, pitting Tommy against the darkest possible version of himself.'),
  ('1102c4ca-24ad-52e0-b8b0-43a241e2413e', '283ec4c4-55b8-513f-942a-81323157794b', '4a52ad17-cc38-5200-a90f-77ed9bc82103', 1, 'Absolute Beginner', 'Still Water captures Trini''s disciplined composure and quiet heroism.'),
  ('9d9f8ad3-e741-51b2-9991-28245e7bc5bc', '878e378d-03bb-5fd6-ae15-d31fe564261e', '143d9eed-34b5-50da-bcee-3bd7918d1567', 1, 'Best Introduction', 'The Long Halloween is the finest Two-Face origin story and one of the best Batman comics period — it works as a standalone noir mystery for readers with no prior DC knowledge.'),
  ('3766719d-c595-5dd0-be63-4086620e27c6', '1f126a7b-ee19-5ae2-bc70-44d7d3b37f64', '1e0ba950-f0ae-5ef1-a208-cce1f2ac14eb', 1, 'The definitive Ultron story', '''Ultron Unlimited'' captures the villain at his most terrifying and is the ideal introduction.'),
  ('7a715a22-5660-5b94-ae35-f3a9800b89a7', '84980f5e-ba2b-5111-92d4-0e4628b593c6', 'a28d42eb-5ffa-5ccf-b059-5635e45a6d0e', 1, 'Classic Fan', 'Trace Venom from a mysterious black costume to the symbiote nemesis who knows all of Spider-Man''s secrets.'),
  ('50eeb668-47d6-5d63-b21b-3e442048a478', '2be580a9-54b0-5f83-b29b-fc7585a8890c', '9839f687-52cc-5bd2-b1a2-423b8d5dcc37', 1, 'Absolute Beginner', 'This arc reveals the Violator behind the Clown disguise and his role against Spawn.'),
  ('61094188-f902-5a65-bd82-3344051f9233', '5d3f7c5e-1e99-5146-97d0-ce7373d1b57f', 'cb459ad4-ed8c-5f20-8379-d5aaa2b09c5f', 1, 'Absolute Beginner', 'Discover one of the team''s standout operatives.'),
  ('9e9d9bc9-3e75-5c56-b841-c6ddd2c9be3b', 'e348cdc2-3977-522f-877e-9b4cdecceba9', '03b40217-0cbb-5b12-aaa2-7e4291249503', 1, 'Absolute Beginner', 'Willow''s introduction shows how an ordinary student becomes the gang''s magical backbone.'),
  ('eb9e02d0-bbcf-5df9-8d92-51f7b3e64bba', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', '3b8a318e-3ca6-5089-9bda-49eb30431766', 1, 'Absolute Beginner', 'Start at the beginning to meet Sara Pezzini and watch the Witchblade choose her; this origin needs no prior knowledge.'),
  ('fcf9c322-7c55-5ea0-8246-baafa4fa355f', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', '8cd5e66e-52b7-595b-bd22-632f92e31956', 2, 'Classic Fan', 'The defining clash with Kenneth Irons and Ian Nottingham is the heart of the classic Top Cow run.'),
  ('f6183698-c2ca-597c-925b-75d6c167a3cb', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', 'ad4ceab3-7b85-5d9e-9131-5f1af22c9337', 3, 'Modern Era', 'War of the Witchblades reframes the mythology and is the best entry point into the artifact''s later cosmic stakes.'),
  ('d94b5e90-9d63-5a5d-a867-4f03b2a1a36c', '411d9474-16b6-5c50-a3fa-36f22c778276', 'e3989aad-bb63-50a3-ac00-fd9d05876218', 1, 'Absolute Beginner', 'Origin tells Logan''s life story from the very beginning in six self-contained issues, requiring zero prior knowledge of the X-Men.'),
  ('bcfa85f0-4ef6-5b8a-b9c7-e9a19c418773', '411d9474-16b6-5c50-a3fa-36f22c778276', '16f27f20-72bc-57ec-b47f-71b2574561e5', 2, 'Classic Fan', 'The Claremont/Miller Japan saga is the definitive vintage Wolverine: tragic, honor-bound, and the blueprint every later solo story follows.'),
  ('7f643c04-5468-5891-84c5-a57e45ac604e', '411d9474-16b6-5c50-a3fa-36f22c778276', '214e50e1-4ad0-57fc-a256-97e0efbbb15c', 3, 'Modern Era', 'Old Man Logan is a self-contained modern classic that captures Logan''s grief, rage, and humanity, and inspired the film Logan.'),
  ('0d439321-7630-5997-bffb-fa18ae8e6adb', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', '1e7f1d7d-d2d9-5dfc-a674-62b164ca578c', 1, 'Absolute Beginner', 'Greg Rucka''s Rebirth run rebuilds Diana from first principles, retelling her arrival in Man''s World with modern art and clear, welcoming storytelling that needs no prior knowledge.'),
  ('9d26a339-b9ed-57de-a098-8f0b02d3e948', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', '8207d545-74d3-5a0f-b8ee-c327a7700d3c', 2, 'Classic Fan', 'George Perez''s Gods and Mortals is the definitive modern origin, grounding Diana in Greek myth and defining the character for a generation of readers.'),
  ('e11ed865-48a9-5a56-8b8d-2aadae35d158', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', '3a2189ac-d666-5085-8987-a48ee7fc3f22', 3, 'Modern Era', 'Azzarello and Chiang''s Blood reinvents Wonder Woman''s mythology as a horror-laced divine family drama, a bold and self-contained modern entry point.'),
  ('141d284b-41c1-56a0-b46f-346d1d7078d7', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', '56151a61-03a6-5319-b40c-a5f5ff677e6b', 1, 'Start with the all-time classic', 'The Dark Phoenix Saga is the definitive X-Men epic and the perfect showcase of the team''s heart, stakes, and characters.'),
  ('b5f9555d-6ca0-5251-86de-b75d3fa837bf', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', '272b5ace-7eda-5abb-a911-e026541199d7', 2, 'The most adapted X-Men story', 'Days of Future Past is short, self-contained, and captures the franchise''s core themes through a gripping time-travel thriller.'),
  ('eb174be3-e624-5fe8-b46c-85a1d62a024f', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', 'd02eabd8-8c07-59d7-88dd-73608ed2989c', 3, 'The modern reinvention', 'House of X / Powers of X reboots the mutant status quo and is the ideal jumping-on point for contemporary readers.'),
  ('f20507a2-4c39-59cf-933e-197775dbb322', 'f62d2c40-f7ae-51be-87fd-ffab0e0f6237', '57516ddd-0fb9-5bf5-b273-f17f7448cded', 1, 'Absolute Beginner', 'Xander''s introduction captures the gang''s everyman spirit and grounded humor.'),
  ('f7313e4e-8605-5f9c-8526-03595c3b2025', '89b546be-6991-54a1-a207-5fdafbd26ee7', '9d04df0e-afd2-59b2-894d-7c174b40f87c', 1, 'Absolute Beginner', 'Start at the very beginning to meet the roster and the celebrity-hero premise as Image fans first did in 1992.'),
  ('e27b9cd2-e813-5893-a460-aaff4089d2cb', '89b546be-6991-54a1-a207-5fdafbd26ee7', '0d37922c-cc05-5024-a188-f951719a141f', 2, 'Classic Fan', 'A high-stakes early showcase for the away division and the franchise''s harder edge.'),
  ('a74a1576-7753-5688-a03c-ede6dcf39c3f', '89b546be-6991-54a1-a207-5fdafbd26ee7', '43e3a1ac-d3f9-5dfc-b246-11da0c9f6949', 3, 'Modern Era', 'The contemporary relaunch sharpens the satire of fame and sponsorship for new readers.'),
  ('ae725f9d-51f6-5c41-bccf-60a1ad128bc1', '2f4b9d8d-8685-529a-b34d-a2bc3e39ef60', 'aef667a3-4d4e-5873-807e-6d806682e66b', 1, 'Absolute Beginner', 'Rhythm and Resolve reveals the courage and depth behind Zack''s easygoing charm.'),
  ('4648ffc9-40fe-5186-b213-e8315a989642', '0ff251a9-e3eb-5e72-9be3-ac49ca4e02d0', '83e63e73-465a-5256-99a5-d58c4790d919', 1, 'Villain Spotlight', 'Blitz is Zoom''s defining story and a cornerstone of Geoff Johns'' celebrated Flash run.')
insert into relationships ("id", "entity_id", "related_id", "relationship", "summary", "notes") values
  ('1b03324d-c791-5447-aa26-5fa4b798a2b0', '5077371b-ec42-5e42-978e-c7d720a6ff1c', '7786b507-312a-539d-8a23-29295e4b1a30', 'ally', 'Aaron shares Erica''s lineage and at times aids her despite the Order''s wishes.', 'Their bond is complicated by loyalty, rivalry, and the secrets of the House of Slaughter.'),
  ('3645eef8-3c15-523b-a751-27f5dc271f1c', '8239a78a-c7f8-54b8-b823-3a0387f9ccf7', '7554762e-8839-52ac-b0f4-03e2d44cda89', 'enemy', 'Jensen is the FBI agent leading the hunt for the Empty Man.', 'His investigation drives the original story and reveals the affliction''s unknowable nature.'),
  ('934c085c-c7c5-5f3e-9f70-177f2f854d51', 'ffac191d-640b-59b0-9a6c-2c3d9aeeb98d', '7554762e-8839-52ac-b0f4-03e2d44cda89', 'enemy', 'Langford works the federal task force trying to contain the Empty Man.', 'Her rigorous methods are steadily defeated by the affliction''s impossible behavior.'),
  ('dd063f32-9be1-5c13-bfd6-602865ab8839', '710b82cd-cfe7-58fb-9e14-b7d0b699cbfb', '4322fa09-0a88-5804-93f9-0fbf9175f54e', 'ally', 'Dragon''s police partner and a key emotional connection in his early career.', 'Their partnership grows from professional respect into one of the series'' defining relationships.'),
  ('63459508-24f9-540d-87ab-9a34b2f55d09', 'c4001d41-6a31-5d98-9b1a-dcff2110c389', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'ally', 'Alfred''s relationship with Bruce Wayne is the only one in Batman''s life that predates his choice to become Batman — he knew the boy before the mission consumed him.', 'Across most continuities, Alfred helped train Bruce and has disapproved of specific choices while never abandoning the larger project.'),
  ('4af224a1-cc18-5cba-9c5d-831ac8122ea7', 'b5249e33-edfa-5bc1-aaa2-b03e5a4453fe', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', 'ally', 'A soul-cursed vampire who fights beside Buffy despite his nature, bound to her by love.', 'Angel''s romance and partnership with Buffy complicate every battle, his soul forever at war with his demon.'),
  ('4537d552-c8ce-53d2-a048-8950ae5f6ec3', '559e093e-4477-566a-abce-9ade8afe79c8', 'ddc90de2-8e7d-5dd1-bde9-72646019ee2b', 'enemy', 'A multiverse-spanning foe waging a personal vendetta against Mark.', 'Angstrom blames Invincible for the accident that transformed him and never stops seeking revenge.'),
  ('c3156fa5-b881-549c-8fbd-2c1e764e9ffc', 'e1d3db22-d396-5b47-a3eb-2fd70f4e8d48', '7c004d0d-1535-57a7-9f09-ef7cf865a072', 'enemy', 'The Anti-Spawn is created to hunt and destroy the Hellspawn.', 'As the Redeemer, it brings Heaven''s war directly to Al Simmons.'),
  ('f0a95e44-2f9e-5341-b580-354e40163748', '92c2c3fd-aea6-57ab-bfc3-0d4d5af52bfd', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', 'enemy', 'Apocalypse views the X-Men as either potential Horsemen or obstacles to be culled in his endless culling of the weak.', 'Ancient, immensely powerful, and driven by survival-of-the-fittest dogma.'),
  ('536b1ade-5bea-5268-bfc3-2f6ef89a9943', '36642001-e8a9-5065-87f9-0502cf4edac5', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'ally', 'A founding member who represents the seas on the League.', 'Original founder and later a leader of the Detroit-era team.'),
  ('87dd5fa4-8d9d-51d5-9dd2-1f015fee1c8b', 'd679bf65-5e35-5ddb-94fb-c5446bf4e277', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', 'enemy', 'Ares is Wonder Woman''s archnemesis, the god of war forever opposed to her mission of peace.', 'Their conflict is foundational to her modern origin in George Perez''s Gods and Mortals.'),
  ('bf46f1c6-baff-56ea-9b84-35a57a2c3aff', 'c31f6730-0efb-548f-9c3c-c8c04aed7c04', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'enemy', 'Arnim Zola is a recurring genetic-engineering nemesis whose horrifying experiments repeatedly target Captain America.', 'Zola imprisoned Steve Rogers in Dimension Z for years during Rick Remender''s acclaimed run.'),
  ('71ca80cf-4f72-5f69-ad98-dbfe88355b01', '1d2e2e20-67a0-5ff6-b32e-f27309a51253', '7a66364d-547b-54c4-948e-de4f1d756d38', 'ally', 'Atom Eve fights alongside the Guardians as one of Earth''s most powerful heroes.', 'Her abilities make her a decisive force in the team''s largest conflicts.'),
  ('e88903d6-a207-5514-a1e6-7acbc2beba20', '77db7ea3-8ed7-5273-add1-d93259b39938', 'a8434c59-8838-500a-a059-d60b3b33a59e', 'enemy', 'Atrocitus opposes Hal Jordan as the rage-fueled antithesis of the Green Lantern''s will and order.', 'Introduced in 2008, Atrocitus blames the Guardians and their Lanterns for the massacre of his people and clashes with Hal across the War of Light.'),
  ('80be3988-cad4-59fd-b6a8-6b37c27a1b9f', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', 'ally', 'A founding member and the team''s chief technologist and financier.', 'Tony Stark bankrolled the original team and provided Avengers Mansion and much of its technology.'),
  ('2ef3d900-8036-5173-846d-4afe897d82d9', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'ally', 'The team''s enduring field leader and moral compass.', 'Joined in The Avengers #4 after being thawed from the ice and has led countless rosters since.'),
  ('1b2ef2cd-dbe7-52cf-a6d8-dc6f464e5513', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'de8ec54e-9f19-561c-bcb0-a114f019363c', 'ally', 'A founding member and the team''s resident god-tier powerhouse.', 'The God of Thunder lends both raw might and a cosmic perspective to the team.'),
  ('542b0ce6-ba69-57ec-9c05-17a324b3f17c', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', 'ally', 'Fellow protectors of Earth who have allied with the Avengers many times despite occasional friction.', 'The two teams have clashed and cooperated, most notably during events centered on mutantkind.'),
  ('5dd62b33-f14d-5ac3-8410-651147d4b561', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', '1b08cd24-f7d8-50c9-8aed-bcfd1655a338', 'enemy', 'The Mad Titan whose pursuit of ultimate power makes him the team''s most apocalyptic foe.', 'His quest for the Infinity Gems has repeatedly put the entire universe at risk.'),
  ('62ac7ec9-7a37-59a3-8115-0009b39e0389', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', '1f126a7b-ee19-5ae2-bc70-44d7d3b37f64', 'enemy', 'A genocidal artificial intelligence created by an Avenger, perpetually bent on humanity''s extinction.', 'Ultron''s origin within the team makes him one of their most personal and recurring threats.'),
  ('fdcc5631-73af-5ae5-8742-c0546e75a32f', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', '1f49fb7c-fb73-52ec-8ba2-e5bf8b640f09', 'enemy', 'The trickster god whose scheming inadvertently created the team and who remains a frequent adversary.', 'Loki''s manipulation of the Hulk indirectly led to the Avengers'' formation.'),
  ('02e3dad9-6005-5fe5-95a1-3a89bd31c812', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', '74817bfe-b087-5d7b-83ac-2aea450e5656', 'enemy', 'A time-traveling conqueror obsessed with subjugating the Avengers across history.', 'Kang has battled the team throughout the timestream in some of their most intricate sagas.'),
  ('24355c16-50cd-555f-b6d5-e88b3be24c82', '948cf5fe-fe35-5e34-9f70-089f1b266b31', '89b546be-6991-54a1-a207-5fdafbd26ee7', 'ally', 'Badrock is a core member of Youngblood.', 'He provides muscle and emotional grounding for the squad.'),
  ('ea57a5ef-192f-510b-9ad3-6aeae4fe99d8', '6307652f-ef23-59c7-bf66-eb6ce5ed6e9c', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'enemy', 'Bane chose Batman as his primary target not from grudge or accident but from calculation — Batman represented the highest available proof of his own superiority.', 'Tom King''s ''I Am Bane'' arc is the best post-Knightfall Bane story, reestablishing him as a credible threat after years of diminishing returns.'),
  ('1c0139f8-67ae-5746-8fd1-609aa75ba60b', '6e0c7dd7-5e7a-5e9b-9a74-1424a8db9121', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'ally', 'Barbara''s relationship with Batman shifted from protégé to peer over decades — Oracle''s intelligence network made her arguably more operationally significant to Gotham''s safety than Batman himself.', 'Her paralysis in The Killing Joke and Batman''s failure to prevent it is a permanent tension in their working relationship.'),
  ('3c32cd14-9bee-55ee-9f1f-cd2968ca147c', '45ba8447-d9b0-5e63-b25d-3f181ed157a7', '4322fa09-0a88-5804-93f9-0fbf9175f54e', 'ally', 'A super-strong hero who frequently teams with Dragon against major threats.', 'Barbaric backs Dragon up in battles that demand more than one powerhouse.'),
  ('4391058e-e855-55fe-894f-3914f5b32eec', 'd95c67d0-9578-5ab8-8ec3-cd61bef7c92f', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'enemy', 'The Zemo legacy carries a generational vendetta against Captain America rooted in the wartime tragedy of Bucky''s apparent death.', 'Heinrich Zemo''s drone-plane trap seemingly killed Bucky and froze Cap, a grudge his son Helmut continues to pursue.'),
  ('196d3b6c-e04e-5dea-9be9-26fb0f034001', '46a5721c-458f-5262-b06c-881e6b7f98bc', '16c71808-cd7a-588a-8f41-653051d42c23', 'ally', 'Commissioner James Gordon is Batman''s most enduring institutional ally — the one honest cop in a corrupt city who decided, without ever formally acknowledging the partnership, that Gotham needed a man the law couldn''t be. Their relationship is built on mutual respect and deliberate ambiguity: Gordon does not officially know Batman''s identity, and Batman has never confirmed it.', 'Introduced Detective Comics #27 (1939). Their dynamic is the spine of nearly every major Batman story.'),
  ('47d61e7d-f086-5c29-b62c-e358db52954d', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'ef33d492-4f93-52fc-bfe8-b86b454eb253', 'ally', 'The original Robin and Batman''s first ward, Dick Grayson became Nightwing and eventually assumed the Batman mantle when Bruce was incapacitated. He represents everything Batman might have become if grief had not calcified into obsession — and their relationship, complicated by mentorship and deep disagreement about methods, is the most emotionally rich in Bruce''s life.', 'First appeared Detective Comics #38 (1940). Later starred in New Teen Titans and his own Nightwing series.'),
  ('a7125b69-8c3a-5f21-b69e-356b67fce0bc', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'c4001d41-6a31-5d98-9b1a-dcff2110c389', 'ally', 'Alfred Pennyworth is Bruce Wayne''s butler, field medic, archivist, and the only person who has known him across every version of himself. He maintains Wayne Manor and the Batcave with equal competence, and his dry, precise commentary functions as the conscience Bruce doesn''t always listen to.', 'First appeared Batman #16 (1943). One of the few constants across every continuity and adaptation.'),
  ('54f142dc-f33e-52e0-8789-092e1043c8c2', '46a5721c-458f-5262-b06c-881e6b7f98bc', '3e12c541-fd4c-54c0-ad44-ceda960d5635', 'ally', 'Selina Kyle operates as thief, rival, adversary, and the closest thing Bruce Wayne has to a genuine romantic equal. Their dynamic has defined a particular kind of superhero relationship — built on mutual recognition between two people who chose their identities rather than inherited them.', 'First appeared Batman #1 (1940). Became Catwoman as a title character and eventually Batman''s fiancée in Tom King''s run.'),
  ('bb586bed-cc89-5e4b-87d3-0bd23d7d0f28', '46a5721c-458f-5262-b06c-881e6b7f98bc', '6e0c7dd7-5e7a-5e9b-9a74-1424a8db9121', 'ally', 'Barbara Gordon served as Batgirl before Alan Moore''s Killing Joke and returned as Oracle — the Batman family''s intelligence hub — for decades afterward. Her arc from field operative to information broker represents one of the more convincing disability narratives in mainstream comics.', 'First appeared Detective Comics #359 (1967). Her role as Oracle defined the post-Killing Joke era.'),
  ('ecc2ebac-1461-5e53-a689-5e83bf98e1fd', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'ad8850b8-8aec-5819-bba1-9a55932f4612', 'ally', 'Lucius Fox runs the business side of Wayne Enterprises with the competence that allows Bruce Wayne to fund his operations without scrutiny. His relationship with Bruce involves a careful, mutually agreed-upon level of not-quite-knowing what all that R&D budget is actually purchasing.', 'First appeared Batman #307 (1979). Became prominent via Christopher Nolan''s film trilogy.'),
  ('657961ba-4a56-514b-94fe-0b84823787ba', '46a5721c-458f-5262-b06c-881e6b7f98bc', '8162a5f2-092c-55f0-b3c9-fc354fe236cd', 'enemy', 'The Joker is Batman''s defining antagonist and philosophical shadow — a figure whose existence implicitly asks whether Batman''s refusal to kill is principle or avoidance. Where Batman imposes order through preparation and discipline, the Joker dismantles it through pure, weaponized chaos.', 'First appeared Batman #1 (1940). Has murdered Jason Todd, paralyzed Barbara Gordon, and murdered Sarah Essen Gordon across major storylines.'),
  ('1bd0cad2-38d7-50dc-8101-47343b1bdf2e', '46a5721c-458f-5262-b06c-881e6b7f98bc', '878e378d-03bb-5fd6-ae15-d31fe564261e', 'enemy', 'Harvey Dent was Gotham''s most effective district attorney and Bruce Wayne''s friend before acid destroyed half his face and his sense that the world was anything other than random. Two-Face functions as a mirror of what Bruce might become if his own certainty ever fractured.', 'First appeared Detective Comics #66 (1942). His prosecution of mob boss Sal Maroni, whose acid attack disfigured him, is a core origin story.'),
  ('0829819e-f595-5c52-bc11-669794a6b79b', '46a5721c-458f-5262-b06c-881e6b7f98bc', '1a61ff3c-d1d1-52b6-beb8-c1dc60642f40', 'enemy', 'Ra''s al Ghul views Batman as the world''s greatest detective and the only man worthy of inheriting his centuries-old organization — and simultaneously as the chief obstacle to his plan to reduce the global population. Their conflict is adversarial precisely because Ra''s takes Batman seriously.', 'First appeared Batman #232 (1971). Created by Denny O''Neil and Neal Adams.'),
  ('9925f616-1eef-5068-86b5-b951cdbdbceb', '46a5721c-458f-5262-b06c-881e6b7f98bc', '6307652f-ef23-59c7-bf66-eb6ce5ed6e9c', 'enemy', 'Bane did what no villain before him had managed: he broke Batman''s back and took Gotham while Bruce recovered. His defining characteristic is not raw strength but tactical patience — he studied Batman before making a single move.', 'First appeared Batman: Vengeance of Bane #1 (1993). Created by Chuck Dixon, Doug Moench, and Graham Nolan.'),
  ('b6b769e0-3fdd-581f-990a-dfd1ac7ba230', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'b0977b5f-d359-5193-a417-cd73e680f6dc', 'enemy', 'Oswald Cobblepot occupies a specific niche in Gotham''s power structure as the underworld''s most legitimate-seeming face — a black-market broker and information merchant who prefers deal-making to violence. His conflict with Batman is as much economic as it is physical.', 'First appeared Detective Comics #58 (1941). His Iceberg Lounge persona dates to the early 1990s.'),
  ('23b49c3d-996a-54a4-bab2-9fa976c1930e', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'f8057d23-7b86-5e3a-ba0d-ad82d360cb6d', 'enemy', 'Edward Nigma cannot commit a crime without leaving a clue — his compulsion to prove he is smarter than the world''s greatest detective makes him a consistent threat and an occasional, unlikely ally when his arrogance aligns with Batman''s goals.', 'First appeared Detective Comics #140 (1948). Became briefly heroic as a private detective during Paul Dini''s run.'),
  ('da1a79df-c555-5da2-8d37-4682ade761e8', 'c574c3b8-581d-56a5-95bd-6ac9f05e58c1', '0ce552c3-1204-54bd-805c-27a3e9153de6', 'ally', 'Bautista is a veteran member of the House of Slaughter.', 'He upholds the order''s traditions and mentors newer hunters.'),
  ('77813738-aade-593e-bf5b-8ce6909f89b4', '0c19853d-1aac-5dcf-817b-22515ad05e2f', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', 'ally', 'Beast Boy is a long-serving and beloved member of the Teen Titans.', 'He provides comic relief while carrying real emotional weight.'),
  ('ac343782-c799-5579-915a-caaec24d3ffe', '8e1ef9a0-54ee-5617-9109-d7b2c965a107', 'b23f30f2-61cd-515a-a3e8-f07f14502f2d', 'ally', 'Billy is a founding member and the chief technologist of the Power Rangers.', 'His inventions repeatedly save the team when power alone is not enough.'),
  ('7a384c20-8945-525b-a4d4-ef948e4329f7', '117737bd-7e5e-5807-ae9d-aebd4e273a32', '7a66364d-547b-54c4-948e-de4f1d756d38', 'ally', 'Black Samson is a veteran member of the reformed Guardians.', 'His experience steadies the younger roster in tough fights.'),
  ('86cfd490-dde3-5362-98ca-4b06b97c7539', '0a680e29-e289-5b76-ad11-9ae6b24f0542', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'ally', 'A trusted Avenger whose espionage skills and tactical mind make her invaluable to the team.', 'She became a prominent and beloved member, especially in modern rosters.'),
  ('d13539fc-750f-5aec-bd18-ef2e29010a90', 'c176cf47-e3aa-5124-96a3-c40653063787', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'enemy', 'A planet-collecting machine intelligence that menaces the entire DC Universe.', 'His galaxy-spanning schemes repeatedly bring him into conflict with the League.'),
  ('1555a812-cc9b-55a9-8aea-d5ef9edd8d64', 'cf13b5e8-4a72-5e83-80fa-cdab07827c1b', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', 'enemy', 'Brother Blood''s cult repeatedly menaces the Teen Titans across multiple eras.', 'He is a recurring antagonist in both comics and the animated series.'),
  ('2b65c84b-cb52-50f0-86fa-7cfbca3d0bb7', 'bc3388da-87e3-5978-bd9a-c1c8218aad6f', '7554762e-8839-52ac-b0f4-03e2d44cda89', 'ally', 'Soporus serves the Empty Man by preaching its presence as revelation.', 'His ministry recruits converts and accelerates the spread of the contagion.'),
  ('7f07a4c0-aecf-589a-9173-3bb03fcea9de', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', 'e348cdc2-3977-522f-877e-9b4cdecceba9', 'ally', 'Buffy''s closest friend and the gang''s resident witch, whose magic becomes indispensable to the fight.', 'Willow stumbles onto Buffy''s secret early and chooses loyalty, growing from shy student into a powerful spellcaster at Buffy''s side.'),
  ('17d7cd7a-c94e-5371-9d21-38a34a69e5dd', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', 'f62d2c40-f7ae-51be-87fd-ffab0e0f6237', 'ally', 'The everyman heart of the Scooby Gang, fighting beside Buffy without powers of his own.', 'Xander''s humor and unwavering loyalty anchor the group even when the supernatural stakes leave him outmatched.'),
  ('5348aaf3-9323-5854-87ea-c510d9da8ecc', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', '1a1511e9-19d7-51cf-a5ad-c81d49093aaf', 'ally', 'Buffy''s Watcher and mentor, the Sunnydale High librarian who trains and guides her.', 'Giles supplies the lore and discipline Buffy needs, serving as a steadying father figure throughout her calling.'),
  ('19e28360-1e97-5083-b1f5-e7396687596f', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', 'b5249e33-edfa-5bc1-aaa2-b03e5a4453fe', 'ally', 'A brooding vampire cursed with a soul who fights alongside Buffy despite his nature.', 'Angel''s romance and uneasy partnership with Buffy complicate every battle, his soul forever at war with his demon.'),
  ('e0459fd1-4948-51f4-bcb0-2ad75d4564e7', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', 'ba7706c6-1c90-505f-a393-ee1461db2e96', 'enemy', 'An ancient vampire lord seeking to crack open the Hellmouth and end the world.', 'The Master embodies the first great threat of Buffy''s tenure, an old and patient evil bound beneath Sunnydale.'),
  ('c624738e-92aa-535f-9f83-0a00d22fedab', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', '957f32fa-3926-509c-9983-994040b5e2ba', 'enemy', 'A deranged, prophetic vampire whose madness makes her unpredictable and dangerous.', 'Driven insane long ago, Drusilla wields visions and cruelty in equal measure as she menaces Buffy and her friends.'),
  ('e9d1df7b-327c-5240-bb34-d09ea0351a82', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', 'dbf622dd-5942-599c-be08-5440f5a3f2be', 'enemy', 'A swaggering, violent vampire who relishes the hunt and the challenge a Slayer presents.', 'Spike begins as a lethal antagonist drawn to Sunnydale by the thrill of killing Slayers, his loyalties always in flux.'),
  ('9de8e145-ad1a-5715-885b-68a9f1a61553', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', 'cb6f7717-ddd8-5824-b129-8a4fc74cc300', 'enemy', 'A child vampire of prophecy who serves as a sinister figurehead for the forces of darkness.', 'Small and unassuming, the Anointed One commands fear and ritual among Sunnydale''s vampires as a herald of doom.'),
  ('6c6c0d30-b933-54a1-bfbd-11045ef5e14e', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', 'ally', 'Cap''s longtime Avengers teammate and ideological foil, with whom he shares deep respect and occasional bitter conflict.', 'Their philosophical clash over government oversight drove the Civil War event (2006-2007), splitting the hero community in two.'),
  ('45d9d1c3-43ed-5c31-8e1b-73ab5498df9a', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'de8ec54e-9f19-561c-bcb0-a114f019363c', 'ally', 'A founding-era Avengers comrade and one of Cap''s most trusted allies in battle.', 'The two have fought side by side since the early Avengers run; Cap is one of the few mortals Thor regards as a true equal and is famously worthy enough to lift Mjolnir.'),
  ('cc70e8e0-e55c-5fd9-b114-c3e9f8c2fabe', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', 'ally', 'A younger hero who looks up to Cap as a mentor and moral north star.', 'During Civil War, Spider-Man ultimately sided with Cap''s anti-registration cause after being inspired by his stand for principle over law.'),
  ('5d9cbf03-aae7-5d68-b30e-d46e8fc87e18', 'f0f9597b-2580-532b-9882-2aefcd510a65', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'ally', 'The team Cap has led more than any other hero, serving as its tactical leader and moral center.', 'Revived by the Avengers in issue #4 (1964), Cap quickly became the team''s field commander and its defining symbol of leadership.'),
  ('47fde4b1-ac25-5097-b566-dbccd7d3f52b', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'db496c89-2091-5e0e-8859-371dc2cdd7a7', 'enemy', 'Cap''s arch-nemesis and the embodiment of the fascist ideology he was created to oppose.', 'Created as Hitler''s chief agent, the Skull has menaced Cap since the 1940s and orchestrated the conspiracy in The Death of Captain America.'),
  ('ef6e7bcd-ea39-5d5d-aac5-a3a6e159dcee', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'd95c67d0-9578-5ab8-8ec3-cd61bef7c92f', 'enemy', 'The aristocratic mastermind responsible for the wartime tragedy that defined Cap''s modern life.', 'The original Baron Heinrich Zemo set the drone-plane trap that seemingly killed Bucky and froze Cap; his son Helmut continues the vendetta as a Masters of Evil leader.'),
  ('80f35966-d5cd-5f69-91d3-df6721a934b0', 'f0f9597b-2580-532b-9882-2aefcd510a65', '523b3b97-51a2-5f4c-a5a4-785316b20408', 'enemy', 'A brutal mercenary and the Red Skull''s most loyal enforcer, a relentless physical threat to Cap.', 'Crossbones served as the trigger man in the assassination plot during The Death of Captain America storyline.'),
  ('dff9e95d-3103-5301-852d-2c7c41854591', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'c31f6730-0efb-548f-9c3c-c8c04aed7c04', 'enemy', 'A Nazi biochemist whose consciousness lives on in monstrous artificial bodies, perpetually scheming against Cap.', 'Zola imprisoned Steve Rogers in Dimension Z during Rick Remender''s run, forcing him to survive for years in a world built by the geneticist''s twisted science.'),
  ('e317c403-79dd-50fa-bad8-4684888a7dbf', 'f07139dc-c0a7-5000-a560-893f3fe017b0', '448be678-268c-522f-9477-a07422c30fd0', 'enemy', 'Captain Cold leads the Rogues against the Flash while maintaining a grudging mutual respect with the hero.', 'Their rivalry was central to Geoff Johns'' acclaimed Rogues stories and the ''Rogue War'' arc.'),
  ('4fa39cfb-0c77-55fb-8571-027ed2a269fd', 'b445ddd6-e1dd-515d-a9bd-222dd45eec5b', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', 'ally', 'Dante shields Sara from departmental scrutiny while she chases unexplainable cases.', 'He balances bureaucratic pressure with genuine loyalty toward Sara.'),
  ('eabe3c16-7068-5f06-918d-f5a7c340b64c', '3e12c541-fd4c-54c0-ad44-ceda960d5635', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'ally', 'Selina and Bruce''s relationship is the most emotionally complex in either character''s history — a decades-long negotiation between two people who understand each other too well to be easy.', 'Tom King''s run made their engagement and its collapse one of the era''s defining Batman storylines.'),
  ('deed414e-291b-5abe-9b37-ff0166a133cc', 'ba6e0e90-bee5-5088-b30a-9eb56df8fe0e', '89b546be-6991-54a1-a207-5fdafbd26ee7', 'ally', 'Chapel serves on Youngblood''s away division.', 'He executes the team''s most dangerous covert operations.'),
  ('43be1026-9a42-53e7-a2b6-9618eec49b16', '14696e46-299e-58f0-801d-c8e2df42ef87', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', 'enemy', 'The Cheetah is Wonder Woman''s most personal nemesis, a former friend turned obsessive predator.', 'Barbara Ann Minerva''s fall from friend to foe is central to Greg Rucka''s Rebirth-era Year One.'),
  ('3d626185-855d-51cb-aa38-f31d55f9cba3', '3c4082e1-3859-549a-a960-213fe1561bf3', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', 'enemy', 'Circe is an immortal sorceress who hates the Amazons and repeatedly schemes to destroy Wonder Woman.', 'Her machinations drive the line-wide War of the Gods crossover targeting Diana and Themyscira.'),
  ('61ca5482-2330-52dd-b420-0ed2b13f6629', 'c54a55aa-319d-57b6-9a52-dbe35d255a81', '7c004d0d-1535-57a7-9f09-ef7cf865a072', 'ally', 'Cogliostro mentors Al Simmons through the early days of his damnation.', 'He reveals the rules of necroplasm and the nature of the Hellspawn bargain.'),
  ('e3d89e51-3805-525e-b86f-6456f518861c', '9afcef8f-d470-5866-b0ae-2f4c597c32a7', 'ddc90de2-8e7d-5dd1-bde9-72646019ee2b', 'enemy', 'The Viltrumite enforcer who delivers Invincible''s most brutal defeat.', 'Conquest''s assault pushes Mark to the brink and escalates the series'' stakes dramatically.'),
  ('53515b30-4c77-5101-93d9-c92a84c3f9b3', '523b3b97-51a2-5f4c-a5a4-785316b20408', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'enemy', 'Crossbones is a relentless mercenary enforcer who repeatedly serves as the physical instrument of plots against Captain America.', 'As the Red Skull''s chief enforcer, he played the role of trigger man in The Death of Captain America.'),
  ('263f81d8-d9b1-548e-8639-a15c5f96335c', '969b933e-c61f-5070-9f28-08874232cf5f', '7786b507-312a-539d-8a23-29295e4b1a30', 'enemy', 'Cutter''s ruthless code puts him in violent opposition to Erica.', 'He would kill witnesses Erica fights to protect, making their conflict deeply personal.'),
  ('b4c95c74-5dc1-56d8-b532-719d6f1020c6', '2e60e526-80aa-5940-b950-3211d8e45eee', '4322fa09-0a88-5804-93f9-0fbf9175f54e', 'enemy', 'A monstrous schemer who repeatedly seizes power and torments Dragon across decades.', 'Cyberface evolves from underling to world-conquering threat, becoming one of Dragon''s most persistent foes.'),
  ('6dabd102-594f-594e-822f-9c15b70fd129', 'cd1d8c92-fd02-5109-a100-cab73f34b4c4', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', 'ally', 'Cyborg is a founding member of the New Teen Titans and one of its most steadfast heroes.', 'His Titans tenure predates his later Justice League membership.'),
  ('c4e4fd89-316d-59ef-85d3-b8ed6aeab716', 'be70c828-5b8f-5431-a529-20b5ca4371ef', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', 'ally', 'Cyclops is the X-Men''s founding member and longtime field leader.', 'The strategic and moral center of the team across eras.'),
  ('2465d44c-5a9a-5ed6-bef1-60915de08351', 'cb0c266f-1125-5c99-8a2b-6ae28743dca9', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', 'ally', 'Danny is Sara''s late partner whose spirit continues to guide her.', 'His death and lingering presence serve as a moral compass for Sara across the classic era.'),
  ('79f4e5e5-d5dd-52ac-a496-baf529b753ea', 'f878ca08-45b4-5eff-8cc1-617cabb5c42b', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'enemy', 'The galaxy-conquering tyrant whose invasion forged the modern League.', 'Among the team''s most dangerous recurring foes.'),
  ('ce452a93-37bf-5f9a-8391-b075df5457bb', '62eb906a-1df5-5cc2-97dd-873e0b5842a3', '89b546be-6991-54a1-a207-5fdafbd26ee7', 'enemy', 'Darkthornn is a recurring enemy of Youngblood.', 'His incursions escalate the team''s missions to cosmic scale.'),
  ('6383c8c3-2746-5b41-9cd8-42ea73079a2a', 'f2583e7b-114a-5d55-ab97-0984e1eccd83', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', 'enemy', 'Deathstroke is the Teen Titans'' signature archenemy, hunting them across generations.', 'His vendetta defines the New Teen Titans era.'),
  ('115e5c9c-c1e0-50d5-b6eb-641c2462ce2e', 'ef33d492-4f93-52fc-bfe8-b86b454eb253', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'ally', 'Batman trained Dick Grayson and shaped his entire heroic identity — a debt Dick has spent decades repaying by proving he can exceed the model.', 'Their relationship is the Batman family''s most emotionally complicated axis, defined by love, control, disappointment, and pride in about equal measure.'),
  ('ac507655-ed01-531b-8050-8a35bfc99fd7', 'c2d6b0c2-3e9a-56f9-bd37-b32a72dd1c7d', '89b546be-6991-54a1-a207-5fdafbd26ee7', 'ally', 'Diehard is a founding member of Youngblood.', 'He offers tactical leadership and a veteran''s perspective.'),
  ('2f8122fe-9df3-5384-bb16-9825f1fb1c82', '9b5ba614-a266-558f-aa96-db377463623e', '7554762e-8839-52ac-b0f4-03e2d44cda89', 'ally', 'Dixon acts as the Empty Man''s instrument among the living.', 'He carries the contagion forward and protects the faithful without hesitation.'),
  ('b483fe19-9e6d-56e3-95ba-831be80bffff', '3c5f0196-f609-537d-84f9-fd627af1ec2f', '7a66364d-547b-54c4-948e-de4f1d756d38', 'enemy', 'Doc Seismic''s planet-threatening schemes pit him against the Guardians.', 'His seismic attacks make him a recurring large-scale menace for the team.'),
  ('2f43a46c-2bcc-5f21-ba9c-a0860d0247f0', '73c0cf5c-4285-555b-9528-9baef6ff50ad', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', 'enemy', 'Doctor Octopus is Spider-Man''s most cerebral and persistent adversary.', 'Otto Octavius masterminded the ''Master Planner'' saga and later swapped minds with Peter to become the ''Superior Spider-Man.'''),
  ('63caba1d-0683-50e7-836c-f79cd91b42a0', '9b69f6c8-ec9a-52fd-b306-7d63305f8662', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', 'enemy', 'Doctor Poison is one of Wonder Woman''s oldest enemies, a chemist who wields deadly toxins against her.', 'First appearing in Sensation Comics #2 (1942), Doctor Poison is a founding member of Villainy Incorporated.'),
  ('930c1295-e58a-5da9-beca-4408a2f86a84', '46646717-ad59-58fe-b11c-5a2c94afdca4', '2530b133-d2b6-5355-86bd-7709a4d5d39e', 'enemy', 'Doomsday is the unstoppable creature that fought Superman to a mutual death, the only foe ever to kill him in single combat.', 'Their cataclysmic battle in The Death of Superman defines both characters and remains one of comics'' most famous duels.'),
  ('a3eac4ce-4409-5a04-a6c0-46b53aa9c5aa', '957f32fa-3926-509c-9983-994040b5e2ba', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', 'enemy', 'A deranged, prophetic vampire whose madness makes her an unpredictable threat to Buffy.', 'Driven insane long ago, Drusilla wields visions and cruelty as she menaces Buffy and her friends.'),
  ('90cdef57-f2e4-5da3-b62f-528332f801a3', 'c76e1fcc-bbee-55c1-9c65-e08b0069d8f3', '7a66364d-547b-54c4-948e-de4f1d756d38', 'ally', 'Dupli-Kate is a dependable member of the reformed Guardians.', 'Her duplication ability makes her a versatile field asset for the team.'),
  ('5aa44fe5-794b-58ee-aa45-4c36ff479193', 'b1bf0d33-b129-5c85-99cc-fa296bde3f3b', '7786b507-312a-539d-8a23-29295e4b1a30', 'enemy', 'Edwin''s authority over the Slaughter line threatens Erica''s hard-won freedom.', 'His ambitions for the house make him a dangerous obstacle to Erica''s independence.'),
  ('64e03c64-d963-5b1e-b9c8-f4781f5191ca', '7786b507-312a-539d-8a23-29295e4b1a30', '0ce552c3-1204-54bd-805c-27a3e9153de6', 'ally', 'The clandestine house that trained Erica as a monster hunter and supplied her bandanas and gear.', 'Erica is a product of the House of Slaughter, though her bond with it is fraught with rebellion and debt.'),
  ('92651ea6-d9a5-5586-b104-d124a157a6f8', '7786b507-312a-539d-8a23-29295e4b1a30', 'baad7ecb-7d52-5a70-b832-c4b4732b363a', 'ally', 'The teenage survivor of the Archer''s Peak attack who can see the monster and joins Erica''s hunt.', 'James becomes Erica''s reluctant partner and witness, anchoring her to the human cost of the work.'),
  ('b8231b0e-a2e6-5374-8c27-793a74f01b0e', '7786b507-312a-539d-8a23-29295e4b1a30', '5077371b-ec42-5e42-978e-c7d720a6ff1c', 'ally', 'A fellow operative of the House of Slaughter whose loyalties weave between the Order and Erica herself.', 'Aaron shares Erica''s lineage and training, making him both a potential ally and a complicated rival within the house.'),
  ('05c7c0d8-665d-5229-a1a6-ce652c540e72', '7786b507-312a-539d-8a23-29295e4b1a30', 'b63521f5-2a13-55a7-bcea-27fc760fc7b2', 'ally', 'An Archer''s Peak local drawn into the orbit of the killings who lends Erica aid during the hunt.', 'Jace represents the ordinary townsfolk whose lives are upended by monsters and by Erica''s arrival.'),
  ('be644411-0a0a-55dc-b744-67d68f707a02', '7786b507-312a-539d-8a23-29295e4b1a30', '020a1748-e513-5ace-b1d1-b411c03ff7d1', 'enemy', 'The unseen creature stalking the children of Archer''s Peak that Erica is contracted to destroy.', 'Visible only to certain children, the monster embodies the central threat Erica was trained to hunt.'),
  ('2fb227fd-7388-5a77-b4ed-cfafd43791ac', '7786b507-312a-539d-8a23-29295e4b1a30', '969b933e-c61f-5070-9f28-08874232cf5f', 'enemy', 'A ruthless hunter whose brutal philosophy puts him in violent opposition to Erica.', 'Cutter operates by a colder code, clashing with Erica over how monsters—and witnesses—should be handled.'),
  ('420dbfee-251a-5f35-96f4-2f001e0ff1d2', '7786b507-312a-539d-8a23-29295e4b1a30', 'b1bf0d33-b129-5c85-99cc-fa296bde3f3b', 'enemy', 'A senior figure of the Slaughter lineage whose authority and ambitions threaten Erica''s freedom.', 'Edwin''s stake in the House of Slaughter makes him a dangerous obstacle to Erica''s independence.'),
  ('72dfee6f-36eb-5661-bcf9-c0e6e6379cdc', '7786b507-312a-539d-8a23-29295e4b1a30', '2ca0f6bb-d5b2-50c6-81a7-c9beb04d4d7d', 'enemy', 'The vast secret organization that polices monster hunters and seeks to bring Erica back under control.', 'The Order prizes secrecy and obedience, putting its institutional will at odds with Erica''s defiance.'),
  ('15cf3c14-15c6-5101-983d-967ae791ced1', '3435af88-847a-586f-8c00-d1fe9dd6c158', '4322fa09-0a88-5804-93f9-0fbf9175f54e', 'ally', 'The lieutenant who recruited Dragon and championed him within the police department.', 'Frank''s early faith in Dragon gives the amnesiac hero a purpose and a home in Chicago.'),
  ('6e18f71e-e8a6-5dbc-8dc9-45052a0b4b24', '958eb5e9-3e62-5425-a491-e9291563bffd', '2530b133-d2b6-5355-86bd-7709a4d5d39e', 'enemy', 'Zod is Superman''s Kryptonian equal in power, a militaristic tyrant who believes he, not Kal-El, should command their people''s destiny.', 'From Phantom Zone schemes to the New Krypton war, Zod forces Superman to fight a foe who matches him blow for blow.'),
  ('7f155009-0fdd-5db9-b7a9-13d188e286ac', '6a5e6aa2-737a-53d6-bed1-a2e26f802777', '89b546be-6991-54a1-a207-5fdafbd26ee7', 'enemy', 'Giga is a recurring threat to Youngblood.', 'Its scale forces the team to coordinate both divisions.'),
  ('7a13d899-5f50-54d7-9815-f9ab6993c6a2', '8ff83210-4b2a-5819-9f95-69342e126100', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', 'ally', 'Gleason helps Sara interpret the impossible evidence her cases generate.', 'His forensic support anchors Sara''s supernatural investigations in real police science.'),
  ('d964eec0-6162-5465-8f7a-90f23cf8ba06', 'c19b3b7f-d0d0-5b8b-82c9-d7568fc281f7', '784afd7e-b4e8-547a-a63d-fdc8fa966fc6', 'enemy', 'The Green Ranger Goldar repeatedly battles in the field.', 'Goldar is a recurring physical antagonist throughout Tommy''s tenure.'),
  ('89bbea97-03b3-5101-aabf-0b9246732816', '01810fc2-2f93-5c21-b522-f232e59ac1ca', '448be678-268c-522f-9477-a07422c30fd0', 'enemy', 'Gorilla Grodd is a recurring nemesis whose telepathy and strength make him one of the Flash''s deadliest threats.', 'Grodd debuted in The Flash #106 (1959) and returned as a savage menace in Geoff Johns'' modern Flash run.'),
  ('bd1592b8-12bc-5541-bfcd-d24f8205d4cb', '587462a9-16e0-57f3-a1a6-84b0ce8c7f74', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'ally', 'The League''s outspoken everyman and social conscience.', 'Joined during the classic Satellite era.'),
  ('1f6db561-64bb-561f-b218-600d7157f84b', '2bf45ce8-3c51-51de-8b48-94d766ee72dd', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', 'enemy', 'The Green Goblin is Spider-Man''s most personal and destructive archenemy.', 'Knowing Peter''s secret identity, Norman Osborn has repeatedly attacked the hero''s loved ones, most infamously in ''The Night Gwen Stacy Died.'''),
  ('917dbd52-0678-54c5-84f1-c7981ca20519', 'a8434c59-8838-500a-a059-d60b3b33a59e', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'ally', 'Hal Jordan is a founding member of the Justice League and its resident space-faring powerhouse.', 'Hal joined in the team''s earliest adventures (The Brave and the Bold #28, 1960) and has served across countless rosters as the League''s cosmic specialist.'),
  ('8b2f0188-2670-5ce1-b3b8-70522f98fa3a', 'a8434c59-8838-500a-a059-d60b3b33a59e', '448be678-268c-522f-9477-a07422c30fd0', 'ally', 'Hal and Barry Allen are the closest of friends, the twin pillars of the Silver Age and the heart of the Justice League.', 'Their friendship is a cornerstone of DC lore; Barry was among those who never gave up on Hal and helped welcome him back in Green Lantern: Rebirth.'),
  ('5cb9e4e3-f94d-55e9-ba03-185f161494ef', 'a8434c59-8838-500a-a059-d60b3b33a59e', '2530b133-d2b6-5355-86bd-7709a4d5d39e', 'ally', 'Hal stands beside Superman as a fellow founder of the Justice League and trusted teammate.', 'The two have clashed and reconciled many times; Superman supported Hal''s reinstatement during Green Lantern: Rebirth despite the carnage of Emerald Twilight.'),
  ('61f81311-5c49-57c8-a539-01d00cdbbe29', 'a8434c59-8838-500a-a059-d60b3b33a59e', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'ally', 'Hal and Batman are uneasy allies whose differing temperaments make for a famously prickly partnership.', 'Batman distrusted Hal after Parallax, and the two have repeatedly butted heads over willpower and discipline, including a memorable jaw-breaking exchange in Green Lantern: Rebirth.'),
  ('bf6bcfe6-2ed4-506d-ad5c-9e801618b488', 'a8434c59-8838-500a-a059-d60b3b33a59e', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', 'ally', 'Hal serves alongside Wonder Woman as a fellow Justice League stalwart.', 'The two have fought side by side through major League crises, including the cosmic events surrounding Blackest Night.'),
  ('c9e973c6-9c42-5941-96a2-7799fa4526f3', 'a8434c59-8838-500a-a059-d60b3b33a59e', '2a1b8c6d-9df0-53b2-afb7-33330b4bde2c', 'enemy', 'Sinestro is Hal''s archenemy, a former Green Lantern turned master of fear.', 'Introduced in Green Lantern #7 (1961), Sinestro escalated from a yellow-ring renegade to the architect of the Sinestro Corps War, the dark mirror of Hal''s own discipline.'),
  ('9f35e9b8-f4bd-58ff-b53f-835c82bb1649', 'a8434c59-8838-500a-a059-d60b3b33a59e', '0592afef-f365-56b1-9f86-5fe1d601e77e', 'enemy', 'Parallax is the cosmic entity of fear that corrupted Hal and turned him against the Corps.', 'Revealed in Green Lantern: Rebirth (2004) as the parasite behind Emerald Twilight, Parallax remains the embodiment of the fear that Hal''s will must constantly overcome.'),
  ('aa7318e9-3e7d-59fc-80c4-2c111b919eae', 'a8434c59-8838-500a-a059-d60b3b33a59e', '77db7ea3-8ed7-5273-add1-d93259b39938', 'enemy', 'Atrocitus is the rage-fueled leader of the Red Lantern Corps and a recurring threat to Hal.', 'Created by Geoff Johns and introduced in the Rage of the Red Lanterns prelude (2008), Atrocitus blames the Guardians and their Lanterns for the slaughter of his people.'),
  ('131d7b03-ff58-58c6-91ac-faf37e7fde70', 'a8434c59-8838-500a-a059-d60b3b33a59e', 'c97ff53b-f9dd-5c73-a8c2-fe3b40b6353c', 'enemy', 'Hector Hammond is a psychic megalomaniac obsessed with Hal''s ring and with Carol Ferris.', 'Debuting in Green Lantern #5 (1960), the evolved Hammond is one of Hal''s earliest and most persistent foes, attacking the mind rather than the body.'),
  ('85e82b95-fb26-5843-ad68-ddd3e510220f', '7a66364d-547b-54c4-948e-de4f1d756d38', 'ddc90de2-8e7d-5dd1-bde9-72646019ee2b', 'ally', 'Invincible works alongside the Guardians repeatedly and becomes one of Earth''s most reliable defenders.', 'Mark Grayson''s path intertwines with the team from its earliest days, often fighting beside them against world-ending threats.'),
  ('38830db7-6d42-556b-b443-34ef9a2041fc', '7a66364d-547b-54c4-948e-de4f1d756d38', '65cb3481-4f7e-5599-8b71-78e119c216d3', 'ally', 'The Immortal is a longtime leader and anchor of the Guardians across multiple incarnations.', 'His millennia of experience make him the steady backbone of both the original and reformed teams.'),
  ('84b50d6a-0693-5e20-90a8-56aa8fb58cb7', '7a66364d-547b-54c4-948e-de4f1d756d38', '1d2e2e20-67a0-5ff6-b32e-f27309a51253', 'ally', 'Atom Eve is among the most powerful members associated with the team and a key ally in crises.', 'Her matter-manipulation abilities make her invaluable in the team''s largest battles.'),
  ('d7b87b56-9850-5484-a701-256598d937f0', '7a66364d-547b-54c4-948e-de4f1d756d38', 'ee1e4f5e-6664-5a73-aa9b-e4da8f5771d2', 'ally', 'Robot serves as a strategist and organizer central to rebuilding the team after its collapse.', 'His intellect and resources help reconstitute the Guardians into a functioning institution.'),
  ('f0d17c3c-ffb4-5638-8f1d-458d101bdb09', '7a66364d-547b-54c4-948e-de4f1d756d38', '3c5f0196-f609-537d-84f9-fd627af1ec2f', 'enemy', 'Doc Seismic threatens the planet with seismic catastrophe, drawing the Guardians into direct conflict.', 'His earth-shaking schemes make him a recurring large-scale menace the team must contain.'),
  ('f07c2a8a-cb78-5b02-a810-804d0a3b6ee5', '7a66364d-547b-54c4-948e-de4f1d756d38', 'dfc637b9-6e5c-599c-9fe6-b1fe299d1669', 'enemy', 'The Lizard League is a recurring criminal organization the Guardians repeatedly dismantle.', 'Their reptilian-themed operatives stage attacks that demand a coordinated team response.'),
  ('303a47ed-0f00-5483-b3a5-a91ca109e4fb', '7a66364d-547b-54c4-948e-de4f1d756d38', '4cd10521-bed3-5ec1-b7d1-8edc1f5a5d11', 'enemy', 'Machine Head''s criminal empire pits organized super-crime against the Guardians.', 'As a crime lord commanding numerous super-powered enforcers, he is a persistent strategic threat.'),
  ('b946735d-b578-54cc-9fb7-e2102534026c', '7a66364d-547b-54c4-948e-de4f1d756d38', '86a41202-7aff-5ac9-8b83-d2f5d4b54fed', 'enemy', 'The Mauler Twins repeatedly clash with the team through their schemes and cloning technology.', 'Their genius-level intellect and self-cloning make them an unpredictable recurring danger.'),
  ('d978be49-436e-5895-9da3-131a84c8df04', 'a16e772f-3014-5979-a4f7-94e95fa78e9c', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'ally', 'A long-serving Avenger whose marksmanship and grit let him stand alongside the team''s most powerful members.', 'He reformed from an early adversary into one of the team''s most enduring fixtures.'),
  ('d4c9a1f5-51d0-5968-a192-f9cd332a3ada', 'c97ff53b-f9dd-5c73-a8c2-fe3b40b6353c', 'a8434c59-8838-500a-a059-d60b3b33a59e', 'enemy', 'Hector Hammond is a recurring psychic nemesis obsessed with Hal Jordan''s ring and Carol Ferris.', 'Debuting in Green Lantern #5 (1960), Hammond attacks Hal''s mind and willpower, making him one of the hero''s oldest and most distinctive foes.'),
  ('e3a73292-26be-5157-99d1-c26f6e8be825', 'a1645541-25a2-527e-93d9-b087dbf5890a', 'de8ec54e-9f19-561c-bcb0-a114f019363c', 'enemy', 'Hela repeatedly seeks to claim Thor''s soul and deny him an honorable death, making her one of his deadliest foes.', 'Her infamous curse of brittle bones in Walter Simonson''s run is among the cruelest fates ever inflicted on the Thunder God.'),
  ('e03df451-2857-5f39-8872-581bfa2523c6', '0ce552c3-1204-54bd-805c-27a3e9153de6', '7786b507-312a-539d-8a23-29295e4b1a30', 'ally', 'Erica is the House''s most formidable hunter and its central figure.', 'Raised within the order, she remains bound to it even as her conscience pulls her away from its rules.'),
  ('e987dd64-fca7-5c4e-b491-bf879c78abb1', '0ce552c3-1204-54bd-805c-27a3e9153de6', '5077371b-ec42-5e42-978e-c7d720a6ff1c', 'ally', 'Aaron is a high-ranking operative whose loyalty to the House is complicated by ambition.', 'He grew up alongside Erica and rose through the masks, becoming a power broker within the order.'),
  ('72e2e72d-7969-5e2c-a549-1b26f4f51b36', '0ce552c3-1204-54bd-805c-27a3e9153de6', 'b63521f5-2a13-55a7-bcea-27fc760fc7b2', 'ally', 'Jace is a devoted hunter who serves the House''s missions in the field.', 'His faith in the order is tested when an assignment''s true purpose is hidden from him.'),
  ('cf2faf1d-7fce-57f5-8f04-1e9bec3909b4', '0ce552c3-1204-54bd-805c-27a3e9153de6', 'c574c3b8-581d-56a5-95bd-6ac9f05e58c1', 'ally', 'Bautista is a seasoned member of the Slaughter line who upholds the order''s traditions.', 'He represents the steadier, old-guard hunters who keep the House''s machinery running.'),
  ('0db17eb3-b489-5cb2-8196-00aecd8863e1', '0ce552c3-1204-54bd-805c-27a3e9153de6', '2ca0f6bb-d5b2-50c6-81a7-c9beb04d4d7d', 'enemy', 'A rival monster-hunting authority whose methods and aims clash with the House.', 'The two organizations vie over jurisdiction and philosophy in the hidden war against monsters.'),
  ('373ef1cd-047a-57ce-9162-c3d50208a488', '0ce552c3-1204-54bd-805c-27a3e9153de6', 'b1786fae-ce5d-5cfa-bfea-19b3b6ba84a4', 'enemy', 'A corrupted faction wielding the order''s highest authority against its own.', 'Those who hold ultimate rank can turn the House''s power inward, threatening dissenting hunters.'),
  ('cb51ebf0-6c21-5466-b430-a443f46224aa', '0ce552c3-1204-54bd-805c-27a3e9153de6', '969b933e-c61f-5070-9f28-08874232cf5f', 'enemy', 'A dangerous adversary who stalks the House''s hunters in the field.', 'Cutter embodies the lethal threats that even trained members of the order struggle to survive.'),
  ('053cdd61-c7be-5530-9267-c94de382e94f', '0ce552c3-1204-54bd-805c-27a3e9153de6', '020a1748-e513-5ace-b1d1-b411c03ff7d1', 'enemy', 'The unseen creatures the House was founded to destroy.', 'Invisible to most people, these monsters are the eternal reason the order exists.'),
  ('f24f3ff2-7d32-5e0a-b2d1-b9f1cd3c6f5f', '9d16c1a7-8edc-51c7-8a4d-00f28e78ab0a', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'ally', 'A founding member of the Avengers whose immense strength has saved the team many times.', 'Though his volatility led to an early departure, he remains tied to the team''s origin and history.'),
  ('25dbb1b4-c03d-5f2a-afc2-21fc8f9ff6a4', '61fa87f0-8567-588c-a50f-30857c065c7b', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', 'enemy', 'Nottingham is Irons'' enforcer ordered to hunt Sara, yet obsessively drawn to her.', 'His divided loyalty makes him a tragic and unpredictable threat to Sara.'),
  ('e8f5faeb-9d02-541d-86b4-71a303b8bd5f', 'ddc90de2-8e7d-5dd1-bde9-72646019ee2b', '7a66364d-547b-54c4-948e-de4f1d756d38', 'ally', 'Earth''s premier super-team that Invincible repeatedly fights alongside and eventually counts among his closest allies.', 'Mark works with successive incarnations of the team throughout his career, often coordinating responses to global and cosmic threats.'),
  ('760b0e18-06a2-519f-9390-55ac573fb678', 'ddc90de2-8e7d-5dd1-bde9-72646019ee2b', '6a03558f-184a-5db6-a341-0c6f4fad2eab', 'ally', 'Mark''s father, whose complicated legacy defines Invincible''s journey from adversary to uneasy ally.', 'After a violent estrangement, the two ultimately stand together against the Viltrumite Empire.'),
  ('6775b436-0dae-571b-ae5b-686427e68cd3', 'ddc90de2-8e7d-5dd1-bde9-72646019ee2b', '1d2e2e20-67a0-5ff6-b32e-f27309a51253', 'ally', 'A powerful matter-manipulating hero and Mark''s most steadfast partner in life and battle.', 'Eve''s reality-bending abilities and emotional support are central to Mark''s survival through his hardest trials.'),
  ('c2d458e6-f80e-58e7-912f-0a34a846856f', 'ddc90de2-8e7d-5dd1-bde9-72646019ee2b', 'ee1e4f5e-6664-5a73-aa9b-e4da8f5771d2', 'ally', 'A brilliant strategist and longtime teammate whose technological genius repeatedly aids Invincible.', 'Robot leads team operations and provides tactical resources, though his methods grow increasingly questionable over time.'),
  ('71b67bec-3b28-5250-9402-4a5c7d7c0bea', 'ddc90de2-8e7d-5dd1-bde9-72646019ee2b', '9afcef8f-d470-5866-b0ae-2f4c597c32a7', 'enemy', 'A merciless Viltrumite enforcer who delivers the most punishing beating of Invincible''s life.', 'Conquest''s arrival escalates the series into life-or-death stakes and tests Mark''s resolve to its limit.'),
  ('b67cc280-57d9-5873-93cd-68320aa4638f', 'ddc90de2-8e7d-5dd1-bde9-72646019ee2b', '559e093e-4477-566a-abce-9ade8afe79c8', 'enemy', 'A dimension-hopping genius whose personal vendetta against Invincible spans countless realities.', 'Angstrom blames Mark for an accident and pursues relentless, escalating schemes across the multiverse.'),
  ('ee86de98-f518-56ca-94d4-0f12f879c223', 'ddc90de2-8e7d-5dd1-bde9-72646019ee2b', '4cd10521-bed3-5ec1-b7d1-8edc1f5a5d11', 'enemy', 'A ruthless crime lord who controls much of the city''s underworld and clashes with Invincible.', 'Machine Head commands armies of hired villains and represents the grounded, street-level threats Mark must manage.'),
  ('84e3ef9a-09af-5817-bad5-304fc0093921', 'ddc90de2-8e7d-5dd1-bde9-72646019ee2b', '86a41202-7aff-5ac9-8b83-d2f5d4b54fed', 'enemy', 'A pair of cloning super-geniuses whose recurring schemes repeatedly entangle Invincible.', 'Forever arguing over which is the original, the Maulers'' technology causes chaos that Mark must clean up.'),
  ('d60061b0-a00f-5177-b92a-431a709032aa', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'ally', 'Tony Stark and Steve Rogers are the twin pillars of the Avengers, bound by mutual respect despite clashing worldviews.', 'Their friendship famously fractured into open conflict during the superhero Civil War over the Superhuman Registration Act.'),
  ('c3a9efd4-0192-500c-b30b-b869bbec053c', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', 'de8ec54e-9f19-561c-bcb0-a114f019363c', 'ally', 'Iron Man fights alongside the God of Thunder as a founding Avenger, balancing science against Thor''s mysticism.', 'Together with Ant-Man, Wasp, and Hulk, they founded the Avengers in The Avengers #1 (1963).'),
  ('475fad2e-ed0a-5a89-872d-21772cdf66d5', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', 'ally', 'Tony becomes a mentor and benefactor to the young Spider-Man, providing technology and guidance.', 'During Civil War, Iron Man designed the Iron Spider armor for Peter Parker before their alliance was tested by the Registration Act.'),
  ('83f3a1a1-2810-575b-b3df-212a12e5465c', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'ally', 'Iron Man is a founding member, frequent financier, and recurring leader of Earth''s Mightiest Heroes.', 'He bankrolled Avengers Mansion through the Maria Stark Foundation and has led numerous incarnations of the team.'),
  ('f1976c6b-2661-5b14-9712-31ca3caba894', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', '29db753d-37a2-5ec6-90da-bae6daeed5d4', 'enemy', 'The Mandarin is Iron Man''s archnemesis, a brilliant warlord whose ten alien power rings rival Stark''s technology.', 'First appearing in Tales of Suspense #50 (1964), he represents an ancient, mystical counterpoint to Tony''s modern science.'),
  ('a447ba58-13c7-58b9-809a-963b0b9ab258', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', '976abf28-99fc-5073-80fc-0b26f69b73d3', 'enemy', 'Obadiah Stane is the ruthless corporate raider who orchestrated Tony''s downfall and seized his company.', 'His psychological warfare against Stark drove the events surrounding Demon in a Bottle and led to the creation of the Iron Monger armor.'),
  ('bdec032f-acc8-5074-b304-00e400202870', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', 'f0271d65-dd6d-55e6-af3c-518db63b89fd', 'enemy', 'Whiplash is a recurring armored mercenary who battles Iron Man with high-tech energy whips.', 'Debuting in Tales of Suspense #97 (1968), the identity has been worn by several villains, including Mark Scarlotti and Anton Vanko.'),
  ('8e395f1c-4130-5ded-ad3b-5519616b9f12', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', '1f126a7b-ee19-5ae2-bc70-44d7d3b37f64', 'enemy', 'Ultron is the genocidal artificial intelligence whose existence Iron Man feels deeply responsible for combating.', 'Though created by Hank Pym, Ultron''s threat became central to Iron Man''s fears about AI, culminating in events like Age of Ultron.'),
  ('48b7f9d0-7fa5-56e5-9d21-92e31234282e', 'b63521f5-2a13-55a7-bcea-27fc760fc7b2', '7786b507-312a-539d-8a23-29295e4b1a30', 'ally', 'Jace aids Erica as the killings sweep through Archer''s Peak.', 'He represents the ordinary residents whose lives are upended by the hunt.'),
  ('3a1a4b13-971b-5c47-a68f-9bbf683cb98e', 'bffd2788-f7ee-5c11-98b0-47612d6a468b', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', 'enemy', 'As bearer of the Darkness, Jackie is the cosmic counterpart whose path repeatedly clashes with Sara''s.', 'Their bond as wielders of opposing primal forces swings between conflict and uneasy alliance.'),
  ('a9c5ee5c-a63d-522c-84e9-63e1c1dcdf93', '2939c01b-6e85-5e58-b250-e29d6afb5b8d', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', 'ally', 'Jake is Sara''s trusted NYPD partner who backs her through her most dangerous cases.', 'He stands by Sara even as her work pulls them both into supernatural conflict.'),
  ('f6e41f2e-b94d-50bf-a89c-79a180522563', 'baad7ecb-7d52-5a70-b832-c4b4732b363a', '7786b507-312a-539d-8a23-29295e4b1a30', 'ally', 'Erica takes James under her protection and relies on his ability to see the monster.', 'Their partnership grounds Erica''s hunt in the human stakes of Archer''s Peak.'),
  ('189ca424-a6be-52b2-99b5-e0873e2fc800', '16c71808-cd7a-588a-8f41-653051d42c23', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'ally', 'Gordon''s partnership with Batman is the architecture of Gotham''s fragile safety net — a deliberate, mutually useful arrangement that neither party has ever formalized.', 'The Bat-Signal on GCPD rooftop represents the public face of a relationship built on productive ambiguity.'),
  ('3cf3982d-3866-5261-9720-0ce5042aae73', 'dcc0b1e2-6bc8-506d-8d00-599cb1e9383b', 'b23f30f2-61cd-515a-a3e8-f07f14502f2d', 'ally', 'Jason is the founding leader of the Power Rangers.', 'His command and conviction form the backbone of the team.'),
  ('2cb5e019-92fa-5f33-bd49-c661f6355c6e', '9332422c-3ea9-54d6-8e3f-305a4b2d0f0c', '7c004d0d-1535-57a7-9f09-ef7cf865a072', 'enemy', 'Wynn ordered Al Simmons'' murder, igniting Spawn''s quest for vengeance.', 'He is Spawn''s chief human antagonist and a symbol of earthly corruption.'),
  ('29808236-3cd3-59ba-97db-582a75798952', 'f743dec3-c799-5685-82f8-db313aa431b8', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', 'ally', 'Jean Grey is a founding member and emotional core of the X-Men.', 'Her Phoenix bond ties her to the team''s greatest triumphs and tragedies.'),
  ('7d60bddc-d9c7-5818-a719-48032879208c', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'ally', 'A founding pillar of the modern League and its premier strategist.', 'Often the team''s tactical planner and contingency-minded conscience.'),
  ('b9991971-8bd8-5c67-9dc6-3c1e97532bef', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', '2530b133-d2b6-5355-86bd-7709a4d5d39e', 'ally', 'The moral heart and frequent field leader of the League.', 'Embodies the team''s ideals and anchors its public image.'),
  ('e117d4e6-0950-5a6f-a65d-5fd15b973bba', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', 'ally', 'A founding member and the League''s foremost warrior-diplomat.', 'Bridges the team''s combat power and its principles of justice.'),
  ('28af3ac7-0877-5e36-9c1a-06afd4b8c049', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', '448be678-268c-522f-9477-a07422c30fd0', 'ally', 'An original founder whose speed makes him the team''s first responder.', 'Present at the very first assembly against Starro.'),
  ('6a0f8e0a-ef35-57b3-a6ce-8154fe471fb7', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'a8434c59-8838-500a-a059-d60b3b33a59e', 'ally', 'A founding member linking the League to the cosmic Green Lantern Corps.', 'Provides interstellar reach and willpower-driven firepower.'),
  ('420b4f4a-faf0-5544-bb0a-4170e8ad5439', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', 'ally', 'The junior counterpart team, often allied with the League in crises.', 'Many Titans graduate into League membership over time.'),
  ('fb90a5be-d9a1-5eca-a6a1-43f8533d48eb', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'f878ca08-45b4-5eff-8cc1-617cabb5c42b', 'enemy', 'The tyrant of Apokolips whose invasion forged the modern League.', 'One of the team''s greatest and most recurring existential threats.'),
  ('7d3d2fff-b7bd-536f-b493-ef5bda05af39', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'e305af9b-4cc3-5518-89e6-f43963628ebe', 'enemy', 'Criminal mastermind who founds villainous coalitions to oppose the League.', 'Architect of the Injustice League and Secret Society.'),
  ('66fb840c-c59e-5381-a8a8-9d7da3f37bd9', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'c176cf47-e3aa-5124-96a3-c40653063787', 'enemy', 'A coldly logical alien intelligence that menaces the whole DC Universe.', 'Collector of worlds whose schemes repeatedly draw in the League.'),
  ('4f40d135-006e-5b2c-910c-12913f36aff1', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', '4b010e1a-5893-5779-942b-f5c94d6fe793', 'enemy', 'The mind-controlling alien conqueror the League first formed to stop.', 'A signature recurring menace dating to the team''s debut.'),
  ('90c29fd0-e59b-53ca-a647-1c4ddb5acd0a', '74817bfe-b087-5d7b-83ac-2aea450e5656', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'enemy', 'Kang has battled the Avengers across the timestream in some of their longest and most complex conflicts.', 'His mastery of time travel makes him a uniquely persistent and unpredictable adversary.'),
  ('3b37fd02-d457-539a-8961-a4311382ed96', '62974dbb-5bfc-5c10-a11a-ffecb2d03a80', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', 'enemy', 'Irons orchestrated Sara''s bonding with the Witchblade to control it through her.', 'He is Sara''s primary antagonist across the classic run, manipulating events for centuries.'),
  ('f9fe96c8-a92e-5446-b7e6-c187794add25', '9677b8cd-620c-5f15-815b-bc307efe9501', 'b23f30f2-61cd-515a-a3e8-f07f14502f2d', 'ally', 'Kimberly is a founding member and emotional anchor of the Power Rangers.', 'Her compassion and judgment hold the team together.'),
  ('25e17bbb-9300-51a6-9395-fd0bb38ab2f2', '95c4e2f0-5988-54e7-9a18-95554586cc1f', '411d9474-16b6-5c50-a3fa-36f22c778276', 'enemy', 'Lady Deathstrike is a cyborg warrior obsessed with reclaiming the adamantium she believes Logan stole.', 'She remade her body with adamantium and blades specifically to match and kill Wolverine, blaming him for desecrating her father''s legacy.'),
  ('8f7fd6af-9405-5517-a4e3-cb79e10ce7ce', 'e305af9b-4cc3-5518-89e6-f43963628ebe', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'enemy', 'The criminal mastermind who repeatedly organizes villains against the League.', 'Founder of the Injustice League and Secret Society of Super-Villains.'),
  ('b6cf3492-2de4-5fe5-bcff-969f7e61cf01', '1f49fb7c-fb73-52ec-8ba2-e5bf8b640f09', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'enemy', 'Loki''s scheme against Thor inadvertently created the Avengers, and he has plotted against them ever since.', 'He holds the unique distinction of being the foe responsible for the team''s formation.'),
  ('01827d7c-532f-5c07-a5aa-dee01f3db12d', '62d3ff58-5877-5948-afd9-512ee5eb96a9', '784afd7e-b4e8-547a-a63d-fdc8fa966fc6', 'enemy', 'The prime Tommy whom Drakkon represents as a dark, conquering alternate self.', 'Drakkon is the central villain of Shattered Grid and Tommy''s literal dark mirror.'),
  ('1e56118f-b65e-5409-9d04-ad7d56408455', 'a60dcbe3-6f65-5d40-9806-6cb0c90c5c29', '784afd7e-b4e8-547a-a63d-fdc8fa966fc6', 'enemy', 'The Green Ranger who stands against Zedd''s campaign of conquest.', 'Zedd represents a colder, more strategic threat than Rita.'),
  ('3b3ab6e7-d94f-5576-8552-6518e52f7971', 'ad8850b8-8aec-5819-bba1-9a55932f4612', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'ally', 'Lucius provides the material and financial foundation that makes Batman operationally possible — the unacknowledged logistics behind every piece of equipment.', 'The degree to which Lucius formally knows Bruce is Batman varies by continuity; in Nolan''s films he knows completely.'),
  ('1ad69761-684a-57cf-831b-bc80b016df81', '4cd10521-bed3-5ec1-b7d1-8edc1f5a5d11', 'ddc90de2-8e7d-5dd1-bde9-72646019ee2b', 'enemy', 'A crime lord whose underworld empire repeatedly puts him at odds with Invincible.', 'Machine Head''s hired villains keep Mark fighting battles on the ground as well as in the stars.'),
  ('863a2f7e-677e-5579-8b10-2d649070bd1b', '0882f404-5e91-5e5f-ab13-effa153e4492', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', 'enemy', 'Magneto is the X-Men''s defining adversary, opposing Xavier''s dream with the conviction that mutants must rule.', 'Archenemy who has occasionally fought alongside the team.'),
  ('ea042a4a-f532-5478-9817-7966d502b21e', 'e04135bf-0e34-5add-8c14-e9c345b1fae2', '7c004d0d-1535-57a7-9f09-ef7cf865a072', 'enemy', 'Malebolgia is the demon lord who damned Al and commands him from Hell.', 'He is the architect of Spawn''s curse and the target of his rebellion.'),
  ('e8497b48-44c1-5b92-a20e-db1bde582697', 'c87a39f2-008e-57ba-9fa5-e93d2da2d911', 'de8ec54e-9f19-561c-bcb0-a114f019363c', 'enemy', 'Malekith''s ambitions repeatedly bring him into conflict with Thor, culminating in an all-consuming war for the Nine Realms.', 'He served as the central antagonist of Jason Aaron''s run, escalating into the warlord of War of the Realms (2019).'),
  ('bb62a498-1ab3-510b-8bcd-b9c6a0789e00', '67852c9d-4ede-5e29-959f-5d58f6dd2255', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'ally', 'A founding member and the steadfast heart of the team.', 'Original founder and one of its longest-serving leaders.'),
  ('719dc9ce-18d5-5151-b60f-2d2722365483', '4621bf98-c20c-5812-ad91-16eff4826513', '4322fa09-0a88-5804-93f9-0fbf9175f54e', 'enemy', 'A diminutive alien mastermind whose interdimensional schemes target Dragon.', 'Mister Glum''s plots draw Dragon into conflicts far beyond Chicago''s streets.'),
  ('6b67be0d-d690-5577-849e-3e0be905b30a', 'f671ab1f-e733-51ec-818a-82ed22652b8a', '411d9474-16b6-5c50-a3fa-36f22c778276', 'enemy', 'Mister Sinister is a genetic manipulator whose obsession with mutant DNA repeatedly sets him against Logan and the X-Men.', 'His Marauders carried out the Mutant Massacre and his cloning schemes have ensnared Wolverine and his allies for decades.'),
  ('258e8017-6c18-57c5-b97e-1d0a606ed439', '6d3b22e4-ecd2-569b-b088-750d3beb5c95', '7554762e-8839-52ac-b0f4-03e2d44cda89', 'enemy', 'Monica opposes the Empty Man after it touches her own family.', 'Her personal loss makes her both a fierce opponent and a vulnerable target.'),
  ('4686e673-092f-5faf-b46a-685eef01e20e', '56ff7566-933b-58c5-a916-a526373f5076', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', 'enemy', 'Mystique has repeatedly targeted the X-Men through her Brotherhood and her gift for impersonation.', 'Allegiances shift, but she is most often a dangerous adversary.'),
  ('7b147b2a-41e5-5caa-a4e1-1b16e0b9da8b', '0b1f9dae-3b8b-50eb-9e6e-dcf3208d3996', '7c004d0d-1535-57a7-9f09-ef7cf865a072', 'ally', 'Nyx lends her magical expertise to Spawn''s crusade.', 'She fights alongside Spawn against supernatural threats in the modern era.'),
  ('ce92f118-1bd0-53ab-82c1-2b29443a2cea', '976abf28-99fc-5073-80fc-0b26f69b73d3', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', 'enemy', 'Obadiah Stane is the corporate raider who seized Tony Stark''s company and built the Iron Monger to destroy him.', 'His psychological warfare is closely tied to the events surrounding Tony''s struggle with alcoholism.'),
  ('ab641e40-9da0-55ad-8802-a0a193db164c', '39a095b5-92fa-558e-9fa8-297e694171e5', '411d9474-16b6-5c50-a3fa-36f22c778276', 'enemy', 'Omega Red is a Soviet super-soldier whose deadly powers and shared past make him one of Logan''s fiercest enemies.', 'Their connection runs through the Carbonadium Synthesizer and Wolverine''s Cold War-era covert missions.'),
  ('eed9de1b-9d03-5b25-a5c0-d6149055f206', '6a03558f-184a-5db6-a341-0c6f4fad2eab', 'ddc90de2-8e7d-5dd1-bde9-72646019ee2b', 'ally', 'His son and eventual battlefield ally against the empire that sent him to Earth.', 'Their relationship moves from idolization through betrayal to hard-won reconciliation.'),
  ('0d46f349-4e3c-56ef-930c-7f5172050c39', '3168c6d7-6c83-5cf1-b287-da914c7d1f7c', '4322fa09-0a88-5804-93f9-0fbf9175f54e', 'enemy', 'The armored crime lord who serves as Dragon''s foundational nemesis.', 'Overlord''s control of Chicago''s underworld makes him the defining villain of Dragon''s first cases.'),
  ('8cc63833-e5e2-5ef1-a977-90770ce78224', '5ab96773-d320-5296-9110-d63c607a0ee2', '89b546be-6991-54a1-a207-5fdafbd26ee7', 'enemy', 'Overtkill is a recurring foe of Youngblood.', 'His raw firepower forces the team to fight at full strength.'),
  ('6bf1bbc2-9497-5378-a030-8941fcbab9ef', '0592afef-f365-56b1-9f86-5fe1d601e77e', 'a8434c59-8838-500a-a059-d60b3b33a59e', 'enemy', 'Parallax is the fear entity that corrupted Hal Jordan and remains the embodiment of the fear he must overcome.', 'From Emerald Twilight (1994) through Green Lantern: Rebirth (2004), Parallax represents the internal enemy at the heart of Hal''s mythology.'),
  ('88ad334d-1c4e-599d-a9a0-f2fbafc64ccf', 'b23f30f2-61cd-515a-a3e8-f07f14502f2d', '784afd7e-b4e8-547a-a63d-fdc8fa966fc6', 'ally', 'The Green and later White Ranger, Tommy is the team''s most storied warrior and eventual leader.', 'Once turned against the Rangers by Rita, Tommy earned his place through repeated sacrifice and became the heart of the team.'),
  ('088faee8-5654-588a-9d10-535f8f383180', 'b23f30f2-61cd-515a-a3e8-f07f14502f2d', 'dcc0b1e2-6bc8-506d-8d00-599cb1e9383b', 'ally', 'The original Red Ranger and the team''s founding leader.', 'Jason''s discipline and sense of duty hold the team together through its earliest and hardest battles.'),
  ('8ff993a2-825a-5f60-acde-95ce7d1cbc77', 'b23f30f2-61cd-515a-a3e8-f07f14502f2d', '9677b8cd-620c-5f15-815b-bc307efe9501', 'ally', 'The Pink Ranger, whose agility and compassion balance the team.', 'Kimberly''s bond with Tommy and her steady judgment make her a moral anchor for the Rangers.'),
  ('e64c5838-af1b-5425-9040-61fa59e8c3d8', 'b23f30f2-61cd-515a-a3e8-f07f14502f2d', '8e1ef9a0-54ee-5617-9109-d7b2c965a107', 'ally', 'The Blue Ranger and the team''s brilliant technologist.', 'Billy''s inventions and analytical mind repeatedly turn the tide when raw power is not enough.'),
  ('85a71ff8-8ec1-537e-855d-ba4e9a4a73ce', 'b23f30f2-61cd-515a-a3e8-f07f14502f2d', '46ce85d8-b615-5195-825a-b79f1d802603', 'enemy', 'The space witch whose schemes first forced Zordon to summon the Rangers.', 'Rita''s relentless monster-making and psychological warfare define the team''s earliest existential threats.'),
  ('830c756f-aa62-5829-ad37-5a0522749005', 'b23f30f2-61cd-515a-a3e8-f07f14502f2d', 'a60dcbe3-6f65-5d40-9806-6cb0c90c5c29', 'enemy', 'The Emperor of Evil, a far colder and more powerful menace than Rita.', 'Zedd''s arrival raises the stakes for the Rangers, threatening Angel Grove with conquest rather than mere chaos.'),
  ('4e21d24b-4ad2-5e5a-9361-4dd8ce7c2c44', 'b23f30f2-61cd-515a-a3e8-f07f14502f2d', 'c19b3b7f-d0d0-5b8b-82c9-d7568fc281f7', 'enemy', 'The winged warrior and loyal enforcer of Rita and Zedd.', 'Goldar is the Rangers'' most persistent hand-to-hand adversary, returning again and again for vengeance.'),
  ('510704e7-ad34-5481-a0a9-48e3f6759498', 'b23f30f2-61cd-515a-a3e8-f07f14502f2d', '62d3ff58-5877-5948-afd9-512ee5eb96a9', 'enemy', 'An alternate-timeline Tommy who conquered his world and now wars across the multiverse.', 'Drakkon is the dark mirror of everything the Rangers stand for, weaponizing the Morphin Grid itself against them.'),
  ('0a85cc57-d0af-5471-a1dc-4bdf2dbed32a', '2691870e-40bb-5f64-880b-9c2f4cfaf09d', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', 'ally', 'Professor X is the founder, mentor, and guiding ideal of the X-Men.', 'His dream of coexistence is the franchise''s foundation.'),
  ('c831edfd-8a76-53fe-b33d-7c3958ce5d7d', '1a61ff3c-d1d1-52b6-beb8-c1dc60642f40', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'enemy', 'Ra''s al Ghul''s relationship with Batman is adversarial in the specific sense that Ra''s considers Batman qualified to evaluate his plan and still rejects it — making Batman''s opposition the highest form of compliment he could offer.', 'Ra''s is also the grandfather of Damian Wayne, making his antagonism with Bruce permanently entangled with family.'),
  ('fb61f955-35f6-5678-9619-c3aca80e753b', '346596df-b4b3-5cfa-be46-35c6f0951535', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', 'ally', 'Raven founded the New Teen Titans and remains one of its most pivotal members.', 'Her struggle against Trigon is central to the team''s history.'),
  ('ccc7e3b0-d5a5-5197-9cff-820124567ab8', 'db496c89-2091-5e0e-8859-371dc2cdd7a7', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'enemy', 'The Red Skull is Captain America''s arch-nemesis and the fascist antithesis of everything Cap stands for.', 'Their feud began in Captain America Comics #1 (1941) and has continued across every era of the character.'),
  ('959cca2a-152c-594d-b80e-ccbf2c62fdfb', 'ad0aeda8-5962-52a4-a9c9-4395afe2a044', '448be678-268c-522f-9477-a07422c30fd0', 'enemy', 'The Reverse-Flash is Barry Allen''s archenemy, obsessed with destroying the hero he once idolized.', 'Thawne murdered Barry''s mother and is the engine behind Flashpoint (2011) and The Flash: Rebirth (2009).'),
  ('440a3579-a705-5c8e-a2f5-2696f7239f84', '338980ff-b028-502a-aacd-072080eed01c', '7a66364d-547b-54c4-948e-de4f1d756d38', 'ally', 'Rex Splode is a core member of the reformed Guardians of the Globe.', 'His explosive powers and growth define his tenure on the team.'),
  ('953e7aa6-ef7b-5b44-a57b-d0111789400d', '8aa69805-f754-5744-bca1-ded0fc7bbf61', '4322fa09-0a88-5804-93f9-0fbf9175f54e', 'ally', 'A fast, agile hero and frequent ally in Dragon''s super-team engagements.', 'Ricochet''s speed complements Dragon''s brute force in their shared battles.'),
  ('983845d9-c141-5c7e-87da-0459fe990663', '46ce85d8-b615-5195-825a-b79f1d802603', '784afd7e-b4e8-547a-a63d-fdc8fa966fc6', 'enemy', 'The hero Rita first corrupted and now seeks to destroy.', 'Rita''s manipulation is the origin of Tommy''s lasting guilt.'),
  ('d8c3bb6d-9787-555c-bc25-8020742816f0', 'ee1e4f5e-6664-5a73-aa9b-e4da8f5771d2', '7a66364d-547b-54c4-948e-de4f1d756d38', 'ally', 'Robot leads the reformation of the Guardians and serves as its chief strategist.', 'His intellect rebuilds the team, though his methods remain controversial.'),
  ('040efb2c-c5e0-5fab-8494-0899e8a0656b', '899505b8-a56a-5ca8-aeca-d8d7a2969cd6', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', 'ally', 'Rogue reformed to become a stalwart member and frequent leader of the X-Men.', 'Her redemption arc is a cornerstone of the modern team.'),
  ('f345bf5a-d4f3-53b4-b9bb-6bf24830ccce', '1a1511e9-19d7-51cf-a5ad-c81d49093aaf', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', 'ally', 'Buffy''s Watcher and mentor, supplying the lore and discipline her calling demands.', 'Giles trains and steadies Buffy, serving as a father figure throughout her tenure as Slayer.'),
  ('6fe7e0b9-4e1f-5f29-a95c-26209deaafa3', 'd3ce5131-893b-5d10-a5e8-5ec39dd0a85a', '411d9474-16b6-5c50-a3fa-36f22c778276', 'enemy', 'Sabretooth is Wolverine''s savage opposite and most personal nemesis.', 'Their blood feud spans decades; Creed delights in killing the people Logan loves and claims a shared, manipulated past.'),
  ('f394a1f8-cb2e-58a1-93a4-7a728047a1cf', '519242ce-776c-5906-b032-8ebc5b4d5614', '7c004d0d-1535-57a7-9f09-ef7cf865a072', 'ally', 'The detectives repeatedly cross paths with Spawn, sometimes aiding his war.', 'Their investigations intersect with Spawn''s crusade against street-level evil.'),
  ('ae2d98a6-adc4-5f93-95eb-f9253cca71bb', '7b94e1aa-83f4-508c-a457-770f2588339b', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', 'enemy', 'Sandman is a recurring early foe whose shape-shifting sand powers make him hard to defeat.', 'Flint Marko debuted in Amazing Spider-Man #4 and became a founding member of the Sinister Six, repeatedly clashing with Spider-Man over the decades.'),
  ('e3364c4a-7914-5d76-a8c2-e716150bf9e4', '4322fa09-0a88-5804-93f9-0fbf9175f54e', '710b82cd-cfe7-58fb-9e14-b7d0b699cbfb', 'ally', 'Dragon''s police partner and one of his closest personal connections on the force.', 'Alex Wilde works alongside Dragon at the precinct, and their bond becomes one of the emotional anchors of his early career.'),
  ('141aab10-51dc-5c80-b080-3b3936892d7c', '4322fa09-0a88-5804-93f9-0fbf9175f54e', '3435af88-847a-586f-8c00-d1fe9dd6c158', 'ally', 'The police lieutenant who first recruited Dragon and championed him within the department.', 'Frank Darling''s faith in Dragon gives the amnesiac newcomer a place and a purpose in Chicago.'),
  ('76491618-e430-5388-af74-1202384fbb07', '4322fa09-0a88-5804-93f9-0fbf9175f54e', '45ba8447-d9b0-5e63-b25d-3f181ed157a7', 'ally', 'A super-strong hero who fights alongside Dragon as a trusted teammate.', 'Barbaric and his partner often back Dragon up against threats too big for one hero to handle.'),
  ('afe30750-b605-59b2-b9ea-65d37fabaa4a', '4322fa09-0a88-5804-93f9-0fbf9175f54e', '8aa69805-f754-5744-bca1-ded0fc7bbf61', 'ally', 'A fast, agile hero and frequent ally during Dragon''s larger super-team engagements.', 'Ricochet''s speed complements Dragon''s brute force in their shared battles.'),
  ('409ef5a7-c2ee-5e3d-a86a-5d74f018de8f', '4322fa09-0a88-5804-93f9-0fbf9175f54e', '3168c6d7-6c83-5cf1-b287-da914c7d1f7c', 'enemy', 'The armored crime lord who rules Chicago''s superhuman underworld and Dragon''s foundational nemesis.', 'Overlord''s grip on the city''s organized crime makes him the defining antagonist of Dragon''s earliest cases.'),
  ('4ead830c-b27c-5cf9-aff4-f19275a19864', '4322fa09-0a88-5804-93f9-0fbf9175f54e', '2e60e526-80aa-5940-b950-3211d8e45eee', 'enemy', 'A monstrous, scheming villain who repeatedly seizes power and torments Dragon across decades.', 'Cyberface evolves from underling to world-conquering threat, becoming one of Dragon''s most persistent enemies.'),
  ('052501f5-f3df-5a97-a82e-2a49441aa244', '4322fa09-0a88-5804-93f9-0fbf9175f54e', 'ac67cff0-9d3b-5d42-8875-72fb6d8c1e95', 'enemy', 'A vicious, recurring foe whose brutality tests Dragon at his limits.', 'The Fiend embodies the savage, no-holds-barred violence that defines the series'' rogues.'),
  ('23728d58-9d20-5a14-9847-27b49856ce06', '4322fa09-0a88-5804-93f9-0fbf9175f54e', '4621bf98-c20c-5812-ad91-16eff4826513', 'enemy', 'A diminutive alien mastermind with grand, world-threatening ambitions.', 'Mister Glum''s schemes from another dimension draw Dragon into conflicts far beyond Chicago''s streets.'),
  ('09766fa7-eba0-5463-91ba-afc5dd839f25', '8657ab06-96b9-5dfb-87e2-ad5c9e8e68ce', '89b546be-6991-54a1-a207-5fdafbd26ee7', 'ally', 'Sentinel is a member of Youngblood across modern eras.', 'He bridges the team''s classic and contemporary rosters.'),
  ('add803e0-9618-5567-9d31-078ee53d477e', 'b6ee5c85-5da2-5a36-b6ca-e1fd21313c28', '89b546be-6991-54a1-a207-5fdafbd26ee7', 'ally', 'Shaft leads Youngblood''s home team.', 'He is the squad''s public face and tactical commander.'),
  ('c7c9db51-ef31-56ab-a656-7a6444b7ba05', '2a1b8c6d-9df0-53b2-afb7-33330b4bde2c', 'a8434c59-8838-500a-a059-d60b3b33a59e', 'enemy', 'Sinestro is Hal Jordan''s archenemy and the dark reflection of the Green Lantern ideal.', 'Their rivalry began in Green Lantern #7 (1961) and peaked in the Sinestro Corps War, a generational struggle between will and fear.'),
  ('0e42bf9a-5b2c-5622-abdb-1cd43c67ded0', '7c004d0d-1535-57a7-9f09-ef7cf865a072', 'c54a55aa-319d-57b6-9a52-dbe35d255a81', 'ally', 'A weathered old Hellspawn who mentors Al in the nature of his powers and the war he was made for.', 'Cogliostro appears early in Spawn''s existence as a guide, revealing hard truths about necroplasm and the cost of the bargain.'),
  ('102643d1-cab1-582c-83de-664d2395f2a6', '7c004d0d-1535-57a7-9f09-ef7cf865a072', '519242ce-776c-5906-b032-8ebc5b4d5614', 'ally', 'Two NYPD homicide detectives whose investigations repeatedly cross paths with Spawn''s war on the streets.', 'Sam Burke and Twitch Williams orbit Spawn''s world, occasionally aiding him and earning their own spinoff series.'),
  ('d32cff36-b5a3-57d8-83b0-5e57bb62131a', '7c004d0d-1535-57a7-9f09-ef7cf865a072', '8d91b245-3858-5d29-a38b-d5d88f524623', 'ally', 'Al Simmons'' best friend from his former life, now married to the woman Al left behind.', 'Terry''s safety becomes a recurring concern, and his unknowing connection to Al''s past drives much of the early emotional stakes.'),
  ('e5a39f82-b3c2-5d3c-9fdb-595446133474', '7c004d0d-1535-57a7-9f09-ef7cf865a072', '0b1f9dae-3b8b-50eb-9e6e-dcf3208d3996', 'ally', 'A witch with ties to the supernatural underworld who becomes a key ally in Spawn''s later crusades.', 'Nyx lends magical expertise and fights alongside Spawn against threats that span Heaven and Hell.'),
  ('3b6530dd-029c-5291-91a0-e909a107a14d', '7c004d0d-1535-57a7-9f09-ef7cf865a072', '2be580a9-54b0-5f83-b29b-fc7585a8890c', 'enemy', 'A grotesque demon and Hell''s enforcer, sent to torment Spawn and bend him to Malebolgia''s will.', 'The Violator, often disguised as the clownish Clown, is Spawn''s most persistent and personal foe.'),
  ('28f62e2b-53b7-5faa-809b-c1ac88b5d8e2', '7c004d0d-1535-57a7-9f09-ef7cf865a072', 'e04135bf-0e34-5add-8c14-e9c345b1fae2', 'enemy', 'The demon lord who struck the bargain that made Al into a Hellspawn and commands him from the depths of Hell.', 'Malebolgia is the architect of Spawn''s damnation and the ultimate target of his rebellion.'),
  ('6b9083f7-62b4-5260-ad9e-0221dc868048', '7c004d0d-1535-57a7-9f09-ef7cf865a072', '9332422c-3ea9-54d6-8e3f-305a4b2d0f0c', 'enemy', 'The corrupt government spymaster responsible for ordering Al Simmons'' murder.', 'Wynn''s betrayal set Spawn''s tragedy in motion, making him a human target for Al''s earthly vengeance.'),
  ('0bb7ecb4-82ff-510a-b315-6d3ebfef798d', '7c004d0d-1535-57a7-9f09-ef7cf865a072', 'e1d3db22-d396-5b47-a3eb-2fd70f4e8d48', 'enemy', 'A Heaven-aligned counterpart created to destroy the Hellspawn, mirroring Spawn''s powers with holy purpose.', 'The Anti-Spawn (Redeemer) embodies the war between Heaven and Hell turned directly against Al.'),
  ('9b35dcb2-a102-587f-a476-cde3d5bae799', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', 'ally', 'A mentor figure who saw Peter''s potential and helped equip him for bigger threats.', 'Tony Stark recruited and outfitted Spider-Man during the ''Civil War'' era and acted as his mentor in the Marvel Cinematic Universe, building him advanced suits and a place on the Avengers'' radar.'),
  ('1c3fab48-2b49-5b30-bd39-50fa77cbac17', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'ally', 'A moral compass and fellow Avenger whom Spider-Man deeply admires.', 'The two fought side by side in the Avengers and on opposite sides of ''Civil War'' over the Superhuman Registration Act, with Cap''s example pushing Peter to take a public stand.'),
  ('44234f07-445a-5f99-a1d2-bde5dba82a10', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', '411d9474-16b6-5c50-a3fa-36f22c778276', 'ally', 'An unlikely, bickering friendship forged through repeated team-ups.', 'The mismatched pair headlined the long-running ''Astonishing Spider-Man & Wolverine'' team-ups, their odd-couple banter becoming a fan-favorite dynamic across Avengers stories.'),
  ('c76f3b25-a3cc-5cd7-b056-ea36029ecc5e', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'ally', 'Spider-Man finally graduated from solo street hero to full Avenger.', 'After decades on the sidelines, Spider-Man joined the team during Brian Michael Bendis''s ''New Avengers'' run, bringing his street-level perspective to Earth''s Mightiest Heroes.'),
  ('a917aaa9-d53a-59c3-8585-d2d02e258f55', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', '2bf45ce8-3c51-51de-8b48-94d766ee72dd', 'enemy', 'His most personal nemesis, who knows his identity and has hurt those closest to him.', 'Norman Osborn discovered Spider-Man''s identity, killed Gwen Stacy in ''The Night Gwen Stacy Died,'' and has tormented Peter across generations as the architect of his greatest losses.'),
  ('489098bc-7cce-55fa-ade8-01de29bd3c94', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', '73c0cf5c-4285-555b-9528-9baef6ff50ad', 'enemy', 'A brilliant scientist whose mechanical arms make him one of Spider-Man''s deadliest foes.', 'Otto Octavius orchestrated the ''Master Planner'' saga and once swapped minds with Peter to become the ''Superior Spider-Man,'' making him both intellectual rival and physical match.'),
  ('9c759aeb-5e1c-5156-9be7-19aaf41337c7', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', '84980f5e-ba2b-5111-92d4-0e4628b593c6', 'enemy', 'An alien symbiote bonded to a man who hates Peter, twisting Spider-Man''s own image against him.', 'After Spider-Man rejected the alien costume, it bonded with Eddie Brock to become Venom, a dark mirror immune to his spider-sense who knows his secret identity.'),
  ('c8bf6073-0fcd-5af0-8755-fa454dbfd491', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', '7b94e1aa-83f4-508c-a457-770f2588339b', 'enemy', 'A shape-shifting petty criminal able to transform his body into living sand.', 'Flint Marko gained sand-based powers in a nuclear test accident and became an early recurring foe, clashing with Spider-Man solo and as a member of the Sinister Six and Frightful Four.'),
  ('0cb3d849-d54c-58cb-884c-2478ea1966ce', 'dbf622dd-5942-599c-be08-5440f5a3f2be', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', 'enemy', 'A swaggering vampire drawn to Sunnydale by the thrill of killing a Slayer.', 'Spike begins as a lethal antagonist relishing the hunt, his loyalties toward Buffy always in flux.'),
  ('c39c52b3-070d-50da-8630-5c50c0de937c', 'fd108db8-86ea-51c7-a555-0d05ee01eaa5', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', 'ally', 'Starfire is a core member of the New Teen Titans and one of its emotional anchors.', 'Her loyalty and warmth define the team''s found-family dynamic.'),
  ('d9ee3ae8-9878-570c-8f6b-86511936073f', '4b010e1a-5893-5779-942b-f5c94d6fe793', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'enemy', 'The mind-controlling alien the League first assembled to defeat.', 'The team''s very first foe and a recurring planetary threat.'),
  ('707dff0d-f6e5-57cc-a506-f29a432c5ca3', '5fb83c49-8889-5548-9c30-32774f14089f', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', 'ally', 'Storm is a longtime core member and leader of the X-Men.', 'One of the team''s most powerful and respected figures.'),
  ('0e97f09d-7aef-521a-b9fa-e4ea6a072621', '2530b133-d2b6-5355-86bd-7709a4d5d39e', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'ally', 'Superman''s closest and most complementary friend, the World''s Finest pairing of brightest hope and darkest vigilance.', 'Their dynamic anchors stories like The World''s Finest and Jeph Loeb''s Superman/Batman run; Batman famously keeps a kryptonite contingency should Superman ever fall.'),
  ('f3fd9bd5-c698-5903-9128-3f6120cf1848', '2530b133-d2b6-5355-86bd-7709a4d5d39e', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', 'ally', 'A fellow founding pillar of the heroic community whom Superman regards as a peer in both power and principle.', 'The two have stood together since the Justice League''s founding and were briefly romantically paired during the New 52 era''s Superman/Wonder Woman series.'),
  ('ec5777bd-5e0f-5bd8-8f7a-daf7450f75bf', '2530b133-d2b6-5355-86bd-7709a4d5d39e', '448be678-268c-522f-9477-a07422c30fd0', 'ally', 'A trusted Justice League teammate whose friendly speed rivalry with Superman is a long-running fan favorite.', 'Their good-natured charity races, dating back to the Silver Age, are a recurring tradition across comics and animation.'),
  ('bad6b7e4-a0e4-56fc-9259-ada5b12bc43f', '2530b133-d2b6-5355-86bd-7709a4d5d39e', 'a8434c59-8838-500a-a059-d60b3b33a59e', 'ally', 'A dependable Justice League ally who guards Earth''s sector of the cosmos alongside Superman.', 'Hal Jordan and Superman have fought side by side since the League''s earliest cases, balancing willpower-forged constructs against raw Kryptonian might.'),
  ('6bbc17a2-7925-57fc-80a5-376e8fe43fc6', '2530b133-d2b6-5355-86bd-7709a4d5d39e', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'ally', 'The world''s premier super-team, of which Superman is a founding member and moral cornerstone.', 'From the Justice League of America through the JLA and Rebirth eras, Superman is consistently portrayed as the team''s heart and most trusted leader.'),
  ('cb77ab59-b20a-5005-b62e-82b4d74852ec', '2530b133-d2b6-5355-86bd-7709a4d5d39e', 'e305af9b-4cc3-5518-89e6-f43963628ebe', 'enemy', 'Superman''s greatest nemesis, a brilliant Metropolis billionaire who hates him out of wounded pride and jealous ambition.', 'Reinvented by John Byrne in The Man of Steel as a corrupt corporate magnate, Luthor''s obsession drives stories from All-Star Superman to countless schemes against the Man of Steel.'),
  ('9def448a-2ce1-5374-af9d-c89e5b50cef3', '2530b133-d2b6-5355-86bd-7709a4d5d39e', 'c176cf47-e3aa-5124-96a3-c40653063787', 'enemy', 'A coldly logical alien intelligence who collects and bottles entire cities, including the last surviving Kryptonian capital.', 'Brainiac''s theft of Kandor before Krypton''s destruction makes him a living link to Superman''s lost heritage, central to Geoff Johns''s modern Brainiac arc.'),
  ('b9f1c4fe-a347-5219-874a-049be2ed9961', '2530b133-d2b6-5355-86bd-7709a4d5d39e', '958eb5e9-3e62-5425-a491-e9291563bffd', 'enemy', 'A ruthless Kryptonian military commander who shares Superman''s powers but none of his compassion.', 'Banished to the Phantom Zone before Krypton''s fall, Zod escapes to challenge Superman as his equal in strength, a conflict explored in stories like New Krypton.'),
  ('c070241b-b617-548f-9d2e-5a84e13edd80', '2530b133-d2b6-5355-86bd-7709a4d5d39e', '46646717-ad59-58fe-b11c-5a2c94afdca4', 'enemy', 'A mindless engineered killing machine that evolves to overcome any threat, and the only foe ever to slay Superman in single combat.', 'Doomsday''s debut rampage in The Death of Superman ended with both combatants striking simultaneous killing blows.'),
  ('201d9926-4c4c-5596-a08c-334a647cab3b', '22bf9525-aa52-53e2-9019-eb5bca2af4d2', 'de8ec54e-9f19-561c-bcb0-a114f019363c', 'enemy', 'Surtur exists to destroy Asgard and bring about Ragnarok, forcing Thor into apocalyptic last stands.', 'His forging of the Twilight Sword drove the climactic Surtur Saga in Walter Simonson''s run.'),
  ('076db17c-3c45-5705-9562-19ea758c9f86', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'ally', 'The Titans began as the proteges of Justice League members and remain the League''s most trusted younger counterpart.', 'Many Titans graduate into Justice League membership, reinforcing the mentorship legacy between the two teams.'),
  ('a7d6f14c-1927-552b-a372-649221b50eda', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', '448be678-268c-522f-9477-a07422c30fd0', 'ally', 'The Flash''s legacy is woven into the Titans through Kid Flash, a founding member, making the speedster a longtime ally and mentor figure.', 'Wally West served on the Titans for years before inheriting the Flash mantle.'),
  ('a61a15cb-0c8d-5c93-ae24-16f3e9d8860e', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', 'ef33d492-4f93-52fc-bfe8-b86b454eb253', 'ally', 'As the team''s original leader, Dick Grayson is the heart and soul of the Titans across nearly every incarnation.', 'His leadership defines the team even after he becomes Nightwing.'),
  ('3d2000a2-5a00-555c-bc47-67a57cc890fc', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', 'cd1d8c92-fd02-5109-a100-cab73f34b4c4', 'ally', 'Cyborg is one of the New Teen Titans'' founding modern members and a steadfast pillar of the team.', 'His tenure with the Titans long predates his later Justice League membership.'),
  ('75e18959-debb-593f-b0aa-6186f36193b1', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', 'f2583e7b-114a-5d55-ab97-0984e1eccd83', 'enemy', 'Deathstroke the Terminator is the Teen Titans'' signature archenemy, a master assassin who has hunted them for decades.', 'His vendetta drives The Judas Contract and countless subsequent conflicts.'),
  ('fcc55e1a-41ee-515b-8106-ac2a8193a588', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', '745311fc-5ddc-5bc8-9bc2-1572b83737bb', 'enemy', 'The interdimensional demon Trigon is Raven''s father and one of the most powerful cosmic threats the team has ever faced.', 'The team was partly assembled to oppose his invasion of Earth.'),
  ('0870ad79-aa98-544a-a7c7-8731dd5f833e', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', 'cf13b5e8-4a72-5e83-80fa-cdab07827c1b', 'enemy', 'Brother Blood is an immortal cult leader whose Church of Blood repeatedly menaces the Titans.', 'He is a recurring ideological villain across multiple eras and the animated series.'),
  ('0b01d13f-07ed-5ca0-8f41-2d5675aec84e', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', 'f321da7b-48eb-5581-8bcb-fd783155520f', 'enemy', 'Terra infiltrated the team as a recruit while secretly serving Deathstroke, becoming one of comics'' most infamous traitors.', 'Her betrayal is the emotional core of The Judas Contract.'),
  ('341dbebf-8061-5b76-81dd-df169918e5d0', 'f321da7b-48eb-5581-8bcb-fd783155520f', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', 'enemy', 'Terra infiltrated the Teen Titans while secretly working against them, becoming an infamous traitor.', 'Her betrayal is the emotional core of The Judas Contract.'),
  ('253eb1ec-ca8f-5aef-a57a-941e9be680b2', '8d91b245-3858-5d29-a38b-d5d88f524623', '7c004d0d-1535-57a7-9f09-ef7cf865a072', 'ally', 'Terry was Al Simmons'' best friend and remains tied to the life Spawn lost.', 'Spawn watches over Terry and his family even from a distance.'),
  ('64ed995d-f503-550e-aba0-8f85386eda0d', '1b08cd24-f7d8-50c9-8aed-bcfd1655a338', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'enemy', 'The Avengers stand among the few forces capable of opposing the Mad Titan''s apocalyptic ambitions.', 'Thanos''s pursuit of the Infinity Gems repeatedly brings him into conflict with Earth''s Mightiest Heroes.'),
  ('255fb0bf-613a-55d9-a72e-16187bea5098', 'cb6f7717-ddd8-5824-b129-8a4fc74cc300', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', 'enemy', 'A child vampire of prophecy who serves as a sinister figurehead against Buffy.', 'The Anointed One commands fear and ritual among Sunnydale''s vampires as a herald of doom.'),
  ('92851009-2f93-5bb9-a85a-097f17afc66f', '9c3c540e-398e-55d7-af73-fda8fd38b93f', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', 'enemy', 'The Curator covets the Witchblade and schemes to take it from Sara.', 'He represents the collectors and cultists who view Sara as merely an obstacle to possessing the blade.'),
  ('c119800f-21e6-5c90-8955-d05349bddb27', '450f9bd3-dbd8-5444-b88e-732df39fb341', '89b546be-6991-54a1-a207-5fdafbd26ee7', 'enemy', 'The Disciples are recurring enemies of Youngblood.', 'Their ideological crusade keeps them in conflict with the team.'),
  ('2803726a-1db0-52df-a0fc-286d934dc799', '7648e80f-c11b-5c40-abd6-0e19b5d8ed9e', '7554762e-8839-52ac-b0f4-03e2d44cda89', 'ally', 'The Empty Cult preserves and spreads the worship of the Empty Man.', 'Its underground network guarantees the affliction always returns.'),
  ('24b75367-4230-5aad-89ee-5b3c3cd12c57', '7554762e-8839-52ac-b0f4-03e2d44cda89', '4714cfea-ef2c-556a-899f-bc09147b519f', 'ally', 'The Faithful are the congregation of the afflicted who welcome the Empty Man''s presence rather than resist it.', 'They emerge during the first outbreak, transforming a contagion into a movement that the task force cannot quarantine.'),
  ('7f8fba82-51b8-5714-8a41-e42926989147', '7554762e-8839-52ac-b0f4-03e2d44cda89', 'bc3388da-87e3-5978-bd9a-c1c8218aad6f', 'ally', 'Brother Soporus is a charismatic preacher who interprets the Empty Man''s visions for the newly afflicted.', 'He shepherds converts and frames the affliction as revelation, making him a key vector for the contagion''s spread.'),
  ('cbe5886a-d1cb-5f9b-9501-4908c6d1d1e1', '7554762e-8839-52ac-b0f4-03e2d44cda89', '7648e80f-c11b-5c40-abd6-0e19b5d8ed9e', 'ally', 'The Empty Cult is the organized underground that preserves the faith between outbreaks.', 'Its rituals and silent recruitment ensure the Empty Man always has caretakers waiting to begin again.'),
  ('0cb079c0-f81b-5ae7-ad13-557ee1e85fa6', '7554762e-8839-52ac-b0f4-03e2d44cda89', '9b5ba614-a266-558f-aa96-db377463623e', 'ally', 'Dixon is a devoted servant of the affliction who acts as its hands among the living.', 'Once an ordinary man, he embraced the presence and now carries the contagion forward without hesitation.'),
  ('bd5a76d7-7930-5337-8ad8-9e49323e62ca', '7554762e-8839-52ac-b0f4-03e2d44cda89', '8239a78a-c7f8-54b8-b823-3a0387f9ccf7', 'enemy', 'Agent Jensen is an FBI investigator assigned to track and contain the Empty Man outbreak.', 'His pursuit of the affliction drives the original investigation and exposes how little anyone truly understands it.'),
  ('b2471f75-1d5c-5154-9d42-8f463fbd66e8', '7554762e-8839-52ac-b0f4-03e2d44cda89', 'ffac191d-640b-59b0-9a6c-2c3d9aeeb98d', 'enemy', 'Agent Langford partners on the federal task force hunting the source of the contagion.', 'Her methodical approach is steadily undermined as the case refuses to behave like any disease she has known.'),
  ('e905976e-46ad-5dcc-aee5-d65a6c0757f5', '7554762e-8839-52ac-b0f4-03e2d44cda89', '6d3b22e4-ecd2-569b-b088-750d3beb5c95', 'enemy', 'Monica Jensen is drawn into the investigation when the affliction touches her own family.', 'Her personal stake makes her one of the Empty Man''s most determined opponents and one of its most vulnerable targets.'),
  ('0d1db637-6e35-583a-956f-2c056bf1bef6', '7554762e-8839-52ac-b0f4-03e2d44cda89', '2746a6b9-b9dd-5829-a0b1-bb4f656b6d54', 'enemy', 'The Protectors are the joint FBI and CDC task force established to contain the Empty Man.', 'They represent the institutional response to the outbreak, repeatedly outmatched by a horror that adapts to every defense.'),
  ('5793f740-da1d-5559-a9b4-ee66d2530efd', '4714cfea-ef2c-556a-899f-bc09147b519f', '7554762e-8839-52ac-b0f4-03e2d44cda89', 'ally', 'The Faithful worship the Empty Man and spread its presence willingly.', 'They turn the affliction from a disease into a movement no quarantine can hold.'),
  ('586467b2-3aa5-5a1b-82ae-81dc654f2213', 'ac67cff0-9d3b-5d42-8875-72fb6d8c1e95', '4322fa09-0a88-5804-93f9-0fbf9175f54e', 'enemy', 'A vicious recurring foe whose brutality tests Dragon at his limits.', 'The Fiend embodies the savage violence that defines the series'' rogues.'),
  ('a7d28cde-c33f-5664-b774-afe18ef4a572', '448be678-268c-522f-9477-a07422c30fd0', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'ally', 'The Flash and Batman are close friends and Justice League founders whose contrasting temperaments make them a formidable detective duo.', 'Their bond is central to The Button (2017), where the two investigate a timestream mystery together, and Barry often turns to Bruce as a forensic peer.'),
  ('df1b9a78-4440-5eff-9acc-2165fe9ded7a', '448be678-268c-522f-9477-a07422c30fd0', '2530b133-d2b6-5355-86bd-7709a4d5d39e', 'ally', 'The Flash and Superman are founding Justice League members and famously friendly rivals over who is truly the fastest.', 'Their good-natured charity races have appeared repeatedly since the Silver Age, including the classic ''Superman vs. The Flash'' race stories.'),
  ('d5c7f86e-52d1-5dba-9a10-aa3a66048367', '448be678-268c-522f-9477-a07422c30fd0', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', 'ally', 'The Flash and Wonder Woman serve side by side as core pillars of the Justice League, trusting each other implicitly in battle.', 'Both were reunited as founders in the Justice League relaunch following Flashpoint, fighting Darkseid''s invasion in the New 52 ''Origin'' arc.'),
  ('c1043d9f-0f94-5c33-b5aa-9670f136d25e', '448be678-268c-522f-9477-a07422c30fd0', 'a8434c59-8838-500a-a059-d60b3b33a59e', 'ally', 'Barry Allen and Hal Jordan share the closest friendship in the Justice League, a partnership of speed and willpower.', 'Their bond was canonized in the Silver Age and celebrated in numerous Brave and the Bold and Justice League team-ups; both debuted as Silver Age reinventions.'),
  ('034552df-51d4-5556-9c58-97edae4a1461', '448be678-268c-522f-9477-a07422c30fd0', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'member', 'The Flash is a founding member of the Justice League, providing rescue speed and tactical reconnaissance.', 'Barry has been a League mainstay since The Brave and the Bold #28 (1960) and was a founder in the post-Flashpoint relaunch.'),
  ('5d281cd6-850b-5c30-afb4-ad8112e8349d', '448be678-268c-522f-9477-a07422c30fd0', 'ad0aeda8-5962-52a4-a9c9-4395afe2a044', 'enemy', 'Eobard Thawne, the Reverse-Flash, is Barry''s obsessive archenemy who has tormented him across time itself.', 'Thawne murdered Barry''s mother to engineer his suffering, the inciting tragedy that drives Flashpoint (2011) and The Flash: Rebirth (2009).'),
  ('31a4412b-8a0f-57b1-b1c3-eae57b214eb6', '448be678-268c-522f-9477-a07422c30fd0', 'f07139dc-c0a7-5000-a560-893f3fe017b0', 'enemy', 'Leonard Snart, Captain Cold, is the cold-gun-wielding leader of the Rogues and Barry''s most persistent street-level foe.', 'As de facto leader of the Rogues, Cold organizes Central City''s criminals against the Flash, a dynamic established in the Silver Age and central to Geoff Johns'' run.'),
  ('192d70da-690a-5d08-8207-449a6ebdd71f', '448be678-268c-522f-9477-a07422c30fd0', '01810fc2-2f93-5c21-b522-f232e59ac1ca', 'enemy', 'Gorilla Grodd is a hyper-intelligent telepathic ape who seeks to conquer humanity and destroy the Flash.', 'Grodd first menaced Barry in The Flash #106 (1959) and returned as a brutal threat in Geoff Johns'' ''Rogues'' and ''Reverse-Flash'' era stories.'),
  ('c9dea126-8b6a-5740-872e-93983adab2ec', '448be678-268c-522f-9477-a07422c30fd0', '0ff251a9-e3eb-5e72-9be3-ac49ca4e02d0', 'enemy', 'Hunter Zolomon, Zoom, is a tragic foe who believes inflicting trauma will make the Flash a better hero.', 'Zoom debuted in The Flash #197 (2003) tormenting Wally West, and his time-warping speed makes him one of the most dangerous speedsters Barry faces.'),
  ('0d0a010d-2fd0-5941-aa6c-2cc89ac426c4', '65cb3481-4f7e-5599-8b71-78e119c216d3', '7a66364d-547b-54c4-948e-de4f1d756d38', 'ally', 'The Immortal leads and anchors the Guardians across multiple rosters.', 'His experience and resilience make him the team''s steady center.'),
  ('6801b4ca-f093-51ec-a9fe-047c352429de', '8162a5f2-092c-55f0-b3c9-fc354fe236cd', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'enemy', 'The Joker''s obsession with Batman is the organizing principle of his entire existence — he has said explicitly that without Batman, he would have no reason to do any of it.', 'He has murdered Jason Todd (second Robin), paralyzed Barbara Gordon, and killed Sarah Essen Gordon across major storylines.'),
  ('8850cd6a-e084-5b2c-8377-f662304805a9', 'dfc637b9-6e5c-599c-9fe6-b1fe299d1669', '7a66364d-547b-54c4-948e-de4f1d756d38', 'enemy', 'The Lizard League is a recurring criminal organization the Guardians repeatedly fight.', 'Their coordinated attacks require a full team response to contain.'),
  ('6ebb7bb3-bf48-5cda-94cc-944e80661a1f', '29db753d-37a2-5ec6-90da-bae6daeed5d4', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', 'enemy', 'The Mandarin is Iron Man''s archnemesis, pitting his alien power rings against Stark technology.', 'Their decades-long rivalry frames a recurring conflict between ancient power and modern science.'),
  ('13e5874a-4512-5b93-9b99-e18dc8ca5a90', 'ba7706c6-1c90-505f-a393-ee1461db2e96', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', 'enemy', 'An ancient vampire lord seeking to crack open the Hellmouth and end Buffy''s world.', 'The Master is the first great threat of Buffy''s calling, an old and patient evil bound beneath Sunnydale.'),
  ('35d21c27-dcad-576d-adef-415642b45945', '86a41202-7aff-5ac9-8b83-d2f5d4b54fed', 'ddc90de2-8e7d-5dd1-bde9-72646019ee2b', 'enemy', 'Cloning super-geniuses whose recurring schemes repeatedly clash with Invincible.', 'Their inventions and cloning antics make them a persistent, unpredictable threat.'),
  ('ace21f19-5970-5fc7-a39e-01d3887fa7ea', '020a1748-e513-5ace-b1d1-b411c03ff7d1', '7786b507-312a-539d-8a23-29295e4b1a30', 'enemy', 'The creature is the target of Erica''s hunt in Archer''s Peak.', 'Only certain children can see it, making it a uniquely insidious threat.'),
  ('8d690f2c-d219-50d3-b9bf-e5f9ae8541a8', '2ca0f6bb-d5b2-50c6-81a7-c9beb04d4d7d', '7786b507-312a-539d-8a23-29295e4b1a30', 'enemy', 'The Order seeks to bring the defiant Erica back under its strict control.', 'Its demands for secrecy and obedience place it at odds with Erica''s independence.'),
  ('6cd45769-b95d-5386-aded-265d0a1fbeee', 'b0977b5f-d359-5193-a417-cd73e680f6dc', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'enemy', 'Penguin and Batman operate in a sustained adversarial détente — Penguin knows Batman will not kill him, and Batman knows that Penguin occasionally provides information that serves his purposes.', 'Their relationship has leaned into informant territory in several post-2000 runs.'),
  ('2e028bf4-5c3b-53fe-811a-61dce3b6ab36', '2746a6b9-b9dd-5829-a0b1-bb4f656b6d54', '7554762e-8839-52ac-b0f4-03e2d44cda89', 'enemy', 'The Protectors are the task force charged with containing the Empty Man.', 'They represent the institutional defense repeatedly outmatched by the affliction.'),
  ('a95d8972-57f0-5dd7-a87a-ff045d6ace95', 'f8057d23-7b86-5e3a-ba0d-ad82d360cb6d', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'enemy', 'The Riddler''s entire criminal career is structured around demanding Batman''s attention and acknowledgment — every scheme is a performance staged for an audience of one.', 'His turn as a private detective gave Batman an uneasy semi-ally who brought his own complicated motivations to every case.'),
  ('9f2baf84-5d56-5a90-8bbd-e3988b7f1714', 'b1786fae-ce5d-5cfa-bfea-19b3b6ba84a4', '0ce552c3-1204-54bd-805c-27a3e9153de6', 'enemy', 'The corrupted white mask wields the House''s authority against its own.', 'It embodies the danger of unchecked power at the top of the order.'),
  ('336af975-fa03-5b06-b8d2-b4fec62210cc', 'de8ec54e-9f19-561c-bcb0-a114f019363c', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', 'ally', 'A founding fellow Avenger whose science-minded pragmatism often clashes with Thor''s mythic worldview.', 'Both helped found the Avengers in Avengers #1 (1963); their differing philosophies came to a head during the superhero Civil War, when Tony''s cloning of Thor strained their friendship.'),
  ('7bf31a77-59c7-5c28-8fdf-378f0c812e48', 'de8ec54e-9f19-561c-bcb0-a114f019363c', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'ally', 'A brother-in-arms and fellow founding Avenger whom Thor deeply respects for his moral conviction.', 'Thor has long honored Steve Rogers'' worthiness; famously, Captain America briefly lifted Mjolnir during the original Fear Itself event and again in later stories.'),
  ('3759075c-0e96-56d5-9144-fa6c29032cd1', 'de8ec54e-9f19-561c-bcb0-a114f019363c', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'ally', 'Thor is a founding member of Earth''s Mightiest Heroes and one of its heaviest hitters, fighting alongside the team across countless threats.', 'He joined in Avengers #1 (1963) and has served across countless rosters, including the cosmic-facing teams during the modern era.'),
  ('0802ded3-0231-57fa-b8f0-e05cb6992175', 'de8ec54e-9f19-561c-bcb0-a114f019363c', '411d9474-16b6-5c50-a3fa-36f22c778276', 'ally', 'A fellow Avenger and battlefield comrade whose gruff pragmatism contrasts with Thor''s nobility but earns his respect.', 'The two served together on the New Avengers and Avengers rosters during Brian Michael Bendis''s run and fought side by side across numerous events.'),
  ('e5180192-7066-5d65-99a0-d4d92e546497', 'de8ec54e-9f19-561c-bcb0-a114f019363c', '1f49fb7c-fb73-52ec-8ba2-e5bf8b640f09', 'enemy', 'Thor''s adopted brother and the trickster god whose schemes set the Thunder God''s earliest adventures in motion.', 'Loki''s plot to discredit Thor inadvertently led to the formation of the Avengers in Avengers #1 (1963); their rivalry is the oldest in Thor''s mythos.'),
  ('44d2ba9a-74b3-5310-a26a-b8b6fb1f86bf', 'de8ec54e-9f19-561c-bcb0-a114f019363c', 'a1645541-25a2-527e-93d9-b087dbf5890a', 'enemy', 'The Asgardian goddess of death who repeatedly seeks dominion over Thor''s soul and the realm of the dead.', 'Hela has cursed Thor with unbreakable bones and immortality to deny him a warrior''s death, a recurring torment across the Silver and Bronze Age runs.'),
  ('ee8975cf-bb7f-558b-94f3-77b614bdf290', 'de8ec54e-9f19-561c-bcb0-a114f019363c', 'c87a39f2-008e-57ba-9fa5-e93d2da2d911', 'enemy', 'The malevolent dark elf whose cruelty and ambition culminate in an all-out War of the Realms.', 'Malekith served as the central antagonist of Jason Aaron''s run, escalating from schemer to warlord who united the Nine Realms against Thor in War of the Realms (2019).'),
  ('2318142c-0d36-5397-be31-a9891ed5ede2', 'de8ec54e-9f19-561c-bcb0-a114f019363c', '22bf9525-aa52-53e2-9019-eb5bca2af4d2', 'enemy', 'The colossal fire demon of Muspelheim sworn to bring about Ragnarok and the destruction of Asgard.', 'Surtur''s forging of the Twilight Sword drove Walter Simonson''s apocalyptic Surtur Saga (Thor #349-353), the definitive Ragnarok confrontation.'),
  ('1fb9bc7f-5ad6-51c9-8b32-2bbf7738820c', '784afd7e-b4e8-547a-a63d-fdc8fa966fc6', 'dcc0b1e2-6bc8-506d-8d00-599cb1e9383b', 'ally', 'The original Red Ranger and team leader who must learn to trust the former enemy now fighting beside him.', 'Their evolving partnership, from suspicion to mutual respect, anchors the early BOOM! Studios run.'),
  ('b23b4edc-059a-54dc-9275-8e31115a97fb', '784afd7e-b4e8-547a-a63d-fdc8fa966fc6', '9677b8cd-620c-5f15-815b-bc307efe9501', 'ally', 'The Pink Ranger whose belief in Tommy''s redemption helps him find a place on the team.', 'Kimberly is among the first to extend genuine trust to Tommy after his liberation from control.'),
  ('23b3337e-08e6-53a8-a5a8-84e6d99b0546', '784afd7e-b4e8-547a-a63d-fdc8fa966fc6', '8e1ef9a0-54ee-5617-9109-d7b2c965a107', 'ally', 'The Blue Ranger and team technologist who studies the instability of Tommy''s Green Ranger power.', 'Billy''s analytical support proves vital as Tommy''s abilities begin to fade.'),
  ('bd55d7f8-af15-52c7-a19c-a8caf0766f4e', '784afd7e-b4e8-547a-a63d-fdc8fa966fc6', 'b23f30f2-61cd-515a-a3e8-f07f14502f2d', 'ally', 'The team Tommy joins after breaking free of enemy control, fighting alongside them across timelines.', 'Tommy''s membership is hard-won, defined by the team''s gradual acceptance of a former adversary.'),
  ('5363ebc0-2e13-50f2-b2fd-dfcabd83109f', '784afd7e-b4e8-547a-a63d-fdc8fa966fc6', '46ce85d8-b615-5195-825a-b79f1d802603', 'enemy', 'The space witch who originally corrupted Tommy and turned him against the Rangers.', 'Rita''s manipulation is the source of Tommy''s lasting guilt and the team''s initial distrust.'),
  ('5e918bfc-325e-55ac-a997-50f06f109c67', '784afd7e-b4e8-547a-a63d-fdc8fa966fc6', 'a60dcbe3-6f65-5d40-9806-6cb0c90c5c29', 'enemy', 'The Emperor of Evil whose schemes escalate the threats Tommy and the team must face.', 'Zedd represents a darker, more calculating menace than Rita in the BOOM! continuity.'),
  ('0c15d493-4c0b-59c8-b60b-998e93a41feb', '784afd7e-b4e8-547a-a63d-fdc8fa966fc6', 'c19b3b7f-d0d0-5b8b-82c9-d7568fc281f7', 'enemy', 'The brutal warrior enforcer who repeatedly clashes with Tommy on the battlefield.', 'Goldar serves as a recurring physical antagonist throughout Tommy''s tenure.'),
  ('759bc52a-e86a-5306-82ea-3bb3d7a2e6aa', '784afd7e-b4e8-547a-a63d-fdc8fa966fc6', '62d3ff58-5877-5948-afd9-512ee5eb96a9', 'enemy', 'A tyrannical alternate-timeline Tommy who never abandoned the Green Ranger mantle and instead conquered.', 'Drakkon is Tommy''s dark mirror and the central villain of the Shattered Grid event.'),
  ('25bec756-8e8e-57a5-a53b-17b16de06eea', '745311fc-5ddc-5bc8-9bc2-1572b83737bb', 'ca6554da-5e3d-5de0-b00f-c1dd6d6c10b7', 'enemy', 'Trigon is the cosmic demon the Teen Titans were partly formed to oppose.', 'His connection to Raven makes the conflict deeply personal.'),
  ('38fc3122-f13e-5d86-a38e-4c3e01790297', '283ec4c4-55b8-513f-942a-81323157794b', 'b23f30f2-61cd-515a-a3e8-f07f14502f2d', 'ally', 'Trini is a founding member of the Power Rangers and the team''s steadiest fighter.', 'Her calm and discipline make her a center of gravity in battle.'),
  ('7c02a712-5cbf-5bc3-9b18-b8e53e06d321', '878e378d-03bb-5fd6-ae15-d31fe564261e', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'enemy', 'Two-Face is Batman''s most personal villain — Harvey Dent was one of Bruce Wayne''s only real friends, and his destruction represents a failure Batman cannot rationalize away.', 'Their history is explored most fully in Loeb and Sale''s Long Halloween and Dark Victory.'),
  ('6342c1dc-4471-57ac-9142-b322d11e771b', '1f126a7b-ee19-5ae2-bc70-44d7d3b37f64', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'enemy', 'Created by an Avenger, Ultron views the team as both family to be destroyed and the chief obstacle to his conquest.', 'His origin within the team makes their rivalry deeply personal.'),
  ('d34df41b-4229-53e8-8480-52b5bd71b3c7', '84980f5e-ba2b-5111-92d4-0e4628b593c6', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', 'enemy', 'Venom is a dark reflection of Spider-Man who knows his identity and is immune to his spider-sense.', 'Born from the alien costume Spider-Man rejected, Venom debuted as a relentless stalker in ''The Alien Costume Saga'' culminating in Amazing Spider-Man #300.'),
  ('bb379ebe-19be-5ede-af85-8e3c1cb7e721', '2be580a9-54b0-5f83-b29b-fc7585a8890c', '7c004d0d-1535-57a7-9f09-ef7cf865a072', 'enemy', 'The Violator torments Spawn and seeks to bend him to Hell''s will.', 'Often disguised as the Clown, he is Spawn''s most personal nemesis.'),
  ('c05dc995-9e1b-5d6c-9f4f-de56e5585830', '5d3f7c5e-1e99-5146-97d0-ce7373d1b57f', '89b546be-6991-54a1-a207-5fdafbd26ee7', 'ally', 'Vogue is a core member of Youngblood.', 'She is central to the team''s media image and frontline strength.'),
  ('c4d5cdcb-d4f9-5f7c-9daf-964886460f67', 'f0271d65-dd6d-55e6-af3c-518db63b89fd', 'dc4fa6e5-9cd9-530d-af32-949d8b71c053', 'enemy', 'Whiplash is a recurring armored mercenary who battles Iron Man with high-tech energy whips.', 'The identity has been worn by several characters, including Mark Scarlotti and Anton Vanko.'),
  ('052ae34a-8a28-5a8f-8ad2-e4b4e350035d', 'e348cdc2-3977-522f-877e-9b4cdecceba9', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', 'ally', 'Buffy''s best friend and the Scooby Gang''s witch, loyal through every crisis.', 'Willow''s magic and intellect repeatedly turn the tide in Buffy''s battles against the darkness.'),
  ('de3f7fde-8743-5a23-91b8-9e6a46eee0bf', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', '2939c01b-6e85-5e58-b250-e29d6afb5b8d', 'ally', 'Sara''s loyal NYPD partner who backs her up even when her cases turn supernatural.', 'Jake repeatedly puts himself in danger alongside Sara, becoming one of the few people she trusts with the truth about the Witchblade.'),
  ('6a779919-cb0b-55dd-a184-1983f1983e4a', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', 'cb0c266f-1125-5c99-8a2b-6ae28743dca9', 'ally', 'Sara''s murdered partner whose spirit continues to guide and advise her from beyond.', 'Danny''s death early in Sara''s career haunts her, and his lingering presence serves as a moral compass throughout the classic era.'),
  ('3cb36e67-046a-5980-844b-f7bf4009c05c', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', '8ff83210-4b2a-5819-9f95-69342e126100', 'ally', 'A medical examiner and forensic ally who helps Sara make sense of the impossible evidence the Witchblade leaves behind.', 'Gleason provides the grounded police-procedural support that anchors Sara''s supernatural investigations in real detective work.'),
  ('ad595474-fa25-5316-8c54-102512fac884', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', 'b445ddd6-e1dd-515d-a9bd-222dd45eec5b', 'ally', 'Sara''s commanding officer who shields her from departmental scrutiny while she chases unexplainable cases.', 'Dante balances bureaucratic pressure with genuine loyalty, often covering for Sara when her methods defy explanation.'),
  ('427e88c3-d0e8-5367-861f-db1c41db2f77', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', '62974dbb-5bfc-5c10-a11a-ffecb2d03a80', 'enemy', 'The immortal industrialist who orchestrated Sara''s bonding with the Witchblade to control it through her.', 'Irons is Sara''s primary antagonist across the classic run, manipulating events for centuries to claim the artifact''s power.'),
  ('cb6f14d5-a796-57e6-8953-42515077b258', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', '61fa87f0-8567-588c-a50f-30857c065c7b', 'enemy', 'Irons'' deadly enforcer who is obsessively drawn to Sara even as he is ordered to hunt her.', 'Nottingham''s divided loyalty between his master and his fascination with Sara makes him a tragic and unpredictable threat.'),
  ('348fcf23-56e8-53c9-af69-085caba01837', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', 'bffd2788-f7ee-5c11-98b0-47612d6a468b', 'enemy', 'The bearer of the Darkness, the Witchblade''s cosmic counterpart, whose path repeatedly crosses and clashes with Sara''s.', 'As wielders of opposing primal forces, Sara and Jackie are bound in a relationship that swings between conflict and uneasy alliance.'),
  ('392fafc5-7066-593e-b44f-8704d5f1da1f', '01c70c6d-1abe-52c6-b91b-bc82eee7a0c9', '9c3c540e-398e-55d7-af73-fda8fd38b93f', 'enemy', 'A keeper of forbidden artifacts who covets the Witchblade and schemes to wrest it from Sara.', 'The Curator represents the long line of collectors and cultists who view Sara as merely an obstacle to possessing the blade.'),
  ('cc395f8e-e36b-5e0e-b587-4e2f429885a8', '411d9474-16b6-5c50-a3fa-36f22c778276', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', 'ally', 'The X-Men are the family that turned Logan from a loner into a hero and a mentor.', 'Recruited in Giant-Size X-Men #1 (1975); served as one of the team''s most loyal members and later headmaster of the Jean Grey School.'),
  ('88265136-25da-5b71-b168-e783a9279fc5', '411d9474-16b6-5c50-a3fa-36f22c778276', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'ally', 'Logan joined the Avengers as the team''s willing-to-do-the-ugly-things member.', 'Brought onto Brian Michael Bendis''s New Avengers in 2010, controversially serving on both the Avengers and X-Men simultaneously.'),
  ('3351a9fc-a782-54fe-b19c-4e19f2145f39', '411d9474-16b6-5c50-a3fa-36f22c778276', 'f0f9597b-2580-532b-9882-2aefcd510a65', 'ally', 'Two old soldiers who fought in the same war and respect each other across very different moral codes.', 'Their shared WWII history was depicted in stories like the Uncanny X-Men/Captain America team-ups; Cap is one of the few who openly trusts Logan''s judgment.'),
  ('b8f0856c-4497-5eb1-9901-53021afc8be0', '411d9474-16b6-5c50-a3fa-36f22c778276', 'dff297dd-1766-50d3-a8a8-e8b0da0f4191', 'ally', 'An odd-couple friendship between the wisecracking kid and the grizzled veteran who secretly looks out for him.', 'Frequent partners in stories like ''Astonishing Spider-Man & Wolverine'' (2010) by Jason Aaron, where the two are flung through time together.'),
  ('a06cc90a-7468-594d-9cd9-a658d11fc1c2', '411d9474-16b6-5c50-a3fa-36f22c778276', 'd3ce5131-893b-5d10-a5e8-5ec39dd0a85a', 'enemy', 'Logan''s savage dark mirror, a killer whose history is tangled with his own.', 'A decades-long rivalry running through the Hama Wolverine run; Creed murders Logan''s loved ones and repeatedly torments him on his birthday.'),
  ('a9d2f4d0-1d1d-59b2-93a0-150e2d44ec86', '411d9474-16b6-5c50-a3fa-36f22c778276', '95c4e2f0-5988-54e7-9a18-95554586cc1f', 'enemy', 'A vengeful cyborg who blames Logan for the adamantium process and hunts him to reclaim it.', 'Yuriko Oyama believes the adamantium bonding desecrated her father''s legacy; she had her own skeleton laced with the metal to kill Wolverine.'),
  ('18c15163-f332-5e0a-b4db-1643ac81c63b', '411d9474-16b6-5c50-a3fa-36f22c778276', '39a095b5-92fa-558e-9fa8-297e694171e5', 'enemy', 'A Soviet super-soldier whose deadly tendrils and life-draining powers make him one of Logan''s most lethal foes.', 'Tied to Wolverine''s Cold War past via the lost Carbonadium Synthesizer; a central antagonist in the early-''90s Jim Lee X-Men run.'),
  ('a6d61e0d-8b81-5829-a887-2e73259cd9ad', '411d9474-16b6-5c50-a3fa-36f22c778276', 'f671ab1f-e733-51ec-818a-82ed22652b8a', 'enemy', 'A genetic manipulator who sees Logan as prime material for his experiments.', 'Sinister''s obsession with mutant DNA repeatedly puts him at odds with Wolverine and the X-Men, notably across the X-line''s cloning and Marauder plots.'),
  ('41e1a03f-c9dd-558a-825b-1682c2fc5904', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', '2530b133-d2b6-5355-86bd-7709a4d5d39e', 'ally', 'A fellow founding pillar of the Justice League and one of Diana''s most trusted peers.', 'The two are often portrayed as the moral and physical equals of the DC Universe; their relationship ranges from deep friendship to a romance explored during the New 52 era.'),
  ('70c8686b-d69e-5350-a165-1e3dc95bc11d', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'ally', 'A close comrade-in-arms whose grim pragmatism contrasts with Diana''s compassion.', 'Their philosophical clash is dramatized in Greg Rucka and J.G. Jones''s The Hiketeia, where Diana''s sacred oath puts her at odds with Batman''s pursuit of justice.'),
  ('51e4a907-a69a-53d6-84eb-54155cba58e1', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', '448be678-268c-522f-9477-a07422c30fd0', 'ally', 'A fellow Justice League founder and dependable teammate in the field.', 'Diana and Barry Allen have stood together since the League''s earliest adventures, frequently coordinating during crises like the various Crisis events.'),
  ('f491799e-bd4f-508b-9957-47b63b002534', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', 'a8434c59-8838-500a-a059-d60b3b33a59e', 'ally', 'A founding Justice Leaguer who fights alongside Diana against cosmic and earthly threats.', 'Hal Jordan and Diana have served together across numerous League rosters, their willpower and warrior spirit complementing each other in battle.'),
  ('68ece84a-f5ac-51e5-b5d3-677dde88f19f', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', '5ad2b081-03d1-5020-9fa2-08d27c056fa3', 'ally', 'Diana is a founding member and frequent leader of the world''s premier superhero team.', 'She has anchored the League since its inception, serving as its diplomatic conscience and one of its three central icons alongside Superman and Batman.'),
  ('e7978601-cd54-5857-9c36-24e5e4c8b4fd', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', 'd679bf65-5e35-5ddb-94fb-c5446bf4e277', 'enemy', 'The Greek god of war and Diana''s archnemesis, whose love of conflict is the antithesis of her mission of peace.', 'Ares schemes to ignite global nuclear war in George Perez''s Gods and Mortals, establishing him as her defining mythological foe.'),
  ('9c15cce0-c612-52e9-b1f7-6547af08d33f', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', '14696e46-299e-58f0-801d-c8e2df42ef87', 'enemy', 'Diana''s most personal rival, a friend turned bestial predator consumed by obsession.', 'The Barbara Ann Minerva incarnation is a former friend transformed by a cursed ritual; her fall from grace is retold in Greg Rucka''s Year One.'),
  ('35d7f5aa-b026-5ba3-bea0-27b4d99ef27b', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', '3c4082e1-3859-549a-a960-213fe1561bf3', 'enemy', 'An immortal sorceress who despises the Amazons and seeks to corrupt or destroy Diana through magic and manipulation.', 'Circe orchestrates the line-wide War of the Gods crossover and repeatedly transforms Diana''s allies, making her one of her most cunning recurring villains.'),
  ('4121db1d-5bb7-55db-8a91-ded7ecbfa2b9', '4145cfc9-c475-5dcf-9c49-817bd6375cb6', '9b69f6c8-ec9a-52fd-b306-7d63305f8662', 'enemy', 'A masked chemist and toxin specialist who has plagued Wonder Woman since the Golden Age.', 'First appearing in Sensation Comics #2 (1942), Doctor Poison is among Diana''s oldest foes and a founding member of Villainy Incorporated.'),
  ('b2d88b46-76f6-5a96-9ad4-1aa73b1d4a01', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'ally', 'Earth''s Mightiest Heroes have stood beside the X-Men against world-ending threats despite periodic tensions over mutant affairs.', 'Allies and occasional rivals; clashed during Avengers vs. X-Men before reuniting against common foes.'),
  ('d200ace9-6431-52fe-b850-ca04c6815076', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', '411d9474-16b6-5c50-a3fa-36f22c778276', 'ally', 'Wolverine is one of the team''s most loyal and ferocious members, embodying its willingness to do what others will not.', 'Longtime core member since the All-New, All-Different relaunch.'),
  ('8e90c08a-1b28-5f49-af72-87487b9472b0', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', 'be70c828-5b8f-5431-a529-20b5ca4371ef', 'ally', 'Cyclops is the team''s foundational field leader and the moral center of countless campaigns.', 'Founding member and frequent leader.'),
  ('c22bca1e-8528-582e-af18-f8b5495791ee', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', '5fb83c49-8889-5548-9c30-32774f14089f', 'ally', 'Storm has led the X-Men through some of their darkest hours, balancing compassion with command.', 'Joined in the all-new roster and rose to leadership.'),
  ('3f4c6371-0ed0-5e6d-9677-bbdfbb1b1504', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', '0882f404-5e91-5e5f-ab13-effa153e4492', 'enemy', 'The Master of Magnetism is the X-Men''s most iconic adversary, an ideological foil to Xavier''s dream.', 'Has oscillated between archenemy and reluctant ally over the decades.'),
  ('21751d4c-8111-5f07-a213-9b55d46b55b5', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', 'f671ab1f-e733-51ec-818a-82ed22652b8a', 'enemy', 'A ruthless geneticist obsessed with mutant DNA, Sinister has manipulated the X-Men''s bloodlines for centuries.', 'Long-game schemer tied to the Summers and Grey legacies.'),
  ('2266a53c-858f-5f46-a0d5-33542c75035d', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', '92c2c3fd-aea6-57ab-bfc3-0d4d5af52bfd', 'enemy', 'The ancient mutant En Sabah Nur preaches survival of the fittest, making him a recurring existential threat.', 'Believes only the strong deserve to inherit the world.'),
  ('7478faab-3848-5b3b-afe5-22493fc652e0', '3b5f2557-5b0c-5219-9f56-5e78e8c161cb', '56ff7566-933b-58c5-a916-a526373f5076', 'enemy', 'The shapeshifting terrorist has repeatedly targeted the X-Men through infiltration and her Brotherhood.', 'Master of disguise with shifting allegiances.'),
  ('25bef977-e38d-5103-8e9e-c2fc21cae719', 'f62d2c40-f7ae-51be-87fd-ffab0e0f6237', 'bd239ffa-2e95-55ec-bdaa-0bfc6c4e5c65', 'ally', 'A founding Scooby and Buffy''s steadfast friend, fighting without powers of his own.', 'Xander''s loyalty and humor keep the gang together even when the supernatural stakes leave him outgunned.'),
  ('d6fff1cb-961a-58b0-a58e-0e936eb6cae9', '89b546be-6991-54a1-a207-5fdafbd26ee7', 'b6ee5c85-5da2-5a36-b6ca-e1fd21313c28', 'ally', 'Shaft is the field leader of the home team and the franchise''s signature archer.', 'He coordinates the squad''s most public missions and embodies its celebrity-hero ethos.'),
  ('42bdf9fb-b145-52de-897d-53aa514139aa', '89b546be-6991-54a1-a207-5fdafbd26ee7', '948cf5fe-fe35-5e34-9f70-089f1b266b31', 'ally', 'Badrock is the team''s rock-bodied powerhouse and youthful heart.', 'His teenage perspective grounds the team amid the spectacle of fame.'),
  ('f77d32a6-e369-5570-8ff3-30fd3c268f6a', '89b546be-6991-54a1-a207-5fdafbd26ee7', 'c2d6b0c2-3e9a-56f9-bd37-b32a72dd1c7d', 'ally', 'Diehard is a veteran cyborg soldier who anchors the team''s experience.', 'He carries decades of conflict and serves as a tactical conscience for younger members.'),
  ('f3f0170e-1ffb-5a2e-bb65-b576c23d31a1', '89b546be-6991-54a1-a207-5fdafbd26ee7', '5d3f7c5e-1e99-5146-97d0-ce7373d1b57f', 'ally', 'Vogue is a striking combatant blending model-grade poise with lethal skill.', 'She thrives in the media glare while remaining a dangerous frontline operative.'),
  ('e9385834-73e9-51af-a0b9-4ee19abfabf9', '89b546be-6991-54a1-a207-5fdafbd26ee7', '5ab96773-d320-5296-9110-d63c607a0ee2', 'enemy', 'Overtkill is a cybernetic killing machine repeatedly pitted against the team.', 'His relentless assaults test the squad''s coordination and firepower.'),
  ('77f4de43-e7ee-53c6-928c-92dd221270c2', '89b546be-6991-54a1-a207-5fdafbd26ee7', '62eb906a-1df5-5cc2-97dd-873e0b5842a3', 'enemy', 'Darkthornn is an extradimensional warlord menacing the away division.', 'His incursions escalate the team''s missions to world-threatening scale.'),
  ('2ca100ff-b8ab-5404-ace0-d92562e6349e', '89b546be-6991-54a1-a207-5fdafbd26ee7', '6a5e6aa2-737a-53d6-bed1-a2e26f802777', 'enemy', 'Giga is a towering threat whose raw scale overwhelms conventional response.', 'Containing Giga forces the team to coordinate both divisions at once.'),
  ('e8b91253-33b5-5194-a9af-547e75e2f368', '89b546be-6991-54a1-a207-5fdafbd26ee7', '450f9bd3-dbd8-5444-b88e-732df39fb341', 'enemy', 'The Disciples are a fanatical organization opposing the team''s sanctioned heroics.', 'Their ideological crusade makes them recurring adversaries across eras.'),
  ('10bc3708-dfdc-543e-a05e-3f8bf82bfced', '2f4b9d8d-8685-529a-b34d-a2bc3e39ef60', 'b23f30f2-61cd-515a-a3e8-f07f14502f2d', 'ally', 'Zack is a founding member of the Power Rangers and the team''s morale.', 'His optimism and agility keep the team grounded and unpredictable in battle.'),
  ('dc23f3d6-5641-576b-801f-996b1b0724e6', '0ff251a9-e3eb-5e72-9be3-ac49ca4e02d0', '448be678-268c-522f-9477-a07422c30fd0', 'enemy', 'Zoom torments the Flash out of a twisted belief that suffering will make him a greater hero.', 'Zoom first targeted Wally West in The Flash #197 (2003) and remains a major threat to the Flash legacy, including Barry Allen.')
