  ('02ed35cf-b0c9-58b0-abac-4077cb613f08', 'c4001d41-6a31-5d98-9b1a-dcff2110c389', 'animated_series', 'Batman: The Animated Series', 1992, 1, 'Max', 'Clive Revill and Efrem Zimbalist Jr. voiced Alfred across the animated series, establishing the dry, attentive persona that most adaptations follow.', 'Max'),
  ('3137b839-311b-5a09-ac86-f09a16f05907', 'c4001d41-6a31-5d98-9b1a-dcff2110c389', 'film', 'Batman Begins', 2005, 1, 'Max', 'Michael Caine''s Alfred across the Nolan trilogy is the definitive live-action version, expanding the character''s emotional depth and backstory.', 'Max'),
