  ('82ef7138-5aa2-5f29-9087-5ccd614ba7c1', '77db7ea3-8ed7-5273-add1-d93259b39938', 'animated_series', 'Green Lantern: The Animated Series', 2011, NULL, 'Cartoon Network', 'Atrocitus serves as a primary antagonist leading the Red Lantern Corps against Hal Jordan.', 'Max'),
