  ('26d6b3e4-f079-5ea2-ad23-9add95666d1f', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'animated_series', 'The Avengers: Earth''s Mightiest Heroes', 2010, 1, 'Disney XD', 'A critically acclaimed animated series widely praised for faithfully adapting classic comic storylines.', 'Disney+'),
  ('13916a21-57c1-5999-b763-5b2aa8799d14', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'film', 'The Avengers', 2012, 2, 'Theatrical', 'The first Avengers film, directed by Joss Whedon, which united the Marvel Cinematic Universe''s heroes for the first time.', 'Disney+'),
  ('2a9c433e-bace-5f40-8db7-0a493e929207', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'film', 'Avengers: Endgame', 2019, 3, 'Theatrical', 'The culmination of the Infinity Saga and one of the highest-grossing films of all time.', 'Disney+'),
  ('bd70f4b9-33b2-5efa-bc6c-3fc6f8bc5f05', '792c4fec-b5e9-5bd8-a62c-2357e0555fcc', 'video_game', 'Marvel''s Avengers', 2020, NULL, 'PlayStation, Xbox, PC', 'An action-adventure game developed by Crystal Dynamics featuring a roster of playable Avengers.', NULL),
  ('19ce036e-b938-53ab-9933-def2ed5a6739', '948cf5fe-fe35-5e34-9f70-089f1b266b31', 'video_game', 'Youngblood (Sega CD prototype era)', NULL, NULL, 'Sega CD', 'A fan-favorite playable bruiser.', NULL),
  ('d4de4849-01a2-5c43-b914-38a1f05c57c7', '948cf5fe-fe35-5e34-9f70-089f1b266b31', 'animated_series', 'Youngblood (proposed animated adaptation)', NULL, NULL, NULL, 'Highlighted as a marketable character.', NULL),
  ('be74feff-922f-56cd-9cdd-ba33e45d6dd0', '6307652f-ef23-59c7-bf66-eb6ce5ed6e9c', 'film', 'The Dark Knight Rises', 2012, NULL, 'Max', 'Tom Hardy''s Bane is physically imposing and rhetorically precise — Nolan''s version leans into the character''s ability to dismantle institutions rather than just people.', 'Max'),
  ('610a1975-7240-5328-8120-1e06c1e42387', '6307652f-ef23-59c7-bf66-eb6ce5ed6e9c', 'animated_series', 'Batman: The Animated Series', 1992, 1, 'Max', 'Bane appears in the animated series in a Knightfall-adjacent episode, voiced by Henry Silva.', 'Max'),
  ('bbe6ee61-aeeb-51b3-8491-06cf3d3ad005', '6307652f-ef23-59c7-bf66-eb6ce5ed6e9c', 'video_game', 'Batman: Arkham Asylum', 2009, NULL, 'PlayStation, Xbox, PC', 'Bane is a major antagonist in Arkham Asylum, with a Venom-fueled design that references both his comics and film appearances.', NULL),
  ('62b1ccd1-aae9-546a-b15e-07661b411dfb', '6e0c7dd7-5e7a-5e9b-9a74-1424a8db9121', 'animated_series', 'Batman: The Animated Series', 1992, 1, 'Max', 'Batgirl appears in the animated series with Melissa Gilbert voicing the character.', 'Max'),
  ('0b56ad19-2ff7-5b74-96ea-1bf3354d421e', '6e0c7dd7-5e7a-5e9b-9a74-1424a8db9121', 'animated_series', 'Batman Beyond', 1999, NULL, 'Max', 'Barbara Gordon appears as an older, retired Commissioner Gordon-era figure — a version of the character that traces her full arc from Batgirl to law enforcement.', 'Max'),
  ('92fae0fb-4d73-596e-9b0b-dc7dc3e71393', '6e0c7dd7-5e7a-5e9b-9a74-1424a8db9121', 'film', 'Batman: The Killing Joke (Animated)', 2016, NULL, 'Max', 'The animated adaptation of Moore''s story adds a Barbara-centric prologue that attempts to contextualize her role, with Tara Strong voicing the character.', 'Max'),
  ('a0859723-c583-5433-8804-2e313ffc50d3', '45ba8447-d9b0-5e63-b25d-3f181ed157a7', 'animated_series', 'Savage Dragon', 1995, 1, 'USA Network', 'Appears among the allied heroes in the animated series.', NULL),
  ('0b292e32-ebee-5fbd-a2c5-fd864123c79b', '45ba8447-d9b0-5e63-b25d-3f181ed157a7', 'video_game', 'Savage Dragon: The Game', 2014, 2, 'Mobile', 'Featured as one of the allied characters.', NULL),
  ('319aab3f-724b-5eca-a843-3326f19db0fc', 'd95c67d0-9578-5ab8-8ec3-cd61bef7c92f', 'film', 'Captain America: Civil War', 2016, NULL, 'Disney+', 'Daniel Bruhl plays Helmut Zemo, who manipulates the Avengers into tearing themselves apart.', 'Disney+'),
  ('8f063205-28d0-5d0b-9890-ac8f24d7a3d6', 'd95c67d0-9578-5ab8-8ec3-cd61bef7c92f', 'live_action', 'The Falcon and the Winter Soldier', 2021, NULL, 'Disney+', 'Bruhl returns as a charismatic and dangerous Zemo aiding Sam and Bucky against the Flag Smashers.', 'Disney+'),
  ('82064eb4-314c-5082-b356-150722c8ca5a', 'd95c67d0-9578-5ab8-8ec3-cd61bef7c92f', 'animated_series', 'The Avengers: Earth''s Mightiest Heroes', 2010, NULL, 'Disney+', 'Helmut Zemo appears as a leader of the Masters of Evil opposing the Avengers.', 'Disney+'),
  ('8789278d-96d4-5831-a8b6-cf0fdf83cad9', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'animated_series', 'Batman: The Animated Series', 1992, 1, 'Max', 'The definitive animated adaptation, responsible for creating or redefining much of the character''s supporting cast. Kevin Conroy''s voice performance became the template against which every subsequent Batman is measured. Introduced Harley Quinn to the wider DC mythology.', 'Max'),
  ('26148067-52c3-59fb-bc55-f0b4a60dd9ae', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'film', 'Batman (Tim Burton)', 1989, 1, 'Max', 'Tim Burton''s gothic, expressionist take was the film that established Batman as a serious big-budget property. Michael Keaton''s performance leans into Bruce Wayne''s oddness rather than suppressing it, making him one of the most interesting live-action versions of the character.', 'Max'),
  ('66e91b51-9e0f-5a99-8060-46dbf4922e9e', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'film', 'Batman Begins', 2005, 2, 'Max', 'Christopher Nolan''s origin film is the closest major theatrical adaptation to Year One''s psychological realism. It takes seriously the question of why Bruce Wayne would choose this particular method of becoming a symbol.', 'Max'),
  ('fd95add7-d65f-5791-b9ed-fa415cd9d837', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'film', 'The Dark Knight', 2008, 3, 'Max', 'Nolan''s second Batman film elevated the Joker conflict to the level of philosophical argument and is widely considered one of the finest superhero films produced. Heath Ledger''s Joker performance remains a cultural reference point.', 'Max'),
  ('586688cb-16d0-575e-bb62-c84746538819', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'film', 'The Batman', 2022, NULL, 'Max', 'Matt Reeves'' film treats Batman as a Year Two detective story in a Gotham modeled on 1970s crime cinema. Robert Pattinson''s version is the most explicitly Year One-adjacent theatrical Batman, emotionally unfinished and still learning what the symbol is supposed to mean.', 'Max'),
  ('13456929-bd1a-5d70-bbac-e9b9cb5058b8', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'video_game', 'Batman: Arkham Asylum', 2009, 1, 'PlayStation, Xbox, PC', 'Rocksteady''s first Arkham game is still the most tightly constructed entry — a contained gothic horror-action game that takes the Joker''s takeover of Arkham seriously as a logistics and power problem. Kevin Conroy and Mark Hamill reprise their animated series roles.', NULL),
  ('953cc11f-542c-5c73-a77b-6a149679bdde', '46a5721c-458f-5262-b06c-881e6b7f98bc', 'video_game', 'Batman: Arkham City', 2011, 2, 'PlayStation, Xbox, PC', 'The follow-up expands Arkham Asylum''s premise into an open-world prison district, giving the rogues gallery more space and the story more emotional ambition. Widely considered the best game in the series.', NULL),
  ('4fe27b79-2dcb-536c-b4b7-891076d8161b', 'c574c3b8-581d-56a5-95bd-6ac9f05e58c1', 'podcast', 'BOOM! Studios Official Podcast', 2021, NULL, 'Various', 'Franchise coverage.', NULL),
  ('e72c2cd0-e6ea-50e4-a561-0829dfccb712', 'c574c3b8-581d-56a5-95bd-6ac9f05e58c1', 'audio_drama', 'Something is Killing the Children (audio edition)', 2022, NULL, 'Audio', 'Franchise audio adaptation.', NULL),
