  ('2287cbfa-ec5e-54cb-b4e3-cbcc22878779', '0c19853d-1aac-5dcf-817b-22515ad05e2f', 'animated_series', 'Teen Titans Go!', 2013, 2, 'Cartoon Network', 'A comedic version of Beast Boy anchors the ensemble.', 'Max'),
