  ('4150338c-06c2-5a84-acfb-a38806e72308', '0a680e29-e289-5b76-ad11-9ae6b24f0542', 'film', 'The Avengers', 2012, 1, 'Theatrical', 'Black Widow, played by Scarlett Johansson, is a founding member of the cinematic team.', 'Disney+'),
  ('bede8bdd-6cff-58ef-8b24-c1773be6c9b1', '0a680e29-e289-5b76-ad11-9ae6b24f0542', 'film', 'Black Widow', 2021, 2, 'Theatrical', 'A solo film exploring Natasha''s past and her ties to the Red Room.', 'Disney+'),
