  ('a9cc9151-5657-54a6-a1fc-8952415ca889', 'b0977b5f-d359-5193-a417-cd73e680f6dc', 'film', 'Batman Returns', 1992, NULL, 'Max', 'Danny DeVito''s Penguin is Tim Burton''s most grotesque creation — a figure of genuine pathos and horror whose ambitions toward Gotham''s power structures read as monstrous self-parody.', 'Max'),
  ('ba0dc22f-46e6-5d1b-9c4a-3eb61326b632', 'b0977b5f-d359-5193-a417-cd73e680f6dc', 'animated_series', 'Batman: The Animated Series', 1992, 1, 'Max', 'David Ogden Stiers voiced a sophisticated, conniving Penguin who embodied the upper-crust criminal businessman persona the comics developed in parallel.', 'Max'),
  ('b29e0a49-3c50-5148-ae1d-4b6c2bff63c4', 'b0977b5f-d359-5193-a417-cd73e680f6dc', 'live_action', 'The Penguin (HBO Series)', 2024, NULL, 'Max', 'Colin Farrell reprises his role from The Batman in a limited series charting Oz Cobblepot''s rise through Gotham''s criminal hierarchy following the events of the film.', 'Max'),
  ('bd0b99a1-053b-5151-a5bc-660e9d6f7519', '2746a6b9-b9dd-5829-a0b1-bb4f656b6d54', 'film', 'The Empty Man', 2020, 1, '20th Century Studios', 'The film''s investigative apparatus parallels the task force.', 'Disney+ / Hulu (region dependent)'),
