  ('02e74c46-05b4-5f44-b055-de894334a30e', 'f8057d23-7b86-5e3a-ba0d-ad82d360cb6d', 'film', 'The Batman', 2022, NULL, 'Max', 'Paul Dano''s Riddler is the most radical film reimagining of any major Batman villain — a methodical, ideologically driven serial killer whose riddles are YouTube manifestos rather than wordplay.', 'Max'),
  ('a90d3681-94b6-50d0-a7c5-379a56567401', 'f8057d23-7b86-5e3a-ba0d-ad82d360cb6d', 'animated_series', 'Batman: The Animated Series', 1992, 1, 'Max', 'John Glover voiced the Riddler in the animated series'' two Riddler episodes, which are among the show''s tightest mystery constructions.', 'Max'),
  ('cb303d29-3189-5ec9-ae26-a90a16e715c1', 'f8057d23-7b86-5e3a-ba0d-ad82d360cb6d', 'film', 'Batman Forever', 1995, NULL, 'Max', 'Jim Carrey''s Riddler leans entirely into the character''s theatrical mania and status obsession, at the cost of any puzzle-solving credibility.', 'Max'),
  ('1ced30d3-3df0-563c-a275-390eac505efb', 'b1786fae-ce5d-5cfa-bfea-19b3b6ba84a4', 'podcast', 'BOOM! Studios Official Podcast', 2021, NULL, 'Various', 'Franchise coverage.', NULL),
